--
-- Name: _auto_post_document_to_gl_internal(text, uuid, date); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public._auto_post_document_to_gl_internal(p_document_type text, p_document_id uuid, p_posting_date date DEFAULT CURRENT_DATE) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_company_id      uuid;
    v_document        record;
    v_journal_id      uuid;
    v_journal_number  text;
    v_total_debit     numeric(18,2) := 0;
    v_total_credit    numeric(18,2) := 0;
    v_posting_rule    record;
    v_line_number     integer := 0;
    v_description     text;
    v_doc_amount      numeric(18,2);
BEGIN
    -- Resolve company_id directly from the document
    SELECT company_id INTO v_company_id
    FROM public.documents
    WHERE id = p_document_id;

    IF v_company_id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Document not found or has no company_id');
    END IF;

    -- Check if already posted (idempotency)
    IF public.is_document_posted(p_document_type, p_document_id) THEN
        RETURN jsonb_build_object('success', false, 'error', 'Already posted');
    END IF;

    -- Load document data
    SELECT d.*, o.doc_no as order_doc_no
    INTO v_document
    FROM public.documents d
    LEFT JOIN public.orders o ON o.id = d.order_id
    WHERE d.id = p_document_id;

    -- Calculate document amount
    SELECT COALESCE(SUM(di.quantity * di.unit_price), 0)
    INTO v_doc_amount
    FROM public.document_items di
    WHERE di.document_id = p_document_id;

    IF v_doc_amount <= 0 THEN
        RETURN jsonb_build_object('success', false, 'error', 'Document has no line items or zero amount');
    END IF;

    -- Load posting rules for this document type
    SELECT * INTO v_posting_rule
    FROM public.gl_posting_rules
    WHERE company_id = v_company_id
    AND document_type = p_document_type
    AND is_active = true
    LIMIT 1;

    IF v_posting_rule IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'No active posting rule for ' || p_document_type);
    END IF;

    -- Generate journal number
    v_journal_number := public.generate_journal_number(v_company_id, p_document_type);
    v_description := p_document_type || ' - ' || v_document.doc_no;

    -- Create GL journal
    INSERT INTO public.gl_journals (
        company_id, journal_number, journal_date, posting_date,
        description, journal_type, status,
        total_debit, total_credit,
        source_document_type, source_document_id,
        created_by, posted_by, posted_at
    ) VALUES (
        v_company_id, v_journal_number, p_posting_date, p_posting_date,
        v_description,
        CASE WHEN p_document_type LIKE 'SUPPLIER%' THEN p_document_type ELSE p_document_type END,
        'POSTED',
        v_doc_amount, v_doc_amount,
        p_document_type, p_document_id,
        COALESCE(auth.uid(), '00000000-0000-0000-0000-000000000000'::uuid),
        COALESCE(auth.uid(), '00000000-0000-0000-0000-000000000000'::uuid),
        now()
    ) RETURNING id INTO v_journal_id;

    -- Create debit line
    v_line_number := v_line_number + 1;
    INSERT INTO public.gl_journal_lines (
        journal_id, account_id, line_number, description,
        debit_amount, credit_amount, entity_type, entity_id, created_by
    ) VALUES (
        v_journal_id, v_posting_rule.debit_account_id, v_line_number,
        v_description,
        v_doc_amount, 0,
        CASE WHEN p_document_type IN ('SALES_INVOICE','RECEIPT') THEN 'CUSTOMER' ELSE 'SUPPLIER' END,
        v_document.issued_to_org_id,
        COALESCE(auth.uid(), '00000000-0000-0000-0000-000000000000'::uuid)
    );

    -- Create credit line
    v_line_number := v_line_number + 1;
    INSERT INTO public.gl_journal_lines (
        journal_id, account_id, line_number, description,
        debit_amount, credit_amount, entity_type, entity_id, created_by
    ) VALUES (
        v_journal_id, v_posting_rule.credit_account_id, v_line_number,
        v_description,
        0, v_doc_amount,
        CASE WHEN p_document_type IN ('SALES_INVOICE','RECEIPT') THEN 'CUSTOMER' ELSE 'SUPPLIER' END,
        v_document.issued_to_org_id,
        COALESCE(auth.uid(), '00000000-0000-0000-0000-000000000000'::uuid)
    );

    -- Update journal totals
    UPDATE public.gl_journals
    SET total_debit = v_doc_amount, total_credit = v_doc_amount
    WHERE id = v_journal_id;

    -- Record in document postings
    INSERT INTO public.gl_document_postings (
        company_id, document_type, document_id, document_number,
        journal_id, posted_amount, posting_status, created_by
    ) VALUES (
        v_company_id, p_document_type, p_document_id,
        v_document.doc_no,
        v_journal_id, v_doc_amount, 'POSTED',
        COALESCE(auth.uid(), '00000000-0000-0000-0000-000000000000'::uuid)
    );

    RETURN jsonb_build_object(
        'success', true,
        'journal_id', v_journal_id,
        'journal_number', v_journal_number,
        'amount', v_doc_amount
    );
END;
$$;


