-- Name: _movement_warehouse_id(text, uuid, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public._movement_warehouse_id(p_movement_type text, p_from uuid, p_to uuid) RETURNS uuid
    LANGUAGE sql IMMUTABLE
    AS $$
  SELECT CASE
           WHEN p_movement_type IN ('manual_out','shipment','transfer_out') THEN p_from
           WHEN p_movement_type IN ('manual_in','purchase_in','transfer_in','adjust_in') THEN p_to
           ELSE COALESCE(p_from, p_to)
         END
$$;


