--
-- Name: accrue_referral_from_scan(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.accrue_referral_from_scan() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_settings  record;
  v_assignment record;
  v_org_id    uuid;
  v_rm_amount numeric(12,2);
BEGIN
  -- Only process collected points events (not manual adjustments)
  IF NEW.collected_points IS NOT TRUE THEN
    RETURN NEW;
  END IF;

  IF NEW.consumer_id IS NULL THEN
    RETURN NEW;
  END IF;

  IF COALESCE(NEW.points_amount, 0) <= 0 THEN
    RETURN NEW;
  END IF;

  -- Find the HQ org for settings
  SELECT id INTO v_org_id FROM public.organizations WHERE org_type_code = 'HQ' LIMIT 1;

  -- Get settings
  SELECT * INTO v_settings
  FROM public.referral_incentive_settings
  WHERE org_id = v_org_id;

  IF NOT FOUND OR NOT v_settings.enabled THEN
    RETURN NEW;
  END IF;

  -- Find active assignment for this consumer
  SELECT * INTO v_assignment
  FROM public.reference_assignments
  WHERE shop_user_id = NEW.consumer_id
    AND effective_to IS NULL
    AND effective_from <= COALESCE(NEW.scanned_at, now())
  ORDER BY effective_from DESC
  LIMIT 1;

  IF NOT FOUND OR v_assignment.reference_user_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Calculate RM equivalent
  v_rm_amount := (NEW.points_amount::numeric / v_settings.conversion_points) * v_settings.conversion_rm;

  -- Insert accrual
  INSERT INTO public.referral_accruals (
    org_id, reference_user_id, shop_user_id,
    source_type, source_id, points_amount, rm_amount,
    assignment_id, event_at
  )
  VALUES (
    v_org_id, v_assignment.reference_user_id, NEW.consumer_id,
    'qr_scan', NEW.id, NEW.points_amount, v_rm_amount,
    v_assignment.id, COALESCE(NEW.scanned_at, now())
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.accrue_referral_from_scan() OWNER TO supabase_admin;

--
-- Name: accrue_referral_from_transaction(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.accrue_referral_from_transaction() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_settings   record;
  v_assignment record;
  v_org_id     uuid;
  v_rm_amount  numeric(12,2);
BEGIN
  -- Only process MIGRATION type if include_migration_points is ON
  IF NEW.transaction_type != 'MIGRATION' THEN
    RETURN NEW;
  END IF;

  IF NEW.user_id IS NULL THEN
    RETURN NEW;
  END IF;

  IF COALESCE(NEW.points_amount, 0) <= 0 THEN
    RETURN NEW;
  END IF;

  -- Find HQ org
  SELECT id INTO v_org_id FROM public.organizations WHERE org_type_code = 'HQ' LIMIT 1;

  -- Get settings
  SELECT * INTO v_settings
  FROM public.referral_incentive_settings
  WHERE org_id = v_org_id;

  IF NOT FOUND OR NOT v_settings.enabled OR NOT v_settings.include_migration_points THEN
    RETURN NEW;
  END IF;

  -- Find active assignment
  SELECT * INTO v_assignment
  FROM public.reference_assignments
  WHERE shop_user_id = NEW.user_id
    AND effective_to IS NULL
    AND effective_from <= COALESCE(NEW.transaction_date, now())
  ORDER BY effective_from DESC
  LIMIT 1;

  IF NOT FOUND OR v_assignment.reference_user_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Calculate RM
  v_rm_amount := (NEW.points_amount::numeric / v_settings.conversion_points) * v_settings.conversion_rm;

  -- Insert accrual
  INSERT INTO public.referral_accruals (
    org_id, reference_user_id, shop_user_id,
    source_type, source_id, points_amount, rm_amount,
    assignment_id, event_at
  )
  VALUES (
    v_org_id, v_assignment.reference_user_id, NEW.user_id,
    'migration', NEW.id, NEW.points_amount, v_rm_amount,
    v_assignment.id, COALESCE(NEW.transaction_date, now())
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.accrue_referral_from_transaction() OWNER TO supabase_admin;

--
-- Name: add_conversation_note(uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.add_conversation_note(p_conversation_id uuid, p_note_text text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_admin_id UUID := auth.uid();
    v_note_id UUID;
BEGIN
    IF NOT public.is_support_admin() THEN
        RAISE EXCEPTION 'Access denied';
    END IF;
    
    INSERT INTO public.support_conversation_notes (
        conversation_id,
        admin_id,
        note_text
    ) VALUES (
        p_conversation_id,
        v_admin_id,
        p_note_text
    )
    RETURNING id INTO v_note_id;
    
    -- Log event
    PERFORM public.log_conversation_event(
        p_conversation_id,
        'admin',
        v_admin_id,
        'note_added',
        NULL,
        jsonb_build_object('note_id', v_note_id),
        NULL
    );
    
    RETURN v_note_id;
END;
$$;


