-- Name: COLUMN document_signatures.document_type; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON COLUMN public.document_signatures.document_type IS 'Type of document: PO, INVOICE, PAYMENT, or RECEIPT';


--
-- Name: COLUMN document_signatures.document_id; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON COLUMN public.document_signatures.document_id IS 'FK to documents table';


--
-- Name: COLUMN document_signatures.signer_user_id; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON COLUMN public.document_signatures.signer_user_id IS 'User who signed the document';


--
-- Name: COLUMN document_signatures.signer_role; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON COLUMN public.document_signatures.signer_role IS 'Role of signer at time of signing (e.g. HQ_ADMIN, POWER_USER, MANUFACTURER)';


--
-- Name: COLUMN document_signatures.signature_image_url; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON COLUMN public.document_signatures.signature_image_url IS 'Snapshot copy of users.signature_url at signing time';


--
-- Name: COLUMN document_signatures.signature_hash; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON COLUMN public.document_signatures.signature_hash IS 'SHA256 hash of (document payload + signer_user_id + signed_at) for integrity verification';


--
-- Name: COLUMN document_signatures.metadata; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON COLUMN public.document_signatures.metadata IS 'Additional signature metadata (IP address, user agent, etc.)';


--
-- Name: add_document_signature(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.add_document_signature(p_document_id uuid, p_signer_user_id uuid, p_signer_role text) RETURNS public.document_signatures
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_signature public.document_signatures;
    v_doc public.documents;
    v_user_signature_url TEXT;
    v_hash TEXT;
    v_metadata JSONB;
BEGIN
    -- Get document details
    SELECT * INTO v_doc FROM public.documents WHERE id = p_document_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Document not found: %', p_document_id;
    END IF;

    -- Get user's signature URL
    SELECT signature_url INTO v_user_signature_url 
    FROM public.users 
    WHERE id = p_signer_user_id;

    -- Generate signature hash
    v_hash := public.generate_signature_hash(p_document_id, p_signer_user_id, NOW());

    -- Collect metadata (IP, user agent if available)
    v_metadata := jsonb_build_object(
        'ip_address', inet_client_addr()::TEXT,
        'document_type', v_doc.doc_type,
        'document_no', v_doc.doc_no
    );

    -- Insert signature record
    INSERT INTO public.document_signatures (
        document_type,
        document_id,
        signer_user_id,
        signer_role,
        signed_at,
        signature_image_url,
        signature_hash,
        metadata
    ) VALUES (
        v_doc.doc_type::TEXT,
        p_document_id,
        p_signer_user_id,
        p_signer_role,
        NOW(),
        v_user_signature_url,
        v_hash,
        v_metadata
    )
    ON CONFLICT (document_type, document_id, signer_user_id) 
    DO UPDATE SET
        signed_at = NOW(),
        signature_image_url = EXCLUDED.signature_image_url,
        signature_hash = EXCLUDED.signature_hash,
        metadata = EXCLUDED.metadata
    RETURNING * INTO v_signature;

    RETURN v_signature;
END;
$$;


ALTER FUNCTION public.add_document_signature(p_document_id uuid, p_signer_user_id uuid, p_signer_role text) OWNER TO supabase_admin;

--
-- Name: FUNCTION add_document_signature(p_document_id uuid, p_signer_user_id uuid, p_signer_role text); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.add_document_signature(p_document_id uuid, p_signer_user_id uuid, p_signer_role text) IS 'Records a digital signature for a document. Captures signer details and creates integrity hash.';


--
-- Name: adjust_inventory_quantity(uuid, uuid, integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.adjust_inventory_quantity(p_variant_id uuid, p_organization_id uuid, p_delta integer) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  UPDATE public.product_inventory
  SET 
    quantity_on_hand = quantity_on_hand + p_delta,
    updated_at = now()
  WHERE variant_id = p_variant_id
    AND organization_id = p_organization_id;
    
  IF NOT FOUND THEN
    -- If record doesn't exist, create it (though it should exist if we have QR codes)
    INSERT INTO public.product_inventory (
      variant_id,
      organization_id,
      quantity_on_hand,
      quantity_reserved,
      quantity_available
    ) VALUES (
      p_variant_id,
      p_organization_id,
      GREATEST(p_delta, 0),
      0,
      GREATEST(p_delta, 0)
    );
  END IF;
END;
$$;


