--
-- Name: admin_blast_message(text, jsonb); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.admin_blast_message(p_message text, p_attachments jsonb DEFAULT '[]'::jsonb) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
declare
  u record;
  v_thread_id uuid;
begin
  if (auth.jwt() ->> 'role') not in ('admin','hq_admin','power_user') then
    raise exception 'Not authorized';
  end if;

  for u in select id from auth.users loop
    v_thread_id := public.get_or_create_announcement_thread(u.id);

    insert into public.support_messages (
      thread_id,
      sender_type,
      sender_user_id,
      body,
      attachments
    )
    values (
      v_thread_id,
      'system',
      null,
      p_message,
      p_attachments
    );
  end loop;
end;
$$;


