-- Name: FUNCTION allocate_inventory_for_order(p_order_id uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.allocate_inventory_for_order(p_order_id uuid) IS 'Allocates inventory for D2H/S2D orders. Movement shows warehouse location with per-order allocation (Before: 0, After: qty).';


--
-- Name: apply_hr_coa_template(uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.apply_hr_coa_template(p_company_id uuid, p_template text DEFAULT 'SME_BASIC_MY'::text) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_created integer := 0;
  v_skipped integer := 0;
  v_accounts jsonb;
  v_rec jsonb;
  v_code text;
  v_name text;
  v_type public.gl_account_type;
  v_subtype text;
  v_normal text;
  v_description text;
BEGIN
  -- Define template accounts based on template name
  IF p_template = 'SME_MY_PAYROLL_SPLIT' THEN
    -- More granular: splits employer contributions
    v_accounts := '[
      {"code": "6100", "name": "Salaries & Wages Expense",                  "type": "EXPENSE",   "subtype": "Operating Expense",     "normal": "DEBIT",  "desc": "Gross salaries and wages including OT and allowances"},
      {"code": "6110", "name": "Employer Statutory Contributions Expense",   "type": "EXPENSE",   "subtype": "Operating Expense",     "normal": "DEBIT",  "desc": "EPF/SOCSO/EIS employer contributions"},
      {"code": "6200", "name": "Staff Claims Expense",                      "type": "EXPENSE",   "subtype": "Operating Expense",     "normal": "DEBIT",  "desc": "Employee expense claim reimbursements"},
      {"code": "2200", "name": "Payroll Payable",                           "type": "LIABILITY",  "subtype": "Current Liability",     "normal": "CREDIT", "desc": "Net salaries payable to employees"},
      {"code": "2210", "name": "EPF Payable",                               "type": "LIABILITY",  "subtype": "Current Liability",     "normal": "CREDIT", "desc": "Employee + employer EPF contributions payable"},
      {"code": "2220", "name": "SOCSO Payable",                             "type": "LIABILITY",  "subtype": "Current Liability",     "normal": "CREDIT", "desc": "Employee + employer SOCSO contributions payable"},
      {"code": "2230", "name": "EIS Payable",                               "type": "LIABILITY",  "subtype": "Current Liability",     "normal": "CREDIT", "desc": "Employee + employer EIS contributions payable"},
      {"code": "2240", "name": "PCB/MTD Payable",                           "type": "LIABILITY",  "subtype": "Current Liability",     "normal": "CREDIT", "desc": "Income tax withholding (PCB/MTD) payable"},
      {"code": "2250", "name": "Other Deductions Payable",                  "type": "LIABILITY",  "subtype": "Current Liability",     "normal": "CREDIT", "desc": "Loan, advance, and other deductions payable"},
      {"code": "2300", "name": "Employee Claims Payable",                   "type": "LIABILITY",  "subtype": "Current Liability",     "normal": "CREDIT", "desc": "Approved expense claims awaiting reimbursement"}
    ]'::jsonb;

  ELSE
    -- Default: SME_BASIC_MY — simple payroll accounts
    v_accounts := '[
      {"code": "6100", "name": "Salaries & Wages Expense",    "type": "EXPENSE",   "subtype": "Operating Expense",     "normal": "DEBIT",  "desc": "Gross salaries and wages including OT and allowances"},
      {"code": "6200", "name": "Staff Claims Expense",        "type": "EXPENSE",   "subtype": "Operating Expense",     "normal": "DEBIT",  "desc": "Employee expense claim reimbursements"},
      {"code": "2200", "name": "Payroll Payable",             "type": "LIABILITY",  "subtype": "Current Liability",     "normal": "CREDIT", "desc": "Net salaries payable to employees"},
      {"code": "2210", "name": "EPF Payable",                 "type": "LIABILITY",  "subtype": "Current Liability",     "normal": "CREDIT", "desc": "Employee + employer EPF contributions payable"},
      {"code": "2220", "name": "SOCSO Payable",               "type": "LIABILITY",  "subtype": "Current Liability",     "normal": "CREDIT", "desc": "Employee + employer SOCSO contributions payable"},
      {"code": "2230", "name": "EIS Payable",                 "type": "LIABILITY",  "subtype": "Current Liability",     "normal": "CREDIT", "desc": "Employee + employer EIS contributions payable"},
      {"code": "2240", "name": "PCB/MTD Payable",             "type": "LIABILITY",  "subtype": "Current Liability",     "normal": "CREDIT", "desc": "Income tax withholding (PCB/MTD) payable"},
      {"code": "2250", "name": "Other Deductions Payable",    "type": "LIABILITY",  "subtype": "Current Liability",     "normal": "CREDIT", "desc": "Loan, advance, and other deductions payable"},
      {"code": "2300", "name": "Employee Claims Payable",     "type": "LIABILITY",  "subtype": "Current Liability",     "normal": "CREDIT", "desc": "Approved expense claims awaiting reimbursement"}
    ]'::jsonb;
  END IF;

  -- Upsert each account (idempotent)
  FOR v_rec IN SELECT * FROM jsonb_array_elements(v_accounts)
  LOOP
    v_code    := v_rec->>'code';
    v_name    := v_rec->>'name';
    v_type    := (v_rec->>'type')::public.gl_account_type;
    v_subtype := v_rec->>'subtype';
    v_normal  := v_rec->>'normal';
    v_description := v_rec->>'desc';

    IF EXISTS (
      SELECT 1 FROM public.gl_accounts
      WHERE company_id = p_company_id AND code = v_code
    ) THEN
      -- Account exists: update name, subtype, description if changed (never renumber/delete)
      UPDATE public.gl_accounts
      SET name = v_name,
          subtype = v_subtype,
          description = v_description,
          updated_at = now()
      WHERE company_id = p_company_id AND code = v_code;
      v_skipped := v_skipped + 1;
    ELSE
      INSERT INTO public.gl_accounts (
        company_id, code, name, account_type, subtype,
        description, normal_balance, is_system, is_active
      ) VALUES (
        p_company_id, v_code, v_name, v_type, v_subtype,
        v_description, v_normal, true, true
      );
      v_created := v_created + 1;
    END IF;
  END LOOP;

  RETURN jsonb_build_object(
    'template', p_template,
    'company_id', p_company_id,
    'created', v_created,
    'skipped_updated', v_skipped,
    'total_accounts', v_created + v_skipped
  );
END;
$$;


ALTER FUNCTION public.apply_hr_coa_template(p_company_id uuid, p_template text) OWNER TO supabase_admin;

--
-- Name: apply_inventory_ship_adjustment(uuid, uuid, integer, integer, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.apply_inventory_ship_adjustment(p_variant_id uuid, p_organization_id uuid, p_units integer, p_cases integer DEFAULT 0, p_shipped_at timestamp with time zone DEFAULT now()) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_current_qty integer;
  v_org_name text;
  v_variant_name text;
BEGIN
  -- Get current quantity
  SELECT quantity_on_hand INTO v_current_qty
  FROM public.product_inventory
  WHERE variant_id = p_variant_id
    AND organization_id = p_organization_id
  FOR UPDATE;

  v_current_qty := COALESCE(v_current_qty, 0);

  -- Check if sufficient stock
  IF v_current_qty < p_units THEN
    -- Get names for better error message
    SELECT org_name INTO v_org_name FROM public.organizations WHERE id = p_organization_id;
    SELECT variant_name INTO v_variant_name FROM public.product_variants WHERE id = p_variant_id;
    
    RAISE EXCEPTION 'Insufficient stock for shipment. On hand: %, requested: %. Variant: % (%), Org: % (%)', 
      v_current_qty, p_units, COALESCE(v_variant_name, 'Unknown'), p_variant_id, COALESCE(v_org_name, 'Unknown'), p_organization_id;
  END IF;

  -- Update inventory
  UPDATE public.product_inventory
  SET 
    quantity_on_hand = quantity_on_hand - p_units,
    quantity_available = quantity_available - p_units,
    updated_at = now()
  WHERE variant_id = p_variant_id
    AND organization_id = p_organization_id;
    
  -- If no row was updated (shouldn't happen due to check above, but if row didn't exist), raise error
  IF NOT FOUND THEN
     SELECT org_name INTO v_org_name FROM public.organizations WHERE id = p_organization_id;
     SELECT variant_name INTO v_variant_name FROM public.product_variants WHERE id = p_variant_id;
     
     RAISE EXCEPTION 'Inventory record not found for Variant % (%) in Org % (%)', 
       COALESCE(v_variant_name, 'Unknown'), p_variant_id, COALESCE(v_org_name, 'Unknown'), p_organization_id;
  END IF;
END;
$$;


ALTER FUNCTION public.apply_inventory_ship_adjustment(p_variant_id uuid, p_organization_id uuid, p_units integer, p_cases integer, p_shipped_at timestamp with time zone) OWNER TO supabase_admin;

--
-- Name: apply_inventory_ship_adjustment_deprecated_56910(uuid, uuid, integer, integer, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.apply_inventory_ship_adjustment_deprecated_56910(p_variant_id uuid, p_organization_id uuid, p_units integer, p_cases integer, p_shipped_at timestamp with time zone) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_current_units INTEGER;
    v_current_cases INTEGER;
    v_current_qty INTEGER;
BEGIN
    -- Get current inventory
    SELECT 
        COALESCE(units_on_hand, 0),
        COALESCE(cases_on_hand, 0),
        COALESCE(quantity_on_hand, 0)
    INTO 
        v_current_units,
        v_current_cases,
        v_current_qty
    FROM product_inventory
    WHERE variant_id = p_variant_id
      AND organization_id = p_organization_id;

    -- If no inventory record exists, log warning and exit
    IF NOT FOUND THEN
        RAISE WARNING 'No inventory record found for variant % in organization %', p_variant_id, p_organization_id;
        RETURN;
    END IF;

    -- Update inventory by reducing shipped quantities
    -- IMPORTANT: quantity_on_hand is the main field that shows in UI "On Hand" column
    -- units_on_hand and cases_on_hand are auxiliary tracking fields
    UPDATE product_inventory
    SET
        quantity_on_hand = GREATEST(0, quantity_on_hand - p_units),  -- Main quantity field
        units_on_hand = GREATEST(0, units_on_hand - p_units),
        cases_on_hand = GREATEST(0, cases_on_hand - p_cases),
        updated_at = p_shipped_at
    WHERE variant_id = p_variant_id
      AND organization_id = p_organization_id;

    -- Log the adjustment
    RAISE NOTICE 'Inventory adjusted for variant % in org %: shipped % units (was: % units, % cases, % qty), reduced quantity_on_hand', 
        p_variant_id, p_organization_id, p_units, v_current_units, v_current_cases, v_current_qty;

EXCEPTION
    WHEN OTHERS THEN
        RAISE WARNING 'Error in apply_inventory_ship_adjustment: %', SQLERRM;
        -- Don't raise error to prevent blocking shipment process
END;
$$;


ALTER FUNCTION public.apply_inventory_ship_adjustment_deprecated_56910(p_variant_id uuid, p_organization_id uuid, p_units integer, p_cases integer, p_shipped_at timestamp with time zone) OWNER TO supabase_admin;

--
-- Name: FUNCTION apply_inventory_ship_adjustment_deprecated_56910(p_variant_id uuid, p_organization_id uuid, p_units integer, p_cases integer, p_shipped_at timestamp with time zone); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.apply_inventory_ship_adjustment_deprecated_56910(p_variant_id uuid, p_organization_id uuid, p_units integer, p_cases integer, p_shipped_at timestamp with time zone) IS 'Adjusts inventory aggregates when products are shipped from warehouse to distributor. Reduces quantity_on_hand, units_on_hand, and cases_on_hand. The quantity_available is auto-calculated as quantity_on_hand - quantity_allocated.';


--
-- Name: approve_payment_request(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.approve_payment_request(p_request_id uuid) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_req            record;
  v_order_id       uuid;
  v_amount         numeric := 0;
  v_currency       text := 'MYR';
  v_company_id     uuid;
  v_order_type     text;
  v_payment_id     uuid := gen_random_uuid();
  v_payment_no     text;
  v_payment_base   text;
  v_now            timestamptz := now();
  v_existing_pay   uuid;
  v_order          record;
  v_order_json     jsonb;
  v_buyer_org      uuid;
  v_seller_org     uuid;
  v_created_by     uuid;
  v_requested_pct  numeric := 0;
  v_suffix_counter integer := 0;
  v_conflict       boolean := false;
  v_has_final_proof boolean := false;
BEGIN
  SELECT *
  INTO v_req
  FROM public.documents d
  WHERE d.id = p_request_id
    AND d.doc_type = 'PAYMENT_REQUEST'
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'approve_payment_request(): request % not found or not a PAYMENT_REQUEST', p_request_id;
  END IF;

  BEGIN
    v_order_id := NULLIF((v_req.payload->>'order_id')::uuid, NULL);
  EXCEPTION WHEN OTHERS THEN
    v_order_id := NULL;
  END;

  IF v_order_id IS NULL THEN
    RAISE EXCEPTION 'approve_payment_request(): request % has no order_id in payload', p_request_id;
  END IF;

  BEGIN
    v_amount := COALESCE((v_req.payload->>'requested_amount')::numeric, 0);
  EXCEPTION WHEN OTHERS THEN
    v_amount := 0;
  END;

  BEGIN
    v_requested_pct := COALESCE((v_req.payload->>'requested_percent')::numeric, 0);
  EXCEPTION WHEN OTHERS THEN
    v_requested_pct := 0;
  END;

  BEGIN
    v_currency := COALESCE(NULLIF(v_req.payload->>'currency', ''), 'MYR');
  EXCEPTION WHEN OTHERS THEN
    v_currency := 'MYR';
  END;

  IF v_amount <= 0 THEN
    RAISE EXCEPTION 'approve_payment_request(): requested_amount must be > 0 for request %', p_request_id;
  END IF;

  SELECT d.id
  INTO v_existing_pay
  FROM public.documents d
  WHERE d.doc_type = 'PAYMENT'
    AND (d.payload ? 'source_request_id')
    AND d.payload->>'source_request_id' = p_request_id::text
  LIMIT 1;

  IF v_existing_pay IS NOT NULL THEN
    IF v_req.status <> 'acknowledged' THEN
      UPDATE public.documents
      SET status = 'acknowledged', updated_at = v_now
      WHERE id = p_request_id;
    END IF;
    RETURN v_existing_pay;
  END IF;

  SELECT EXISTS (
    SELECT 1
    FROM public.document_files df
    WHERE df.document_id = p_request_id
  )
  INTO v_has_final_proof;

  IF NOT v_has_final_proof THEN
    RAISE EXCEPTION 'approve_payment_request(): final payment document is required before approval';
  END IF;

  SELECT o.* INTO v_order
  FROM public.orders o
  WHERE o.id = v_order_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'approve_payment_request(): order % not found for request %', v_order_id, p_request_id;
  END IF;

  v_order_json := to_jsonb(v_order);

  v_buyer_org := COALESCE(
    NULLIF(v_order_json ->> 'buyer_org_id', '')::uuid,
    NULLIF(v_order_json ->> 'hq_org_id', '')::uuid,
    NULLIF(v_order_json ->> 'customer_org_id', '')::uuid,
    NULLIF(v_order_json ->> 'distributor_org_id', '')::uuid,
    NULLIF(v_order_json ->> 'warehouse_org_id', '')::uuid
  );

  v_seller_org := COALESCE(
    NULLIF(v_order_json ->> 'seller_org_id', '')::uuid,
    NULLIF(v_order_json ->> 'manufacturer_org_id', '')::uuid,
    NULLIF(v_order_json ->> 'vendor_org_id', '')::uuid,
    NULLIF(v_order_json ->> 'supplier_org_id', '')::uuid
  );

  IF v_buyer_org IS NULL OR v_seller_org IS NULL THEN
    RAISE EXCEPTION 'approve_payment_request(): order % missing buyer/seller organization context', v_order_id;
  END IF;

  BEGIN
    v_company_id := NULLIF(v_order_json ->> 'company_id', '')::uuid;
  EXCEPTION WHEN OTHERS THEN
    v_company_id := NULL;
  END;

  IF v_company_id IS NULL AND v_buyer_org IS NOT NULL THEN
    BEGIN
      v_company_id := public.get_company_id(v_buyer_org);
    EXCEPTION WHEN OTHERS THEN
      v_company_id := NULL;
    END;
  END IF;

  BEGIN
    v_order_type := public.detect_order_type(v_buyer_org, v_seller_org)::text;
  EXCEPTION WHEN OTHERS THEN
    v_order_type := NULL;
  END;

  IF v_order_type IS NULL THEN
    v_order_type := COALESCE(v_order_json ->> 'order_type', 'HM');
  END IF;

  BEGIN
    v_created_by := auth.uid();
  EXCEPTION WHEN OTHERS THEN
    v_created_by := NULL;
  END;

  IF v_created_by IS NULL THEN
    BEGIN
      v_created_by := COALESCE(v_req.acknowledged_by, v_req.created_by, NULLIF(v_order_json ->> 'approved_by', '')::uuid, NULLIF(v_order_json ->> 'created_by', '')::uuid);
    EXCEPTION WHEN OTHERS THEN
      v_created_by := COALESCE(v_req.acknowledged_by, v_req.created_by);
    END;
  END IF;

  v_payment_no := NULL;
  v_payment_base := NULL;

  IF v_order.order_no IS NOT NULL THEN
    BEGIN
      v_payment_no := NULLIF(public.format_doc_no_from_order('PAY', v_order.order_no), 'PAY-');
    EXCEPTION WHEN OTHERS THEN
      v_payment_no := NULL;
    END;
  END IF;

  IF v_payment_no IS NULL AND v_req.doc_no IS NOT NULL THEN
    BEGIN
      v_payment_no := NULLIF(public.format_doc_no_from_order('PAY', v_req.doc_no), 'PAY-');
    EXCEPTION WHEN OTHERS THEN
      v_payment_no := NULL;
    END;
  END IF;

  IF v_payment_no IS NOT NULL THEN
    v_payment_no := v_payment_no || '-BAL';
  END IF;

  IF v_payment_no IS NULL THEN
    BEGIN
      IF v_company_id IS NOT NULL AND v_order_type IS NOT NULL THEN
        v_payment_no := public.generate_doc_number(v_company_id, 'PAY', v_order_type) || '-BAL';
      ELSE
        v_payment_no := 'PAY-' || to_char(v_now, 'YYMMDDHH24MISS') || '-' || right(encode(gen_random_bytes(2), 'hex'), 4) || '-BAL';
      END IF;
    EXCEPTION WHEN OTHERS THEN
      v_payment_no := 'PAY-' || to_char(v_now, 'YYMMDDHH24MISS') || '-' || right(encode(gen_random_bytes(2), 'hex'), 4) || '-BAL';
    END;
  END IF;

  v_payment_base := v_payment_no;

  LOOP
    SELECT EXISTS (
      SELECT 1
      FROM public.documents
      WHERE doc_no = v_payment_no
        AND (
          (company_id = v_company_id) OR
          (company_id IS NULL AND v_company_id IS NULL)
        )
    )
    INTO v_conflict;

    EXIT WHEN NOT v_conflict;

    v_suffix_counter := v_suffix_counter + 1;

    IF v_suffix_counter >= 20 THEN
      v_payment_no := v_payment_base || '-' || right(encode(gen_random_bytes(3), 'hex'), 6);
      EXIT;
    END IF;

    v_payment_no := v_payment_base || '-' || LPAD(v_suffix_counter::text, 2, '0');
  END LOOP;

  INSERT INTO public.documents (
    id,
    order_id,
    doc_type,
    doc_no,
    status,
    issued_by_org_id,
    issued_to_org_id,
    company_id,
    payload,
    created_by,
    created_at,
    updated_at,
    payment_percentage
  )
  VALUES (
    v_payment_id,
    v_order_id,
    'PAYMENT',
    v_payment_no,
    'pending',
    v_buyer_org,
    v_seller_org,
    v_company_id,
    jsonb_build_object(
      'order_id', v_order_id::text,
      'source_request_id', p_request_id::text,
      'amount', v_amount,
      'currency', v_currency,
      'note', 'Balance 50% created from approved PAYMENT_REQUEST'
    ),
    v_created_by,
    v_now,
    v_now,
    NULLIF(ROUND(v_requested_pct * 100)::integer, 0)
  );

  IF v_req.status <> 'acknowledged' THEN
    UPDATE public.documents
    SET status = 'acknowledged', updated_at = v_now
    WHERE id = p_request_id;
  END IF;

  BEGIN
    PERFORM public.add_document_signature(p_request_id, auth.uid(), 'HQ_APPROVER');
  EXCEPTION WHEN OTHERS THEN
    NULL;
  END;

  BEGIN
    INSERT INTO public.notifications_outbox (id, org_id, channel, template_code, payload_json, status, created_at)
    VALUES (
      gen_random_uuid(),
      NULL,
      'inapp',
      'FIN_BALANCE_PAYMENT_CREATED',
      jsonb_build_object(
        'order_id', v_order_id::text,
        'request_id', p_request_id::text,
        'payment_id', v_payment_id::text,
        'payment_no', v_payment_no,
        'amount', v_amount,
        'currency', v_currency
      ),
      'queued',
      v_now
    );
  EXCEPTION WHEN undefined_table THEN
    RAISE NOTICE 'notifications_outbox not present; skipping PAYMENT created notification';
  WHEN OTHERS THEN
    RAISE WARNING 'Could not enqueue PAYMENT created notification: %', SQLERRM;
  END;

  RETURN v_payment_id;
END;
$$;


ALTER FUNCTION public.approve_payment_request(p_request_id uuid) OWNER TO supabase_admin;

--
-- Name: approve_reference_change(uuid, text, uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.approve_reference_change(p_change_id uuid, p_action text, p_reviewer_id uuid, p_reason text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_change record;
  v_assignment_id uuid;
  v_new_ref_user record;
BEGIN
  SELECT * INTO v_change FROM public.reference_change_log WHERE id = p_change_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Change request not found');
  END IF;

  IF v_change.status != 'pending' THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Change request is not pending');
  END IF;

  IF p_action = 'approve' THEN
    -- Close old assignment
    UPDATE public.reference_assignments
    SET effective_to = now()
    WHERE shop_user_id = v_change.shop_user_id
      AND effective_to IS NULL;

    -- Resolve new reference user
    SELECT id, full_name INTO v_new_ref_user
    FROM public.users
    WHERE phone = (
      CASE
        WHEN v_change.new_reference_phone LIKE '+6%' THEN regexp_replace(v_change.new_reference_phone, '[^0-9+]', '', 'g')
        WHEN regexp_replace(v_change.new_reference_phone, '[^0-9]', '', 'g') LIKE '0%' THEN '+6' || regexp_replace(v_change.new_reference_phone, '[^0-9]', '', 'g')
        ELSE '+60' || regexp_replace(v_change.new_reference_phone, '[^0-9]', '', 'g')
      END
    )
    LIMIT 1;

    -- Create new assignment
    INSERT INTO public.reference_assignments (
      org_id, shop_user_id, reference_user_id, reference_phone,
      effective_from, change_source, created_by
    )
    VALUES (
      v_change.org_id, v_change.shop_user_id, v_new_ref_user.id, v_change.new_reference_phone,
      now(), 'admin', p_reviewer_id
    )
    RETURNING id INTO v_assignment_id;

    -- Update users.referral_phone
    UPDATE public.users
    SET referral_phone = v_change.new_reference_phone,
        updated_at = now()
    WHERE id = v_change.shop_user_id;

    -- Update change log
    UPDATE public.reference_change_log
    SET status = 'approved',
        reviewed_by = p_reviewer_id,
        reviewed_at = now(),
        effective_from = now(),
        assignment_id = v_assignment_id
    WHERE id = p_change_id;

  ELSIF p_action = 'reject' THEN
    UPDATE public.reference_change_log
    SET status = 'rejected',
        reviewed_by = p_reviewer_id,
        reviewed_at = now(),
        rejection_reason = p_reason
    WHERE id = p_change_id;
  ELSE
    RETURN jsonb_build_object('ok', false, 'error', 'Invalid action. Use approve or reject.');
  END IF;

  RETURN jsonb_build_object(
    'ok', true,
    'change_id', p_change_id,
    'action', p_action,
    'assignment_id', v_assignment_id
  );
END;
$$;


ALTER FUNCTION public.approve_reference_change(p_change_id uuid, p_action text, p_reviewer_id uuid, p_reason text) OWNER TO supabase_admin;

--
-- Name: archive_old_audit_logs(integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.archive_old_audit_logs(days_to_keep integer DEFAULT 90) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  rows_archived INTEGER;
BEGIN
  -- Ensure archive table exists with identical structure
  CREATE TABLE IF NOT EXISTS public.audit_logs_archive (LIKE public.audit_logs INCLUDING ALL);

  -- Move & count rows older than the retention window
  WITH moved AS (
    DELETE FROM public.audit_logs
    WHERE created_at < (CURRENT_DATE - (days_to_keep * INTERVAL '1 day'))
    RETURNING *
  )
  INSERT INTO public.audit_logs_archive
  SELECT * FROM moved;

  GET DIAGNOSTICS rows_archived = ROW_COUNT;

  RAISE NOTICE 'Archived % audit log records older than % days', rows_archived, days_to_keep;
  RETURN rows_archived;
END;
$$;


ALTER FUNCTION public.archive_old_audit_logs(days_to_keep integer) OWNER TO supabase_admin;

--
-- Name: FUNCTION archive_old_audit_logs(days_to_keep integer); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.archive_old_audit_logs(days_to_keep integer) IS 'Archives audit logs older than N days (default 90) into audit_logs_archive and removes them from the hot table.';


--
-- Name: assign_case_number_from_sequence(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.assign_case_number_from_sequence() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  units_per_case integer;
BEGIN
  -- Only process if case_number is not set and not a buffer code
  IF NEW.case_number IS NULL AND (NEW.is_buffer IS NULL OR NEW.is_buffer = false) THEN
    -- Get expected units per case from master codes
    SELECT qmc.expected_unit_count INTO units_per_case
    FROM public.qr_master_codes qmc
    WHERE qmc.batch_id = NEW.batch_id
    LIMIT 1;
    
    -- Calculate case number: Case 1 = sequences 1-100, Case 2 = 101-200, etc.
    IF units_per_case > 0 THEN
      NEW.case_number := ceil(NEW.sequence_number::numeric / units_per_case);
    END IF;
  END IF;
  
  -- Auto-populate variant_key if not set
  IF NEW.variant_key IS NULL AND NEW.code IS NOT NULL THEN
    NEW.variant_key := extract_variant_key_from_code(NEW.code);
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.assign_case_number_from_sequence() OWNER TO supabase_admin;

--
-- Name: FUNCTION assign_case_number_from_sequence(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.assign_case_number_from_sequence() IS 'Auto-calculates case_number from sequence_number based on units_per_case from qr_master_codes.';


--
-- Name: assign_conversation(uuid, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.assign_conversation(p_conversation_id uuid, p_admin_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_actor_id UUID := auth.uid();
    v_old_admin_id UUID;
BEGIN
    IF NOT public.is_support_admin() THEN
        RAISE EXCEPTION 'Access denied';
    END IF;
    
    SELECT assigned_admin_id INTO v_old_admin_id
    FROM public.support_conversations
    WHERE id = p_conversation_id;
    
    UPDATE public.support_conversations
    SET assigned_admin_id = p_admin_id,
        updated_at = NOW()
    WHERE id = p_conversation_id;
    
    -- Log event
    PERFORM public.log_conversation_event(
        p_conversation_id,
        'admin',
        v_actor_id,
        CASE WHEN p_admin_id IS NULL THEN 'unassigned' ELSE 'assigned' END::public.support_event_type,
        jsonb_build_object('admin_id', v_old_admin_id),
        jsonb_build_object('admin_id', p_admin_id),
        NULL
    );
END;
$$;


ALTER FUNCTION public.assign_conversation(p_conversation_id uuid, p_admin_id uuid) OWNER TO supabase_admin;

--
-- Name: audit_trigger_func(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.audit_trigger_func() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_user_id uuid;
  v_user_email text;
  v_old_data jsonb;
  v_new_data jsonb;
  v_changed_fields text[];
  v_entity_id uuid;
  v_headers json;
BEGIN
  -- Current auth user (may be NULL for service calls)
  v_user_id := auth.uid();

  -- Email is best-effort (auth.users is Supabase-managed)
  SELECT email INTO v_user_email FROM auth.users WHERE id = v_user_id;

  -- Prepare old/new payloads and changed field list
  IF TG_OP = 'DELETE' THEN
    v_old_data := to_jsonb(OLD);
    v_new_data := NULL;
  ELSIF TG_OP = 'UPDATE' THEN
    v_old_data := to_jsonb(OLD);
    v_new_data := to_jsonb(NEW);
    SELECT array_agg(key)
      INTO v_changed_fields
    FROM jsonb_each(v_new_data)
    WHERE v_new_data->key IS DISTINCT FROM v_old_data->key;
  ELSIF TG_OP = 'INSERT' THEN
    v_old_data := NULL;
    v_new_data := to_jsonb(NEW);
  END IF;

  -- Try to capture the entity id from either new or old row
  v_entity_id := COALESCE(
    NULLIF((v_new_data->>'id')::uuid, NULL),
    NULLIF((v_old_data->>'id')::uuid, NULL)
  );

  -- Request headers (may be null outside http context)
  v_headers := NULLIF(current_setting('request.headers', true), '')::json;

  INSERT INTO public.audit_logs (
    user_id,
    user_email,
    action,
    entity_type,   -- table name
    entity_id,
    old_values,
    new_values,
    changed_fields,
    ip_address,
    user_agent
  )
  VALUES (
    v_user_id,
    v_user_email,
    TG_OP,
    TG_TABLE_NAME,
    v_entity_id,
    v_old_data,
    v_new_data,
    v_changed_fields,
    inet_client_addr(),
    COALESCE(v_headers->>'user-agent', NULL)
  );

  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION public.audit_trigger_func() OWNER TO supabase_admin;

--
-- Name: auto_activate_journeys_on_ship(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.auto_activate_journeys_on_ship() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_journey_record record;
  v_order_id uuid;
BEGIN
  -- Only process if status changed to received_warehouse
  IF NEW.status = 'received_warehouse' AND (OLD.status IS NULL OR OLD.status != 'received_warehouse') THEN
    
    -- Get the order_id from the batch
    SELECT qb.order_id INTO v_order_id
    FROM public.qr_batches qb
    WHERE qb.id = NEW.batch_id;
    
    IF v_order_id IS NULL THEN
      RETURN NEW;
    END IF;
    
    -- Find journeys linked to this order that are pending activation
    FOR v_journey_record IN
      SELECT jc.id, jc.name
      FROM public.journey_configurations jc
      INNER JOIN public.journey_order_links jol ON jol.journey_config_id = jc.id
      WHERE jol.order_id = v_order_id
        AND jc.is_active = false
        AND jc.activation_status = 'pending_ship'
    LOOP
      -- Auto-activate the journey
      UPDATE public.journey_configurations
      SET 
        is_active = true,
        activation_status = 'auto_activated'
      WHERE id = v_journey_record.id;
      
      RAISE NOTICE 'Auto-activated journey % (%) for order % at received_warehouse status', 
        v_journey_record.name, v_journey_record.id, v_order_id;
    END LOOP;
    
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.auto_activate_journeys_on_ship() OWNER TO supabase_admin;

--
-- Name: FUNCTION auto_activate_journeys_on_ship(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.auto_activate_journeys_on_ship() IS 'Automatically activate journeys when products reach received_warehouse status';


