-- Name: auto_assign_admin_on_reply(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.auto_assign_admin_on_reply() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Only if sender is admin and conversation not yet assigned
    IF NEW.sender_type = 'admin' AND NEW.sender_admin_id IS NOT NULL THEN
        UPDATE public.support_conversations
        SET assigned_admin_id = NEW.sender_admin_id
        WHERE id = NEW.conversation_id
          AND assigned_admin_id IS NULL;
    END IF;
    
    RETURN NEW;
END;
$$;


