--
-- Name: auto_create_stock_adjustment_from_movement(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.auto_create_stock_adjustment_from_movement() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_reason_id uuid;
  v_manufacturer_id uuid;
  v_adjustment_id uuid;
  v_reason_code text;
BEGIN
  -- Check if reason is relevant
  IF NEW.reason IS NULL THEN
    RETURN NEW;
  END IF;

  -- Explicitly ignore warehouse_receive
  IF NEW.reason = 'warehouse_receive' THEN
    RETURN NEW;
  END IF;

  -- If from_organization_id is NULL (e.g. addition), we can't create an adjustment record
  -- that requires organization_id (which maps to from_organization_id).
  IF NEW.from_organization_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Get reason_id and code
  SELECT id, reason_code INTO v_reason_id, v_reason_code
  FROM public.stock_adjustment_reasons
  WHERE reason_name = NEW.reason OR reason_code = NEW.reason
  LIMIT 1;

  -- If not a quality/return issue, ignore
  -- Note: If v_reason_code is NULL, this condition is NULL (false), so it skips.
  IF v_reason_code NOT IN ('quality_issue', 'return_to_supplier') THEN
    RETURN NEW;
  END IF;

  -- Determine manufacturer
  v_manufacturer_id := NEW.manufacturer_id;
  
  IF v_manufacturer_id IS NULL THEN
    -- Try to find from variant -> product -> manufacturer
    -- Using a safe approach with exception handling in case tables differ
    BEGIN
        SELECT p.manufacturer_id INTO v_manufacturer_id
        FROM public.product_variants v
        JOIN public.products p ON p.id = v.product_id
        WHERE v.id = NEW.variant_id;
    EXCEPTION WHEN OTHERS THEN
        -- Ignore errors if tables don't exist or schema differs
        NULL;
    END;
  END IF;

  -- Create stock_adjustment header
  INSERT INTO public.stock_adjustments (
    organization_id,
    reason_id,
    notes,
    proof_images,
    status,
    created_by,
    target_manufacturer_org_id,
    manufacturer_status,
    manufacturer_assigned_at
  ) VALUES (
    NEW.from_organization_id, -- For adjustment (negative), it's from.
    v_reason_id,
    NEW.notes,
    NEW.evidence_urls,
    'pending',
    NEW.created_by,
    v_manufacturer_id,
    'pending',
    CASE WHEN v_manufacturer_id IS NOT NULL THEN now() ELSE NULL END
  ) RETURNING id INTO v_adjustment_id;

  -- Create stock_adjustment_item
  -- Note: stock_adjustment_items table has columns: system_quantity, physical_quantity, adjustment_quantity
  INSERT INTO public.stock_adjustment_items (
    adjustment_id,
    variant_id,
    system_quantity,
    physical_quantity,
    adjustment_quantity,
    unit_cost
  ) VALUES (
    v_adjustment_id,
    NEW.variant_id,
    COALESCE(NEW.quantity_before, 0),
    COALESCE(NEW.quantity_after, 0),
    NEW.quantity_change,
    NEW.unit_cost
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.auto_create_stock_adjustment_from_movement() OWNER TO supabase_admin;

--
-- Name: auto_generate_display_doc_no(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.auto_generate_display_doc_no() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_prefix text;
    v_year integer;
    v_order_id uuid;
BEGIN
    -- Only generate if display_doc_no is not already set
    IF NEW.display_doc_no IS NULL AND NEW.company_id IS NOT NULL THEN
        IF TG_TABLE_NAME = 'orders' THEN
            -- For orders, use the standard sequence generation
            v_prefix := get_display_prefix_from_legacy(NEW.order_no, NULL);
            v_year := EXTRACT(YEAR FROM COALESCE(NEW.created_at, NOW()))::integer;
            NEW.display_doc_no := generate_display_doc_number(NEW.company_id, v_prefix, v_year);
            
            -- Extract and store base_seq for child documents to reference
            NEW.base_seq := extract_seq_from_display_doc_no(NEW.display_doc_no);
            
        ELSIF TG_TABLE_NAME = 'documents' THEN
            -- For documents, use order-referenced numbering
            v_year := EXTRACT(YEAR FROM COALESCE(NEW.created_at, NOW()))::integer;
            
            -- Check if order_id exists
            IF NEW.order_id IS NOT NULL THEN
                -- Use order-referenced document numbering
                NEW.display_doc_no := generate_order_referenced_doc_number(
                    NEW.company_id, 
                    NEW.order_id, 
                    NEW.doc_type::text, 
                    v_year
                );
            ELSE
                -- Fallback to standard numbering if no order_id
                v_prefix := get_display_prefix_from_legacy(NEW.doc_no, NEW.doc_type::text);
                NEW.display_doc_no := generate_display_doc_number(NEW.company_id, v_prefix, v_year);
            END IF;
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.auto_generate_display_doc_no() OWNER TO supabase_admin;

--
-- Name: FUNCTION auto_generate_display_doc_no(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.auto_generate_display_doc_no() IS 'Auto-generates display_doc_no. Orders get independent sequences; documents reference their parent order sequence.';


--
-- Name: auto_post_document_to_gl(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.auto_post_document_to_gl() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_posting_mode text;
    v_company_id   uuid;
    v_doc_type     text;
    v_result       jsonb;
BEGIN
    -- Map document doc_type to GL posting document_type
    v_doc_type := CASE NEW.doc_type
        WHEN 'INVOICE' THEN 'SALES_INVOICE'
        WHEN 'RECEIPT' THEN 'RECEIPT'
        ELSE NULL
    END;

    -- Only auto-post supported document types
    IF v_doc_type IS NULL THEN
        RETURN NEW;
    END IF;

    -- documents.company_id is the HQ org id (references organizations)
    v_company_id := NEW.company_id;

    IF v_company_id IS NULL THEN
        RETURN NEW;  -- Can't determine tenant, skip silently
    END IF;

    -- Check if AUTO posting is enabled for this tenant
    SELECT posting_mode INTO v_posting_mode
    FROM public.gl_settings
    WHERE company_id = v_company_id;

    IF v_posting_mode IS DISTINCT FROM 'AUTO' THEN
        RETURN NEW;  -- Manual mode, skip
    END IF;

    -- Idempotency check
    IF public.is_document_posted(v_doc_type, NEW.id) THEN
        RETURN NEW;
    END IF;

    -- Attempt auto-posting (swallow errors to not block document creation)
    BEGIN
        v_result := public._auto_post_document_to_gl_internal(v_doc_type, NEW.id, CURRENT_DATE);

        IF (v_result->>'success')::boolean THEN
            RAISE NOTICE 'Auto-posted document % (%) to GL: journal %',
                NEW.id, v_doc_type, v_result->>'journal_number';
        ELSE
            RAISE WARNING 'Auto-post failed for document % (%): %',
                NEW.id, v_doc_type, v_result->>'error';
        END IF;
    EXCEPTION WHEN OTHERS THEN
        RAISE WARNING 'Auto-post exception for document % (%): %',
            NEW.id, v_doc_type, SQLERRM;
    END;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.auto_post_document_to_gl() OWNER TO supabase_admin;

--
-- Name: FUNCTION auto_post_document_to_gl(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.auto_post_document_to_gl() IS 'Trigger function: auto-posts INVOICE and RECEIPT documents to GL when posting_mode = AUTO in gl_settings.';


--
-- Name: auto_post_payment_to_gl(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.auto_post_payment_to_gl() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_posting_mode text;
    v_company_id   uuid;
    v_doc_type     text;
    v_result       jsonb;
BEGIN
    -- document_status enum: 'pending', 'acknowledged', 'completed'
    -- Only fire when status transitions to 'completed'
    IF NEW.status <> 'completed' THEN
        RETURN NEW;
    END IF;

    -- Determine GL document type from doc_type (document_type enum)
    -- PAYMENT → deposit or balance (determined by doc_no / payload)
    -- PAYMENT_REQUEST → supplier invoice recognition
    IF NEW.doc_type = 'PAYMENT_REQUEST' THEN
        v_doc_type := 'SUPPLIER_INVOICE_RECOGNITION';
    ELSIF NEW.doc_type = 'PAYMENT' THEN
        -- Determine deposit vs balance using same logic as get_payment_posting_details
        IF NEW.doc_no LIKE '%-BAL%' OR (NEW.payload ? 'source_request_id') THEN
            v_doc_type := 'SUPPLIER_BALANCE_PAYMENT';
        ELSE
            v_doc_type := 'SUPPLIER_DEPOSIT_PAYMENT';
        END IF;
    ELSE
        RETURN NEW;  -- Unsupported doc_type, skip
    END IF;

    -- documents.company_id = HQ org id
    v_company_id := NEW.company_id;

    IF v_company_id IS NULL THEN
        RETURN NEW;
    END IF;

    -- Check AUTO mode
    SELECT posting_mode INTO v_posting_mode
    FROM public.gl_settings
    WHERE company_id = v_company_id;

    IF v_posting_mode IS DISTINCT FROM 'AUTO' THEN
        RETURN NEW;
    END IF;

    IF public.is_document_posted(v_doc_type, NEW.id) THEN
        RETURN NEW;
    END IF;

    BEGIN
        v_result := public._auto_post_document_to_gl_internal(v_doc_type, NEW.id, CURRENT_DATE);

        IF (v_result->>'success')::boolean THEN
            RAISE NOTICE 'Auto-posted payment % (%) to GL: journal %',
                NEW.id, v_doc_type, v_result->>'journal_number';
        ELSE
            RAISE WARNING 'Auto-post failed for payment % (%): %',
                NEW.id, v_doc_type, v_result->>'error';
        END IF;
    EXCEPTION WHEN OTHERS THEN
        RAISE WARNING 'Auto-post exception for payment % (%): %',
            NEW.id, v_doc_type, SQLERRM;
    END;

    RETURN NEW;
END;
$$;


