--
-- Name: backfill_display_doc_numbers(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.backfill_display_doc_numbers(p_company_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_job_id uuid;
    v_orders_processed integer := 0;
    v_docs_processed integer := 0;
    v_failed integer := 0;
    v_order_record RECORD;
    v_doc_record RECORD;
    v_display_no text;
    v_prefix text;
    v_year integer;
    v_running_job uuid;
BEGIN
    -- Check for running jobs
    SELECT id INTO v_running_job
    FROM public.doc_migration_jobs
    WHERE company_id = p_company_id
      AND status = 'running'
      AND started_at > NOW() - INTERVAL '1 hour';
    
    IF v_running_job IS NOT NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Migration already in progress',
            'job_id', v_running_job
        );
    END IF;
    
    -- Create job record
    INSERT INTO public.doc_migration_jobs (company_id, status)
    VALUES (p_company_id, 'running')
    RETURNING id INTO v_job_id;
    
    BEGIN
        -- Process orders without display_doc_no
        FOR v_order_record IN
            SELECT id, order_no, created_at
            FROM public.orders
            WHERE company_id = p_company_id
              AND display_doc_no IS NULL
              AND order_no IS NOT NULL
            ORDER BY created_at ASC, id ASC
        LOOP
            BEGIN
                v_prefix := get_display_prefix_from_legacy(v_order_record.order_no, NULL);
                v_year := EXTRACT(YEAR FROM v_order_record.created_at)::integer;
                v_display_no := generate_display_doc_number(p_company_id, v_prefix, v_year);
                
                UPDATE public.orders
                SET display_doc_no = v_display_no
                WHERE id = v_order_record.id;
                
                v_orders_processed := v_orders_processed + 1;
            EXCEPTION WHEN OTHERS THEN
                v_failed := v_failed + 1;
                RAISE NOTICE 'Failed to process order %: %', v_order_record.id, SQLERRM;
            END;
        END LOOP;
        
        -- Process documents without display_doc_no
        -- FIX: Cast doc_type to text in the SELECT!
        FOR v_doc_record IN
            SELECT id, doc_no, doc_type::text as doc_type_text, created_at
            FROM public.documents
            WHERE company_id = p_company_id
              AND display_doc_no IS NULL
              AND doc_no IS NOT NULL
            ORDER BY created_at ASC, id ASC
        LOOP
            BEGIN
                v_prefix := get_display_prefix_from_legacy(v_doc_record.doc_no, v_doc_record.doc_type_text);
                v_year := EXTRACT(YEAR FROM v_doc_record.created_at)::integer;
                v_display_no := generate_display_doc_number(p_company_id, v_prefix, v_year);
                
                UPDATE public.documents
                SET display_doc_no = v_display_no
                WHERE id = v_doc_record.id;
                
                v_docs_processed := v_docs_processed + 1;
            EXCEPTION WHEN OTHERS THEN
                v_failed := v_failed + 1;
                RAISE NOTICE 'Failed to process document %: %', v_doc_record.id, SQLERRM;
            END;
        END LOOP;
        
        -- Mark job as completed
        UPDATE public.doc_migration_jobs
        SET status = 'completed',
            completed_at = NOW(),
            records_processed = v_orders_processed + v_docs_processed,
            records_failed = v_failed
        WHERE id = v_job_id;
        
        RETURN jsonb_build_object(
            'success', true,
            'job_id', v_job_id,
            'records_processed', v_orders_processed + v_docs_processed,
            'orders_processed', v_orders_processed,
            'documents_processed', v_docs_processed,
            'records_failed', v_failed
        );
    EXCEPTION WHEN OTHERS THEN
        -- Mark job as failed
        UPDATE public.doc_migration_jobs
        SET status = 'failed',
            completed_at = NOW(),
            error_message = SQLERRM,
            records_failed = v_failed
        WHERE id = v_job_id;
        
        RETURN jsonb_build_object(
            'success', false,
            'job_id', v_job_id,
            'error', SQLERRM,
            'records_failed', v_failed
        );
    END;
END;
$$;


ALTER FUNCTION public.backfill_display_doc_numbers(p_company_id uuid) OWNER TO supabase_admin;

--
-- Name: FUNCTION backfill_display_doc_numbers(p_company_id uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.backfill_display_doc_numbers(p_company_id uuid) IS 'Safely backfills display_doc_no for all historical orders and documents. Idempotent and concurrent-safe.';


--
-- Name: batch_post_documents(text, date, date, integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.batch_post_documents(p_document_type text, p_start_date date, p_end_date date, p_limit integer DEFAULT 100) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_company_id uuid;
    v_doc record;
    v_result jsonb;
    v_posted_count integer := 0;
    v_skipped_count integer := 0;
    v_error_count integer := 0;
    v_errors jsonb := '[]'::jsonb;
BEGIN
    -- Check permission
    IF NOT public.is_hq_admin() THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Only HQ Admins can batch post'
        );
    END IF;
    
    v_company_id := public.get_user_company_id();
    
    -- Process based on document type
    CASE p_document_type
        WHEN 'SALES_INVOICE' THEN
            FOR v_doc IN 
                SELECT o.id, o.order_no, o.created_at::date as doc_date
                FROM public.orders o
                WHERE o.company_id = v_company_id
                AND o.created_at::date BETWEEN p_start_date AND p_end_date
                AND o.status IN ('delivered', 'completed')
                AND NOT EXISTS (
                    SELECT 1 FROM public.gl_document_postings dp
                    WHERE dp.document_type = 'SALES_INVOICE'
                    AND dp.document_id = o.id
                    AND dp.posting_status = 'POSTED'
                )
                ORDER BY o.created_at
                LIMIT p_limit
            LOOP
                BEGIN
                    v_result := public.post_document_to_gl('SALES_INVOICE', v_doc.id, v_doc.doc_date);
                    
                    IF (v_result->>'success')::boolean THEN
                        v_posted_count := v_posted_count + 1;
                    ELSE
                        v_error_count := v_error_count + 1;
                        v_errors := v_errors || jsonb_build_object(
                            'document_id', v_doc.id,
                            'document_number', v_doc.order_no,
                            'error', v_result->>'error'
                        );
                    END IF;
                EXCEPTION WHEN OTHERS THEN
                    v_error_count := v_error_count + 1;
                    v_errors := v_errors || jsonb_build_object(
                        'document_id', v_doc.id,
                        'document_number', v_doc.order_no,
                        'error', SQLERRM
                    );
                END;
            END LOOP;
            
        WHEN 'RECEIPT' THEN
            -- NOTE: payments table does not exist yet
            RETURN jsonb_build_object(
                'success', false,
                'error', 'RECEIPT batch posting not yet implemented - payments table required'
            );
            
        ELSE
            RETURN jsonb_build_object(
                'success', false,
                'error', 'Batch posting not implemented for document type: ' || p_document_type
            );
    END CASE;
    
    RETURN jsonb_build_object(
        'success', true,
        'posted_count', v_posted_count,
        'skipped_count', v_skipped_count,
        'error_count', v_error_count,
        'errors', v_errors
    );
END;
$$;


ALTER FUNCTION public.batch_post_documents(p_document_type text, p_start_date date, p_end_date date, p_limit integer) OWNER TO supabase_admin;

--
-- Name: batch_regenerate_doc_numbers(uuid, integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.batch_regenerate_doc_numbers(p_company_id uuid, p_limit integer DEFAULT 100) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_order_id uuid;
    v_processed integer := 0;
    v_result jsonb;
    v_results jsonb := '[]'::jsonb;
BEGIN
    -- Process orders that have documents but might need renumbering
    FOR v_order_id IN 
        SELECT DISTINCT o.id
        FROM public.orders o
        INNER JOIN public.documents d ON d.order_id = o.id
        WHERE o.company_id = p_company_id
          AND o.display_doc_no IS NOT NULL
          AND EXISTS (
              -- Find documents that don't follow the order-referenced format
              SELECT 1 FROM public.documents d2
              WHERE d2.order_id = o.id
                AND d2.display_doc_no IS NOT NULL
                AND d2.display_doc_no NOT LIKE '%' || LPAD(COALESCE(o.base_seq, extract_seq_from_display_doc_no(o.display_doc_no))::text, 6, '0') || '%'
          )
        ORDER BY o.created_at ASC
        LIMIT p_limit
    LOOP
        v_result := regenerate_order_doc_numbers(v_order_id);
        v_results := v_results || v_result;
        v_processed := v_processed + 1;
    END LOOP;
    
    RETURN jsonb_build_object(
        'success', true,
        'company_id', p_company_id,
        'orders_processed', v_processed,
        'details', v_results
    );
END;
$$;


ALTER FUNCTION public.batch_regenerate_doc_numbers(p_company_id uuid, p_limit integer) OWNER TO supabase_admin;

