-- Name: FUNCTION can_access_org(p_org_id uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.can_access_org(p_org_id uuid) IS 'Checks if current user can access organization data based on org hierarchy (descendant/ancestor) and HQ override';


--
-- Name: can_collect_point_reward(uuid, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.can_collect_point_reward(p_redeem_item_id uuid, p_user_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_collection_mode TEXT;
    v_per_user_limit BOOLEAN;
    v_existing_collection RECORD;
BEGIN
    -- Get the reward settings
    SELECT collection_mode, per_user_limit 
    INTO v_collection_mode, v_per_user_limit
    FROM redeem_items 
    WHERE id = p_redeem_item_id AND category = 'point';
    
    -- If not a point reward or not found, allow collection
    IF NOT FOUND THEN
        RETURN TRUE;
    END IF;
    
    -- If no user limit, always allow
    IF NOT v_per_user_limit THEN
        RETURN TRUE;
    END IF;
    
    -- Check based on collection mode
    CASE v_collection_mode
        WHEN 'once' THEN
            -- Check if user has ever collected
            SELECT * INTO v_existing_collection
            FROM point_reward_collections
            WHERE redeem_item_id = p_redeem_item_id AND user_id = p_user_id
            LIMIT 1;
            
            RETURN NOT FOUND;
            
        WHEN 'daily' THEN
            -- Check if user has collected today
            SELECT * INTO v_existing_collection
            FROM point_reward_collections
            WHERE redeem_item_id = p_redeem_item_id 
              AND user_id = p_user_id 
              AND collection_date = CURRENT_DATE
            LIMIT 1;
            
            RETURN NOT FOUND;
            
        ELSE
            -- 'always' mode - always allow
            RETURN TRUE;
    END CASE;
END;
$$;


ALTER FUNCTION public.can_collect_point_reward(p_redeem_item_id uuid, p_user_id uuid) OWNER TO supabase_admin;

--
-- Name: can_consumer_redeem_gift(uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.can_consumer_redeem_gift(p_redeem_gift_id uuid, p_consumer_phone text) RETURNS jsonb
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
    v_result jsonb;
    v_gift record;
    v_consumer_redemption_count integer;
BEGIN
    -- Get gift details
    SELECT * INTO v_gift
    FROM public.redeem_gifts
    WHERE id = p_redeem_gift_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'can_redeem', false,
            'reason', 'gift_not_found'
        );
    END IF;
    
    -- Check if gift is active
    IF v_gift.is_active = false THEN
        RETURN jsonb_build_object(
            'can_redeem', false,
            'reason', 'gift_inactive'
        );
    END IF;
    
    -- Check date range
    IF v_gift.start_date IS NOT NULL AND now() < v_gift.start_date THEN
        RETURN jsonb_build_object(
            'can_redeem', false,
            'reason', 'not_started',
            'start_date', v_gift.start_date
        );
    END IF;
    
    IF v_gift.end_date IS NOT NULL AND now() > v_gift.end_date THEN
        RETURN jsonb_build_object(
            'can_redeem', false,
            'reason', 'expired',
            'end_date', v_gift.end_date
        );
    END IF;
    
    -- Check if gifts are still available
    IF v_gift.claimed_quantity >= v_gift.total_quantity THEN
        RETURN jsonb_build_object(
            'can_redeem', false,
            'reason', 'sold_out'
        );
    END IF;
    
    -- Check consumer's redemption count
    SELECT COUNT(*) INTO v_consumer_redemption_count
    FROM public.redeem_gift_transactions
    WHERE redeem_gift_id = p_redeem_gift_id
    AND consumer_phone = p_consumer_phone;
    
    IF v_consumer_redemption_count >= v_gift.limit_per_consumer THEN
        RETURN jsonb_build_object(
            'can_redeem', false,
            'reason', 'limit_reached',
            'limit', v_gift.limit_per_consumer
        );
    END IF;
    
    -- All checks passed
    RETURN jsonb_build_object(
        'can_redeem', true,
        'gift_name', v_gift.gift_name,
        'available_quantity', v_gift.total_quantity - v_gift.claimed_quantity,
        'consumer_remaining_claims', v_gift.limit_per_consumer - v_consumer_redemption_count
    );
END;
$$;


