-- Name: check_agreement_expiry(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.check_agreement_expiry() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.agreement_end_date IS NOT NULL
     AND NEW.agreement_end_date < CURRENT_DATE
     AND COALESCE(NEW.is_active, true) = true THEN
    NEW.is_active := false;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.check_agreement_expiry() OWNER TO supabase_admin;

--
-- Name: check_department_circular_reference(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.check_department_circular_reference() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_current_id uuid;
  v_depth int := 0;
  v_max_depth int := 10; -- Reasonable max depth to prevent infinite loops
BEGIN
  -- If no parent is set, no check needed
  IF NEW.parent_department_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Cannot be own parent
  IF NEW.parent_department_id = NEW.id THEN
    RAISE EXCEPTION 'A department cannot be its own parent';
  END IF;

  -- Walk up the tree to check for cycles
  v_current_id := NEW.parent_department_id;
  
  WHILE v_current_id IS NOT NULL AND v_depth < v_max_depth LOOP
    IF v_current_id = NEW.id THEN
      RAISE EXCEPTION 'Circular reference detected in department hierarchy';
    END IF;
    
    SELECT parent_department_id INTO v_current_id
    FROM departments
    WHERE id = v_current_id;
    
    v_depth := v_depth + 1;
  END LOOP;

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.check_department_circular_reference() OWNER TO supabase_admin;

--
-- Name: check_order_shipped_to_distributor(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.check_order_shipped_to_distributor(p_order_id uuid) RETURNS boolean
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  v_total_codes integer;
  v_shipped_codes integer;
BEGIN
  -- Count total QR codes for this order
  SELECT COUNT(DISTINCT qmc.id)
  INTO v_total_codes
  FROM public.qr_master_codes qmc
  INNER JOIN public.qr_batches qb ON qb.id = qmc.batch_id
  WHERE qb.order_id = p_order_id;
  
  -- If no codes, return false
  IF v_total_codes = 0 THEN
    RETURN false;
  END IF;
  
  -- Count codes that have reached shipped_distributor status
  SELECT COUNT(DISTINCT qmc.id)
  INTO v_shipped_codes
  FROM public.qr_master_codes qmc
  INNER JOIN public.qr_batches qb ON qb.id = qmc.batch_id
  WHERE qb.order_id = p_order_id
    AND qmc.status = 'shipped_distributor';
  
  -- Return true if at least one code has shipped (or all have shipped)
  RETURN v_shipped_codes > 0;
END;
$$;


