--
-- Name: check_organization_dependencies(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.check_organization_dependencies(p_org_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_org_type TEXT;
  v_org_name TEXT;
  v_org_code TEXT;
  v_result jsonb := '{}';
  v_blocking_records jsonb := '[]';
  v_has_blockers BOOLEAN := FALSE;
  v_count INTEGER;
BEGIN
  -- Get organization details
  SELECT org_type_code, org_name, org_code
  INTO v_org_type, v_org_name, v_org_code
  FROM public.organizations
  WHERE id = p_org_id;

  -- Check if organization exists
  IF v_org_type IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Organization not found',
      'error_code', 'ORG_NOT_FOUND'
    );
  END IF;

  -- Check for orders (buyer/seller)
  SELECT COUNT(*) INTO v_count FROM public.orders WHERE buyer_org_id = p_org_id OR seller_org_id = p_org_id;
  IF v_count > 0 THEN
    v_has_blockers := TRUE;
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'orders',
      'display_name', 'Orders',
      'count', v_count,
      'description', 'Orders where this organization is buyer or seller',
      'action', 'Orders cannot be deleted for audit reasons. You must cancel or transfer orders first.',
      'priority', 1,
      'records', (
        SELECT jsonb_agg(jsonb_build_object(
          'id', o.id,
          'reference', COALESCE(o.order_no, 'Order #' || SUBSTRING(o.id::text, 1, 8)),
          'status', o.status,
          'created_at', o.created_at
        ))
        FROM (SELECT * FROM public.orders WHERE buyer_org_id = p_org_id OR seller_org_id = p_org_id LIMIT 5) o
      )
    );
  END IF;

  -- Check for child organizations
  SELECT COUNT(*) INTO v_count FROM public.organizations WHERE parent_org_id = p_org_id AND is_active = true;
  IF v_count > 0 THEN
    v_has_blockers := TRUE;
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'organizations',
      'display_name', 'Child Organizations',
      'count', v_count,
      'description', 'Active child organizations under this parent',
      'action', 'Delete or deactivate child organizations first',
      'priority', 2,
      'records', (
        SELECT jsonb_agg(jsonb_build_object(
          'id', o.id,
          'reference', o.org_name,
          'code', o.org_code,
          'type', o.org_type_code
        ))
        FROM (SELECT * FROM public.organizations WHERE parent_org_id = p_org_id AND is_active = true LIMIT 5) o
      )
    );
  END IF;

  -- Check for products (manufacturer_id)
  SELECT COUNT(*) INTO v_count FROM public.products WHERE manufacturer_id = p_org_id;
  IF v_count > 0 THEN
    v_has_blockers := TRUE;
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'products',
      'display_name', 'Products',
      'count', v_count,
      'description', 'Products manufactured by this organization',
      'action', 'Delete products or reassign them to another manufacturer',
      'priority', 3,
      'can_force_delete', true,
      'records', (
        SELECT jsonb_agg(jsonb_build_object(
          'id', p.id,
          'reference', p.product_name,
          'code', p.product_code
        ))
        FROM (SELECT * FROM public.products WHERE manufacturer_id = p_org_id LIMIT 10) p
      )
    );
  END IF;

  -- Check for QR batches
  SELECT COUNT(*) INTO v_count FROM public.qr_batches WHERE company_id = p_org_id;
  IF v_count > 0 THEN
    v_has_blockers := TRUE;
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'qr_batches',
      'display_name', 'QR Batches',
      'count', v_count,
      'description', 'QR code batches created by this organization',
      'action', 'Delete QR batches first',
      'priority', 4,
      'records', (
        SELECT jsonb_agg(jsonb_build_object(
          'id', b.id,
          'reference', b.batch_code,
          'status', b.status,
          'total_codes', b.total_codes
        ))
        FROM (SELECT * FROM public.qr_batches WHERE company_id = p_org_id LIMIT 5) b
      )
    );
  END IF;

  -- Check for QR master codes (manufacturer_org_id)
  SELECT COUNT(*) INTO v_count FROM public.qr_master_codes WHERE manufacturer_org_id = p_org_id;
  IF v_count > 0 THEN
    v_has_blockers := TRUE;
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'qr_master_codes',
      'display_name', 'QR Master Codes',
      'count', v_count,
      'description', 'QR master codes linked to this manufacturer',
      'action', 'QR codes are linked to products from this manufacturer',
      'priority', 5,
      'records', (
        SELECT jsonb_agg(jsonb_build_object(
          'id', q.id,
          'reference', q.master_code,
          'status', q.status
        ))
        FROM (SELECT * FROM public.qr_master_codes WHERE manufacturer_org_id = p_org_id LIMIT 5) q
      )
    );
  END IF;

  -- Check for QR codes (company_id)
  SELECT COUNT(*) INTO v_count FROM public.qr_codes WHERE company_id = p_org_id;
  IF v_count > 0 THEN
    v_has_blockers := TRUE;
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'qr_codes',
      'display_name', 'QR Codes',
      'count', v_count,
      'description', 'QR codes owned by this organization',
      'action', 'Delete QR codes first (via batches)',
      'priority', 6,
      'records', (
        SELECT jsonb_agg(jsonb_build_object(
          'id', q.id,
          'reference', q.serial_code,
          'status', q.status
        ))
        FROM (SELECT * FROM public.qr_codes WHERE company_id = p_org_id LIMIT 5) q
      )
    );
  END IF;

  -- Check for users
  SELECT COUNT(*) INTO v_count FROM public.users WHERE organization_id = p_org_id;
  IF v_count > 0 THEN
    -- Users can be deleted with the org, not a blocker
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'users',
      'display_name', 'Users',
      'count', v_count,
      'description', 'Users belonging to this organization',
      'action', 'Will be automatically removed when organization is deleted',
      'priority', 100,
      'auto_delete', true,
      'records', (
        SELECT jsonb_agg(jsonb_build_object(
          'id', u.id,
          'reference', COALESCE(u.email, u.phone),
          'role', u.role_code
        ))
        FROM (SELECT * FROM public.users WHERE organization_id = p_org_id LIMIT 5) u
      )
    );
  END IF;

  -- Check for product pricing
  SELECT COUNT(*) INTO v_count FROM public.product_pricing WHERE organization_id = p_org_id;
  IF v_count > 0 THEN
    v_has_blockers := TRUE;
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'product_pricing',
      'display_name', 'Product Pricing',
      'count', v_count,
      'description', 'Product pricing records for this organization',
      'action', 'Delete product pricing records first',
      'priority', 7,
      'can_force_delete', true,
      'records', null
    );
  END IF;

  -- Check for product SKUs
  SELECT COUNT(*) INTO v_count FROM public.product_skus WHERE organization_id = p_org_id;
  IF v_count > 0 THEN
    v_has_blockers := TRUE;
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'product_skus',
      'display_name', 'Product SKUs',
      'count', v_count,
      'description', 'Product SKU records for this organization',
      'action', 'Delete product SKUs first',
      'priority', 8,
      'can_force_delete', true,
      'records', null
    );
  END IF;

  -- Check for stock adjustments
  SELECT COUNT(*) INTO v_count FROM public.stock_adjustments WHERE organization_id = p_org_id;
  IF v_count > 0 THEN
    v_has_blockers := TRUE;
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'stock_adjustments',
      'display_name', 'Stock Adjustments',
      'count', v_count,
      'description', 'Stock adjustment records',
      'action', 'Stock adjustment records need to be handled',
      'priority', 9,
      'records', null
    );
  END IF;

  -- Check for campaigns (lucky draw, scratch card, etc.)
  SELECT COUNT(*) INTO v_count FROM public.lucky_draw_campaigns WHERE company_id = p_org_id;
  IF v_count > 0 THEN
    v_has_blockers := TRUE;
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'lucky_draw_campaigns',
      'display_name', 'Lucky Draw Campaigns',
      'count', v_count,
      'description', 'Active lucky draw campaigns',
      'action', 'Delete or end campaigns first',
      'priority', 10,
      'records', (
        SELECT jsonb_agg(jsonb_build_object(
          'id', c.id,
          'reference', c.campaign_name,
          'status', c.status
        ))
        FROM (SELECT * FROM public.lucky_draw_campaigns WHERE company_id = p_org_id LIMIT 5) c
      )
    );
  END IF;

  SELECT COUNT(*) INTO v_count FROM public.scratch_card_campaigns WHERE org_id = p_org_id;
  IF v_count > 0 THEN
    v_has_blockers := TRUE;
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'scratch_card_campaigns',
      'display_name', 'Scratch Card Campaigns',
      'count', v_count,
      'description', 'Active scratch card campaigns',
      'action', 'Delete or end campaigns first',
      'priority', 11,
      'records', null
    );
  END IF;

  SELECT COUNT(*) INTO v_count FROM public.spin_wheel_campaigns WHERE org_id = p_org_id;
  IF v_count > 0 THEN
    v_has_blockers := TRUE;
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'spin_wheel_campaigns',
      'display_name', 'Spin Wheel Campaigns',
      'count', v_count,
      'description', 'Active spin wheel campaigns',
      'action', 'Delete or end campaigns first',
      'priority', 12,
      'records', null
    );
  END IF;

  SELECT COUNT(*) INTO v_count FROM public.daily_quiz_campaigns WHERE org_id = p_org_id;
  IF v_count > 0 THEN
    v_has_blockers := TRUE;
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'daily_quiz_campaigns',
      'display_name', 'Daily Quiz Campaigns',
      'count', v_count,
      'description', 'Active daily quiz campaigns',
      'action', 'Delete or end campaigns first',
      'priority', 13,
      'records', null
    );
  END IF;

  -- Check for documents
  SELECT COUNT(*) INTO v_count FROM public.documents WHERE issued_by_org_id = p_org_id OR issued_to_org_id = p_org_id;
  IF v_count > 0 THEN
    v_has_blockers := TRUE;
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'documents',
      'display_name', 'Documents',
      'count', v_count,
      'description', 'Documents issued by or to this organization',
      'action', 'Documents are linked to orders and cannot be deleted',
      'priority', 14,
      'records', null
    );
  END IF;

  -- Check for consumer activations
  SELECT COUNT(*) INTO v_count FROM public.consumer_activations WHERE company_id = p_org_id;
  IF v_count > 0 THEN
    v_has_blockers := TRUE;
    v_blocking_records := v_blocking_records || jsonb_build_object(
      'table_name', 'consumer_activations',
      'display_name', 'Consumer Activations',
      'count', v_count,
      'description', 'Consumer warranty activations',
      'action', 'Consumer activation records exist',
      'priority', 15,
      'records', null
    );
  END IF;

  -- Return the result
  RETURN jsonb_build_object(
    'success', true,
    'org_id', p_org_id,
    'org_name', v_org_name,
    'org_code', v_org_code,
    'org_type', v_org_type,
    'can_delete', NOT v_has_blockers,
    'has_blocking_records', v_has_blockers,
    'blocking_records', v_blocking_records,
    'deletion_order', CASE WHEN v_has_blockers THEN 
      'To delete this organization, you must first delete the blocking records in order of priority (lowest number first).'
    ELSE
      'This organization can be safely deleted.'
    END
  );

END;
$$;


