--
-- Name: check_phone_exists(text, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.check_phone_exists(p_phone text, p_exclude_user_id uuid DEFAULT NULL::uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_phone text;
  v_exists boolean;
BEGIN
  v_phone := public.normalize_phone_e164(p_phone);
  IF v_phone IS NULL THEN
    RETURN false;
  END IF;

  SELECT EXISTS (
    SELECT 1
    FROM auth.users
    WHERE public.normalize_phone_e164(phone) = v_phone
      AND (p_exclude_user_id IS NULL OR id != p_exclude_user_id)
    UNION ALL
    SELECT 1
    FROM public.users
    WHERE public.normalize_phone_e164(phone) = v_phone
      AND (p_exclude_user_id IS NULL OR id != p_exclude_user_id)
  ) INTO v_exists;

  RETURN v_exists;
END;
$$;


ALTER FUNCTION public.check_phone_exists(p_phone text, p_exclude_user_id uuid) OWNER TO supabase_admin;

--
-- Name: check_serapod_user_phone(text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.check_serapod_user_phone(p_phone text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_phone text;
  v_exists boolean;
BEGIN
  v_phone := public.normalize_phone_e164(p_phone);
  IF v_phone IS NULL THEN
    RETURN false;
  END IF;

  SELECT EXISTS (
    SELECT 1
    FROM public.users u
    JOIN public.organizations o ON u.organization_id = o.id
    WHERE public.normalize_phone_e164(u.phone) = v_phone
      AND u.is_active = true
      AND (
        o.org_type_code = 'HQ'
        OR o.org_name ILIKE '%Serapod%'
      )
  ) INTO v_exists;

  RETURN v_exists;
END;
$$;


ALTER FUNCTION public.check_serapod_user_phone(p_phone text) OWNER TO supabase_admin;

