-- Name: check_whatsapp_admin(uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.check_whatsapp_admin(p_org_id uuid, p_phone_digits text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_phone text;
BEGIN
  v_phone := public.normalize_phone_e164(p_phone_digits);
  IF v_phone IS NULL THEN
    RETURN false;
  END IF;

  RETURN EXISTS (
    SELECT 1
    FROM public.whatsapp_bot_admins
    WHERE org_id = p_org_id
      AND public.normalize_phone_e164(phone_digits) = v_phone
      AND is_active = true
  );
END;
$$;


