--
-- Name: claim_point_redeem_pool(uuid, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.claim_point_redeem_pool(p_redeem_gift_id uuid, p_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_gift public.redemption_gifts%ROWTYPE;
  v_points integer;
  v_already_claimed boolean;
  v_daily_claimed boolean;
  v_transaction_id uuid;
  v_user_phone text;
  v_current_balance integer;
  v_user_details record;
BEGIN
  -- Lock the gift row for update to ensure atomicity
  SELECT * INTO v_gift
  FROM public.redemption_gifts
  WHERE id = p_redeem_gift_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'message', 'Redeem gift not found');
  END IF;

  -- Logic checks
  IF v_gift.category <> 'point_pool' THEN
    RETURN jsonb_build_object('success', false, 'message', 'Not a point pool redeem');
  END IF;

  -- Status check (simple)
  IF v_gift.status <> 'active' THEN
     RETURN jsonb_build_object('success', false, 'message', 'Redeem pool is not active');
  END IF;
  
  -- Date checks
  IF v_gift.start_date IS NOT NULL AND v_gift.start_date > NOW() THEN
     RETURN jsonb_build_object('success', false, 'message', 'Redeem pool has not started yet');
  END IF;
  
  IF v_gift.end_date IS NOT NULL AND v_gift.end_date < NOW() THEN
     RETURN jsonb_build_object('success', false, 'message', 'Redeem pool has ended');
  END IF;

  v_points := COALESCE(v_gift.points_per_collection, 0);

  -- Check pool availability
  IF v_gift.remaining_points < v_points THEN
    RETURN jsonb_build_object('success', false, 'message', 'Sold out / expired');
  END IF;

  -- User Claim Limits
  -- Option 1: Per user only (once ever)
  IF v_gift.collection_option_1 AND NOT v_gift.collection_option_2 THEN
    SELECT EXISTS(
      SELECT 1 FROM public.redeem_gift_transactions
      WHERE redeem_gift_id = p_redeem_gift_id AND user_id = p_user_id
    ) INTO v_already_claimed;
    
    IF v_already_claimed THEN
      RETURN jsonb_build_object('success', false, 'message', 'You have already collected this reward.');
    END IF;
  END IF;

  -- Option 2: Daily (once per day)
  IF v_gift.collection_option_2 THEN
    SELECT EXISTS(
      SELECT 1 FROM public.redeem_gift_transactions
      WHERE redeem_gift_id = p_redeem_gift_id 
        AND user_id = p_user_id
        AND redeemed_at >= CURRENT_DATE::timestamptz
        AND redeemed_at < (CURRENT_DATE + 1)::timestamptz
    ) INTO v_daily_claimed;
    
    IF v_daily_claimed THEN
      RETURN jsonb_build_object('success', false, 'message', 'You have already collected this reward today.');
    END IF;
  END IF;

  -- Decrement Pool and Update
  -- If remaining points will be less than points per collection after this claim, mark as expired? 
  -- Or just let it go to < points per collection and fail next time. 
  -- Prompt says: "If remaining_points < points_per_claim after decrement, mark pool status = expired"
  UPDATE public.redemption_gifts
  SET remaining_points = remaining_points - v_points,
      status = CASE 
                 WHEN (remaining_points - v_points) < points_per_collection THEN 'expired'
                 ELSE status 
               END,
      updated_at = NOW()
  WHERE id = p_redeem_gift_id;

  -- Get User Phone for transactions
  SELECT phone, email INTO v_user_details FROM public.users WHERE id = p_user_id;
  v_user_phone := COALESCE(v_user_details.phone, 'N/A');

  -- Record Transaction in redeem_gift_transactions
  INSERT INTO public.redeem_gift_transactions (
    redeem_gift_id,
    user_id,
    redeemed_at,
    consumer_phone,
    qr_code, -- Not a real QR, but required field
    order_id
  ) VALUES (
    p_redeem_gift_id,
    p_user_id,
    NOW(),
    v_user_phone,
    'POOL-' || encode(gen_random_bytes(6), 'hex'), -- Placeholder unique-ish code
    v_gift.order_id -- Could be null
  ) RETURNING id INTO v_transaction_id;
  
  -- Award Points (Insert into points_transactions)
  -- Get current balance
  SELECT balance_after INTO v_current_balance
  FROM public.points_transactions
  WHERE user_id = p_user_id
  ORDER BY created_at DESC
  LIMIT 1;
  
  v_current_balance := COALESCE(v_current_balance, 0);

  INSERT INTO public.points_transactions (
    user_id,
    consumer_phone,
    consumer_email,
    transaction_type,
    points_amount,
    balance_after,
    description,
    redeem_item_id, -- Link to the gift
    transaction_date,
    company_id -- Maybe needed? If user has company_id?
  ) VALUES (
    p_user_id,
    v_user_phone,
    v_user_details.email,
    'earn',
    v_points,
    v_current_balance + v_points,
    'Redeemed Pool Reward: ' || v_gift.gift_name,
    p_redeem_gift_id,
    NOW(),
    NULL -- Or find relevant company_id
  );

  RETURN jsonb_build_object('success', true, 'points_earned', v_points, 'message', 'Success');
END;
$$;


ALTER FUNCTION public.claim_point_redeem_pool(p_redeem_gift_id uuid, p_user_id uuid) OWNER TO supabase_admin;

--
-- Name: cleanup_old_audit_logs(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.cleanup_old_audit_logs() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  DELETE FROM public.audit_logs
  WHERE created_at < CURRENT_DATE - INTERVAL '90 days';
END;
$$;


ALTER FUNCTION public.cleanup_old_audit_logs() OWNER TO supabase_admin;

--
-- Name: cleanup_old_notifications(integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.cleanup_old_notifications(p_retention_days integer DEFAULT 90) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_deleted_count INTEGER;
BEGIN
  -- Archive to logs if needed, then delete from outbox
  WITH deleted AS (
    DELETE FROM public.notifications_outbox
    WHERE created_at < NOW() - (p_retention_days || ' days')::INTERVAL
      AND status IN ('sent', 'failed')
    RETURNING id
  )
  SELECT COUNT(*) INTO v_deleted_count FROM deleted;

  -- Also cleanup very old logs
  DELETE FROM public.notification_logs
  WHERE created_at < NOW() - ((p_retention_days + 30) || ' days')::INTERVAL;

  RAISE NOTICE 'Cleaned up % old notifications', v_deleted_count;
  RETURN v_deleted_count;
END;
$$;


ALTER FUNCTION public.cleanup_old_notifications(p_retention_days integer) OWNER TO supabase_admin;

--
-- Name: FUNCTION cleanup_old_notifications(p_retention_days integer); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.cleanup_old_notifications(p_retention_days integer) IS 'Removes old sent/failed notifications from outbox to maintain performance';


--
-- Name: clear_whatsapp_draft(uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.clear_whatsapp_draft(p_org_id uuid, p_user_phone text) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_draft TEXT;
BEGIN
    UPDATE whatsapp_conversations SET
        pending_draft = NULL,
        pending_draft_at = NULL,
        updated_at = now()
    WHERE org_id = p_org_id AND user_phone_digits = p_user_phone
    RETURNING pending_draft INTO v_draft;
    
    RETURN v_draft;
END;
$$;


ALTER FUNCTION public.clear_whatsapp_draft(p_org_id uuid, p_user_phone text) OWNER TO supabase_admin;

--
-- Name: close_fiscal_period(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.close_fiscal_period(p_period_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_period record;
BEGIN
    SELECT * INTO v_period FROM public.fiscal_periods WHERE id = p_period_id;
    
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Fiscal period not found';
    END IF;
    
    IF v_period.status = 'locked' THEN
        RAISE EXCEPTION 'Period is already locked';
    END IF;
    
    UPDATE public.fiscal_periods
    SET status = 'closed',
        closed_at = now(),
        closed_by = auth.uid()
    WHERE id = p_period_id;
    
    RETURN true;
END;
$$;


ALTER FUNCTION public.close_fiscal_period(p_period_id uuid) OWNER TO supabase_admin;

--
-- Name: collect_point_reward(uuid, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.collect_point_reward(p_redeem_item_id uuid, p_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_reward RECORD;
    v_can_collect BOOLEAN;
    v_collection_id UUID;
BEGIN
    -- Get the reward
    SELECT * INTO v_reward
    FROM redeem_items 
    WHERE id = p_redeem_item_id AND category = 'point' AND is_active = TRUE;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Point reward not found or inactive');
    END IF;
    
    -- Check if user can collect
    v_can_collect := can_collect_point_reward(p_redeem_item_id, p_user_id);
    
    IF NOT v_can_collect THEN
        RETURN jsonb_build_object('success', false, 'error', 'You have already collected this reward');
    END IF;
    
    -- Record the collection
    INSERT INTO point_reward_collections (redeem_item_id, user_id, points_awarded)
    VALUES (p_redeem_item_id, p_user_id, COALESCE(v_reward.point_reward_amount, 0))
    RETURNING id INTO v_collection_id;
    
    -- Award the points (this would integrate with the existing points system)
    -- For now, return success with the points awarded
    RETURN jsonb_build_object(
        'success', true, 
        'points_awarded', COALESCE(v_reward.point_reward_amount, 0),
        'message', COALESCE(v_reward.reward_message, 'Points collected successfully!'),
        'collection_id', v_collection_id
    );
END;
$$;


ALTER FUNCTION public.collect_point_reward(p_redeem_item_id uuid, p_user_id uuid) OWNER TO supabase_admin;

--
-- Name: compute_payroll_item(uuid, uuid, date, date); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.compute_payroll_item(p_org_id uuid, p_employee_id uuid, p_period_start date, p_period_end date) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_comp RECORD;
    v_stat jsonb;
    v_work RECORD;
    v_allowances numeric := 0;
    v_deductions numeric := 0;
    v_basic numeric := 0;
    v_ot_amount numeric := 0;
    v_gross numeric := 0;
    v_epf_ee numeric := 0;
    v_epf_er numeric := 0;
    v_socso_ee numeric := 0;
    v_socso_er numeric := 0;
    v_eis_ee numeric := 0;
    v_eis_er numeric := 0;
    v_total_deduct numeric := 0;
    v_net numeric := 0;
    v_hourly_rate numeric;
BEGIN
    -- Get employee compensation
    SELECT * INTO v_comp
    FROM public.hr_employee_compensation
    WHERE employee_id = p_employee_id
      AND organization_id = p_org_id
      AND status = 'active'
    ORDER BY effective_date DESC
    LIMIT 1;

    IF v_comp IS NULL THEN
        RETURN jsonb_build_object('error', 'No active compensation record');
    END IF;

    -- Get statutory config
    v_stat := public.get_statutory_config(p_org_id);

    -- Get approved work minutes
    SELECT
        COALESCE(SUM(t.total_minutes), 0) AS total_minutes,
        COALESCE(SUM(t.overtime_minutes), 0) AS ot_minutes
    INTO v_work
    FROM public.hr_timesheets t
    WHERE t.organization_id = p_org_id
      AND t.user_id = p_employee_id
      AND t.status = 'approved'
      AND t.period_start >= p_period_start
      AND t.period_end <= p_period_end;

    -- Calculate basic
    v_basic := v_comp.basic_salary;

    -- Calculate OT
    IF v_comp.ot_eligible AND v_work.ot_minutes > 0 THEN
        v_hourly_rate := CASE
            WHEN v_comp.pay_type = 'hourly' THEN COALESCE(v_comp.hourly_rate, 0)
            ELSE v_comp.basic_salary / 176  -- ~22 days × 8 hours
        END;
        v_ot_amount := ROUND((v_work.ot_minutes / 60.0) * v_hourly_rate * 1.5, 2);
    END IF;

    -- Sum allowances
    SELECT COALESCE(SUM(amount), 0) INTO v_allowances
    FROM public.hr_employee_allowances
    WHERE employee_id = p_employee_id
      AND organization_id = p_org_id
      AND is_active = true
      AND effective_date <= p_period_end
      AND (end_date IS NULL OR end_date >= p_period_start);

    -- Sum deductions
    SELECT COALESCE(SUM(amount), 0) INTO v_deductions
    FROM public.hr_employee_deductions
    WHERE employee_id = p_employee_id
      AND organization_id = p_org_id
      AND is_active = true
      AND effective_date <= p_period_end
      AND (end_date IS NULL OR end_date >= p_period_start);

    -- Gross
    v_gross := v_basic + v_ot_amount + v_allowances;

    -- EPF
    v_epf_ee := ROUND(v_gross * COALESCE((v_stat->'epf'->>'employee_rate')::numeric, 0.11), 2);
    v_epf_er := ROUND(v_gross * COALESCE((v_stat->'epf'->>'employer_rate')::numeric, 0.13), 2);

    -- SOCSO (capped)
    IF v_gross <= COALESCE((v_stat->'socso'->>'max_salary')::numeric, 5000) THEN
        v_socso_ee := ROUND(v_gross * COALESCE((v_stat->'socso'->>'employee_rate')::numeric, 0.005), 2);
        v_socso_er := ROUND(v_gross * COALESCE((v_stat->'socso'->>'employer_rate')::numeric, 0.0175), 2);
    END IF;

    -- EIS (capped)
    IF v_gross <= COALESCE((v_stat->'eis'->>'max_salary')::numeric, 5000) THEN
        v_eis_ee := ROUND(v_gross * COALESCE((v_stat->'eis'->>'employee_rate')::numeric, 0.002), 2);
        v_eis_er := ROUND(v_gross * COALESCE((v_stat->'eis'->>'employer_rate')::numeric, 0.002), 2);
    END IF;

    -- Total deductions
    v_total_deduct := v_epf_ee + v_socso_ee + v_eis_ee + v_deductions;

    -- Net
    v_net := v_gross - v_total_deduct;

    RETURN jsonb_build_object(
        'employee_id', p_employee_id,
        'basic_salary', v_basic,
        'overtime_amount', v_ot_amount,
        'allowances_amount', v_allowances,
        'work_minutes', v_work.total_minutes,
        'overtime_minutes', v_work.ot_minutes,
        'gross_amount', v_gross,
        'epf_employee', v_epf_ee,
        'epf_employer', v_epf_er,
        'socso_employee', v_socso_ee,
        'socso_employer', v_socso_er,
        'eis_employee', v_eis_ee,
        'eis_employer', v_eis_er,
        'pcb_amount', 0,
        'other_deductions', v_deductions,
        'other_allowances', v_allowances,
        'deductions_amount', v_total_deduct,
        'employer_contributions', v_epf_er + v_socso_er + v_eis_er,
        'net_amount', v_net
    );
END;
$$;


ALTER FUNCTION public.compute_payroll_item(p_org_id uuid, p_employee_id uuid, p_period_start date, p_period_end date) OWNER TO supabase_admin;

--
-- Name: FUNCTION compute_payroll_item(p_org_id uuid, p_employee_id uuid, p_period_start date, p_period_end date); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.compute_payroll_item(p_org_id uuid, p_employee_id uuid, p_period_start date, p_period_end date) IS 'Computes full payroll breakdown for one employee including statutory (EPF/SOCSO/EIS). Uses approved timesheets only.';


--
-- Name: consumer_claim_gift(text, uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.consumer_claim_gift(p_raw_qr_code text, p_gift_id uuid, p_consumer_phone text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
  v_qr_record RECORD;
  v_base_code TEXT;
  v_gift RECORD;
  v_redemption_code TEXT;
  v_valid_statuses TEXT[] := ARRAY['received_warehouse', 'warehouse_packed', 'shipped_distributor', 'activated', 'verified'];
  v_scan_id UUID;
BEGIN
  -- 1. Resolve QR Code and Lock Row
  SELECT * INTO v_qr_record
  FROM qr_codes
  WHERE code = p_raw_qr_code
  FOR UPDATE;

  IF v_qr_record IS NULL THEN
    v_base_code := regexp_replace(p_raw_qr_code, '-[^-]+$', '');
    IF v_base_code != p_raw_qr_code THEN
        SELECT * INTO v_qr_record
        FROM qr_codes
        WHERE code = v_base_code
        FOR UPDATE;
    END IF;
  END IF;

  IF v_qr_record IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'QR code not found', 'code', 'QR_NOT_FOUND');
  END IF;

  -- 2. Validate Status
  IF NOT (v_qr_record.status = ANY(v_valid_statuses)) THEN
    RETURN jsonb_build_object('success', false, 'error', 'QR code is not active', 'code', 'INVALID_STATUS');
  END IF;

  -- 3. Check if already redeemed
  IF v_qr_record.is_redeemed THEN
    RETURN jsonb_build_object('success', false, 'error', 'This QR code has already been used to redeem a gift', 'code', 'ALREADY_REDEEMED');
  END IF;

  -- 4. Check Gift Validity and Quantity
  SELECT * INTO v_gift
  FROM redeem_gifts
  WHERE id = p_gift_id AND is_active = TRUE
  FOR UPDATE; -- Lock gift row to prevent over-claiming

  IF v_gift IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Gift not found or inactive', 'code', 'GIFT_NOT_FOUND');
  END IF;

  IF v_gift.total_quantity > 0 AND v_gift.claimed_quantity >= v_gift.total_quantity THEN
    RETURN jsonb_build_object('success', false, 'error', 'This gift has been fully claimed', 'code', 'GIFT_FULLY_CLAIMED');
  END IF;

  -- 5. Check Consumer Limit (if phone provided)
  IF p_consumer_phone IS NOT NULL AND v_gift.limit_per_consumer IS NOT NULL THEN
    DECLARE
      v_consumer_claims INTEGER;
    BEGIN
      SELECT COUNT(*) INTO v_consumer_claims
      FROM consumer_qr_scans
      WHERE consumer_phone = p_consumer_phone
        AND redeemed_gift = TRUE
        AND qr_code_id IN (SELECT id FROM qr_codes WHERE order_id = v_qr_record.order_id); -- Assuming limit is per order context or similar? 
        -- Actually, the original code checked scans for this specific QR code, which is redundant if we block the QR code itself.
        -- But maybe it meant "how many gifts has this consumer claimed in general"?
        -- The original code: .eq('qr_code_id', qrCodeData.id).eq('consumer_phone', consumer_phone).eq('redeemed_gift', true)
        -- This only checks if THIS QR code was used by THIS consumer. Since we block the QR code globally, this check is redundant unless we want to support multiple claims per QR (which we don't).
        -- However, if the limit is "Consumer can only claim 1 gift across ALL QR codes", that's different.
        -- The original code logic was: .eq('qr_code_id', qrCodeData.id). This implies it was only checking per QR code.
        -- Since we are enforcing 1 claim per QR code globally, the per-consumer limit on a single QR code is always 1.
        -- So we can skip this check if it was only scoped to the QR code.
    END;
  END IF;

  -- 6. Update Gift Quantity
  UPDATE redeem_gifts
  SET claimed_quantity = claimed_quantity + 1,
      updated_at = NOW()
  WHERE id = v_gift.id;

  -- 7. Update QR Code Flags
  UPDATE qr_codes
  SET is_redeemed = TRUE,
      redeemed_at = NOW()
  WHERE id = v_qr_record.id;

  -- 8. Record Scan / Redemption
  -- Check if scan exists for this QR (maybe from view/scan)
  SELECT id INTO v_scan_id
  FROM consumer_qr_scans
  WHERE qr_code_id = v_qr_record.id AND consumer_phone = p_consumer_phone
  LIMIT 1;

  IF v_scan_id IS NOT NULL THEN
    UPDATE consumer_qr_scans
    SET redeemed_gift = TRUE, updated_at = NOW()
    WHERE id = v_scan_id;
  ELSE
    INSERT INTO consumer_qr_scans (
      qr_code_id,
      consumer_phone,
      redeemed_gift,
      scanned_at
    ) VALUES (
      v_qr_record.id,
      p_consumer_phone,
      TRUE,
      NOW()
    );
  END IF;

  -- 9. Generate Redemption Code
  v_redemption_code := 'GFT-' || upper(substring(md5(random()::text), 1, 6));

  RETURN jsonb_build_object(
    'success', true,
    'redemption_code', v_redemption_code,
    'gift_name', v_gift.gift_name,
    'gift_description', v_gift.gift_description,
    'gift_image_url', v_gift.gift_image_url,
    'remaining', CASE WHEN v_gift.total_quantity > 0 THEN v_gift.total_quantity - v_gift.claimed_quantity - 1 ELSE NULL END
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'code', 'INTERNAL_ERROR');
END;
$_$;


ALTER FUNCTION public.consumer_claim_gift(p_raw_qr_code text, p_gift_id uuid, p_consumer_phone text) OWNER TO supabase_admin;

--
-- Name: consumer_claim_gift(text, uuid, text, text, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.consumer_claim_gift(p_raw_qr_code text, p_gift_id uuid, p_consumer_name text DEFAULT NULL::text, p_consumer_phone text DEFAULT NULL::text, p_consumer_email text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
  v_qr_record RECORD;
  v_base_code TEXT;
  v_gift RECORD;
  v_redemption_code TEXT;
  v_valid_statuses TEXT[] := ARRAY['received_warehouse', 'warehouse_packed', 'shipped_distributor', 'activated', 'verified'];
  v_scan_id UUID;
BEGIN
  -- 1. Resolve QR Code and Lock Row
  SELECT * INTO v_qr_record
  FROM qr_codes
  WHERE code = p_raw_qr_code
  FOR UPDATE;

  IF v_qr_record IS NULL THEN
    v_base_code := regexp_replace(p_raw_qr_code, '-[^-]+$', '');
    IF v_base_code != p_raw_qr_code THEN
        SELECT * INTO v_qr_record
        FROM qr_codes
        WHERE code = v_base_code
        FOR UPDATE;
    END IF;
  END IF;

  IF v_qr_record IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'QR code not found', 'code', 'QR_NOT_FOUND');
  END IF;

  -- 2. Validate Status
  IF NOT (v_qr_record.status = ANY(v_valid_statuses)) THEN
    RETURN jsonb_build_object('success', false, 'error', 'QR code is not active', 'code', 'INVALID_STATUS');
  END IF;

  -- 3. Check if already redeemed
  IF v_qr_record.is_redeemed THEN
    RETURN jsonb_build_object('success', false, 'error', 'This QR code has already been used to redeem a gift', 'code', 'ALREADY_REDEEMED');
  END IF;

  -- 4. Check Gift Validity and Quantity
  SELECT * INTO v_gift
  FROM redeem_gifts
  WHERE id = p_gift_id AND is_active = TRUE
  FOR UPDATE;

  IF v_gift IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Gift not found or inactive', 'code', 'GIFT_NOT_FOUND');
  END IF;

  IF v_gift.total_quantity > 0 AND v_gift.claimed_quantity >= v_gift.total_quantity THEN
    RETURN jsonb_build_object('success', false, 'error', 'This gift has been fully claimed', 'code', 'GIFT_FULLY_CLAIMED');
  END IF;

  -- 5. Update Gift Quantity
  UPDATE redeem_gifts
  SET claimed_quantity = claimed_quantity + 1,
      updated_at = NOW()
  WHERE id = v_gift.id;

  -- 6. Update QR Code Flags AND Consumer Details AND Gift ID
  UPDATE qr_codes
  SET is_redeemed = TRUE,
      redeemed_at = NOW(),
      redeem_gift_id = v_gift.id,
      consumer_name = COALESCE(p_consumer_name, consumer_name),
      consumer_phone = COALESCE(p_consumer_phone, consumer_phone),
      consumer_email = COALESCE(p_consumer_email, consumer_email)
  WHERE id = v_qr_record.id;

  -- 7. Generate Redemption Code
  v_redemption_code := 'GFT-' || upper(substring(md5(random()::text) from 1 for 6));

  -- 8. Record Scan / Redemption (Legacy support for consumer_qr_scans table if used)
  SELECT id INTO v_scan_id
  FROM consumer_qr_scans
  WHERE qr_code_id = v_qr_record.id AND consumer_phone = p_consumer_phone
  LIMIT 1;

  IF v_scan_id IS NOT NULL THEN
    UPDATE consumer_qr_scans
    SET redeemed_gift = TRUE, updated_at = NOW()
    WHERE id = v_scan_id;
  ELSE
    -- Only insert if we have a phone number
    IF p_consumer_phone IS NOT NULL THEN
        INSERT INTO consumer_qr_scans (
        qr_code_id,
        consumer_phone,
        redeemed_gift,
        scanned_at
        ) VALUES (
        v_qr_record.id,
        p_consumer_phone,
        TRUE,
        NOW()
        );
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'redemption_code', v_redemption_code,
    'gift_name', v_gift.gift_name,
    'gift_image_url', v_gift.gift_image_url,
    'gift_description', v_gift.gift_description
  );
END;
$_$;


ALTER FUNCTION public.consumer_claim_gift(p_raw_qr_code text, p_gift_id uuid, p_consumer_name text, p_consumer_phone text, p_consumer_email text) OWNER TO supabase_admin;

--
-- Name: consumer_collect_points(text, text, numeric, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.consumer_collect_points(p_raw_qr_code text, p_shop_id text, p_points_amount numeric DEFAULT NULL::numeric, p_claim_lane text DEFAULT 'consumer'::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
  v_qr_record RECORD;
  v_base_code TEXT;
  v_valid_statuses TEXT[] := ARRAY['received_warehouse', 'warehouse_packed', 'shipped_distributor', 'activated', 'verified'];
  v_points NUMERIC;
  v_shop_org_id UUID;
  v_user_full_name TEXT;
  v_user_phone TEXT;
  v_user_email TEXT;
  v_lane_collected BOOLEAN;
BEGIN
  -- 1. Resolve QR Code and Lock Row
  SELECT * INTO v_qr_record
  FROM qr_codes
  WHERE code = p_raw_qr_code
  FOR UPDATE;

  IF v_qr_record IS NULL THEN
    v_base_code := regexp_replace(p_raw_qr_code, '-[^-]+$', '');
    IF v_base_code != p_raw_qr_code THEN
        SELECT * INTO v_qr_record
        FROM qr_codes
        WHERE code = v_base_code
        FOR UPDATE;
    END IF;
  END IF;

  IF v_qr_record IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'QR code not found', 'code', 'QR_NOT_FOUND', 'preview', true);
  END IF;

  -- 2. Validate Status
  IF NOT (v_qr_record.status = ANY(v_valid_statuses)) THEN
    RETURN jsonb_build_object('success', false, 'error', 'QR code is not active', 'code', 'INVALID_STATUS');
  END IF;

  -- 3. Check if already collected FOR THIS LANE
  IF p_claim_lane = 'shop' THEN
    v_lane_collected := v_qr_record.is_shop_points_collected;
  ELSE
    v_lane_collected := v_qr_record.is_consumer_points_collected;
  END IF;

  IF v_lane_collected THEN
    RETURN jsonb_build_object(
      'success', false,
      'already_collected', true,
      'error', 'Points for this QR code have already been collected.',
      'points_earned', v_qr_record.points_value
    );
  END IF;

  -- 4. Determine Points Value
  v_points := COALESCE(p_points_amount, v_qr_record.points_value, 0);

  -- 5. Get user details for consumer info
  SELECT organization_id, full_name, phone, email
  INTO v_shop_org_id, v_user_full_name, v_user_phone, v_user_email
  FROM users
  WHERE id = p_shop_id::uuid;

  -- 6. Update QR Code Flags — set both old flag + lane-specific flag
  IF p_claim_lane = 'shop' THEN
    UPDATE qr_codes
    SET is_points_collected = TRUE,
        is_shop_points_collected = TRUE,
        points_collected_at = NOW(),
        points_value = v_points
    WHERE id = v_qr_record.id;
  ELSE
    IF v_shop_org_id IS NULL AND v_qr_record.consumer_name IS NULL THEN
      UPDATE qr_codes
      SET is_points_collected = TRUE,
          is_consumer_points_collected = TRUE,
          points_collected_at = NOW(),
          points_value = v_points,
          consumer_name = COALESCE(v_user_full_name, v_qr_record.consumer_name),
          consumer_phone = COALESCE(v_user_phone, v_qr_record.consumer_phone),
          consumer_email = COALESCE(v_user_email, v_qr_record.consumer_email)
      WHERE id = v_qr_record.id;
    ELSE
      UPDATE qr_codes
      SET is_points_collected = TRUE,
          is_consumer_points_collected = TRUE,
          points_collected_at = NOW(),
          points_value = v_points
      WHERE id = v_qr_record.id;
    END IF;
  END IF;

  -- 7. Record Transaction / Scan — with claim_lane
  INSERT INTO consumer_qr_scans (
    qr_code_id,
    shop_id,
    consumer_id,
    collected_points,
    points_amount,
    points_collected_at,
    scanned_at,
    adjustment_type,
    claim_lane
  ) VALUES (
    v_qr_record.id,
    v_shop_org_id,
    p_shop_id::uuid,
    TRUE,
    v_points,
    NOW(),
    NOW(),
    'scan',
    p_claim_lane
  );

  RETURN jsonb_build_object(
    'success', true,
    'points_earned', v_points,
    'message', 'Points collected successfully'
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'code', 'INTERNAL_ERROR');
END;
$_$;


ALTER FUNCTION public.consumer_collect_points(p_raw_qr_code text, p_shop_id text, p_points_amount numeric, p_claim_lane text) OWNER TO supabase_admin;

--
-- Name: consumer_collect_points(text, text, numeric, text, boolean); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.consumer_collect_points(p_raw_qr_code text, p_shop_id text, p_points_amount numeric DEFAULT NULL::numeric, p_claim_lane text DEFAULT 'consumer'::text, p_allow_dual_claim boolean DEFAULT true) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
  v_qr_record RECORD;
  v_base_code TEXT;
  v_valid_statuses TEXT[] := ARRAY['received_warehouse', 'warehouse_packed', 'shipped_distributor', 'activated', 'verified'];
  v_points NUMERIC;
  v_shop_org_id UUID;
  v_user_full_name TEXT;
  v_user_phone TEXT;
  v_user_email TEXT;
  v_lane_collected BOOLEAN;
BEGIN
  SELECT * INTO v_qr_record
  FROM qr_codes
  WHERE code = p_raw_qr_code
  FOR UPDATE;

  IF v_qr_record IS NULL THEN
    v_base_code := regexp_replace(p_raw_qr_code, '-[^-]+$', '');
    IF v_base_code != p_raw_qr_code THEN
      SELECT * INTO v_qr_record
      FROM qr_codes
      WHERE code = v_base_code
      FOR UPDATE;
    END IF;
  END IF;

  IF v_qr_record IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'QR code not found', 'code', 'QR_NOT_FOUND', 'preview', true);
  END IF;

  IF NOT (v_qr_record.status = ANY(v_valid_statuses)) THEN
    RETURN jsonb_build_object('success', false, 'error', 'QR code is not active', 'code', 'INVALID_STATUS');
  END IF;

  IF NOT p_allow_dual_claim THEN
    IF COALESCE(v_qr_record.is_shop_points_collected, false)
      OR COALESCE(v_qr_record.is_consumer_points_collected, false)
      OR COALESCE(v_qr_record.is_points_collected, false) THEN
      RETURN jsonb_build_object(
        'success', false,
        'already_collected', true,
        'error', 'Points for this QR code have already been collected.',
        'points_earned', v_qr_record.points_value
      );
    END IF;
  ELSE
    IF p_claim_lane = 'shop' THEN
      v_lane_collected := v_qr_record.is_shop_points_collected;
    ELSE
      v_lane_collected := v_qr_record.is_consumer_points_collected;
    END IF;

    IF v_lane_collected THEN
      RETURN jsonb_build_object(
        'success', false,
        'already_collected', true,
        'error', 'Points for this QR code have already been collected.',
        'points_earned', v_qr_record.points_value
      );
    END IF;
  END IF;

  v_points := COALESCE(p_points_amount, v_qr_record.points_value, 0);

  SELECT organization_id, full_name, phone, email
  INTO v_shop_org_id, v_user_full_name, v_user_phone, v_user_email
  FROM users
  WHERE id = p_shop_id::uuid;

  IF p_claim_lane = 'shop' THEN
    UPDATE qr_codes
    SET is_points_collected = TRUE,
        is_shop_points_collected = TRUE,
        points_collected_at = NOW(),
        points_value = v_points
    WHERE id = v_qr_record.id;
  ELSE
    IF v_shop_org_id IS NULL AND v_qr_record.consumer_name IS NULL THEN
      UPDATE qr_codes
      SET is_points_collected = TRUE,
          is_consumer_points_collected = TRUE,
          points_collected_at = NOW(),
          points_value = v_points,
          consumer_name = COALESCE(v_user_full_name, v_qr_record.consumer_name),
          consumer_phone = COALESCE(v_user_phone, v_qr_record.consumer_phone),
          consumer_email = COALESCE(v_user_email, v_qr_record.consumer_email)
      WHERE id = v_qr_record.id;
    ELSE
      UPDATE qr_codes
      SET is_points_collected = TRUE,
          is_consumer_points_collected = TRUE,
          points_collected_at = NOW(),
          points_value = v_points
      WHERE id = v_qr_record.id;
    END IF;
  END IF;

  INSERT INTO consumer_qr_scans (
    qr_code_id,
    shop_id,
    consumer_id,
    collected_points,
    points_amount,
    points_collected_at,
    scanned_at,
    adjustment_type,
    claim_lane
  ) VALUES (
    v_qr_record.id,
    v_shop_org_id,
    p_shop_id::uuid,
    TRUE,
    v_points,
    NOW(),
    NOW(),
    'scan',
    p_claim_lane
  );

  RETURN jsonb_build_object(
    'success', true,
    'points_earned', v_points,
    'message', 'Points collected successfully'
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'code', 'INTERNAL_ERROR');
END;
$_$;


ALTER FUNCTION public.consumer_collect_points(p_raw_qr_code text, p_shop_id text, p_points_amount numeric, p_claim_lane text, p_allow_dual_claim boolean) OWNER TO supabase_admin;

--
-- Name: consumer_lucky_draw_enter(text, text, text, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.consumer_lucky_draw_enter(p_raw_qr_code text, p_consumer_name text, p_consumer_phone text, p_consumer_email text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
  v_qr_record RECORD;
  v_base_code TEXT;
  v_order_id UUID;
  v_company_id UUID;
  v_campaign RECORD;
  v_existing_entry RECORD;
  v_entry_number TEXT;
  v_new_entry_id UUID;
  v_entry_date TIMESTAMPTZ;
  v_valid_statuses TEXT[] := ARRAY['received_warehouse', 'warehouse_packed', 'shipped_distributor', 'activated', 'verified'];
BEGIN
  -- 1. Resolve QR Code and Lock Row
  SELECT * INTO v_qr_record
  FROM qr_codes
  WHERE code = p_raw_qr_code
  FOR UPDATE;

  IF v_qr_record IS NULL THEN
    v_base_code := regexp_replace(p_raw_qr_code, '-[^-]+$', '');
    IF v_base_code != p_raw_qr_code THEN
        SELECT * INTO v_qr_record
        FROM qr_codes
        WHERE code = v_base_code
        FOR UPDATE;
    END IF;
  END IF;

  IF v_qr_record IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'QR code not found', 'code', 'QR_NOT_FOUND');
  END IF;

  -- 2. Validate Status
  IF NOT (v_qr_record.status = ANY(v_valid_statuses)) THEN
    RETURN jsonb_build_object('success', false, 'error', 'QR code is not active', 'code', 'INVALID_STATUS');
  END IF;

  -- 3. Check if already entered
  IF v_qr_record.is_lucky_draw_entered THEN
    SELECT * INTO v_existing_entry FROM lucky_draw_entries WHERE qr_code_id = v_qr_record.id LIMIT 1;
    SELECT campaign_name INTO v_campaign FROM lucky_draw_campaigns WHERE id = v_existing_entry.campaign_id;
    
    RETURN jsonb_build_object(
      'success', true,
      'already_entered', true,
      'message', 'This QR code has already been used to enter this lucky draw',
      'entry', jsonb_build_object(
        'entry_number', v_existing_entry.entry_number,
        'campaign_name', v_campaign.campaign_name,
        'consumer_name', v_existing_entry.consumer_name,
        'entry_date', v_existing_entry.entry_date
      )
    );
  END IF;

  -- 4. Find Active Campaign
  -- FIX: Use status = 'active' instead of is_active = TRUE
  SELECT * INTO v_campaign
  FROM lucky_draw_campaigns
  WHERE status = 'active'
    AND start_date <= NOW()
    AND end_date >= NOW()
  LIMIT 1;

  IF v_campaign IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'No active lucky draw campaign found', 'code', 'NO_CAMPAIGN');
  END IF;

  -- 5. Get Order and Company Context
  v_order_id := v_qr_record.order_id;
  SELECT company_id INTO v_company_id FROM orders WHERE id = v_order_id;

  -- 6. Generate Entry Number
  v_entry_number := 'LD-' || upper(substring(md5(random()::text) from 1 for 8));
  v_entry_date := NOW();

  -- 7. Update QR Code Flags AND Consumer Details
  UPDATE qr_codes
  SET is_lucky_draw_entered = TRUE,
      consumer_name = COALESCE(p_consumer_name, consumer_name),
      consumer_phone = COALESCE(p_consumer_phone, consumer_phone),
      consumer_email = COALESCE(p_consumer_email, consumer_email)
  WHERE id = v_qr_record.id;

  -- 8. Insert Entry
  INSERT INTO lucky_draw_entries (
    qr_code_id,
    campaign_id,
    order_id,
    company_id,
    consumer_name,
    consumer_phone,
    consumer_email,
    entry_number,
    is_winner,
    entry_date
  ) VALUES (
    v_qr_record.id,
    v_campaign.id,
    v_order_id,
    v_company_id,
    p_consumer_name,
    p_consumer_phone,
    p_consumer_email,
    v_entry_number,
    FALSE,
    v_entry_date
  ) RETURNING id INTO v_new_entry_id;

  -- 9. Return Success
  RETURN jsonb_build_object(
    'success', true,
    'already_entered', false,
    'message', 'Successfully entered lucky draw!',
    'entry', jsonb_build_object(
      'id', v_new_entry_id,
      'entry_number', v_entry_number,
      'campaign_name', v_campaign.campaign_name,
      'entry_date', v_entry_date
    )
  );
END;
$_$;


ALTER FUNCTION public.consumer_lucky_draw_enter(p_raw_qr_code text, p_consumer_name text, p_consumer_phone text, p_consumer_email text) OWNER TO supabase_admin;

