--
-- Name: create_support_conversation(text, text, jsonb); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.create_support_conversation(p_subject text, p_message text, p_attachments jsonb DEFAULT '[]'::jsonb) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_conversation_id UUID;
    v_user_id UUID := auth.uid();
BEGIN
    IF v_user_id IS NULL THEN
        RAISE EXCEPTION 'Not authenticated';
    END IF;
    
    -- Create conversation
    INSERT INTO public.support_conversations (
        created_by_user_id,
        subject,
        status,
        last_message_at,
        last_message_preview,
        last_message_sender_type,
        admin_unread_count
    ) VALUES (
        v_user_id,
        p_subject,
        'open',
        NOW(),
        LEFT(p_message, 100),
        'user',
        1
    )
    RETURNING id INTO v_conversation_id;
    
    -- Create first message
    INSERT INTO public.support_conversation_messages (
        conversation_id,
        sender_type,
        sender_user_id,
        message_type,
        body_text,
        attachments
    ) VALUES (
        v_conversation_id,
        'user',
        v_user_id,
        'text',
        p_message,
        p_attachments
    );
    
    -- Log event
    PERFORM public.log_conversation_event(
        v_conversation_id,
        'user',
        v_user_id,
        'conversation_created',
        NULL,
        jsonb_build_object('subject', p_subject),
        NULL
    );
    
    RETURN v_conversation_id;
END;
$$;


