--
-- Name: delete_all_transactions_with_inventory(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.delete_all_transactions_with_inventory() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
  v_deleted_counts jsonb := '{}'::jsonb;
  v_count integer;
BEGIN
  -- Start transaction (implicit in function)
  
  -- ==================================================
  -- PHASE 1: DELETE TRANSACTION-RELATED DATA
  -- ==================================================
  
  -- 1. Delete points transactions (consumer engagement) - if table exists
  BEGIN
    DELETE FROM public.points_transactions
    WHERE id != '00000000-0000-0000-0000-000000000000';
    GET DIAGNOSTICS v_count = ROW_COUNT;
    v_deleted_counts := v_deleted_counts || jsonb_build_object('points_transactions', v_count);
    RAISE NOTICE 'Deleted % points transactions', v_count;
  EXCEPTION WHEN UNDEFINED_TABLE THEN
    RAISE NOTICE 'Table points_transactions does not exist, skipping';
  END;
  
  -- ==================================================
  -- PHASE 2: DELETE QR TRACKING DATA
  -- ==================================================
  
  -- 2. Delete QR codes (individual unit codes)
  BEGIN
    DELETE FROM public.qr_codes
    WHERE id != '00000000-0000-0000-0000-000000000000';
    GET DIAGNOSTICS v_count = ROW_COUNT;
    v_deleted_counts := v_deleted_counts || jsonb_build_object('qr_codes', v_count);
    RAISE NOTICE 'Deleted % QR codes', v_count;
  EXCEPTION WHEN UNDEFINED_TABLE THEN
    RAISE NOTICE 'Table qr_codes does not exist, skipping';
  END;
  
  -- 3. Delete QR master codes (case/box codes)
  BEGIN
    DELETE FROM public.qr_master_codes
    WHERE id != '00000000-0000-0000-0000-000000000000';
    GET DIAGNOSTICS v_count = ROW_COUNT;
    v_deleted_counts := v_deleted_counts || jsonb_build_object('qr_master_codes', v_count);
    RAISE NOTICE 'Deleted % QR master codes', v_count;
  EXCEPTION WHEN UNDEFINED_TABLE THEN
    RAISE NOTICE 'Table qr_master_codes does not exist, skipping';
  END;
  
  -- 4. Delete QR batches
  BEGIN
    DELETE FROM public.qr_batches
    WHERE id != '00000000-0000-0000-0000-000000000000';
    GET DIAGNOSTICS v_count = ROW_COUNT;
    v_deleted_counts := v_deleted_counts || jsonb_build_object('qr_batches', v_count);
    RAISE NOTICE 'Deleted % QR batches', v_count;
  EXCEPTION WHEN UNDEFINED_TABLE THEN
    RAISE NOTICE 'Table qr_batches does not exist, skipping';
  END;
  
  -- ==================================================
  -- PHASE 3: DELETE INVENTORY DATA
  -- ==================================================
  
  -- 5. Delete all stock movements (audit trail)
  BEGIN
    DELETE FROM public.stock_movements
    WHERE id != '00000000-0000-0000-0000-000000000000';
    GET DIAGNOSTICS v_count = ROW_COUNT;
    v_deleted_counts := v_deleted_counts || jsonb_build_object('stock_movements', v_count);
    RAISE NOTICE 'Deleted % stock movements', v_count;
  EXCEPTION WHEN UNDEFINED_TABLE THEN
    RAISE NOTICE 'Table stock_movements does not exist, skipping';
  END;
  
  -- 6. Delete all product inventory records
  -- This resets all inventory counts to zero across all warehouses
  BEGIN
    DELETE FROM public.product_inventory
    WHERE id != '00000000-0000-0000-0000-000000000000';
    GET DIAGNOSTICS v_count = ROW_COUNT;
    v_deleted_counts := v_deleted_counts || jsonb_build_object('product_inventory', v_count);
    RAISE NOTICE 'Deleted % product inventory records', v_count;
  EXCEPTION WHEN UNDEFINED_TABLE THEN
    RAISE NOTICE 'Table product_inventory does not exist, skipping';
  END;
  
  -- ==================================================
  -- PHASE 4: DELETE FINANCIAL DATA
  -- ==================================================
  
  -- 7. Delete payments
  BEGIN
    DELETE FROM public.payments
    WHERE id != '00000000-0000-0000-0000-000000000000';
    GET DIAGNOSTICS v_count = ROW_COUNT;
    v_deleted_counts := v_deleted_counts || jsonb_build_object('payments', v_count);
    RAISE NOTICE 'Deleted % payments', v_count;
  EXCEPTION WHEN UNDEFINED_TABLE THEN
    RAISE NOTICE 'Table payments does not exist, skipping';
  END;
  
  -- 8. Delete invoices
  BEGIN
    DELETE FROM public.invoices
    WHERE id != '00000000-0000-0000-0000-000000000000';
    GET DIAGNOSTICS v_count = ROW_COUNT;
    v_deleted_counts := v_deleted_counts || jsonb_build_object('invoices', v_count);
    RAISE NOTICE 'Deleted % invoices', v_count;
  EXCEPTION WHEN UNDEFINED_TABLE THEN
    RAISE NOTICE 'Table invoices does not exist, skipping';
  END;
  
  -- ==================================================
  -- PHASE 5: DELETE ORDER DATA
  -- ==================================================
  
  -- 9. Delete shipments
  BEGIN
    DELETE FROM public.shipments
    WHERE id != '00000000-0000-0000-0000-000000000000';
    GET DIAGNOSTICS v_count = ROW_COUNT;
    v_deleted_counts := v_deleted_counts || jsonb_build_object('shipments', v_count);
    RAISE NOTICE 'Deleted % shipments', v_count;
  EXCEPTION WHEN UNDEFINED_TABLE THEN
    RAISE NOTICE 'Table shipments does not exist, skipping';
  END;
  
  -- 10. Delete order items
  BEGIN
    DELETE FROM public.order_items
    WHERE id != '00000000-0000-0000-0000-000000000000';
    GET DIAGNOSTICS v_count = ROW_COUNT;
    v_deleted_counts := v_deleted_counts || jsonb_build_object('order_items', v_count);
    RAISE NOTICE 'Deleted % order items', v_count;
  EXCEPTION WHEN UNDEFINED_TABLE THEN
    RAISE NOTICE 'Table order_items does not exist, skipping';
  END;
  
  -- 11. Delete orders
  BEGIN
    DELETE FROM public.orders
    WHERE id != '00000000-0000-0000-0000-000000000000';
    GET DIAGNOSTICS v_count = ROW_COUNT;
    v_deleted_counts := v_deleted_counts || jsonb_build_object('orders', v_count);
    RAISE NOTICE 'Deleted % orders', v_count;
  EXCEPTION WHEN UNDEFINED_TABLE THEN
    RAISE NOTICE 'Table orders does not exist, skipping';
  END;
  
  -- ==================================================
  -- PHASE 6: RESET ORDER SEQUENCE COUNTERS
  -- ==================================================
  -- This ensures next order will be 01, not continue from old numbers
  
  -- 12. Delete all document counters (order numbering sequences)
  BEGIN
    DELETE FROM public.doc_counters
    WHERE id != '00000000-0000-0000-0000-000000000000';
    GET DIAGNOSTICS v_count = ROW_COUNT;
    v_deleted_counts := v_deleted_counts || jsonb_build_object('doc_counters', v_count);
    RAISE NOTICE 'Deleted % document counters (sequences reset)', v_count;
  EXCEPTION WHEN UNDEFINED_TABLE THEN
    RAISE NOTICE 'Table doc_counters does not exist, skipping';
  END;
  
  -- ==================================================
  -- RETURN SUMMARY
  -- ==================================================
  
  RETURN jsonb_build_object(
    'success', true,
    'deleted_counts', v_deleted_counts,
    'total_records', COALESCE(
      (SELECT SUM((value)::integer) FROM jsonb_each_text(v_deleted_counts) WHERE value ~ '^\d+$'),
      0
    ),
    'message', 'All transaction data, inventory, and sequences deleted successfully. Next order will start from 01.'
  );
  
EXCEPTION
  WHEN OTHERS THEN
    -- Rollback happens automatically
    RAISE EXCEPTION 'Transaction deletion failed: %', SQLERRM;
END;
$_$;


ALTER FUNCTION public.delete_all_transactions_with_inventory() OWNER TO supabase_admin;

--
-- Name: FUNCTION delete_all_transactions_with_inventory(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.delete_all_transactions_with_inventory() IS 'Deletes all transaction data including inventory and resets order sequences. Wrapped in transaction for safety. SUPER ADMIN ONLY. Safely handles missing tables.';


--
-- Name: delete_all_transactions_with_inventory_v3(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.delete_all_transactions_with_inventory_v3() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_storage_files_deleted bigint := 0;
  v_count bigint;
  v_start_time timestamp;
  v_end_time timestamp;
  v_table_name text;
  v_tables_deleted text[] := ARRAY[]::text[];
  
  -- List of tables to delete (we'll check which ones exist)
  v_tables_to_check text[] := ARRAY[
    'consumer_activations',
    'points_transactions',
    'lucky_draw_entries',
    'lucky_draw_order_links',
    'lucky_draw_campaigns',
    'redemption_orders',
    'journey_configurations',
    'qr_validation_reports',
    'stock_movements',
    'product_inventory',
    'qr_codes',
    'qr_master_codes',
    'qr_batches',
    'payments',
    'invoices',
    'shipments',
    'order_items',
    'orders',
    'doc_counters',
    'document_signatures',
    'documents',
    'gl_document_postings',
    'gl_journal_lines',
    'gl_journals'
  ];
BEGIN
  v_start_time := clock_timestamp();
  
  RAISE NOTICE 'Starting smart deletion - checking which tables exist...';
  
  -- Set timeouts
  SET LOCAL statement_timeout = '5min';
  SET LOCAL lock_timeout = '10s';
  
  -- Truncate each table individually if it exists
  FOREACH v_table_name IN ARRAY v_tables_to_check
  LOOP
    BEGIN
      -- Check if table exists
      IF EXISTS (
        SELECT 1 FROM information_schema.tables 
        WHERE table_schema = 'public' 
        AND table_name = v_table_name
      ) THEN
        -- Table exists, truncate it
        EXECUTE format('TRUNCATE TABLE public.%I CASCADE', v_table_name);
        v_tables_deleted := array_append(v_tables_deleted, v_table_name);
        RAISE NOTICE 'Truncated table: %', v_table_name;
      ELSE
        RAISE NOTICE 'Table % does not exist, skipping', v_table_name;
      END IF;
    EXCEPTION
      WHEN OTHERS THEN
        RAISE WARNING 'Could not truncate table %: %', v_table_name, SQLERRM;
    END;
  END LOOP;
  
  RAISE NOTICE 'Truncation complete. Deleted % tables', array_length(v_tables_deleted, 1);

  -- Clean up storage files
  BEGIN
    WITH deleted_files AS (
        SELECT array_agg(name) as paths FROM storage.objects WHERE bucket_id = 'qr-codes'
    )
    SELECT INTO v_count array_length(paths, 1) FROM deleted_files;
    IF v_count > 0 THEN
        v_storage_files_deleted := v_storage_files_deleted + COALESCE(v_count, 0);
        RAISE NOTICE 'Marked % files from qr-codes bucket for deletion', v_count;
    END IF;

    WITH deleted_files AS (
        SELECT array_agg(name) as paths FROM storage.objects WHERE bucket_id = 'documents'
    )
    SELECT INTO v_count array_length(paths, 1) FROM deleted_files;
    IF v_count > 0 THEN
        v_storage_files_deleted := v_storage_files_deleted + COALESCE(v_count, 0);
        RAISE NOTICE 'Marked % files from documents bucket for deletion', v_count;
    END IF;
  EXCEPTION
    WHEN OTHERS THEN
      RAISE WARNING 'Could not count storage files: %', SQLERRM;
  END;

  v_end_time := clock_timestamp();

  RETURN jsonb_build_object(
    'success', true,
    'total_records_deleted', 'all',
    'tables_deleted', v_tables_deleted,
    'table_count', array_length(v_tables_deleted, 1),
    'storage_files_deleted', v_storage_files_deleted,
    'method', 'SMART TRUNCATE (checks table existence)',
    'duration_seconds', EXTRACT(EPOCH FROM (v_end_time - v_start_time)),
    'message', format('Deleted data from %s tables successfully', array_length(v_tables_deleted, 1))
  );

END;
$$;


ALTER FUNCTION public.delete_all_transactions_with_inventory_v3() OWNER TO supabase_admin;

--
-- Name: delete_scratch_campaign(uuid, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.delete_scratch_campaign(p_campaign_id uuid, p_user_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_campaign record;
    v_reward record;
    v_allocated_qty integer;
    v_won_qty integer;
    v_return_qty integer;
    v_inventory_id uuid;
    v_current_qty integer;
    v_new_qty integer;
    v_org_id uuid;
    v_company_id uuid;
BEGIN
    -- 1. Get campaign details
    SELECT * INTO v_campaign FROM public.scratch_card_campaigns WHERE id = p_campaign_id;
    
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Campaign not found';
    END IF;

    v_org_id := v_campaign.org_id;
    SELECT get_company_id(v_org_id) INTO v_company_id;

    -- 2. Disable scratch card feature in journey configuration if linked
    IF v_campaign.journey_config_id IS NOT NULL THEN
        UPDATE public.journey_configurations
        SET enable_scratch_card_game = false,
            updated_at = now()
        WHERE id = v_campaign.journey_config_id;
    END IF;

    -- 3. Process product rewards to return stock
    FOR v_reward IN 
        SELECT * FROM public.scratch_card_rewards 
        WHERE campaign_id = p_campaign_id 
        AND type = 'product' 
        AND variant_id IS NOT NULL
    LOOP
        -- Calculate allocated quantity (from rewards table)
        -- Note: The rewards table stores 'product_quantity' which is per win, but we need total allocated.
        -- Wait, the allocation logic in the form uses 'record_stock_movement' directly.
        -- We need to find how much was allocated by summing up 'scratch_game_out' movements for this campaign.
        
        -- Calculate total allocated (sum of negative movements)
        SELECT COALESCE(ABS(SUM(quantity_change)), 0) INTO v_allocated_qty
        FROM public.stock_movements
        WHERE reference_type = 'campaign'
          AND reference_id = p_campaign_id
          AND variant_id = v_reward.variant_id
          AND movement_type = 'scratch_game_out';

        -- Calculate total won (count of wins * quantity per win)
        SELECT COALESCE(COUNT(*), 0) * v_reward.product_quantity INTO v_won_qty
        FROM public.scratch_card_plays
        WHERE campaign_id = p_campaign_id
          AND reward_id = v_reward.id
          AND is_win = true;

        v_return_qty := v_allocated_qty - v_won_qty;

        -- If there is stock to return
        IF v_return_qty > 0 THEN
            -- Find best inventory to return to (same logic as in form: prefer user org or max stock)
            -- For simplicity in RPC, we return to the organization that originally issued the stock if possible,
            -- but stock movements might be split across orgs.
            -- Let's find the most recent 'scratch_game_out' movement for this variant/campaign to get the source org.
            
            SELECT from_organization_id INTO v_org_id
            FROM public.stock_movements
            WHERE reference_type = 'campaign'
              AND reference_id = p_campaign_id
              AND variant_id = v_reward.variant_id
              AND movement_type = 'scratch_game_out'
            ORDER BY created_at DESC
            LIMIT 1;
            
            -- If not found (maybe manual allocation?), default to campaign org
            IF v_org_id IS NULL THEN
                v_org_id := v_campaign.org_id;
            END IF;

            -- Record stock movement (SG+)
            PERFORM public.record_stock_movement(
                p_movement_type := 'scratch_game_in',
                p_variant_id := v_reward.variant_id,
                p_organization_id := v_org_id,
                p_quantity_change := v_return_qty,
                p_unit_cost := 0,
                p_reason := 'Campaign Deleted: ' || v_campaign.name,
                p_reference_type := 'campaign',
                p_reference_id := p_campaign_id,
                p_created_by := p_user_id
            );
        END IF;
    END LOOP;

    -- 4. Delete campaign (and cascade delete rewards/plays if configured, otherwise manual delete)
    -- Assuming cascade delete is set up on foreign keys, otherwise we delete manually
    DELETE FROM public.scratch_card_rewards WHERE campaign_id = p_campaign_id;
    DELETE FROM public.scratch_card_plays WHERE campaign_id = p_campaign_id;
    DELETE FROM public.scratch_card_campaigns WHERE id = p_campaign_id;

END;
$$;


ALTER FUNCTION public.delete_scratch_campaign(p_campaign_id uuid, p_user_id uuid) OWNER TO supabase_admin;

--
-- Name: detect_order_type(uuid, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.detect_order_type(p_buyer_org_id uuid, p_seller_org_id uuid) RETURNS public.order_type
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_buyer text := public.get_org_type(p_buyer_org_id);
  v_seller text := public.get_org_type(p_seller_org_id);
BEGIN
  IF v_buyer='HQ'   AND v_seller='MFG'  THEN RETURN 'H2M'; END IF;
  IF v_buyer='DIST' AND v_seller='HQ'   THEN RETURN 'D2H'; END IF;
  IF v_buyer='SHOP' AND v_seller='DIST' THEN RETURN 'S2D'; END IF;
  RAISE EXCEPTION 'Invalid buyer→seller org types: % → %', v_buyer, v_seller;
END;
$$;


ALTER FUNCTION public.detect_order_type(p_buyer_org_id uuid, p_seller_org_id uuid) OWNER TO supabase_admin;

--
-- Name: documents_ensure_company_id(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.documents_ensure_company_id() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- If company_id is null and order_id is provided, get company_id from the order
    IF NEW.company_id IS NULL AND NEW.order_id IS NOT NULL THEN
        SELECT company_id INTO NEW.company_id
        FROM public.orders
        WHERE id = NEW.order_id;
        
        IF NEW.company_id IS NOT NULL THEN
            RAISE NOTICE 'Auto-populated company_id from order for doc %', NEW.doc_no;
        END IF;
    END IF;
    
    -- If still null and issued_by_org_id is set, get company from org hierarchy
    IF NEW.company_id IS NULL AND NEW.issued_by_org_id IS NOT NULL THEN
        NEW.company_id := public.get_company_id(NEW.issued_by_org_id);
        
        IF NEW.company_id IS NOT NULL THEN
            RAISE NOTICE 'Auto-populated company_id from org hierarchy for doc %', NEW.doc_no;
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.documents_ensure_company_id() OWNER TO supabase_admin;

--
-- Name: FUNCTION documents_ensure_company_id(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.documents_ensure_company_id() IS 'Auto-populates company_id from order or org hierarchy if not provided. Prevents NULL company_id issues.';


--
-- Name: enforce_redemption_cap(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.enforce_redemption_cap() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  lim record;
  curr integer;
  now_ok boolean := true;
BEGIN
  SELECT * INTO lim FROM public.redemption_order_limits rol WHERE rol.order_id = NEW.order_id;
  IF lim.enforce_limit IS NOT TRUE THEN
    RETURN NEW;
  END IF;
  IF lim.max_redemptions IS NULL OR lim.max_redemptions <= 0 THEN
    RAISE EXCEPTION 'REDEMPTION_LIMIT_CONFIG_INVALID';
  END IF;
  IF lim.start_at IS NOT NULL AND now() < lim.start_at THEN
    RAISE EXCEPTION 'REDEMPTION_NOT_STARTED';
  END IF;
  IF lim.end_at IS NOT NULL AND now() > lim.end_at THEN
    RAISE EXCEPTION 'REDEMPTION_ENDED';
  END IF;
  SELECT count(*) INTO curr FROM public.redemption_orders ro WHERE ro.order_id = NEW.order_id;
  IF curr >= lim.max_redemptions THEN
    RAISE EXCEPTION 'REDEMPTION_LIMIT_REACHED';
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.enforce_redemption_cap() OWNER TO supabase_admin;

