--
-- Name: evaluate_user_registration_bonus(uuid, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.evaluate_user_registration_bonus(p_org_id uuid, p_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_progress public.user_registration_bonus_progress%ROWTYPE;
  v_balance integer := 0;
  v_txn_id uuid;
BEGIN
  SELECT * INTO v_progress
  FROM public.user_registration_bonus_progress
  WHERE org_id = p_org_id AND user_id = p_user_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('status', 'not_enrolled');
  END IF;

  IF v_progress.status IN ('awarded', 'expired', 'disabled') THEN
    RETURN jsonb_build_object('status', v_progress.status);
  END IF;

  IF v_progress.bonus_mode = 'instant' THEN
    RETURN jsonb_build_object('status', v_progress.status, 'note', 'instant bonus handled at registration');
  END IF;

  RETURN jsonb_build_object(
    'status', v_progress.status,
    'months_qualified', v_progress.months_qualified,
    'required', v_progress.required_consecutive_months
  );
END;
$$;


ALTER FUNCTION public.evaluate_user_registration_bonus(p_org_id uuid, p_user_id uuid) OWNER TO supabase_admin;

--
-- Name: extract_seq_from_display_doc_no(text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.extract_seq_from_display_doc_no(p_display_doc_no text) RETURNS integer
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
    v_prefix_len integer := 0;
    v_seq_part text;
BEGIN
    IF p_display_doc_no IS NULL OR p_display_doc_no = '' THEN
        RETURN NULL;
    END IF;
    
    -- Find where digits start (after prefix)
    FOR i IN 1..LENGTH(p_display_doc_no) LOOP
        IF SUBSTRING(p_display_doc_no FROM i FOR 1) ~ '[0-9]' THEN
            v_prefix_len := i - 1;
            EXIT;
        END IF;
    END LOOP;
    
    IF v_prefix_len = 0 THEN
        RETURN NULL;
    END IF;
    
    -- Extract sequence part (skip prefix and 2-digit year)
    -- Format: PREFIX + YY + 6-digit sequence
    -- Example: ORD26000017 -> prefix=ORD(3), year=26(2), seq=000017(6)
    v_seq_part := SUBSTRING(p_display_doc_no FROM v_prefix_len + 3);
    
    -- Handle sub-sequence format (e.g., SI26000017-01)
    IF v_seq_part LIKE '%-%' THEN
        v_seq_part := SPLIT_PART(v_seq_part, '-', 1);
    END IF;
    
    RETURN v_seq_part::integer;
EXCEPTION WHEN OTHERS THEN
    RETURN NULL;
END;
$$;


ALTER FUNCTION public.extract_seq_from_display_doc_no(p_display_doc_no text) OWNER TO supabase_admin;

--
-- Name: FUNCTION extract_seq_from_display_doc_no(p_display_doc_no text); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.extract_seq_from_display_doc_no(p_display_doc_no text) IS 'Extracts the sequence number from a display_doc_no (e.g., ORD26000017 -> 17)';


--
-- Name: extract_variant_key_from_code(text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.extract_variant_key_from_code(qr_code text) RETURNS text
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
  variant_key text;
BEGIN
  -- Extract variant key from QR code format
  -- Example: PROD-CELVA9464-CRA-843412-ORD-HM-1125-02-00015
  -- Returns: PROD-CELVA9464-CRA-843412
  
  variant_key := substring(qr_code from '^(PROD-[^-]+-[^-]+-[^-]+)');
  
  RETURN variant_key;
END;
$$;


ALTER FUNCTION public.extract_variant_key_from_code(qr_code text) OWNER TO supabase_admin;

--
-- Name: FUNCTION extract_variant_key_from_code(qr_code text); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.extract_variant_key_from_code(qr_code text) IS 'Extracts product variant key from QR code string for efficient grouping.';


--
-- Name: extract_year_from_legacy_doc_no(text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.extract_year_from_legacy_doc_no(p_legacy_doc_no text) RETURNS integer
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
    v_match text[];
    v_yymm text;
    v_year integer;
BEGIN
    -- Extract YYMM pattern from legacy doc_no
    -- Examples: ORD-HM-1225-01 -> 1225 -> year 2012 (12) or 2025
    -- We need to handle both 2-digit and interpret correctly
    
    -- Match pattern like -YYMM- where YY is year and MM is month
    v_match := regexp_match(p_legacy_doc_no, '-(\d{2})(\d{2})-');
    
    IF v_match IS NOT NULL THEN
        v_year := v_match[1]::integer;
        -- Assume 20XX for years 00-99
        IF v_year >= 0 AND v_year <= 99 THEN
            v_year := 2000 + v_year;
        END IF;
        RETURN v_year;
    END IF;
    
    -- Default to current year
    RETURN EXTRACT(YEAR FROM CURRENT_DATE)::integer;
END;
$$;


ALTER FUNCTION public.extract_year_from_legacy_doc_no(p_legacy_doc_no text) OWNER TO supabase_admin;

--
-- Name: find_or_create_whatsapp_conversation(text, text, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.find_or_create_whatsapp_conversation(p_user_phone text, p_external_chat_id text DEFAULT NULL::text, p_subject text DEFAULT 'WhatsApp Conversation'::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_phone_e164 TEXT;
    v_conversation_id UUID;
    v_user_id UUID;
    v_case_number TEXT;
BEGIN
    -- Normalize phone
    v_phone_e164 := public.normalize_phone_e164(p_user_phone);
    
    -- Try to find existing conversation by phone
    SELECT id INTO v_conversation_id
    FROM public.support_conversations
    WHERE whatsapp_user_phone = v_phone_e164
      AND status NOT IN ('closed', 'spam')
    ORDER BY created_at DESC
    LIMIT 1;
    
    IF v_conversation_id IS NOT NULL THEN
        -- Update external_chat_id if provided
        IF p_external_chat_id IS NOT NULL THEN
            UPDATE public.support_conversations
            SET external_chat_id = p_external_chat_id,
                updated_at = NOW()
            WHERE id = v_conversation_id;
        END IF;
        RETURN v_conversation_id;
    END IF;
    
    -- Try to find user by phone
    SELECT id INTO v_user_id
    FROM public.users
    WHERE public.normalize_phone_e164(phone) = v_phone_e164
    LIMIT 1;
    
    -- Generate case number
    SELECT 'CASE' || (COALESCE(MAX(CAST(NULLIF(regexp_replace(case_number, '[^0-9]', '', 'g'), '') AS INTEGER)), 2000) + 1)
    INTO v_case_number
    FROM public.support_conversations;
    
    -- Create new conversation
    INSERT INTO public.support_conversations (
        case_number,
        created_by_user_id,
        subject,
        status,
        primary_channel,
        whatsapp_user_phone,
        external_chat_id,
        admin_unread_count
    ) VALUES (
        v_case_number,
        COALESCE(v_user_id, '00000000-0000-0000-0000-000000000000'::UUID),
        p_subject,
        'open',
        'whatsapp',
        v_phone_e164,
        p_external_chat_id,
        1
    )
    RETURNING id INTO v_conversation_id;
    
    RETURN v_conversation_id;
END;
$$;


ALTER FUNCTION public.find_or_create_whatsapp_conversation(p_user_phone text, p_external_chat_id text, p_subject text) OWNER TO supabase_admin;

--
-- Name: fn_auto_create_hr_employee(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.fn_auto_create_hr_employee() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_org_type text;
BEGIN
    -- Only create HR employee record for HQ org users
    SELECT org_type_code INTO v_org_type
    FROM public.organizations
    WHERE id = NEW.organization_id;

    IF v_org_type = 'HQ' THEN
        INSERT INTO public.hr_employees (user_id, organization_id, hire_date, status)
        VALUES (NEW.id, NEW.organization_id, COALESCE(NEW.join_date, CURRENT_DATE), 'active')
        ON CONFLICT (user_id, organization_id) DO NOTHING;

        -- Also update user's employee_no
        UPDATE public.users
        SET employee_no = (
            SELECT employee_no FROM public.hr_employees
            WHERE user_id = NEW.id AND organization_id = NEW.organization_id
        )
        WHERE id = NEW.id AND employee_no IS NULL;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_auto_create_hr_employee() OWNER TO supabase_admin;

--
-- Name: fn_calculate_order_total(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.fn_calculate_order_total(p_order_id uuid) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_total numeric := 0;
BEGIN
  -- Try canonical: order_items(qty, unit_price)
  BEGIN
    SELECT COALESCE(SUM( (oi.qty)::numeric * (oi.unit_price)::numeric ), 0)
    INTO v_total
    FROM public.order_items oi
    WHERE oi.order_id = p_order_id;

    IF v_total IS NOT NULL THEN
      RETURN v_total;
    END IF;
  EXCEPTION WHEN undefined_table OR undefined_column THEN
    -- Fallback patterns if your columns are named slightly differently
    BEGIN
      SELECT COALESCE(SUM( (oi.quantity)::numeric * (oi.price)::numeric ), 0)
      INTO v_total
      FROM public.order_items oi
      WHERE oi.order_id = p_order_id;
      RETURN v_total;
    EXCEPTION WHEN OTHERS THEN
      RAISE EXCEPTION 'fn_calculate_order_total(): cannot compute total for order % — please ensure order_items has qty/unit_price (or quantity/price). Error: %',
        p_order_id, SQLERRM;
    END;
  END;

  RETURN COALESCE(v_total, 0);
END;
$$;


ALTER FUNCTION public.fn_calculate_order_total(p_order_id uuid) OWNER TO supabase_admin;

--
-- Name: fn_consumer_activity_stats(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.fn_consumer_activity_stats(p_company_id uuid, p_order_id uuid DEFAULT NULL::uuid, p_activity_type text DEFAULT NULL::text) RETURNS TABLE(total_scans bigint, unique_consumers bigint, total_points bigint, today_scans bigint)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_today date := (now() AT TIME ZONE 'Asia/Kuala_Lumpur')::date;
BEGIN
  RETURN QUERY
  SELECT
    count(*)::bigint AS total_scans,
    count(DISTINCT q.consumer_phone)::bigint AS unique_consumers,
    coalesce(sum(
      CASE WHEN q.is_points_collected THEN
        COALESCE(
          q.points_value,
          (SELECT cqs.points_amount FROM consumer_qr_scans cqs WHERE cqs.qr_code_id = q.id AND cqs.collected_points = true ORDER BY cqs.scanned_at DESC LIMIT 1),
          0
        )
      ELSE 0 END
    ), 0)::bigint AS total_points,
    count(*) FILTER (WHERE (
      COALESCE(q.first_consumer_scan_at, q.points_collected_at, q.redeemed_at, q.lucky_draw_entered_at, q.activated_at)
      AT TIME ZONE 'Asia/Kuala_Lumpur'
    )::date = v_today)::bigint AS today_scans
  FROM qr_codes q
  WHERE q.company_id = p_company_id
    AND (q.is_redeemed = true OR q.is_lucky_draw_entered = true OR q.is_points_collected = true)
    AND (p_order_id IS NULL OR q.order_id = p_order_id)
    AND (
      p_activity_type IS NULL
      OR p_activity_type = 'all'
      OR (p_activity_type = 'lucky_draw'  AND q.is_lucky_draw_entered = true)
      OR (p_activity_type = 'points'      AND q.is_points_collected = true)
      OR (p_activity_type = 'gift'        AND q.is_redeemed = true)
    );
END;
$$;


ALTER FUNCTION public.fn_consumer_activity_stats(p_company_id uuid, p_order_id uuid, p_activity_type text) OWNER TO supabase_admin;

--
-- Name: fn_consumer_analytics_daily(uuid, timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.fn_consumer_analytics_daily(p_company_id uuid, p_from timestamp with time zone, p_to timestamp with time zone) RETURNS TABLE(scan_date date, scans bigint, unique_consumers bigint, points bigint, gifts bigint, lucky_draws bigint)
    LANGUAGE sql STABLE SECURITY DEFINER
    AS $$
  SELECT
    (updated_at AT TIME ZONE 'Asia/Kuala_Lumpur')::date      AS scan_date,
    count(*)::bigint                                          AS scans,
    count(DISTINCT consumer_phone)::bigint                    AS unique_consumers,
    coalesce(sum(CASE WHEN is_points_collected THEN points_value ELSE 0 END), 0)::bigint AS points,
    count(*) FILTER (WHERE is_redeemed)::bigint               AS gifts,
    count(*) FILTER (WHERE is_lucky_draw_entered)::bigint     AS lucky_draws
  FROM qr_codes
  WHERE company_id = p_company_id
    AND (is_redeemed = true OR is_lucky_draw_entered = true OR is_points_collected = true)
    AND updated_at >= p_from
    AND updated_at <= p_to
  GROUP BY scan_date
  ORDER BY scan_date;
$$;


ALTER FUNCTION public.fn_consumer_analytics_daily(p_company_id uuid, p_from timestamp with time zone, p_to timestamp with time zone) OWNER TO supabase_admin;

--
-- Name: fn_consumer_analytics_hourly(uuid, timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.fn_consumer_analytics_hourly(p_company_id uuid, p_from timestamp with time zone, p_to timestamp with time zone) RETURNS TABLE(hour integer, scans bigint)
    LANGUAGE sql STABLE SECURITY DEFINER
    AS $$
  SELECT
    extract(hour FROM updated_at AT TIME ZONE 'Asia/Kuala_Lumpur')::int AS hour,
    count(*)::bigint AS scans
  FROM qr_codes
  WHERE company_id = p_company_id
    AND (is_redeemed = true OR is_lucky_draw_entered = true OR is_points_collected = true)
    AND updated_at >= p_from
    AND updated_at <= p_to
  GROUP BY hour
  ORDER BY hour;
$$;


ALTER FUNCTION public.fn_consumer_analytics_hourly(p_company_id uuid, p_from timestamp with time zone, p_to timestamp with time zone) OWNER TO supabase_admin;

--
-- Name: fn_consumer_analytics_products(uuid, timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.fn_consumer_analytics_products(p_company_id uuid, p_from timestamp with time zone, p_to timestamp with time zone) RETURNS TABLE(product_name text, scan_count bigint, unique_consumers bigint)
    LANGUAGE sql STABLE SECURITY DEFINER
    AS $$
  SELECT
    coalesce(p.product_name, 'Unknown')                      AS product_name,
    count(*)::bigint                                          AS scan_count,
    count(DISTINCT q.consumer_phone)::bigint                  AS unique_consumers
  FROM qr_codes q
  LEFT JOIN products p ON p.id = q.product_id
  WHERE q.company_id = p_company_id
    AND (q.is_redeemed = true OR q.is_lucky_draw_entered = true OR q.is_points_collected = true)
    AND q.updated_at >= p_from
    AND q.updated_at <= p_to
  GROUP BY p.product_name
  ORDER BY scan_count DESC;
$$;


ALTER FUNCTION public.fn_consumer_analytics_products(p_company_id uuid, p_from timestamp with time zone, p_to timestamp with time zone) OWNER TO supabase_admin;

