--
-- Name: fn_consumer_analytics_top_consumers(uuid, timestamp with time zone, timestamp with time zone, integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.fn_consumer_analytics_top_consumers(p_company_id uuid, p_from timestamp with time zone, p_to timestamp with time zone, p_limit integer DEFAULT 50) RETURNS TABLE(phone text, consumer_name text, scan_count bigint, total_points bigint, last_active timestamp with time zone)
    LANGUAGE sql STABLE SECURITY DEFINER
    AS $$
  WITH ranked AS (
    SELECT
      q.consumer_phone                                       AS phone,
      -- pick the latest non-null consumer_name per phone
      (array_agg(q.consumer_name ORDER BY q.updated_at DESC) FILTER (WHERE q.consumer_name IS NOT NULL))[1] AS qr_name,
      count(*)::bigint                                       AS scan_count,
      coalesce(sum(CASE WHEN q.is_points_collected THEN q.points_value ELSE 0 END), 0)::bigint AS total_points,
      max(q.updated_at)                                      AS last_active
    FROM qr_codes q
    WHERE q.company_id = p_company_id
      AND (q.is_redeemed = true OR q.is_lucky_draw_entered = true OR q.is_points_collected = true)
      AND q.updated_at >= p_from
      AND q.updated_at <= p_to
      AND q.consumer_phone IS NOT NULL
    GROUP BY q.consumer_phone
    ORDER BY scan_count DESC
    LIMIT p_limit
  )
  SELECT
    r.phone,
    coalesce(u.full_name, r.qr_name, r.phone) AS consumer_name,
    r.scan_count,
    r.total_points,
    r.last_active
  FROM ranked r
  LEFT JOIN users u ON u.phone = r.phone
  ORDER BY r.scan_count DESC;
$$;


ALTER FUNCTION public.fn_consumer_analytics_top_consumers(p_company_id uuid, p_from timestamp with time zone, p_to timestamp with time zone, p_limit integer) OWNER TO supabase_admin;

--
-- Name: fn_consumer_unique_list(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.fn_consumer_unique_list(p_company_id uuid, p_order_id uuid DEFAULT NULL::uuid, p_activity_type text DEFAULT NULL::text) RETURNS TABLE(phone text, name text, email text, scan_count bigint, last_active timestamp with time zone)
    LANGUAGE sql STABLE SECURITY DEFINER
    AS $$
  WITH grouped AS (
    SELECT
      q.consumer_phone                                     AS phone,
      (array_agg(q.consumer_name ORDER BY q.updated_at DESC)
        FILTER (WHERE q.consumer_name IS NOT NULL))[1]     AS qr_name,
      max(q.consumer_email)                                AS email,
      count(*)::bigint                                     AS scan_count,
      max(q.updated_at)                                    AS last_active
    FROM qr_codes q
    WHERE q.company_id = p_company_id
      AND (q.is_redeemed = true OR q.is_lucky_draw_entered = true OR q.is_points_collected = true)
      AND q.consumer_phone IS NOT NULL
      AND (p_order_id IS NULL OR q.order_id = p_order_id)
      AND (
        p_activity_type IS NULL
        OR p_activity_type = 'all'
        OR (p_activity_type = 'lucky_draw'  AND q.is_lucky_draw_entered = true)
        OR (p_activity_type = 'points'      AND q.is_points_collected = true)
        OR (p_activity_type = 'gift'        AND q.is_redeemed = true)
      )
    GROUP BY q.consumer_phone
  )
  SELECT
    g.phone,
    coalesce(u.full_name, g.qr_name, g.phone) AS name,
    coalesce(g.email, u.email)                 AS email,
    g.scan_count,
    g.last_active
  FROM grouped g
  LEFT JOIN users u ON u.phone = g.phone
  ORDER BY g.scan_count DESC;
$$;


ALTER FUNCTION public.fn_consumer_unique_list(p_company_id uuid, p_order_id uuid, p_activity_type text) OWNER TO supabase_admin;

--
-- Name: fn_create_balance_payment_request(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.fn_create_balance_payment_request(p_order_id uuid) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_order               record;
  v_order_json          jsonb;
  v_terms               jsonb;
  v_doc_id              uuid := gen_random_uuid();
  v_doc_no              text;
  v_status              public.document_status := 'pending';
  v_po_no               text;
  v_company_id          uuid;
  v_order_type          text;
  v_balance_pct         numeric := 0.5;
  v_order_total         numeric := 0;
  v_requested_amount    numeric := 0;
  v_trigger_mode        text := 'on_first_receive';
  v_payload             jsonb;
  v_notify_id           uuid := gen_random_uuid();
  v_now                 timestamptz := now();
  v_buyer_org_id        uuid;
  v_seller_org_id       uuid;
  v_created_by          uuid;
  v_payment_percentage  integer := 0;
BEGIN
  SELECT o.* INTO v_order
  FROM public.orders o
  WHERE o.id = p_order_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Order % not found', p_order_id;
  END IF;

  v_order_json := to_jsonb(v_order);
  v_terms := v_order_json -> 'payment_terms';

  v_po_no := COALESCE(
    NULLIF(v_order_json ->> 'po_no', ''),
    NULLIF(v_order_json ->> 'order_no', ''),
    NULLIF(v_order_json ->> 'doc_no', '')
  );

  BEGIN
    v_balance_pct := COALESCE(NULLIF(v_terms ->> 'balance_pct', '')::numeric, 0.5);
  EXCEPTION WHEN OTHERS THEN
    v_balance_pct := 0.5;
  END;

  BEGIN
    v_trigger_mode := COALESCE(NULLIF(v_terms ->> 'balance_trigger', ''), 'on_first_receive');
  EXCEPTION WHEN OTHERS THEN
    v_trigger_mode := 'on_first_receive';
  END;

  v_order_total := public.fn_calculate_order_total(p_order_id);
  v_requested_amount := round(COALESCE(v_order_total, 0) * COALESCE(v_balance_pct, 0.5), 2);
  v_payment_percentage := COALESCE(ROUND(v_balance_pct * 100)::integer, 0);

  v_buyer_org_id := COALESCE(
    NULLIF(v_order_json ->> 'buyer_org_id', '')::uuid,
    NULLIF(v_order_json ->> 'hq_org_id', '')::uuid,
    NULLIF(v_order_json ->> 'customer_org_id', '')::uuid,
    NULLIF(v_order_json ->> 'distributor_org_id', '')::uuid,
    NULLIF(v_order_json ->> 'warehouse_org_id', '')::uuid
  );

  v_seller_org_id := COALESCE(
    NULLIF(v_order_json ->> 'seller_org_id', '')::uuid,
    NULLIF(v_order_json ->> 'manufacturer_org_id', '')::uuid,
    NULLIF(v_order_json ->> 'vendor_org_id', '')::uuid,
    NULLIF(v_order_json ->> 'supplier_org_id', '')::uuid
  );

  IF v_buyer_org_id IS NULL OR v_seller_org_id IS NULL THEN
    RAISE EXCEPTION 'fn_create_balance_payment_request(): order % missing buyer/seller organization context', p_order_id;
  END IF;

  BEGIN
    v_created_by := NULLIF(v_order_json ->> 'created_by', '')::uuid;
  EXCEPTION WHEN OTHERS THEN
    v_created_by := NULL;
  END;

  IF v_created_by IS NULL THEN
    BEGIN
      v_created_by := NULLIF(v_order_json ->> 'approved_by', '')::uuid;
    EXCEPTION WHEN OTHERS THEN
      v_created_by := NULL;
    END;
  END IF;

  BEGIN
    v_company_id := NULLIF(v_order_json ->> 'company_id', '')::uuid;
  EXCEPTION WHEN OTHERS THEN
    v_company_id := NULL;
  END;

  IF v_company_id IS NULL AND v_buyer_org_id IS NOT NULL THEN
    BEGIN
      v_company_id := public.get_company_id(v_buyer_org_id);
    EXCEPTION WHEN OTHERS THEN
      v_company_id := NULL;
    END;
  END IF;

  BEGIN
    IF v_buyer_org_id IS NOT NULL AND v_seller_org_id IS NOT NULL THEN
      v_order_type := public.detect_order_type(v_buyer_org_id, v_seller_org_id)::text;
    END IF;
  EXCEPTION WHEN OTHERS THEN
    v_order_type := NULL;
  END;

  IF v_order_type IS NULL THEN
    v_order_type := COALESCE(v_order_json ->> 'order_type', 'HM');
  END IF;

  IF (v_order_json ->> 'order_no') IS NOT NULL AND v_order_json ->> 'order_no' <> '' THEN
    v_doc_no := public.format_doc_no_from_order('REQ', v_order_json ->> 'order_no');
  ELSIF v_order_json ->> 'doc_no' IS NOT NULL AND v_order_json ->> 'doc_no' <> '' THEN
    v_doc_no := public.format_doc_no_from_order('REQ', v_order_json ->> 'doc_no');
  ELSIF v_po_no IS NOT NULL AND v_po_no <> '' THEN
    v_doc_no := public.format_doc_no_from_order('REQ', v_po_no);
  ELSE
    v_doc_no := 'REQ-' || to_char(v_now, 'YYMMDDHH24MISS') || '-' || right(encode(gen_random_bytes(2), 'hex'), 4);
  END IF;

  v_payload := jsonb_build_object(
    'order_id', p_order_id::text,
    'po_no', v_po_no,
    'reason', 'BALANCE_50_AFTER_RECEIVE',
    'requested_percent', v_balance_pct,
    'requested_amount', v_requested_amount,
    'currency', 'MYR',
    'trigger_mode', v_trigger_mode,
    'warehouse_receive_snapshot', jsonb_build_object(
      'created_at', to_char(v_now, 'YYYY-MM-DD"T"HH24:MI:SSOF')
    )
  );

  INSERT INTO public.documents (
    id,
    order_id,
    doc_type,
    doc_no,
    status,
    issued_by_org_id,
    issued_to_org_id,
    company_id,
    payload,
    created_by,
    created_at,
    updated_at,
    payment_percentage
  )
  VALUES (
    v_doc_id,
    p_order_id,
    'PAYMENT_REQUEST',
    v_doc_no,
    v_status,
    v_seller_org_id,
    v_buyer_org_id,
    v_company_id,
    v_payload,
    v_created_by,
    v_now,
    v_now,
    NULLIF(v_payment_percentage, 0)
  );

  BEGIN
    INSERT INTO public.notifications_outbox (id, org_id, channel, template_code, payload_json, status, created_at)
    VALUES (
      v_notify_id,
      NULL,
      'inapp',
      'FIN_BALANCE_PAYMENT_REQUEST',
      jsonb_build_object(
        'order_id', p_order_id::text,
        'po_no', v_po_no,
        'doc_id', v_doc_id::text,
        'doc_no', v_doc_no,
        'requested_amount', v_requested_amount
      ),
      'queued',
      v_now
    );
  EXCEPTION WHEN undefined_table THEN
    RAISE NOTICE 'notifications_outbox not present; skipping notification for request %', v_doc_id;
  WHEN OTHERS THEN
    RAISE WARNING 'Could not enqueue notification for request %: %', v_doc_id, SQLERRM;
  END;

  RETURN v_doc_id;
END;
$$;


ALTER FUNCTION public.fn_create_balance_payment_request(p_order_id uuid) OWNER TO supabase_admin;

--
-- Name: fn_create_otp(uuid, text, text, text, text, uuid, text, integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.fn_create_otp(p_org_id uuid, p_channel text, p_phone text, p_email text, p_subject_type text, p_subject_ref uuid, p_purpose text, p_ttl_sec integer DEFAULT 300) RETURNS uuid
    LANGUAGE plpgsql
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  v_id uuid := gen_random_uuid();
  v_code text := lpad(((floor(random()*900000)::int) + 100000)::text, 6, '0');
  v_salt text := encode(gen_random_bytes(16), 'hex');
  v_hash text := encode(digest(v_code || v_salt, 'sha256'), 'hex');
  v_expires timestamptz := now() + make_interval(secs => p_ttl_sec);
BEGIN
  INSERT INTO public.otp_challenges(
    id, org_id, subject_type, subject_ref, channel, phone, email,
    code_hash, salt, expires_at, metadata
  )
  VALUES (
    v_id, p_org_id, p_subject_type, p_subject_ref, p_channel, p_phone, p_email,
    v_hash, v_salt, v_expires,
    jsonb_build_object('purpose', coalesce(p_purpose, 'generic'))
  );

  INSERT INTO public.notifications_outbox(
    id, org_id, channel, to_phone, template_code, payload_json, status
  )
  VALUES (
    gen_random_uuid(), p_org_id, p_channel, p_phone, 'OTP_GENERIC',
    jsonb_build_object('code', v_code, 'expires_at', to_char(v_expires, 'YYYY-MM-DD"T"HH24:MI:SSOF')),
    'queued'
  );

  RETURN v_id;
END;
$$;


ALTER FUNCTION public.fn_create_otp(p_org_id uuid, p_channel text, p_phone text, p_email text, p_subject_type text, p_subject_ref uuid, p_purpose text, p_ttl_sec integer) OWNER TO supabase_admin;

