--
-- Name: fn_get_balance_payment_request(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.fn_get_balance_payment_request(p_order_id uuid) RETURNS public.documents
    LANGUAGE plpgsql
    AS $$
DECLARE
  r public.documents;
BEGIN
  SELECT d.*
  INTO r
  FROM public.documents d
  WHERE d.doc_type = 'PAYMENT_REQUEST'
    AND (d.payload ? 'order_id')
    AND (d.payload->>'order_id') = p_order_id::text
    AND (d.payload->>'reason') = 'BALANCE_50_AFTER_RECEIVE'
  ORDER BY d.created_at DESC
  LIMIT 1;

  RETURN r;
END;
$$;


ALTER FUNCTION public.fn_get_balance_payment_request(p_order_id uuid) OWNER TO supabase_admin;

--
-- Name: fn_test_balance_request_flow(uuid, boolean); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.fn_test_balance_request_flow(p_order_id uuid, p_auto_approve boolean DEFAULT true) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_req_id   uuid;
  v_pay_id   uuid;
  v_req      public.documents;
  v_summary  jsonb;
BEGIN
  -- 1) Simulate a warehouse receive (purchase_in)
  --    Insert is minimal and should align with your stock_movements shape.
  --    If your table has extra NOT NULLs, this may need adjustment later.
  BEGIN
    INSERT INTO public.stock_movements (
      id, movement_type, order_id, created_at
    ) VALUES (
      gen_random_uuid(), 'purchase_in', p_order_id, now()
    );
  EXCEPTION WHEN undefined_table THEN
    RAISE EXCEPTION 'Test failed: public.stock_movements table not found. Ensure SCM module is present.';
  WHEN not_null_violation OR undefined_column THEN
    RAISE EXCEPTION 'Test failed: stock_movements has additional NOT NULL columns; please extend this test to satisfy them.';
  END;

  -- 2) Fetch the newly created PAYMENT_REQUEST
  SELECT public.fn_get_balance_payment_request(p_order_id) INTO v_req;
  IF v_req.id IS NULL THEN
    RAISE EXCEPTION 'PAYMENT_REQUEST was not created by the receive trigger for order %', p_order_id;
  END IF;

  v_req_id := v_req.id;

  -- 3) Optionally approve to create the PAYMENT
  IF p_auto_approve THEN
    v_pay_id := public.approve_payment_request(v_req_id);
  END IF;

  -- 4) Return a concise JSON summary
  v_summary := jsonb_build_object(
    'order_id', p_order_id::text,
    'request_id', v_req_id::text,
    'request_doc_no', v_req.doc_no,
    'request_status', v_req.status,
    'auto_approved', p_auto_approve,
    'payment_id', v_pay_id::text
  );

  RETURN v_summary;
END;
$$;


ALTER FUNCTION public.fn_test_balance_request_flow(p_order_id uuid, p_auto_approve boolean) OWNER TO supabase_admin;

--
-- Name: fn_verify_otp(uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.fn_verify_otp(p_challenge_id uuid, p_code text) RETURNS boolean
    LANGUAGE plpgsql
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  r record;
  v_hash text;
BEGIN
  SELECT *
  INTO r
  FROM public.otp_challenges
  WHERE id = p_challenge_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;

  IF r.status <> 'pending' THEN
    RETURN FALSE;
  END IF;

  IF r.expires_at < now() THEN
    UPDATE public.otp_challenges SET status='expired' WHERE id = r.id;
    RETURN FALSE;
  END IF;

  IF r.attempts >= r.max_attempts THEN
    UPDATE public.otp_challenges SET status='blocked' WHERE id = r.id;
    RETURN FALSE;
  END IF;

  v_hash := encode(digest(p_code || r.salt, 'sha256'), 'hex');

  IF v_hash = r.code_hash THEN
    UPDATE public.otp_challenges
    SET status='verified', verified_at=now()
    WHERE id = r.id;
    RETURN TRUE;
  ELSE
    UPDATE public.otp_challenges
    SET attempts = attempts + 1
    WHERE id = r.id;
    RETURN FALSE;
  END IF;
END;
$$;


ALTER FUNCTION public.fn_verify_otp(p_challenge_id uuid, p_code text) OWNER TO supabase_admin;

