-- Name: force_warranty_bonus_zero_cost(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.force_warranty_bonus_zero_cost() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF LOWER(TRIM(NEW.movement_type)) = 'warranty_bonus' THEN
    NEW.unit_cost := 0;
  END IF;
  RETURN NEW;
END
$$;


