--
-- Name: generate_display_doc_number(uuid, text, integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.generate_display_doc_number(p_company_id uuid, p_doc_type text, p_year integer DEFAULT NULL::integer) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_year integer;
    v_prefix text;
    v_seq integer;
    v_display_no text;
BEGIN
    v_year := COALESCE(p_year, EXTRACT(YEAR FROM CURRENT_DATE)::integer);
    v_prefix := UPPER(TRIM(p_doc_type));
    
    -- Map common doc types
    CASE v_prefix
        WHEN 'ORDER' THEN v_prefix := 'ORD';
        WHEN 'INVOICE' THEN v_prefix := 'SI';
        WHEN 'PAYMENT' THEN v_prefix := 'PV';
        WHEN 'RECEIPT' THEN v_prefix := 'RC';
        WHEN 'PAYMENT_REQUEST' THEN v_prefix := 'BR';
        WHEN 'DELIVERY_ORDER' THEN v_prefix := 'DO';
        WHEN 'GOODS_RECEIVED' THEN v_prefix := 'GR';
        ELSE v_prefix := v_prefix;
    END CASE;
    
    -- Get next sequence (NO RECYCLING CHECK)
    INSERT INTO public.doc_sequences (company_id, doc_type, year, next_seq)
    VALUES (p_company_id, v_prefix, v_year, 2)
    ON CONFLICT (company_id, doc_type, year)
    DO UPDATE SET 
        next_seq = doc_sequences.next_seq + 1,
        updated_at = NOW()
    RETURNING next_seq - 1 INTO v_seq;
    
    v_seq := COALESCE(v_seq, 1);
    
    v_display_no := v_prefix || 
                    LPAD((v_year % 100)::text, 2, '0') || 
                    LPAD(v_seq::text, 6, '0');
    
    RETURN v_display_no;
END;
$$;


