--
-- Name: generate_journal_number(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.generate_journal_number(p_company_id uuid) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_year_month text;
    v_sequence int;
    v_journal_no text;
BEGIN
    v_year_month := to_char(CURRENT_DATE, 'YYYYMM');
    
    -- Get next sequence for this company/month
    SELECT COALESCE(MAX(
        CAST(NULLIF(regexp_replace(journal_no, '^JV-\d{6}-', ''), '') AS integer)
    ), 0) + 1
    INTO v_sequence
    FROM public.gl_journals
    WHERE company_id = p_company_id
    AND journal_no LIKE 'JV-' || v_year_month || '-%';
    
    v_journal_no := 'JV-' || v_year_month || '-' || LPAD(v_sequence::text, 4, '0');
    
    RETURN v_journal_no;
END;
$$;


ALTER FUNCTION public.generate_journal_number(p_company_id uuid) OWNER TO supabase_admin;

--
-- Name: FUNCTION generate_journal_number(p_company_id uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.generate_journal_number(p_company_id uuid) IS 'Generates sequential journal number: JV-YYYYMM-0001';


--
-- Name: generate_journal_number(uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.generate_journal_number(p_company_id uuid, p_journal_type text) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
    v_prefix text;
    v_year text;
    v_sequence integer;
    v_number text;
BEGIN
    -- Determine prefix based on journal type
    v_prefix := CASE p_journal_type
        WHEN 'SALES_INVOICE' THEN 'JV-SI'
        WHEN 'RECEIPT' THEN 'JV-RC'
        WHEN 'SUPPLIER_DEPOSIT' THEN 'JV-SD'
        WHEN 'SUPPLIER_PAYMENT' THEN 'JV-SP'
        WHEN 'REVERSAL' THEN 'JV-RV'
        WHEN 'ADJUSTMENT' THEN 'JV-AJ'
        WHEN 'OPENING' THEN 'JV-OP'
        ELSE 'JV-XX'
    END;
    
    v_year := to_char(CURRENT_DATE, 'YY');
    
    -- Get next sequence number for this company/type/year
    SELECT COALESCE(MAX(
        CASE 
            WHEN journal_number ~ (v_prefix || '-' || v_year || '-[0-9]+$')
            THEN CAST(SUBSTRING(journal_number FROM '[0-9]+$') AS integer)
            ELSE 0
        END
    ), 0) + 1
    INTO v_sequence
    FROM public.gl_journals
    WHERE company_id = p_company_id
    AND journal_number LIKE v_prefix || '-' || v_year || '-%';
    
    v_number := v_prefix || '-' || v_year || '-' || LPAD(v_sequence::text, 6, '0');
    
    RETURN v_number;
END;
$_$;


ALTER FUNCTION public.generate_journal_number(p_company_id uuid, p_journal_type text) OWNER TO supabase_admin;

