--
-- Name: generate_order_referenced_doc_number(uuid, uuid, text, integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.generate_order_referenced_doc_number(p_company_id uuid, p_order_id uuid, p_doc_type text, p_year integer DEFAULT NULL::integer) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_year integer;
    v_prefix text;
    v_order_base_seq integer;
    v_order_display_doc_no text;
    v_sub_seq integer;
    v_display_no text;
    v_is_single_doc boolean;
BEGIN
    -- Use current year if not specified
    v_year := COALESCE(p_year, EXTRACT(YEAR FROM CURRENT_DATE)::integer);
    
    -- Normalize prefix
    v_prefix := UPPER(TRIM(p_doc_type));
    
    -- Map doc_type to display prefix if needed
    CASE v_prefix
        WHEN 'INVOICE' THEN v_prefix := 'SI';
        WHEN 'PAYMENT' THEN v_prefix := 'PV';
        WHEN 'RECEIPT' THEN v_prefix := 'RC';
        WHEN 'PAYMENT_REQUEST' THEN v_prefix := 'BR';
        WHEN 'DELIVERY_ORDER' THEN v_prefix := 'DO';
        WHEN 'GOODS_RECEIVED' THEN v_prefix := 'GR';
        ELSE v_prefix := v_prefix; -- Keep as-is (PO, SO, DO, etc.)
    END CASE;
    
    -- Determine if this doc type is 1:1 with order (no sub-sequence needed)
    v_is_single_doc := v_prefix IN ('PO', 'SO', 'DO', 'GR');
    
    -- Get order's base sequence number and display_doc_no
    SELECT base_seq, display_doc_no 
    INTO v_order_base_seq, v_order_display_doc_no
    FROM public.orders
    WHERE id = p_order_id;
    
    -- If order doesn't have base_seq yet, extract it from display_doc_no
    IF v_order_base_seq IS NULL AND v_order_display_doc_no IS NOT NULL THEN
        v_order_base_seq := extract_seq_from_display_doc_no(v_order_display_doc_no);
        
        -- Update order with extracted base_seq
        IF v_order_base_seq IS NOT NULL THEN
            UPDATE public.orders
            SET base_seq = v_order_base_seq
            WHERE id = p_order_id;
        END IF;
    END IF;
    
    -- If still no base_seq, we need to generate a new sequence (fallback)
    IF v_order_base_seq IS NULL THEN
        -- Generate new sequence number using the original function logic
        INSERT INTO public.doc_sequences (company_id, doc_type, year, next_seq, last_used_at)
        VALUES (p_company_id, 'ORD', v_year, 1, NOW())
        ON CONFLICT (company_id, doc_type, year)
        DO UPDATE SET 
            next_seq = doc_sequences.next_seq + 1,
            last_used_at = NOW(),
            updated_at = NOW()
        RETURNING next_seq INTO v_order_base_seq;
        
        -- Update order with new base_seq
        UPDATE public.orders
        SET base_seq = v_order_base_seq
        WHERE id = p_order_id;
    END IF;
    
    -- For 1:1 documents (PO, SO, DO, GR), use same sequence without sub-sequence
    IF v_is_single_doc THEN
        v_display_no := v_prefix || LPAD((v_year % 100)::text, 2, '0') || LPAD(v_order_base_seq::text, 6, '0');
        RETURN v_display_no;
    END IF;
    
    -- For documents that can have multiples (SI, PV, RC, BR), add sub-sequence
    -- Get next sub-sequence for this order + doc_type
    INSERT INTO public.order_doc_sequences (order_id, doc_type, next_sub_seq)
    VALUES (p_order_id, v_prefix, 1)
    ON CONFLICT (order_id, doc_type)
    DO UPDATE SET 
        next_sub_seq = order_doc_sequences.next_sub_seq + 1,
        updated_at = NOW()
    RETURNING next_sub_seq INTO v_sub_seq;
    
    -- Format: PREFIX + YY + ORDER_SEQ + '-' + SUB_SEQ
    -- Example: SI26000017-01
    v_display_no := v_prefix || LPAD((v_year % 100)::text, 2, '0') || LPAD(v_order_base_seq::text, 6, '0') || '-' || LPAD(v_sub_seq::text, 2, '0');
    
    RETURN v_display_no;
END;
$$;


ALTER FUNCTION public.generate_order_referenced_doc_number(p_company_id uuid, p_order_id uuid, p_doc_type text, p_year integer) OWNER TO supabase_admin;

--
-- Name: FUNCTION generate_order_referenced_doc_number(p_company_id uuid, p_order_id uuid, p_doc_type text, p_year integer); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.generate_order_referenced_doc_number(p_company_id uuid, p_order_id uuid, p_doc_type text, p_year integer) IS 'Generates document numbers that reference their parent order sequence. PO/SO/DO use same number as order, others get sub-sequences (e.g., SI26000017-01)';


--
-- Name: generate_po_number(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.generate_po_number(p_org_id uuid) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_org_code text;
    v_date_str text;
    v_count integer;
    v_po_number text;
BEGIN
    -- Get organization code
    SELECT org_code INTO v_org_code
    FROM public.organizations
    WHERE id = p_org_id;
    
    -- Default to 'ORG' if no code found
    IF v_org_code IS NULL THEN
        v_org_code := 'ORG';
    END IF;
    
    -- Get current date as YYYYMMDD
    v_date_str := to_char(now(), 'YYYYMMDD');
    
    -- Count existing POs for this org today to generate sequence
    -- We look for POs starting with PO-{ORG_CODE}-{YYYYMMDD}-
    SELECT count(*) INTO v_count
    FROM public.orders
    WHERE buyer_org_id = p_org_id
      AND po_doc_no LIKE 'PO-' || v_org_code || '-' || v_date_str || '-%';
      
    -- Generate PO Number: PO-CODE-YYYYMMDD-001
    v_po_number := 'PO-' || v_org_code || '-' || v_date_str || '-' || lpad((v_count + 1)::text, 3, '0');
    
    RETURN v_po_number;
END;
$$;


ALTER FUNCTION public.generate_po_number(p_org_id uuid) OWNER TO supabase_admin;

