-- Name: FUNCTION generate_redemption_code(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.generate_redemption_code() IS 'Automatically generates redemption codes and sets default fulfillment status for redemption transactions';


--
-- Name: generate_signature_hash(uuid, uuid, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.generate_signature_hash(p_document_id uuid, p_signer_user_id uuid, p_signed_at timestamp with time zone) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
    v_doc_payload JSONB;
    v_hash_input TEXT;
    v_hash TEXT;
BEGIN
    -- Get document payload
    SELECT payload INTO v_doc_payload
    FROM public.documents
    WHERE id = p_document_id;

    -- Create hash input: document_payload + user_id + timestamp
    v_hash_input := CONCAT(
        v_doc_payload::TEXT,
        p_signer_user_id::TEXT,
        p_signed_at::TEXT
    );

    -- Generate SHA256 hash
    v_hash := encode(digest(v_hash_input, 'sha256'), 'hex');

    RETURN v_hash;
END;
$$;


