--
-- Name: get_admin_by_whatsapp_phone(text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_admin_by_whatsapp_phone(p_phone text) RETURNS TABLE(admin_user_id uuid, display_name text)
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
    v_phone_e164 TEXT;
BEGIN
    v_phone_e164 := public.normalize_phone_e164(p_phone);
    
    RETURN QUERY
    SELECT awi.admin_user_id, COALESCE(awi.display_name, u.full_name, u.email) as display_name
    FROM public.admin_whatsapp_identities awi
    LEFT JOIN public.users u ON u.id = awi.admin_user_id
    WHERE awi.phone_e164 = v_phone_e164
      AND awi.enabled = true
    LIMIT 1;
END;
$$;


ALTER FUNCTION public.get_admin_by_whatsapp_phone(p_phone text) OWNER TO supabase_admin;

--
-- Name: get_admin_support_unread_count(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_admin_support_unread_count() RETURNS integer
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    IF NOT public.is_support_admin() THEN
        RETURN 0;
    END IF;
    
    RETURN COALESCE((
        SELECT SUM(admin_unread_count)::INTEGER
        FROM public.support_conversations
        WHERE admin_deleted_at IS NULL
          AND status NOT IN ('closed', 'spam', 'resolved')
    ), 0);
END;
$$;


