-- Name: get_batch_variant_counts(uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_batch_variant_counts(p_batch_id uuid, p_status text DEFAULT 'received_warehouse'::text) RETURNS TABLE(variant_id uuid, count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    qc.variant_id,
    COUNT(*)::BIGINT as count
  FROM qr_codes qc
  WHERE qc.batch_id = p_batch_id
    AND qc.status = p_status
    AND qc.is_buffer = false
    AND qc.variant_id IS NOT NULL
  GROUP BY qc.variant_id;
END;
$$;


