CREATE FUNCTION public.get_currency_settings(p_company_id uuid DEFAULT NULL::uuid) RETURNS TABLE(base_currency_code text, base_currency_name text, base_currency_symbol text, decimal_places integer, thousand_separator text, decimal_separator text, symbol_position text)
    LANGUAGE sql STABLE
    AS $$
    SELECT 
        COALESCE(cs.base_currency_code, 'MYR'),
        COALESCE(cs.base_currency_name, 'Malaysian Ringgit'),
        COALESCE(cs.base_currency_symbol, 'RM'),
        COALESCE(cs.decimal_places, 2),
        COALESCE(cs.thousand_separator, ','),
        COALESCE(cs.decimal_separator, '.'),
        COALESCE(cs.symbol_position, 'before')
    FROM (SELECT 1) AS dummy
    LEFT JOIN public.accounting_currency_settings cs 
        ON cs.company_id = COALESCE(p_company_id, public.get_user_company_id());
$$;


