--
-- Name: get_department_hierarchy(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_department_hierarchy(p_organization_id uuid) RETURNS TABLE(id uuid, dept_code text, dept_name text, parent_department_id uuid, manager_user_id uuid, manager_name text, manager_email text, user_count bigint, chart_order integer, sort_order integer, is_active boolean, depth integer, path text[])
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  WITH RECURSIVE dept_tree AS (
    -- Base case: root departments (no parent)
    SELECT 
      d.id,
      d.dept_code,
      d.dept_name,
      d.parent_department_id,
      d.manager_user_id,
      u.full_name as manager_name,
      u.email as manager_email,
      d.chart_order,
      d.sort_order,
      d.is_active,
      0 as depth,
      ARRAY[d.dept_name]::text[] as path
    FROM departments d
    LEFT JOIN users u ON d.manager_user_id = u.id
    WHERE d.organization_id = p_organization_id
      AND d.parent_department_id IS NULL
    
    UNION ALL
    
    -- Recursive case: child departments
    SELECT 
      d.id,
      d.dept_code,
      d.dept_name,
      d.parent_department_id,
      d.manager_user_id,
      u.full_name as manager_name,
      u.email as manager_email,
      d.chart_order,
      d.sort_order,
      d.is_active,
      dt.depth + 1,
      dt.path || d.dept_name
    FROM departments d
    LEFT JOIN users u ON d.manager_user_id = u.id
    INNER JOIN dept_tree dt ON d.parent_department_id = dt.id
    WHERE d.organization_id = p_organization_id
  ),
  user_counts AS (
    SELECT department_id, COUNT(*) as cnt
    FROM users
    WHERE organization_id = p_organization_id
      AND is_active = true
      AND department_id IS NOT NULL
    GROUP BY department_id
  )
  SELECT 
    dt.id,
    dt.dept_code,
    dt.dept_name,
    dt.parent_department_id,
    dt.manager_user_id,
    dt.manager_name,
    dt.manager_email,
    COALESCE(uc.cnt, 0)::bigint as user_count,
    dt.chart_order,
    dt.sort_order,
    dt.is_active,
    dt.depth,
    dt.path
  FROM dept_tree dt
  LEFT JOIN user_counts uc ON dt.id = uc.department_id
  ORDER BY dt.path, dt.chart_order, dt.sort_order, dt.dept_name;
END;
$$;


ALTER FUNCTION public.get_department_hierarchy(p_organization_id uuid) OWNER TO supabase_admin;

