--

COMMENT ON FUNCTION public.get_department_hierarchy(p_organization_id uuid) IS 'Returns department hierarchy tree for org chart visualization';


--
-- Name: get_display_prefix_from_legacy(text, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_display_prefix_from_legacy(p_legacy_doc_no text, p_doc_type text DEFAULT NULL::text) RETURNS text
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
    v_prefix text;
BEGIN
    -- If doc_type is provided, use it directly
    IF p_doc_type IS NOT NULL THEN
        CASE UPPER(p_doc_type)
            WHEN 'PO' THEN RETURN 'PO';
            WHEN 'SO' THEN RETURN 'SO';
            WHEN 'DO' THEN RETURN 'DO';
            WHEN 'INVOICE' THEN RETURN 'SI';
            WHEN 'PAYMENT' THEN RETURN 'PV';
            WHEN 'RECEIPT' THEN RETURN 'RC';
            WHEN 'PAYMENT_REQUEST' THEN RETURN 'BR';
            WHEN 'CREDIT_NOTE' THEN RETURN 'CN';
            WHEN 'DEBIT_NOTE' THEN RETURN 'DN';
            WHEN 'GOODS_RECEIVED' THEN RETURN 'GR';
            WHEN 'DELIVERY_ORDER' THEN RETURN 'DO';
            WHEN 'QUOTATION' THEN RETURN 'QT';
            ELSE RETURN UPPER(p_doc_type);
        END CASE;
    END IF;
    
    -- Parse legacy format to determine prefix
    -- Legacy formats:
    -- Orders: ORD-HM-1225-01 (H2M/M2H orders), ORD-DH-1225-01 (D2H), ORD-SD-1225-01 (S2D)
    -- PO: PO-ORD-HM-1225-01
    -- Invoice: INV-HM-1225-01, INV-ORD-HM-1225-01
    -- Payment: PAY-HM-1225-01
    -- Receipt: RCT-HM-1225-01, RCPT-HM-1225-01
    -- Payment Request: REQ-HM-1225-01
    -- Goods Received: GR-ORD-HM-1225-01
    -- Delivery Order: DO-ORD-HM-1225-01, DO-ORD-DH-1225-01
    -- Credit Note: CN-ORD-HM-1225-01
    -- Debit Note: DN-ORD-HM-1225-01
    
    IF p_legacy_doc_no IS NULL THEN
        RETURN 'ORD';
    END IF;
    
    -- Check specific patterns for Sales Orders (ORD-DH-* for D2H, ORD-SD-* for S2D)
    -- These are D2H or S2D orders which should use SO prefix
    -- FIXED: Use alternation to match both ORD-DH- and ORD-SD- patterns
    IF p_legacy_doc_no ~* '^ORD-(DH|SD)-' THEN
        RETURN 'SO';
    END IF;
    
    -- Check for standard order patterns (ORD-HM-* or ORD-MH-*)
    -- These are H2M or M2H orders which should use ORD prefix
    IF p_legacy_doc_no ~* '^ORD-[HM][HM]-' THEN
        RETURN 'ORD';
    END IF;
    
    -- Check for PO pattern
    IF p_legacy_doc_no ~* '^PO-' THEN
        RETURN 'PO';
    END IF;
    
    -- Check for Invoice pattern
    IF p_legacy_doc_no ~* '^INV-' THEN
        RETURN 'SI';
    END IF;
    
    -- Check for Payment pattern
    IF p_legacy_doc_no ~* '^PAY-' THEN
        RETURN 'PV';
    END IF;
    
    -- Check for Receipt pattern (both RCT and RCPT)
    IF p_legacy_doc_no ~* '^RCT-' OR p_legacy_doc_no ~* '^RCPT-' THEN
        RETURN 'RC';
    END IF;
    
    -- Check for Payment Request pattern
    IF p_legacy_doc_no ~* '^REQ-' THEN
        RETURN 'BR';
    END IF;
    
    -- Check for Goods Received pattern
    IF p_legacy_doc_no ~* '^GR-' THEN
        RETURN 'GR';
    END IF;
    
    -- Check for Delivery Order pattern
    IF p_legacy_doc_no ~* '^DO-' THEN
        RETURN 'DO';
    END IF;
    
    -- Check for Credit Note pattern
    IF p_legacy_doc_no ~* '^CN-' THEN
        RETURN 'CN';
    END IF;
    
    -- Check for Debit Note pattern
    IF p_legacy_doc_no ~* '^DN-' THEN
        RETURN 'DN';
    END IF;
    
    -- Check for Quotation pattern
    IF p_legacy_doc_no ~* '^QT-' OR p_legacy_doc_no ~* '^QUOT-' THEN
        RETURN 'QT';
    END IF;
    
    -- Default to ORD for unknown patterns
    RETURN 'ORD';
END;
$$;


ALTER FUNCTION public.get_display_prefix_from_legacy(p_legacy_doc_no text, p_doc_type text) OWNER TO supabase_admin;

--
-- Name: FUNCTION get_display_prefix_from_legacy(p_legacy_doc_no text, p_doc_type text); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.get_display_prefix_from_legacy(p_legacy_doc_no text, p_doc_type text) IS 'Maps legacy document numbers to new display prefixes. ORD-DH-* and ORD-SD-* become SO, ORD-HM-* stays ORD.';


