--
-- Name: get_doc_migration_status(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_doc_migration_status(p_company_id uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_orders_total integer;
    v_orders_migrated integer;
    v_documents_total integer;
    v_documents_migrated integer;
    v_last_job RECORD;
BEGIN
    -- Get order counts
    SELECT 
        COUNT(*) FILTER (WHERE order_no IS NOT NULL),
        COUNT(*) FILTER (WHERE display_doc_no IS NOT NULL)
    INTO v_orders_total, v_orders_migrated
    FROM public.orders
    WHERE company_id = p_company_id;
    
    -- Get document counts
    SELECT 
        COUNT(*) FILTER (WHERE doc_no IS NOT NULL),
        COUNT(*) FILTER (WHERE display_doc_no IS NOT NULL)
    INTO v_documents_total, v_documents_migrated
    FROM public.documents
    WHERE company_id = p_company_id;
    
    -- Get last job status
    SELECT * INTO v_last_job
    FROM public.doc_migration_jobs
    WHERE company_id = p_company_id
    ORDER BY created_at DESC
    LIMIT 1;
    
    RETURN jsonb_build_object(
        'orders_total', v_orders_total,
        'orders_migrated', v_orders_migrated,
        'orders_pending', v_orders_total - v_orders_migrated,
        'documents_total', v_documents_total,
        'documents_migrated', v_documents_migrated,
        'documents_pending', v_documents_total - v_documents_migrated,
        'last_job', CASE WHEN v_last_job IS NOT NULL THEN
            jsonb_build_object(
                'id', v_last_job.id,
                'status', v_last_job.status,
                'started_at', v_last_job.started_at,
                'completed_at', v_last_job.completed_at,
                'records_processed', v_last_job.records_processed,
                'records_failed', v_last_job.records_failed,
                'error_message', v_last_job.error_message
            )
        ELSE NULL END
    );
END;
$$;


ALTER FUNCTION public.get_doc_migration_status(p_company_id uuid) OWNER TO supabase_admin;

--
-- Name: get_doc_sequences(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_doc_sequences(p_company_id uuid) RETURNS TABLE(doc_type text, year smallint, next_seq integer, last_used_at timestamp with time zone, example_legacy text, example_new text)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        ds.doc_type,
        ds.year,
        ds.next_seq,
        ds.last_used_at,
        CASE ds.doc_type
            WHEN 'ORD' THEN 'ORD-HM-' || LPAD((ds.year % 100)::text, 2, '0') || '01-01'
            WHEN 'SO' THEN 'ORD-DH-' || LPAD((ds.year % 100)::text, 2, '0') || '01-01'
            WHEN 'PO' THEN 'PO-ORD-HM-' || LPAD((ds.year % 100)::text, 2, '0') || '01-01'
            WHEN 'SI' THEN 'INV-HM-' || LPAD((ds.year % 100)::text, 2, '0') || '01-01'
            WHEN 'PV' THEN 'PAY-HM-' || LPAD((ds.year % 100)::text, 2, '0') || '01-01'
            WHEN 'RC' THEN 'RCT-HM-' || LPAD((ds.year % 100)::text, 2, '0') || '01-01'
            WHEN 'BR' THEN 'REQ-HM-' || LPAD((ds.year % 100)::text, 2, '0') || '01-01'
            WHEN 'GR' THEN 'GR-ORD-HM-' || LPAD((ds.year % 100)::text, 2, '0') || '01-01'
            WHEN 'DO' THEN 'DO-ORD-HM-' || LPAD((ds.year % 100)::text, 2, '0') || '01-01'
            WHEN 'CN' THEN 'CN-ORD-HM-' || LPAD((ds.year % 100)::text, 2, '0') || '01-01'
            WHEN 'DN' THEN 'DN-ORD-HM-' || LPAD((ds.year % 100)::text, 2, '0') || '01-01'
            ELSE ds.doc_type || '-XX-' || LPAD((ds.year % 100)::text, 2, '0') || '01-01'
        END as example_legacy,
        ds.doc_type || LPAD((ds.year % 100)::text, 2, '0') || LPAD(ds.next_seq::text, 6, '0') as example_new
    FROM public.doc_sequences ds
    WHERE ds.company_id = p_company_id
    ORDER BY ds.doc_type, ds.year DESC;
END;
$$;


ALTER FUNCTION public.get_doc_sequences(p_company_id uuid) OWNER TO supabase_admin;

