COMMENT ON FUNCTION public.get_doc_sequences(p_company_id uuid) IS 'Returns current document sequences for the UI display';


--
-- Name: get_document_gl_status(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_document_gl_status(p_document_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_company_id uuid;
    v_posting record;
    v_journal record;
BEGIN
    v_company_id := public.get_user_company_id();
    
    SELECT * INTO v_posting
    FROM public.gl_document_postings
    WHERE document_id = p_document_id
    AND company_id = v_company_id
    ORDER BY created_at DESC
    LIMIT 1;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'is_posted', false,
            'posting_status', NULL,
            'journal_id', NULL,
            'journal_number', NULL,
            'posted_amount', NULL,
            'posted_at', NULL
        );
    END IF;
    
    SELECT * INTO v_journal
    FROM public.gl_journals
    WHERE id = v_posting.journal_id;
    
    RETURN jsonb_build_object(
        'is_posted', v_posting.posting_status = 'POSTED',
        'posting_status', v_posting.posting_status,
        'journal_id', v_posting.journal_id,
        'journal_number', COALESCE(v_journal.journal_number, ''),
        'posted_amount', v_posting.posted_amount,
        'posted_at', v_posting.created_at,
        'posting_id', v_posting.id
    );
END;
$$;


ALTER FUNCTION public.get_document_gl_status(p_document_id uuid) OWNER TO supabase_admin;

