CREATE FUNCTION public.get_document_signatures(p_document_id uuid) RETURNS TABLE(id uuid, signer_user_id uuid, signer_name text, signer_role text, signed_at timestamp with time zone, signature_image_url text, signature_hash text)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        ds.id,
        ds.signer_user_id,
        u.full_name AS signer_name,
        ds.signer_role,
        ds.signed_at,
        ds.signature_image_url,
        ds.signature_hash
    FROM public.document_signatures ds
    JOIN public.users u ON u.id = ds.signer_user_id
    WHERE ds.document_id = p_document_id
    ORDER BY ds.signed_at ASC;
END;
$$;


