--
-- Name: get_email_by_phone(text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_email_by_phone(p_phone text) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_phone text;
  v_email text;
BEGIN
  v_phone := public.normalize_phone_e164(p_phone);
  IF v_phone IS NULL THEN
    RETURN NULL;
  END IF;

  SELECT email INTO v_email
  FROM auth.users
  WHERE public.normalize_phone_e164(phone) = v_phone
  LIMIT 1;

  RETURN v_email;
END;
$$;


