--
-- Name: get_email_count_today(uuid, character varying); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_email_count_today(p_org_id uuid, p_provider character varying DEFAULT 'gmail'::character varying) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_today_pst DATE;
  v_count INTEGER;
BEGIN
  -- "today" in LA time, same logic as generated column
  v_today_pst := (NOW() AT TIME ZONE 'America/Los_Angeles')::date;

  SELECT COUNT(*)
  INTO v_count
  FROM public.email_send_log
  WHERE org_id = p_org_id
    AND provider = p_provider
    AND sent_date_pst = v_today_pst
    AND status = 'sent';

  RETURN COALESCE(v_count, 0);
END;
$$;


