-- Name: FUNCTION get_email_count_today(p_org_id uuid, p_provider character varying); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.get_email_count_today(p_org_id uuid, p_provider character varying) IS 'Return how many emails were successfully sent today (LA day) for this org+provider. Used for Gmail 500/day limit.';


--
-- Name: get_email_stats(uuid, character varying, integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_email_stats(p_org_id uuid, p_provider character varying DEFAULT 'gmail'::character varying, p_days integer DEFAULT 7) RETURNS TABLE(send_date date, total_sent integer, total_failed integer, total_emails integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    sent_date_pst AS send_date,
    COUNT(*) FILTER (WHERE status = 'sent')::INTEGER   AS total_sent,
    COUNT(*) FILTER (WHERE status = 'failed')::INTEGER AS total_failed,
    COUNT(*)::INTEGER                                  AS total_emails
  FROM public.email_send_log
  WHERE org_id = p_org_id
    AND provider = p_provider
    AND sent_at >= NOW() - (p_days || ' days')::INTERVAL
  GROUP BY sent_date_pst
  ORDER BY send_date DESC;
END;
$$;


ALTER FUNCTION public.get_email_stats(p_org_id uuid, p_provider character varying, p_days integer) OWNER TO supabase_admin;

