-- Name: FUNCTION get_email_stats(p_org_id uuid, p_provider character varying, p_days integer); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.get_email_stats(p_org_id uuid, p_provider character varying, p_days integer) IS 'Return per-day send counts (sent/failed/total) for charting in UI.';


--
-- Name: get_hq_aggregated_product_count(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_hq_aggregated_product_count(p_hq_id uuid) RETURNS integer
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  v_total int := 0;
BEGIN
  WITH RECURSIVE tree AS (
    SELECT o.id, o.org_type_code
    FROM public.organizations o
    WHERE o.parent_org_id = p_hq_id
      AND o.is_active = TRUE
    UNION ALL
    SELECT c.id, c.org_type_code
    FROM public.organizations c
    JOIN tree t ON c.parent_org_id = t.id
    WHERE c.is_active = TRUE
  ),
  mfgs AS (
    SELECT id FROM tree WHERE org_type_code = 'MFG'
  )
  SELECT COALESCE(SUM(public.get_manufacturer_product_count(id)), 0)::int
  INTO v_total
  FROM mfgs;

  RETURN v_total;
END;
$$;


ALTER FUNCTION public.get_hq_aggregated_product_count(p_hq_id uuid) OWNER TO supabase_admin;

