--
-- Name: get_my_role_level(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_my_role_level() RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_level int;
BEGIN
  -- Direct lookup with no complex joins if possible to be fast
  -- We query users table directly. Since this is SECURITY DEFINER, it bypasses RLS.
  -- However, to be extra safe, we ensure we don't call this function FROM valid RLS unless needed.
  
  SELECT r.role_level INTO v_level
  FROM public.users u
  JOIN public.roles r ON r.role_code = u.role_code
  WHERE u.id = auth.uid();
  
  RETURN COALESCE(v_level, 999);
END;
$$;


ALTER FUNCTION public.get_my_role_level() OWNER TO supabase_admin;

--
-- Name: get_next_approver(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_next_approver(p_user_id uuid) RETURNS TABLE(approver_user_id uuid, approver_type text, approver_name text, approver_email text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_manager_user_id uuid;
    v_department_id uuid;
    v_dept_manager_id uuid;
    v_organization_id uuid;
    v_admin_user_id uuid;
BEGIN
    -- Get user's direct manager, department, and org
    SELECT 
        u.manager_user_id, 
        u.department_id, 
        u.organization_id
    INTO v_manager_user_id, v_department_id, v_organization_id
    FROM public.users u
    WHERE u.id = p_user_id;
    
    -- Priority 1: Direct manager (if set)
    IF v_manager_user_id IS NOT NULL THEN
        RETURN QUERY
        SELECT 
            u.id,
            'direct_manager'::text,
            u.full_name,
            u.email
        FROM public.users u
        WHERE u.id = v_manager_user_id
        AND u.is_active = true;
        
        IF FOUND THEN RETURN; END IF;
    END IF;
    
    -- Priority 2: Department manager (if user has department and dept has manager)
    IF v_department_id IS NOT NULL THEN
        SELECT d.manager_user_id INTO v_dept_manager_id
        FROM public.departments d
        WHERE d.id = v_department_id
        AND d.is_active = true;
        
        IF v_dept_manager_id IS NOT NULL AND v_dept_manager_id != p_user_id THEN
            RETURN QUERY
            SELECT 
                u.id,
                'department_manager'::text,
                u.full_name,
                u.email
            FROM public.users u
            WHERE u.id = v_dept_manager_id
            AND u.is_active = true;
            
            IF FOUND THEN RETURN; END IF;
        END IF;
    END IF;
    
    -- Priority 3: Fallback to any admin in the same organization (lowest role_level first)
    IF v_organization_id IS NOT NULL THEN
        RETURN QUERY
        SELECT 
            u.id,
            'org_admin_fallback'::text,
            u.full_name,
            u.email
        FROM public.users u
        JOIN public.roles r ON r.role_code = u.role_code
        WHERE u.organization_id = v_organization_id
        AND u.is_active = true
        AND r.role_level <= 20
        AND u.id != p_user_id
        ORDER BY r.role_level ASC, u.created_at ASC
        LIMIT 1;
        
        IF FOUND THEN RETURN; END IF;
    END IF;
    
    -- Priority 4: Any super admin as last resort
    RETURN QUERY
    SELECT 
        u.id,
        'super_admin_fallback'::text,
        u.full_name,
        u.email
    FROM public.users u
    JOIN public.roles r ON r.role_code = u.role_code
    WHERE u.is_active = true
    AND r.role_level = 1
    AND u.id != p_user_id
    ORDER BY u.created_at ASC
    LIMIT 1;
    
    RETURN;
END;
$$;


ALTER FUNCTION public.get_next_approver(p_user_id uuid) OWNER TO supabase_admin;

--
-- Name: FUNCTION get_next_approver(p_user_id uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.get_next_approver(p_user_id uuid) IS 'Resolves next approver in chain: direct manager -> department manager -> org admin -> super admin fallback';


--
-- Name: get_next_doc_sub_sequence(uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_next_doc_sub_sequence(p_order_id uuid, p_doc_type text) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_prefix text;
    v_next_seq integer;
BEGIN
    -- Normalize prefix
    v_prefix := UPPER(TRIM(p_doc_type));
    
    -- Map doc_type to display prefix if needed
    CASE v_prefix
        WHEN 'INVOICE' THEN v_prefix := 'SI';
        WHEN 'PAYMENT' THEN v_prefix := 'PV';
        WHEN 'RECEIPT' THEN v_prefix := 'RC';
        WHEN 'PAYMENT_REQUEST' THEN v_prefix := 'BR';
        ELSE v_prefix := v_prefix;
    END CASE;
    
    -- Get current next_sub_seq without incrementing
    SELECT next_sub_seq INTO v_next_seq
    FROM public.order_doc_sequences
    WHERE order_id = p_order_id AND doc_type = v_prefix;
    
    RETURN COALESCE(v_next_seq, 1);
END;
$$;


ALTER FUNCTION public.get_next_doc_sub_sequence(p_order_id uuid, p_doc_type text) OWNER TO supabase_admin;

--
-- Name: FUNCTION get_next_doc_sub_sequence(p_order_id uuid, p_doc_type text); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.get_next_doc_sub_sequence(p_order_id uuid, p_doc_type text) IS 'Returns the next sub-sequence number for a document type within an order (without incrementing)';


--
-- Name: get_notification_stats(uuid, integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_notification_stats(p_org_id uuid, p_days integer DEFAULT 30) RETURNS TABLE(total_sent bigint, total_failed bigint, total_pending bigint, success_rate numeric, by_channel jsonb, by_event jsonb, recent_failures jsonb)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  WITH stats AS (
    SELECT
      COUNT(*) FILTER (WHERE status = 'sent') as sent_count,
      COUNT(*) FILTER (WHERE status = 'failed' AND retry_count >= max_retries) as failed_count,
      COUNT(*) FILTER (WHERE status IN ('queued', 'scheduled', 'processing')) as pending_count,
      jsonb_object_agg(
        channel,
        jsonb_build_object(
          'sent', COUNT(*) FILTER (WHERE status = 'sent'),
          'failed', COUNT(*) FILTER (WHERE status = 'failed')
        )
      ) FILTER (WHERE channel IS NOT NULL) as channel_stats,
      jsonb_object_agg(
        event_code,
        jsonb_build_object(
          'sent', COUNT(*) FILTER (WHERE status = 'sent'),
          'failed', COUNT(*) FILTER (WHERE status = 'failed')
        )
      ) FILTER (WHERE event_code IS NOT NULL) as event_stats
    FROM public.notifications_outbox
    WHERE org_id = p_org_id
      AND created_at >= NOW() - (p_days || ' days')::INTERVAL
  ),
  failures AS (
    SELECT jsonb_agg(
      jsonb_build_object(
        'id', id,
        'event_code', event_code,
        'channel', channel,
        'error', error,
        'created_at', created_at
      ) ORDER BY created_at DESC
    ) as failure_list
    FROM public.notifications_outbox
    WHERE org_id = p_org_id
      AND status = 'failed'
      AND created_at >= NOW() - INTERVAL '7 days'
    LIMIT 10
  )
  SELECT
    s.sent_count::BIGINT,
    s.failed_count::BIGINT,
    s.pending_count::BIGINT,
    CASE 
      WHEN (s.sent_count + s.failed_count) > 0 
      THEN ROUND((s.sent_count::NUMERIC / (s.sent_count + s.failed_count)::NUMERIC) * 100, 2)
      ELSE 0
    END as success_rate,
    COALESCE(s.channel_stats, '{}'::jsonb),
    COALESCE(s.event_stats, '{}'::jsonb),
    COALESCE(f.failure_list, '[]'::jsonb)
  FROM stats s
  CROSS JOIN failures f;
END;
$$;


ALTER FUNCTION public.get_notification_stats(p_org_id uuid, p_days integer) OWNER TO supabase_admin;

--
-- Name: FUNCTION get_notification_stats(p_org_id uuid, p_days integer); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.get_notification_stats(p_org_id uuid, p_days integer) IS 'Returns comprehensive notification statistics for an organization';


--
-- Name: get_or_create_announcement_thread(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_or_create_announcement_thread(p_user_id uuid) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
declare
  v_thread_id uuid;
begin
  select id
    into v_thread_id
  from public.support_threads
  where created_by_user_id = p_user_id
    and subject = 'Announcements'
  limit 1;

  if v_thread_id is null then
    insert into public.support_threads (
      created_by_user_id,
      subject,
      status,
      priority
    )
    values (
      p_user_id,
      'Announcements',
      'open',
      'normal'
    )
    returning id into v_thread_id;
  end if;

  return v_thread_id;
end;
$$;


ALTER FUNCTION public.get_or_create_announcement_thread(p_user_id uuid) OWNER TO supabase_admin;

