--
-- Name: get_payment_posting_details(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_payment_posting_details(p_payment_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_payment record;
    v_order record;
    v_company_id uuid;
    v_payment_amount numeric(18,2);
    v_order_total numeric(18,2);
    v_deposit_pct numeric;
    v_balance_pct numeric;
    v_is_deposit boolean := false;
    v_is_balance boolean := false;
    v_gl_doc_type text;
    v_supplier_org_id uuid;
    v_supplier_name text;
    v_description text;
BEGIN
    v_company_id := public.get_user_company_id();
    
    -- Get payment document
    SELECT * INTO v_payment
    FROM public.documents d
    WHERE d.id = p_payment_id 
    AND d.doc_type = 'PAYMENT'
    AND d.company_id = v_company_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'PAYMENT document not found or not in your company'
        );
    END IF;
    
    -- Get the linked order
    SELECT * INTO v_order
    FROM public.orders o
    WHERE o.id = v_payment.order_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Order not found for this payment'
        );
    END IF;
    
    -- Calculate order total
    SELECT COALESCE(SUM(line_total), 0) INTO v_order_total
    FROM public.order_items
    WHERE order_id = v_order.id;
    
    IF v_order_total <= 0 THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Order has zero total'
        );
    END IF;
    
    -- Get payment terms from order
    v_deposit_pct := COALESCE((v_order.payment_terms->>'deposit_pct')::numeric, 0.3);
    v_balance_pct := COALESCE((v_order.payment_terms->>'balance_pct')::numeric, 0.7);
    
    -- Determine if this is deposit or balance payment based on doc_no suffix
    -- Deposit: PAY-xxx (no suffix or first payment)
    -- Balance: PAY-xxx-BAL (created from PAYMENT_REQUEST approval)
    IF v_payment.doc_no LIKE '%-BAL%' THEN
        v_is_balance := true;
        v_is_deposit := false;
        v_payment_amount := ROUND(v_order_total * v_balance_pct, 2);
        v_gl_doc_type := 'SUPPLIER_BALANCE_PAYMENT';
    ELSE
        -- Check if there's a source_request_id in payload (balance from PAYMENT_REQUEST)
        IF v_payment.payload ? 'source_request_id' THEN
            v_is_balance := true;
            v_is_deposit := false;
            v_payment_amount := COALESCE((v_payment.payload->>'amount')::numeric, ROUND(v_order_total * v_balance_pct, 2));
            v_gl_doc_type := 'SUPPLIER_BALANCE_PAYMENT';
        ELSE
            v_is_deposit := true;
            v_is_balance := false;
            v_payment_amount := ROUND(v_order_total * v_deposit_pct, 2);
            v_gl_doc_type := 'SUPPLIER_DEPOSIT_PAYMENT';
        END IF;
    END IF;
    
    -- Get supplier (seller_org_id from order)
    v_supplier_org_id := v_order.seller_org_id;
    
    SELECT org_name INTO v_supplier_name
    FROM public.organizations
    WHERE id = v_supplier_org_id;
    
    -- Build description
    v_description := CASE 
        WHEN v_is_deposit THEN 'Supplier Deposit Payment (' || ROUND(v_deposit_pct * 100) || '%): ' || v_payment.doc_no
        WHEN v_is_balance THEN 'Supplier Balance Payment (' || ROUND(v_balance_pct * 100) || '%): ' || v_payment.doc_no
        ELSE 'Supplier Payment: ' || v_payment.doc_no
    END;
    
    RETURN jsonb_build_object(
        'success', true,
        'payment_id', p_payment_id,
        'payment_doc_no', v_payment.doc_no,
        'order_id', v_payment.order_id,
        'order_no', v_order.order_no,
        'company_id', v_payment.company_id,
        'gl_doc_type', v_gl_doc_type,
        'payment_amount', v_payment_amount,
        'order_total', v_order_total,
        'deposit_pct', v_deposit_pct,
        'balance_pct', v_balance_pct,
        'is_deposit', v_is_deposit,
        'is_balance', v_is_balance,
        'supplier_org_id', v_supplier_org_id,
        'supplier_name', v_supplier_name,
        'description', v_description
    );
END;
$$;


