-- Name: get_payroll_ready_work_minutes(uuid, date, date); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_payroll_ready_work_minutes(p_org_id uuid, p_period_start date, p_period_end date) RETURNS TABLE(employee_id uuid, total_work_minutes integer, total_overtime_minutes integer, timesheet_ids uuid[])
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        t.user_id AS employee_id,
        COALESCE(SUM(t.total_minutes), 0)::integer AS total_work_minutes,
        COALESCE(SUM(t.overtime_minutes), 0)::integer AS total_overtime_minutes,
        ARRAY_AGG(t.id) AS timesheet_ids
    FROM public.hr_timesheets t
    WHERE t.organization_id = p_org_id
      AND t.status = 'approved'
      AND t.period_start >= p_period_start
      AND t.period_end <= p_period_end
    GROUP BY t.user_id;
END;
$$;


