-- Name: FUNCTION get_pending_notifications(p_limit integer); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.get_pending_notifications(p_limit integer) IS 'Gets pending notifications ready for delivery with priority ordering and locking';


--
-- Name: get_pending_receives_for_warehouse(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_pending_receives_for_warehouse(p_warehouse_org_id uuid) RETURNS TABLE(master_id uuid, master_code text, case_number integer, actual_unit_count integer, expected_unit_count integer, status text, manufacturer_scanned_at timestamp with time zone, warehouse_org_id uuid, manufacturer_org_id uuid, batch_id uuid, company_id uuid, order_id uuid, order_no text, buyer_org_id uuid, buyer_org_name text, seller_org_id uuid)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        mc.id as master_id,
        mc.master_code,
        mc.case_number,
        mc.actual_unit_count,
        mc.expected_unit_count,
        mc.status,
        mc.manufacturer_scanned_at,
        mc.warehouse_org_id,
        mc.manufacturer_org_id,
        qb.id as batch_id,
        qb.company_id,
        qb.order_id,
        COALESCE(o.display_doc_no, o.order_no) as order_no,  -- Prefer display_doc_no
        o.buyer_org_id,
        buyer.org_name as buyer_org_name,
        o.seller_org_id
    FROM qr_master_codes mc
    INNER JOIN qr_batches qb ON qb.id = mc.batch_id
    LEFT JOIN orders o ON o.id = qb.order_id
    LEFT JOIN organizations buyer ON buyer.id = o.buyer_org_id
    WHERE mc.status = 'ready_to_ship'
      AND mc.warehouse_received_at IS NULL
      AND (mc.warehouse_org_id = p_warehouse_org_id OR mc.warehouse_org_id IS NULL)
    ORDER BY mc.manufacturer_scanned_at DESC;
END;
$$;


