--
-- Name: get_posting_preview(text, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_posting_preview(p_document_type text, p_document_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_company_id uuid;
    v_settings record;
    v_lines jsonb := '[]'::jsonb;
    v_total numeric(18,2);
    v_description text;
    v_entity_id uuid;
    v_entity_name text;
    -- Account info
    v_cash_account record;
    v_ap_account record;
    v_ar_account record;
    v_sales_account record;
    v_deposit_account record;
    v_cogs_account record;
    -- Details
    v_payment_details jsonb;
    v_request_details jsonb;
    v_deposit_amount numeric(18,2);
    v_balance_amount numeric(18,2);
    v_order_total numeric(18,2);
BEGIN
    v_company_id := public.get_user_company_id();
    
    -- Get GL settings
    SELECT * INTO v_settings FROM public.gl_settings WHERE company_id = v_company_id;
    
    IF v_settings IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'GL Settings not configured for this company'
        );
    END IF;
    
    -- Pre-fetch all account info
    SELECT id, name, code INTO v_cash_account FROM public.gl_accounts WHERE id = v_settings.cash_account_id;
    SELECT id, name, code INTO v_ap_account FROM public.gl_accounts WHERE id = v_settings.ap_control_account_id;
    SELECT id, name, code INTO v_ar_account FROM public.gl_accounts WHERE id = v_settings.ar_control_account_id;
    SELECT id, name, code INTO v_sales_account FROM public.gl_accounts WHERE id = v_settings.sales_revenue_account_id;
    SELECT id, name, code INTO v_deposit_account FROM public.gl_accounts WHERE id = v_settings.supplier_deposit_account_id;
    SELECT id, name, code INTO v_cogs_account FROM public.gl_accounts WHERE id = v_settings.cogs_account_id;
    
    -- Build preview based on document type
    CASE p_document_type
    
        -- ======================
        -- SUPPLIER_DEPOSIT_PAYMENT (Step 4: HQ pays 30% deposit)
        -- DR Supplier Deposits (Asset), CR Cash/Bank
        -- ======================
        WHEN 'SUPPLIER_DEPOSIT_PAYMENT' THEN
            v_payment_details := public.get_payment_posting_details(p_document_id);
            
            IF NOT (v_payment_details->>'success')::boolean THEN
                RETURN v_payment_details;
            END IF;
            
            IF NOT (v_payment_details->>'is_deposit')::boolean THEN
                RETURN jsonb_build_object(
                    'success', false,
                    'error', 'This is not a deposit payment. Use SUPPLIER_BALANCE_PAYMENT for balance payments.'
                );
            END IF;
            
            v_total := (v_payment_details->>'payment_amount')::numeric;
            v_description := v_payment_details->>'description';
            v_entity_id := (v_payment_details->>'supplier_org_id')::uuid;
            v_entity_name := v_payment_details->>'supplier_name';
            
            IF v_deposit_account.id IS NULL THEN
                RETURN jsonb_build_object('success', false, 'error', 'Supplier Deposits account not configured');
            END IF;
            
            v_lines := jsonb_build_array(
                jsonb_build_object(
                    'account_id', v_deposit_account.id,
                    'account_name', v_deposit_account.name,
                    'account_code', v_deposit_account.code,
                    'debit', v_total,
                    'credit', 0,
                    'entity_type', 'SUPPLIER',
                    'entity_id', v_entity_id,
                    'entity_name', v_entity_name
                ),
                jsonb_build_object(
                    'account_id', v_cash_account.id,
                    'account_name', v_cash_account.name,
                    'account_code', v_cash_account.code,
                    'debit', 0,
                    'credit', v_total,
                    'entity_type', NULL,
                    'entity_id', NULL,
                    'entity_name', NULL
                )
            );
            
        -- ======================
        -- SUPPLIER_INVOICE_RECOGNITION (Step 6: Balance Request - recognize full cost)
        -- DR Purchases/COGS = 100%
        -- CR Supplier Deposits = 30% (apply deposit)
        -- CR Accounts Payable = 70% (remaining liability)
        -- ======================
        WHEN 'SUPPLIER_INVOICE_RECOGNITION' THEN
            v_request_details := public.get_balance_request_posting_details(p_document_id);
            
            IF NOT (v_request_details->>'success')::boolean THEN
                RETURN v_request_details;
            END IF;
            
            v_order_total := (v_request_details->>'order_total')::numeric;
            v_deposit_amount := (v_request_details->>'deposit_amount')::numeric;
            v_balance_amount := (v_request_details->>'balance_amount')::numeric;
            v_description := v_request_details->>'description';
            v_entity_id := (v_request_details->>'supplier_org_id')::uuid;
            v_entity_name := v_request_details->>'supplier_name';
            
            IF v_cogs_account.id IS NULL THEN
                RETURN jsonb_build_object('success', false, 'error', 'COGS/Purchases account not configured. Please set it in Default Accounts.');
            END IF;
            
            IF v_deposit_account.id IS NULL THEN
                RETURN jsonb_build_object('success', false, 'error', 'Supplier Deposits account not configured');
            END IF;
            
            IF v_ap_account.id IS NULL THEN
                RETURN jsonb_build_object('success', false, 'error', 'Accounts Payable account not configured');
            END IF;
            
            v_total := v_order_total;
            
            v_lines := jsonb_build_array(
                -- DR Purchases/COGS = 100%
                jsonb_build_object(
                    'account_id', v_cogs_account.id,
                    'account_name', v_cogs_account.name,
                    'account_code', v_cogs_account.code,
                    'debit', v_order_total,
                    'credit', 0,
                    'entity_type', 'SUPPLIER',
                    'entity_id', v_entity_id,
                    'entity_name', v_entity_name
                ),
                -- CR Supplier Deposits = 30% (apply deposit)
                jsonb_build_object(
                    'account_id', v_deposit_account.id,
                    'account_name', v_deposit_account.name,
                    'account_code', v_deposit_account.code,
                    'debit', 0,
                    'credit', v_deposit_amount,
                    'entity_type', 'SUPPLIER',
                    'entity_id', v_entity_id,
                    'entity_name', v_entity_name
                ),
                -- CR Accounts Payable = 70% (remaining)
                jsonb_build_object(
                    'account_id', v_ap_account.id,
                    'account_name', v_ap_account.name,
                    'account_code', v_ap_account.code,
                    'debit', 0,
                    'credit', v_balance_amount,
                    'entity_type', 'SUPPLIER',
                    'entity_id', v_entity_id,
                    'entity_name', v_entity_name
                )
            );
            
        -- ======================
        -- SUPPLIER_BALANCE_PAYMENT (Step 7: HQ pays 70% balance)
        -- DR Accounts Payable, CR Cash/Bank
        -- ======================
        WHEN 'SUPPLIER_BALANCE_PAYMENT' THEN
            v_payment_details := public.get_payment_posting_details(p_document_id);
            
            IF NOT (v_payment_details->>'success')::boolean THEN
                RETURN v_payment_details;
            END IF;
            
            IF NOT (v_payment_details->>'is_balance')::boolean THEN
                RETURN jsonb_build_object(
                    'success', false,
                    'error', 'This is not a balance payment. Use SUPPLIER_DEPOSIT_PAYMENT for deposit payments.'
                );
            END IF;
            
            v_total := (v_payment_details->>'payment_amount')::numeric;
            v_description := v_payment_details->>'description';
            v_entity_id := (v_payment_details->>'supplier_org_id')::uuid;
            v_entity_name := v_payment_details->>'supplier_name';
            
            IF v_ap_account.id IS NULL THEN
                RETURN jsonb_build_object('success', false, 'error', 'Accounts Payable account not configured');
            END IF;
            
            v_lines := jsonb_build_array(
                jsonb_build_object(
                    'account_id', v_ap_account.id,
                    'account_name', v_ap_account.name,
                    'account_code', v_ap_account.code,
                    'debit', v_total,
                    'credit', 0,
                    'entity_type', 'SUPPLIER',
                    'entity_id', v_entity_id,
                    'entity_name', v_entity_name
                ),
                jsonb_build_object(
                    'account_id', v_cash_account.id,
                    'account_name', v_cash_account.name,
                    'account_code', v_cash_account.code,
                    'debit', 0,
                    'credit', v_total,
                    'entity_type', NULL,
                    'entity_id', NULL,
                    'entity_name', NULL
                )
            );
            
        -- ======================
        -- SALES_INVOICE (AR - for completeness)
        -- ======================
        WHEN 'SALES_INVOICE' THEN
            SELECT 
                COALESCE(
                    (SELECT SUM(oi.line_total) FROM public.order_items oi WHERE oi.order_id = o.id),
                    0
                ),
                'Sales Invoice: ' || o.order_no,
                o.buyer_org_id,
                org.org_name
            INTO v_total, v_description, v_entity_id, v_entity_name
            FROM public.orders o
            LEFT JOIN public.organizations org ON org.id = o.buyer_org_id
            WHERE o.id = p_document_id AND o.company_id = v_company_id;
            
            IF v_total IS NULL OR v_total = 0 THEN
                RETURN jsonb_build_object('success', false, 'error', 'Invoice not found or has zero total');
            END IF;
            
            v_lines := jsonb_build_array(
                jsonb_build_object(
                    'account_id', v_ar_account.id,
                    'account_name', v_ar_account.name,
                    'account_code', v_ar_account.code,
                    'debit', v_total,
                    'credit', 0,
                    'entity_type', 'CUSTOMER',
                    'entity_id', v_entity_id,
                    'entity_name', v_entity_name
                ),
                jsonb_build_object(
                    'account_id', v_sales_account.id,
                    'account_name', v_sales_account.name,
                    'account_code', v_sales_account.code,
                    'debit', 0,
                    'credit', v_total,
                    'entity_type', NULL,
                    'entity_id', NULL,
                    'entity_name', NULL
                )
            );
            
        ELSE
            RETURN jsonb_build_object('success', false, 'error', 'Unknown document type: ' || p_document_type || '. Supported: SUPPLIER_DEPOSIT_PAYMENT, SUPPLIER_INVOICE_RECOGNITION, SUPPLIER_BALANCE_PAYMENT, SALES_INVOICE');
    END CASE;
    
    RETURN jsonb_build_object(
        'success', true,
        'document_type', p_document_type,
        'document_id', p_document_id,
        'description', v_description,
        'total_amount', v_total,
        'lines', v_lines,
        'is_balanced', true
    );
END;
$$;


