--
-- Name: get_receipt_posting_details(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_receipt_posting_details(p_receipt_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_receipt record;
    v_order record;
    v_company_id uuid;
    v_receipt_amount numeric(18,2);
    v_customer_org_id uuid;
    v_customer_name text;
    v_description text;
    v_payload jsonb;
BEGIN
    v_company_id := public.get_user_company_id();
    
    -- Get receipt document
    SELECT * INTO v_receipt
    FROM public.documents d
    WHERE d.id = p_receipt_id 
    AND d.doc_type = 'RECEIPT'
    AND d.company_id = v_company_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'RECEIPT document not found'
        );
    END IF;
    
    SELECT * INTO v_order
    FROM public.orders o
    WHERE o.id = v_receipt.order_id;
    
    v_payload := COALESCE(v_receipt.payload, '{}'::jsonb);
    
    -- First check payload.amount (used by DHReceiptDialog for customer receipts)
    IF v_payload ? 'amount' AND (v_payload->>'amount')::numeric > 0 THEN
        v_receipt_amount := (v_payload->>'amount')::numeric;
    -- Calculate from order with percentage as fallback
    ELSE
        SELECT COALESCE(SUM(line_total), 0) INTO v_receipt_amount
        FROM public.order_items
        WHERE order_id = v_order.id;
        
        IF v_receipt.payment_percentage IS NOT NULL THEN
            v_receipt_amount := ROUND(v_receipt_amount * (v_receipt.payment_percentage::numeric / 100.0), 2);
        END IF;
    END IF;
    
    v_customer_org_id := v_order.buyer_org_id;
    
    -- Build description based on receipt type
    IF v_payload->>'receipt_type' = 'customer_receipt' THEN
        v_description := 'Customer Payment Receipt: ' || v_receipt.doc_no;
    ELSE
        v_description := 'Receipt: ' || v_receipt.doc_no;
    END IF;

    SELECT org_name INTO v_customer_name
    FROM public.organizations
    WHERE id = v_customer_org_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'receipt_amount', v_receipt_amount,
        'customer_org_id', v_customer_org_id,
        'customer_name', v_customer_name,
        'description', v_description,
        'payment_method', COALESCE(v_payload->>'payment_method', 'Bank'),
        'is_partial', COALESCE((v_payload->>'is_partial')::boolean, false)
    );
END;
$$;


ALTER FUNCTION public.get_receipt_posting_details(p_receipt_id uuid) OWNER TO supabase_admin;

