-- Name: get_reference_assigned_shops(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_reference_assigned_shops(p_reference_user_id uuid) RETURNS TABLE(assignment_id uuid, shop_user_id uuid, effective_from timestamp with time zone, shop_name text, shop_phone text)
    LANGUAGE sql STABLE SECURITY DEFINER
    AS $$
  SELECT
    ra.id AS assignment_id,
    ra.shop_user_id,
    ra.effective_from,
    COALESCE(su.full_name, 'Unknown') AS shop_name,
    COALESCE(su.phone, '') AS shop_phone
  FROM public.reference_assignments ra
  LEFT JOIN public.users su ON su.id = ra.shop_user_id
  WHERE ra.reference_user_id = p_reference_user_id
    AND ra.effective_to IS NULL
  ORDER BY ra.effective_from DESC;
$$;


