-- Name: get_statutory_config(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_statutory_config(p_org_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_config jsonb;
BEGIN
    SELECT config->'statutory' INTO v_config
    FROM public.hr_settings
    WHERE organization_id = p_org_id;

    IF v_config IS NULL THEN
        v_config := '{
            "epf": {"employee_rate": 0.11, "employer_rate": 0.13, "category": "A"},
            "socso": {"employee_rate": 0.005, "employer_rate": 0.0175, "max_salary": 5000},
            "eis": {"employee_rate": 0.002, "employer_rate": 0.002, "max_salary": 5000},
            "pcb": {"enabled": false}
        }'::jsonb;
    END IF;

    RETURN v_config;
END;
$$;


