--
-- Name: get_user_org_chart(uuid, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_user_org_chart(p_organization_id uuid, p_department_id uuid DEFAULT NULL::uuid) RETURNS TABLE(id uuid, full_name text, email text, role_code text, role_name text, role_level integer, department_id uuid, department_name text, department_code text, manager_user_id uuid, manager_name text, is_active boolean, depth integer, path uuid[])
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  WITH RECURSIVE user_tree AS (
    -- Base case: users with no manager (root nodes)
    SELECT 
      u.id,
      u.full_name,
      u.email,
      u.role_code,
      r.role_name,
      r.role_level,
      u.department_id,
      d.dept_name as department_name,
      d.dept_code as department_code,
      u.manager_user_id,
      NULL::text as manager_name,
      u.is_active,
      0 as depth,
      ARRAY[u.id]::uuid[] as path
    FROM users u
    LEFT JOIN roles r ON u.role_code = r.role_code
    LEFT JOIN departments d ON u.department_id = d.id
    WHERE u.organization_id = p_organization_id
      AND u.manager_user_id IS NULL
      AND (p_department_id IS NULL OR u.department_id = p_department_id)
    
    UNION ALL
    
    -- Recursive case: users with managers
    SELECT 
      u.id,
      u.full_name,
      u.email,
      u.role_code,
      r.role_name,
      r.role_level,
      u.department_id,
      d.dept_name as department_name,
      d.dept_code as department_code,
      u.manager_user_id,
      ut.full_name as manager_name,
      u.is_active,
      ut.depth + 1,
      ut.path || u.id
    FROM users u
    LEFT JOIN roles r ON u.role_code = r.role_code
    LEFT JOIN departments d ON u.department_id = d.id
    INNER JOIN user_tree ut ON u.manager_user_id = ut.id
    WHERE u.organization_id = p_organization_id
      AND (p_department_id IS NULL OR u.department_id = p_department_id)
  )
  SELECT * FROM user_tree
  ORDER BY path;
END;
$$;


ALTER FUNCTION public.get_user_org_chart(p_organization_id uuid, p_department_id uuid) OWNER TO supabase_admin;

