--
-- Name: get_valid_batch_ids_for_journey(uuid[], text[]); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_valid_batch_ids_for_journey(p_batch_ids uuid[], p_valid_statuses text[]) RETURNS TABLE(batch_id uuid)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT DISTINCT m.batch_id
    FROM qr_master_codes m
    WHERE m.batch_id = ANY(p_batch_ids)
    AND m.status = ANY(p_valid_statuses);
END;
$$;


