-- Name: get_variants_by_master_code(text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.get_variants_by_master_code(p_master_code text) RETURNS TABLE(variant_id uuid, variant_code text, variant_name text)
    LANGUAGE sql STABLE
    AS $$
  SELECT DISTINCT pv.id, pv.variant_code, pv.variant_name
  FROM public.qr_master_codes m
  JOIN public.qr_codes qc         ON qc.master_code_id = m.id
  JOIN public.product_variants pv ON pv.id = qc.variant_id
  WHERE m.master_code = p_master_code;
$$;


