--
-- Name: handle_new_user(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.handle_new_user() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- Extract phone from user_metadata if available
    -- New users default to GUEST role
    INSERT INTO public.users (
        id, 
        email, 
        full_name,
        phone,
        role_code, 
        created_at
    )
    VALUES (
        NEW.id, 
        NEW.email, 
        COALESCE(NEW.raw_user_meta_data->>'full_name', ''),
        COALESCE(NEW.phone, NEW.raw_user_meta_data->>'phone', ''),
        'GUEST', 
        now()
    )
    ON CONFLICT (id) DO UPDATE SET
        phone = COALESCE(EXCLUDED.phone, users.phone),
        full_name = COALESCE(EXCLUDED.full_name, users.full_name);
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.handle_new_user() OWNER TO supabase_admin;

--
-- Name: FUNCTION handle_new_user(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.handle_new_user() IS 'Automatically creates a user record in public.users when a new auth user signs up. Extracts phone and full_name from user_metadata.';


--
-- Name: handle_order_cancellation(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.handle_order_cancellation() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Check if status changed to cancelled
    -- Cast to text to avoid enum errors if 'cancelled' is not yet in the enum
    IF NEW.status::text = 'cancelled' AND OLD.status::text != 'cancelled' THEN
        PERFORM public.release_allocation_for_order(NEW.id);
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.handle_order_cancellation() OWNER TO supabase_admin;

--
-- Name: handle_order_status_change(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.handle_order_status_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.status = 'cancelled' AND OLD.status != 'cancelled' THEN
        -- D2H and S2D: Release allocation only if order was NOT yet fulfilled
        -- If order was 'submitted', allocation exists and needs to be released
        -- If order was 'approved', allocation was already released during fulfillment
        IF NEW.order_type IN ('D2H', 'S2D') AND OLD.status = 'submitted' THEN
             PERFORM public.release_allocation_for_order(NEW.id);
        END IF;
    END IF;

    IF NEW.status = 'shipped_distributor' AND OLD.status != 'shipped_distributor' THEN
        IF NEW.order_type IN ('D2H', 'S2D') THEN
             NULL; 
        END IF;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.handle_order_status_change() OWNER TO supabase_admin;

--
-- Name: FUNCTION handle_order_status_change(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.handle_order_status_change() IS 'Handles order status changes: releases allocation on cancel for D2H/S2D orders ONLY if not yet fulfilled (submitted status).';


--
-- Name: handle_social_login(uuid, text, text, text, text, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.handle_social_login(p_auth_id uuid, p_email text, p_full_name text DEFAULT NULL::text, p_avatar_url text DEFAULT NULL::text, p_provider text DEFAULT 'email'::text, p_phone text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_org_id uuid;
  v_existing_user record;
  v_result jsonb;
BEGIN
  SELECT u.*, o.org_type_code
  INTO v_existing_user
  FROM public.users u
  LEFT JOIN public.organizations o ON o.id = u.organization_id
  WHERE u.id = p_auth_id;

  IF v_existing_user.id IS NOT NULL THEN
    UPDATE public.users SET
      auth_provider = COALESCE(p_provider, auth_provider),
      avatar_url = COALESCE(p_avatar_url, avatar_url),
      full_name = COALESCE(NULLIF(p_full_name, ''), full_name),
      last_login_at = now(),
      updated_at = now()
    WHERE id = p_auth_id;

    v_result := jsonb_build_object(
      'user_id', v_existing_user.id,
      'is_new', false,
      'org_type', v_existing_user.org_type_code,
      'needs_phone', (v_existing_user.phone IS NULL OR v_existing_user.phone = '')
    );
    RETURN v_result;
  END IF;

  SELECT id INTO v_org_id FROM public.organizations WHERE org_type_code = 'END_USER' LIMIT 1;

  INSERT INTO public.users (
    id, email, full_name, phone, organization_id, role_code,
    is_active, auth_provider, avatar_url,
    created_at, updated_at, last_login_at
  ) VALUES (
    p_auth_id,
    p_email,
    COALESCE(p_full_name, split_part(p_email, '@', 1)),
    p_phone,
    v_org_id,
    'GUEST',
    true,
    p_provider,
    p_avatar_url,
    now(), now(), now()
  );

  v_result := jsonb_build_object(
    'user_id', p_auth_id,
    'is_new', true,
    'org_type', 'END_USER',
    'needs_phone', (p_phone IS NULL OR p_phone = '')
  );
  RETURN v_result;

EXCEPTION WHEN unique_violation THEN
  SELECT u.*, o.org_type_code
  INTO v_existing_user
  FROM public.users u
  LEFT JOIN public.organizations o ON o.id = u.organization_id
  WHERE u.id = p_auth_id;

  v_result := jsonb_build_object(
    'user_id', v_existing_user.id,
    'is_new', false,
    'org_type', COALESCE(v_existing_user.org_type_code, 'END_USER'),
    'needs_phone', (v_existing_user.phone IS NULL OR v_existing_user.phone = '')
  );
  RETURN v_result;
END;
$$;


ALTER FUNCTION public.handle_social_login(p_auth_id uuid, p_email text, p_full_name text, p_avatar_url text, p_provider text, p_phone text) OWNER TO supabase_admin;

--
-- Name: hard_delete_order(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.hard_delete_order(p_order_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    SET statement_timeout TO '300s'
    AS $$
DECLARE
    v_order_no TEXT;
    v_display_doc_no TEXT;
    v_company_id UUID;
    v_order_type TEXT;
    v_order_status TEXT;
    v_qr_codes_deleted INTEGER := 0;
    v_qr_batches_deleted INTEGER := 0;
    v_qr_master_codes_deleted INTEGER := 0;
    v_documents_deleted INTEGER := 0;
    v_order_items_deleted INTEGER := 0;
    v_stock_movements_deleted INTEGER := 0;
    v_lucky_draw_entries_deleted INTEGER := 0;
    v_scratch_card_plays_deleted INTEGER := 0;
    v_consumer_qr_scans_deleted INTEGER := 0;
    v_document_files_deleted INTEGER := 0;
    v_consumer_activations_deleted INTEGER := 0;
    v_daily_quiz_plays_deleted INTEGER := 0;
    v_points_transactions_deleted INTEGER := 0;
    v_qr_movements_deleted INTEGER := 0;
    v_consumer_feedback_deleted INTEGER := 0;
    v_allocation_released BOOLEAN := false;
    v_batch_size INTEGER := 10000;
    v_deleted_count INTEGER;
BEGIN
    -- Get order details
    SELECT order_no, display_doc_no, company_id, order_type, status 
    INTO v_order_no, v_display_doc_no, v_company_id, v_order_type, v_order_status
    FROM orders WHERE id = p_order_id;
    
    IF v_order_no IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Order not found'
        );
    END IF;

    RAISE NOTICE 'Starting hard delete for order % (%) - Type: %, Status: %', 
        v_order_no, p_order_id, v_order_type, v_order_status;

    -- =====================================================
    -- STEP 0: RELEASE ALLOCATION BEFORE DELETION
    -- This is critical for D2H and S2D orders that allocate inventory
    -- Must be done BEFORE deleting order_items since release function needs them
    -- =====================================================
    IF v_order_type IN ('D2H', 'S2D') AND v_order_status NOT IN ('completed', 'shipped') THEN
        BEGIN
            RAISE NOTICE 'Releasing allocation for order %...', v_order_no;
            PERFORM public.release_allocation_for_order(p_order_id);
            v_allocation_released := true;
            RAISE NOTICE 'Allocation released successfully for order %', v_order_no;
        EXCEPTION WHEN OTHERS THEN
            RAISE WARNING 'Failed to release allocation for order %: %', v_order_no, SQLERRM;
            -- Continue with deletion even if allocation release fails
            -- The stock_movements deletion will handle the records
        END;
    END IF;

    -- Note: We use batch deletion to avoid timeouts
    -- Triggers remain active but batching prevents long-running transactions

    -- 1. Delete scratch_card_plays (references qr_codes) - in batches
    LOOP
        DELETE FROM scratch_card_plays 
        WHERE id IN (
            SELECT sp.id FROM scratch_card_plays sp
            INNER JOIN qr_codes qc ON sp.qr_code_id = qc.id
            WHERE qc.order_id = p_order_id
            LIMIT v_batch_size
        );
        GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
        v_scratch_card_plays_deleted := v_scratch_card_plays_deleted + v_deleted_count;
        EXIT WHEN v_deleted_count = 0;
    END LOOP;

    -- 2. Delete consumer_qr_scans (references qr_codes) - in batches
    LOOP
        DELETE FROM consumer_qr_scans 
        WHERE id IN (
            SELECT cqs.id FROM consumer_qr_scans cqs
            INNER JOIN qr_codes qc ON cqs.qr_code_id = qc.id
            WHERE qc.order_id = p_order_id
            LIMIT v_batch_size
        );
        GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
        v_consumer_qr_scans_deleted := v_consumer_qr_scans_deleted + v_deleted_count;
        EXIT WHEN v_deleted_count = 0;
    END LOOP;

    -- 3. Delete consumer_activations (references qr_codes) - in batches
    LOOP
        DELETE FROM consumer_activations 
        WHERE id IN (
            SELECT ca.id FROM consumer_activations ca
            INNER JOIN qr_codes qc ON ca.qr_code_id = qc.id
            WHERE qc.order_id = p_order_id
            LIMIT v_batch_size
        );
        GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
        v_consumer_activations_deleted := v_consumer_activations_deleted + v_deleted_count;
        EXIT WHEN v_deleted_count = 0;
    END LOOP;

    -- 4. Delete daily_quiz_plays (references qr_codes) - in batches
    LOOP
        DELETE FROM daily_quiz_plays 
        WHERE id IN (
            SELECT dqp.id FROM daily_quiz_plays dqp
            INNER JOIN qr_codes qc ON dqp.qr_code_id = qc.id
            WHERE qc.order_id = p_order_id
            LIMIT v_batch_size
        );
        GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
        v_daily_quiz_plays_deleted := v_daily_quiz_plays_deleted + v_deleted_count;
        EXIT WHEN v_deleted_count = 0;
    END LOOP;

    -- 5. Delete points_transactions (references qr_codes) - in batches
    LOOP
        DELETE FROM points_transactions 
        WHERE id IN (
            SELECT pt.id FROM points_transactions pt
            INNER JOIN qr_codes qc ON pt.qr_code_id = qc.id
            WHERE qc.order_id = p_order_id
            LIMIT v_batch_size
        );
        GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
        v_points_transactions_deleted := v_points_transactions_deleted + v_deleted_count;
        EXIT WHEN v_deleted_count = 0;
    END LOOP;

    -- 5b. Delete lucky_draw_entries by order_id directly (not just via qr_codes)
    LOOP
        DELETE FROM lucky_draw_entries 
        WHERE id IN (
            SELECT id FROM lucky_draw_entries WHERE order_id = p_order_id LIMIT v_batch_size
        );
        GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
        v_lucky_draw_entries_deleted := v_lucky_draw_entries_deleted + v_deleted_count;
        EXIT WHEN v_deleted_count = 0;
    END LOOP;

    -- Also delete lucky_draw_entries via qr_codes
    LOOP
        DELETE FROM lucky_draw_entries 
        WHERE id IN (
            SELECT lde.id FROM lucky_draw_entries lde
            INNER JOIN qr_codes qc ON lde.qr_code_id = qc.id
            WHERE qc.order_id = p_order_id
            LIMIT v_batch_size
        );
        GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
        v_lucky_draw_entries_deleted := v_lucky_draw_entries_deleted + v_deleted_count;
        EXIT WHEN v_deleted_count = 0;
    END LOOP;

    -- 6. Delete qr_movements (references qr_codes)
    LOOP
        DELETE FROM qr_movements 
        WHERE id IN (
            SELECT qm.id FROM qr_movements qm
            INNER JOIN qr_codes qc ON qm.qr_code_id = qc.id
            WHERE qc.order_id = p_order_id
            LIMIT v_batch_size
        );
        GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
        v_qr_movements_deleted := v_qr_movements_deleted + v_deleted_count;
        EXIT WHEN v_deleted_count = 0;
    END LOOP;

    -- 7. Update consumer_feedback to SET NULL (it has ON DELETE SET NULL)
    UPDATE consumer_feedback SET qr_code_id = NULL
    WHERE qr_code_id IN (SELECT id FROM qr_codes WHERE order_id = p_order_id);
    GET DIAGNOSTICS v_consumer_feedback_deleted = ROW_COUNT;

    -- 8. Delete qr_codes - in batches
    LOOP
        DELETE FROM qr_codes 
        WHERE id IN (SELECT id FROM qr_codes WHERE order_id = p_order_id LIMIT v_batch_size);
        GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
        v_qr_codes_deleted := v_qr_codes_deleted + v_deleted_count;
        EXIT WHEN v_deleted_count = 0;
    END LOOP;

    -- 9. Delete qr_master_codes and qr_batches
    DELETE FROM qr_master_codes 
    WHERE batch_id IN (SELECT id FROM qr_batches WHERE order_id = p_order_id);
    GET DIAGNOSTICS v_qr_master_codes_deleted = ROW_COUNT;

    DELETE FROM qr_batches WHERE order_id = p_order_id;
    GET DIAGNOSTICS v_qr_batches_deleted = ROW_COUNT;

    -- 10. Delete document_files and documents
    DELETE FROM document_files 
    WHERE document_id IN (SELECT id FROM documents WHERE order_id = p_order_id);
    GET DIAGNOSTICS v_document_files_deleted = ROW_COUNT;

    DELETE FROM documents WHERE order_id = p_order_id;
    GET DIAGNOSTICS v_documents_deleted = ROW_COUNT;

    -- 11. Delete stock_movements (by reference_id and reference_no)
    DELETE FROM stock_movements WHERE reference_id = p_order_id;
    GET DIAGNOSTICS v_stock_movements_deleted = ROW_COUNT;
    
    DELETE FROM stock_movements WHERE reference_no = v_order_no;
    GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
    v_stock_movements_deleted := v_stock_movements_deleted + v_deleted_count;

    -- Also delete by display_doc_no if different from order_no
    IF v_display_doc_no IS NOT NULL AND v_display_doc_no <> v_order_no THEN
        DELETE FROM stock_movements WHERE reference_no = v_display_doc_no;
        GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
        v_stock_movements_deleted := v_stock_movements_deleted + v_deleted_count;
    END IF;

    -- 12. Delete order_items
    DELETE FROM order_items WHERE order_id = p_order_id;
    GET DIAGNOSTICS v_order_items_deleted = ROW_COUNT;

    -- 13. Delete order_doc_sequences for this order
    DELETE FROM order_doc_sequences WHERE order_id = p_order_id;

    -- 14. Finally, delete the order
    DELETE FROM orders WHERE id = p_order_id;

    RAISE NOTICE 'Hard delete completed for order %', v_order_no;

    RETURN jsonb_build_object(
        'success', true,
        'order_no', v_order_no,
        'display_doc_no_deleted', v_display_doc_no,
        'allocation_released', v_allocation_released,
        'deleted', jsonb_build_object(
            'qr_codes', v_qr_codes_deleted,
            'qr_batches', v_qr_batches_deleted,
            'qr_master_codes', v_qr_master_codes_deleted,
            'documents', v_documents_deleted,
            'document_files', v_document_files_deleted,
            'order_items', v_order_items_deleted,
            'stock_movements', v_stock_movements_deleted,
            'lucky_draw_entries', v_lucky_draw_entries_deleted,
            'scratch_card_plays', v_scratch_card_plays_deleted,
            'consumer_qr_scans', v_consumer_qr_scans_deleted,
            'consumer_activations', v_consumer_activations_deleted,
            'daily_quiz_plays', v_daily_quiz_plays_deleted,
            'points_transactions', v_points_transactions_deleted,
            'qr_movements', v_qr_movements_deleted,
            'consumer_feedback_nullified', v_consumer_feedback_deleted
        )
    );
EXCEPTION WHEN OTHERS THEN
    RAISE EXCEPTION 'Error deleting order %: %', p_order_id, SQLERRM;
END;
$$;


ALTER FUNCTION public.hard_delete_order(p_order_id uuid) OWNER TO supabase_admin;

--
-- Name: FUNCTION hard_delete_order(p_order_id uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.hard_delete_order(p_order_id uuid) IS 'Hard delete an order and all related data. Releases stock allocation for D2H/S2D orders before deletion.';


--
-- Name: hard_delete_organization(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.hard_delete_organization(p_org_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_org_type TEXT;
  v_org_name TEXT;
  v_org_code TEXT;
  v_has_orders BOOLEAN := FALSE;
  v_order_count INTEGER := 0;
  v_child_count INTEGER := 0;
  v_user_count INTEGER := 0;
  v_deleted_shop_distributors INTEGER := 0;
  v_deleted_distributor_products INTEGER := 0;
  v_deleted_inventory INTEGER := 0;
  v_deleted_users INTEGER := 0;
BEGIN
  -- Get organization details
  SELECT org_type_code, org_name, org_code
  INTO v_org_type, v_org_name, v_org_code
  FROM public.organizations
  WHERE id = p_org_id;

  -- Check if organization exists
  IF v_org_type IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Organization not found',
      'error_code', 'ORG_NOT_FOUND'
    );
  END IF;

  -- Check if organization has any orders (as buyer or seller)
  SELECT 
    EXISTS (
      SELECT 1 FROM public.orders 
      WHERE buyer_org_id = p_org_id OR seller_org_id = p_org_id
    ),
    COUNT(*) 
  INTO v_has_orders, v_order_count
  FROM public.orders 
  WHERE buyer_org_id = p_org_id OR seller_org_id = p_org_id;

  IF v_has_orders THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', format('%s (%s) cannot be deleted because it has %s order(s) in the system', 
        v_org_name, v_org_code, v_order_count),
      'error_code', 'HAS_ORDERS',
      'order_count', v_order_count,
      'org_name', v_org_name,
      'org_code', v_org_code
    );
  END IF;

  -- Check if organization has child organizations
  SELECT COUNT(*) INTO v_child_count
  FROM public.organizations
  WHERE parent_org_id = p_org_id AND is_active = true;

  IF v_child_count > 0 THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', format('%s (%s) cannot be deleted because it has %s active child organization(s)', 
        v_org_name, v_org_code, v_child_count),
      'error_code', 'HAS_CHILDREN',
      'child_count', v_child_count,
      'org_name', v_org_name,
      'org_code', v_org_code
    );
  END IF;

  -- Get count of users before deletion
  SELECT COUNT(*) INTO v_user_count
  FROM public.users
  WHERE organization_id = p_org_id;

  -- Begin deletion process
  -- Note: Many tables have ON DELETE CASCADE, so they'll be auto-deleted
  -- We'll track what we explicitly delete

  -- 1. Delete shop_distributors entries (if SHOP)
  IF v_org_type = 'SHOP' THEN
    DELETE FROM public.shop_distributors
    WHERE shop_id = p_org_id;
    GET DIAGNOSTICS v_deleted_shop_distributors = ROW_COUNT;
  END IF;

  -- 2. Delete shop_distributors entries (if DIST - where this org is the distributor)
  IF v_org_type = 'DIST' THEN
    DELETE FROM public.shop_distributors
    WHERE distributor_id = p_org_id;
    GET DIAGNOSTICS v_deleted_shop_distributors = ROW_COUNT;
  END IF;

  -- 3. Delete distributor_products entries (if DIST)
  IF v_org_type = 'DIST' THEN
    DELETE FROM public.distributor_products
    WHERE distributor_id = p_org_id;
    GET DIAGNOSTICS v_deleted_distributor_products = ROW_COUNT;
  END IF;

  -- 4. Delete product inventory (CASCADE will handle this, but we count it)
  SELECT COUNT(*) INTO v_deleted_inventory
  FROM public.product_inventory
  WHERE organization_id = p_org_id;

  -- 5. Delete users (important to do before org deletion)
  DELETE FROM public.users
  WHERE organization_id = p_org_id;
  GET DIAGNOSTICS v_deleted_users = ROW_COUNT;

  -- 6. Delete notification settings
  DELETE FROM public.org_notification_settings
  WHERE org_id = p_org_id;

  -- 7. Delete message templates
  DELETE FROM public.message_templates
  WHERE org_id = p_org_id;

  -- 8. Delete journey configurations
  DELETE FROM public.journey_configurations
  WHERE org_id = p_org_id;

  -- 9. Delete points rules
  DELETE FROM public.points_rules
  WHERE org_id = p_org_id;

  -- 10. Finally, delete the organization itself
  -- This will CASCADE delete many related records:
  -- - product_inventory (ON DELETE CASCADE)
  -- - distributor_products (ON DELETE CASCADE)
  -- - shop_distributors (ON DELETE CASCADE)
  -- - child organizations (parent_org_id references)
  DELETE FROM public.organizations
  WHERE id = p_org_id;

  -- Return success with deletion summary
  RETURN jsonb_build_object(
    'success', true,
    'message', format('%s (%s) has been permanently deleted', v_org_name, v_org_code),
    'deleted_organization', jsonb_build_object(
      'id', p_org_id,
      'name', v_org_name,
      'code', v_org_code,
      'type', v_org_type
    ),
    'deleted_related_records', jsonb_build_object(
      'users', v_deleted_users,
      'shop_distributors', v_deleted_shop_distributors,
      'distributor_products', v_deleted_distributor_products,
      'inventory_records', v_deleted_inventory
    )
  );

EXCEPTION
  WHEN foreign_key_violation THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Cannot delete organization due to foreign key constraint. There may be related records that need to be deleted first.',
      'error_code', 'FOREIGN_KEY_VIOLATION',
      'org_name', v_org_name,
      'org_code', v_org_code
    );
  WHEN OTHERS THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', format('Unexpected error: %s', SQLERRM),
      'error_code', 'UNEXPECTED_ERROR',
      'org_name', v_org_name,
      'org_code', v_org_code
    );
END;
$$;


ALTER FUNCTION public.hard_delete_organization(p_org_id uuid) OWNER TO supabase_admin;

--
-- Name: FUNCTION hard_delete_organization(p_org_id uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.hard_delete_organization(p_org_id uuid) IS 'Hard deletes an organization and all related data. 
Prevents deletion if:
- Organization has any orders (as buyer or seller)
- Organization has active child organizations
Returns JSON with success status and deletion details.
Automatically removes:
- Users
- Shop-distributor relationships
- Distributor-product relationships  
- Product inventory
- Notification settings
- Message templates
- Journey configurations
- Points rules';


--
-- Name: has_role_level(integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.has_role_level(required_level integer) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    AS $$
    SELECT EXISTS (
        SELECT 1
        FROM public.users u
        JOIN public.roles r ON r.role_code = u.role_code
        WHERE u.id = auth.uid()
        AND r.role_level <= required_level
        AND u.is_active = true
    );
$$;


ALTER FUNCTION public.has_role_level(required_level integer) OWNER TO supabase_admin;

--
-- Name: hr_post_benefit_contribution_run_to_gl(uuid, numeric); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.hr_post_benefit_contribution_run_to_gl(p_run_id uuid, p_amount numeric DEFAULT NULL::numeric) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_run record;
  v_company_id uuid;
  v_mapping record;
  v_journal_id uuid;
  v_journal_no text;
  v_amount numeric;
BEGIN
  SELECT * INTO v_run
  FROM public.hr_benefit_contribution_runs
  WHERE id = p_run_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Benefit contribution run not found';
  END IF;

  IF v_run.status <> 'approved' THEN
    RAISE EXCEPTION 'Benefit contribution run is not approved';
  END IF;

  SELECT public.get_company_id(v_run.organization_id) INTO v_company_id;
  IF v_company_id IS NULL THEN
    RAISE EXCEPTION 'Company not found';
  END IF;

  SELECT * INTO v_mapping
  FROM public.hr_gl_mappings
  WHERE organization_id = v_run.organization_id
    AND document_type = 'HR_BENEFIT_CONTRIBUTION'
    AND is_active = true
  LIMIT 1;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'GL mapping not configured';
  END IF;

  v_amount := COALESCE(
    p_amount,
    NULLIF(v_run.total_amount, 0),
    (v_run.total_employer_amount + v_run.total_employee_amount),
    0
  );

  IF v_amount <= 0 THEN
    RAISE EXCEPTION 'Invalid benefit contribution amount';
  END IF;

  IF EXISTS (
    SELECT 1 FROM public.hr_gl_postings
    WHERE document_type = 'HR_BENEFIT_CONTRIBUTION'
      AND document_id = v_run.id
  ) THEN
    SELECT journal_id INTO v_journal_id
    FROM public.hr_gl_postings
    WHERE document_type = 'HR_BENEFIT_CONTRIBUTION'
      AND document_id = v_run.id
    LIMIT 1;

    RETURN v_journal_id;
  END IF;

  v_journal_no := public.generate_journal_number(v_company_id);

  INSERT INTO public.gl_journals (
    company_id,
    journal_number,
    description,
    journal_type,
    status,
    total_debit,
    total_credit,
    created_at,
    updated_at
  ) VALUES (
    v_company_id,
    v_journal_no,
    'HR Benefit Contribution',
    'ADJUSTMENT',
    'POSTED',
    v_amount,
    v_amount,
    now(),
    now()
  ) RETURNING id INTO v_journal_id;

  INSERT INTO public.gl_journal_lines (
    journal_id,
    account_id,
    line_number,
    description,
    debit_amount,
    credit_amount,
    entity_type,
    entity_id
  ) VALUES
    (v_journal_id, v_mapping.expense_account_id, 1, 'Benefit Contribution Expense', v_amount, 0, 'BENEFIT_RUN', v_run.id),
    (v_journal_id, v_mapping.offset_account_id, 2, 'Benefit Contribution Payable', 0, v_amount, 'BENEFIT_RUN', v_run.id);

  INSERT INTO public.hr_gl_postings (
    organization_id,
    document_type,
    document_id,
    journal_id,
    posted_amount
  ) VALUES (
    v_run.organization_id,
    'HR_BENEFIT_CONTRIBUTION',
    v_run.id,
    v_journal_id,
    v_amount
  );

  RETURN v_journal_id;
END;
$$;


ALTER FUNCTION public.hr_post_benefit_contribution_run_to_gl(p_run_id uuid, p_amount numeric) OWNER TO supabase_admin;

--
-- Name: hr_post_expense_claim_to_gl(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.hr_post_expense_claim_to_gl(p_claim_id uuid) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_claim record;
  v_company_id uuid;
  v_journal_id uuid;
  v_journal_no text;
  v_amount numeric;
  v_claims_expense_id uuid;
  v_claims_payable_id uuid;
BEGIN
  -- Load claim
  SELECT * INTO v_claim
  FROM public.hr_expense_claims
  WHERE id = p_claim_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Expense claim not found: %', p_claim_id;
  END IF;

  IF v_claim.status <> 'approved' THEN
    RAISE EXCEPTION 'Expense claim is not approved (status: %)', v_claim.status;
  END IF;

  -- Resolve company
  SELECT public.get_company_id(v_claim.organization_id) INTO v_company_id;
  IF v_company_id IS NULL THEN
    RAISE EXCEPTION 'Company not found for organization: %', v_claim.organization_id;
  END IF;

  v_amount := COALESCE(v_claim.total_amount, 0);
  IF v_amount <= 0 THEN
    RAISE EXCEPTION 'Invalid claim amount: %', v_amount;
  END IF;

  -- Idempotency check
  IF EXISTS (
    SELECT 1 FROM public.hr_gl_postings
    WHERE document_type = 'EXPENSE_CLAIM'
      AND document_id = v_claim.id
  ) THEN
    SELECT journal_id INTO v_journal_id
    FROM public.hr_gl_postings
    WHERE document_type = 'EXPENSE_CLAIM'
      AND document_id = v_claim.id
    LIMIT 1;
    RETURN v_journal_id;
  END IF;

  -- Load account mappings (new granular style)
  SELECT expense_account_id INTO v_claims_expense_id
  FROM public.hr_gl_mappings
  WHERE organization_id = v_claim.organization_id
    AND document_type = 'EXPENSE_CLAIM' AND mapping_key = 'claims_expense'
    AND is_active = true LIMIT 1;

  SELECT offset_account_id INTO v_claims_payable_id
  FROM public.hr_gl_mappings
  WHERE organization_id = v_claim.organization_id
    AND document_type = 'EXPENSE_CLAIM' AND mapping_key = 'claims_payable'
    AND is_active = true LIMIT 1;

  -- Fallback to legacy mapping if no granular mapping found
  IF v_claims_expense_id IS NULL OR v_claims_payable_id IS NULL THEN
    SELECT expense_account_id, offset_account_id
    INTO v_claims_expense_id, v_claims_payable_id
    FROM public.hr_gl_mappings
    WHERE organization_id = v_claim.organization_id
      AND document_type = 'HR_EXPENSE_CLAIM'
      AND is_active = true
    LIMIT 1;
  END IF;

  IF v_claims_expense_id IS NULL THEN
    RAISE EXCEPTION 'Claims expense account not mapped';
  END IF;
  IF v_claims_payable_id IS NULL THEN
    RAISE EXCEPTION 'Claims payable account not mapped';
  END IF;

  -- Create journal: Dr Expense, Cr Claims Payable
  v_journal_no := public.generate_journal_number(v_company_id);

  INSERT INTO public.gl_journals (
    company_id, journal_number, journal_date, posting_date,
    description, journal_type, status,
    total_debit, total_credit,
    created_at, updated_at
  ) VALUES (
    v_company_id, v_journal_no,
    CURRENT_DATE, CURRENT_DATE,
    format('Expense claim approval – %s', v_claim.id),
    'EXPENSE_CLAIM', 'POSTED',
    v_amount, v_amount,
    now(), now()
  ) RETURNING id INTO v_journal_id;

  INSERT INTO public.gl_journal_lines (
    journal_id, account_id, line_number, description,
    debit_amount, credit_amount, entity_type, entity_id
  ) VALUES
    (v_journal_id, v_claims_expense_id, 1, 'Staff Claims Expense', v_amount, 0, 'EMPLOYEE', v_claim.employee_user_id),
    (v_journal_id, v_claims_payable_id, 2, 'Employee Claims Payable', 0, v_amount, 'EMPLOYEE', v_claim.employee_user_id);

  -- Record posting
  INSERT INTO public.hr_gl_postings (
    organization_id, document_type, document_id,
    journal_id, posted_amount
  ) VALUES (
    v_claim.organization_id, 'EXPENSE_CLAIM', v_claim.id,
    v_journal_id, v_amount
  );

  INSERT INTO public.gl_document_postings (
    company_id, document_type, document_id,
    document_number, journal_id, posted_amount, posting_status
  ) VALUES (
    v_company_id, 'EXPENSE_CLAIM', v_claim.id,
    format('EC-%s', v_claim.id),
    v_journal_id, v_amount, 'POSTED'
  ) ON CONFLICT (company_id, document_type, document_id) DO NOTHING;

  RETURN v_journal_id;
END;
$$;


ALTER FUNCTION public.hr_post_expense_claim_to_gl(p_claim_id uuid) OWNER TO supabase_admin;

--
-- Name: hr_post_expense_reimbursement_to_gl(uuid, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.hr_post_expense_reimbursement_to_gl(p_claim_id uuid, p_bank_account_id uuid DEFAULT NULL::uuid) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_claim record;
  v_company_id uuid;
  v_journal_id uuid;
  v_journal_no text;
  v_claims_payable_id uuid;
  v_bank_id uuid;
  v_amount numeric;
BEGIN
  -- Load claim
  SELECT * INTO v_claim
  FROM public.hr_expense_claims
  WHERE id = p_claim_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Expense claim not found: %', p_claim_id;
  END IF;

  -- Resolve company
  SELECT public.get_company_id(v_claim.organization_id) INTO v_company_id;
  IF v_company_id IS NULL THEN
    RAISE EXCEPTION 'Company not found';
  END IF;

  -- Idempotency
  IF EXISTS (
    SELECT 1 FROM public.hr_gl_postings
    WHERE document_type = 'EXPENSE_REIMBURSEMENT'
      AND document_id = v_claim.id
  ) THEN
    SELECT journal_id INTO v_journal_id
    FROM public.hr_gl_postings
    WHERE document_type = 'EXPENSE_REIMBURSEMENT'
      AND document_id = v_claim.id
    LIMIT 1;
    RETURN v_journal_id;
  END IF;

  -- Must have approval posting first
  IF NOT EXISTS (
    SELECT 1 FROM public.hr_gl_postings
    WHERE document_type IN ('EXPENSE_CLAIM', 'HR_EXPENSE_CLAIM')
      AND document_id = v_claim.id
  ) THEN
    RAISE EXCEPTION 'Expense claim not posted to GL yet — approve and post first';
  END IF;

  v_amount := COALESCE(v_claim.total_amount, 0);
  IF v_amount <= 0 THEN
    RAISE EXCEPTION 'No payable amount';
  END IF;

  -- Get claims payable account
  SELECT offset_account_id INTO v_claims_payable_id
  FROM public.hr_gl_mappings
  WHERE organization_id = v_claim.organization_id
    AND document_type = 'EXPENSE_CLAIM' AND mapping_key = 'claims_payable'
    AND is_active = true LIMIT 1;

  -- Fallback to legacy
  IF v_claims_payable_id IS NULL THEN
    SELECT offset_account_id INTO v_claims_payable_id
    FROM public.hr_gl_mappings
    WHERE organization_id = v_claim.organization_id
      AND document_type = 'HR_EXPENSE_CLAIM'
      AND is_active = true
    LIMIT 1;
  END IF;

  IF v_claims_payable_id IS NULL THEN
    RAISE EXCEPTION 'Claims payable account not mapped';
  END IF;

  -- Get bank/cash account
  v_bank_id := p_bank_account_id;
  IF v_bank_id IS NULL THEN
    SELECT cash_account_id INTO v_bank_id
    FROM public.gl_settings
    WHERE company_id = v_company_id;
  END IF;
  IF v_bank_id IS NULL THEN
    RAISE EXCEPTION 'Bank/cash account not configured';
  END IF;

  -- Dr Claims Payable, Cr Cash/Bank
  v_journal_no := public.generate_journal_number(v_company_id);

  INSERT INTO public.gl_journals (
    company_id, journal_number, journal_date, posting_date,
    description, journal_type, status,
    total_debit, total_credit,
    created_at, updated_at
  ) VALUES (
    v_company_id, v_journal_no,
    CURRENT_DATE, CURRENT_DATE,
    format('Expense reimbursement – %s', v_claim.id),
    'EXPENSE_REIMBURSEMENT', 'POSTED',
    v_amount, v_amount,
    now(), now()
  ) RETURNING id INTO v_journal_id;

  INSERT INTO public.gl_journal_lines (
    journal_id, account_id, line_number, description,
    debit_amount, credit_amount, entity_type, entity_id
  ) VALUES
    (v_journal_id, v_claims_payable_id, 1, 'Employee Claims Payable', v_amount, 0, 'EMPLOYEE', v_claim.employee_user_id),
    (v_journal_id, v_bank_id, 2, 'Cash/Bank Payment', 0, v_amount, 'EMPLOYEE', v_claim.employee_user_id);

  INSERT INTO public.hr_gl_postings (
    organization_id, document_type, document_id,
    journal_id, posted_amount
  ) VALUES (
    v_claim.organization_id, 'EXPENSE_REIMBURSEMENT', v_claim.id,
    v_journal_id, v_amount
  );

  INSERT INTO public.gl_document_postings (
    company_id, document_type, document_id,
    document_number, journal_id, posted_amount, posting_status
  ) VALUES (
    v_company_id, 'EXPENSE_REIMBURSEMENT', v_claim.id,
    format('ER-%s', v_claim.id),
    v_journal_id, v_amount, 'POSTED'
  ) ON CONFLICT (company_id, document_type, document_id) DO NOTHING;

  RETURN v_journal_id;
END;
$$;


ALTER FUNCTION public.hr_post_expense_reimbursement_to_gl(p_claim_id uuid, p_bank_account_id uuid) OWNER TO supabase_admin;

--
-- Name: hr_post_payroll_payment_to_gl(uuid, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.hr_post_payroll_payment_to_gl(p_run_id uuid, p_bank_account_id uuid DEFAULT NULL::uuid) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_run record;
  v_company_id uuid;
  v_journal_id uuid;
  v_journal_no text;
  v_payroll_payable_id uuid;
  v_bank_id uuid;
  v_amount numeric;
BEGIN
  -- Load payroll run
  SELECT * INTO v_run
  FROM public.hr_payroll_runs
  WHERE id = p_run_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Payroll run not found: %', p_run_id;
  END IF;

  -- Resolve company
  SELECT public.get_company_id(v_run.organization_id) INTO v_company_id;
  IF v_company_id IS NULL THEN
    RAISE EXCEPTION 'Company not found';
  END IF;

  -- Idempotency: check if payment already posted
  IF EXISTS (
    SELECT 1 FROM public.hr_gl_postings
    WHERE document_type = 'PAYROLL_PAYMENT'
      AND document_id = v_run.id
  ) THEN
    SELECT journal_id INTO v_journal_id
    FROM public.hr_gl_postings
    WHERE document_type = 'PAYROLL_PAYMENT'
      AND document_id = v_run.id
    LIMIT 1;
    RETURN v_journal_id;
  END IF;

  -- Must have accrual posting first
  IF NOT EXISTS (
    SELECT 1 FROM public.hr_gl_postings
    WHERE document_type = 'PAYROLL_RUN'
      AND document_id = v_run.id
  ) THEN
    RAISE EXCEPTION 'Payroll accrual not posted yet — post payroll run first';
  END IF;

  v_amount := COALESCE(v_run.total_net, 0);
  IF v_amount <= 0 THEN
    RAISE EXCEPTION 'No net payable amount';
  END IF;

  -- Get payroll payable account
  SELECT offset_account_id INTO v_payroll_payable_id
  FROM public.hr_gl_mappings
  WHERE organization_id = v_run.organization_id
    AND document_type = 'PAYROLL_RUN' AND mapping_key = 'payroll_payable'
    AND is_active = true LIMIT 1;

  IF v_payroll_payable_id IS NULL THEN
    RAISE EXCEPTION 'Payroll payable account not mapped';
  END IF;

  -- Get bank/cash account: use provided, or fallback to gl_settings.cash_account_id
  v_bank_id := p_bank_account_id;
  IF v_bank_id IS NULL THEN
    SELECT cash_account_id INTO v_bank_id
    FROM public.gl_settings
    WHERE company_id = v_company_id;
  END IF;
  IF v_bank_id IS NULL THEN
    RAISE EXCEPTION 'Bank/cash account not configured';
  END IF;

  -- Dr Payroll Payable, Cr Cash/Bank
  v_journal_no := public.generate_journal_number(v_company_id);

  INSERT INTO public.gl_journals (
    company_id, journal_number, journal_date, posting_date,
    description, journal_type, status,
    total_debit, total_credit,
    created_at, updated_at
  ) VALUES (
    v_company_id, v_journal_no,
    CURRENT_DATE, CURRENT_DATE,
    format('Payroll payment %s – %s', v_run.period_start, v_run.period_end),
    'PAYROLL_PAYMENT', 'POSTED',
    v_amount, v_amount,
    now(), now()
  ) RETURNING id INTO v_journal_id;

  INSERT INTO public.gl_journal_lines (
    journal_id, account_id, line_number, description,
    debit_amount, credit_amount, entity_type, entity_id
  ) VALUES
    (v_journal_id, v_payroll_payable_id, 1, 'Payroll Payable', v_amount, 0, NULL, NULL),
    (v_journal_id, v_bank_id, 2, 'Cash/Bank Payment', 0, v_amount, NULL, NULL);

  INSERT INTO public.hr_gl_postings (
    organization_id, document_type, document_id,
    journal_id, posted_amount
  ) VALUES (
    v_run.organization_id, 'PAYROLL_PAYMENT', v_run.id,
    v_journal_id, v_amount
  );

  INSERT INTO public.gl_document_postings (
    company_id, document_type, document_id,
    document_number, journal_id, posted_amount, posting_status
  ) VALUES (
    v_company_id, 'PAYROLL_PAYMENT', v_run.id,
    format('PP-%s-%s', v_run.period_start, v_run.period_end),
    v_journal_id, v_amount, 'POSTED'
  ) ON CONFLICT (company_id, document_type, document_id) DO NOTHING;

  RETURN v_journal_id;
END;
$$;


ALTER FUNCTION public.hr_post_payroll_payment_to_gl(p_run_id uuid, p_bank_account_id uuid) OWNER TO supabase_admin;

--
-- Name: hr_post_payroll_run_to_gl(uuid, numeric); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.hr_post_payroll_run_to_gl(p_run_id uuid, p_amount numeric DEFAULT NULL::numeric) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_run record;
  v_company_id uuid;
  v_journal_id uuid;
  v_journal_no text;
  v_line_num integer := 0;
  -- Aggregated totals
  v_total_gross numeric := 0;
  v_total_net numeric := 0;
  v_total_epf numeric := 0;
  v_total_socso numeric := 0;
  v_total_eis numeric := 0;
  v_total_pcb numeric := 0;
  v_total_other_ded numeric := 0;
  v_total_employer_epf numeric := 0;
  v_total_employer_socso numeric := 0;
  v_total_employer_eis numeric := 0;
  -- Account IDs from mappings
  v_salary_expense_id uuid;
  v_payroll_payable_id uuid;
  v_epf_payable_id uuid;
  v_socso_payable_id uuid;
  v_eis_payable_id uuid;
  v_pcb_payable_id uuid;
  v_other_ded_payable_id uuid;
  v_employer_expense_id uuid;
  -- Totals for journal balancing
  v_total_debit numeric := 0;
  v_total_credit numeric := 0;
BEGIN
  -- Load payroll run
  SELECT * INTO v_run
  FROM public.hr_payroll_runs
  WHERE id = p_run_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Payroll run not found: %', p_run_id;
  END IF;

  IF v_run.status <> 'approved' THEN
    RAISE EXCEPTION 'Payroll run is not approved (status: %)', v_run.status;
  END IF;

  -- Resolve company
  SELECT public.get_company_id(v_run.organization_id) INTO v_company_id;
  IF v_company_id IS NULL THEN
    RAISE EXCEPTION 'Company not found for organization: %', v_run.organization_id;
  END IF;

  -- Idempotency check
  IF EXISTS (
    SELECT 1 FROM public.hr_gl_postings
    WHERE document_type = 'PAYROLL_RUN'
      AND document_id = v_run.id
  ) THEN
    SELECT journal_id INTO v_journal_id
    FROM public.hr_gl_postings
    WHERE document_type = 'PAYROLL_RUN'
      AND document_id = v_run.id
    LIMIT 1;
    RETURN v_journal_id;
  END IF;

  -- Aggregate totals from run items
  SELECT
    COALESCE(SUM(basic_salary + overtime_amount + allowances_amount + other_allowances), 0),
    COALESCE(SUM(net_amount), 0),
    COALESCE(SUM(epf_employee), 0),
    COALESCE(SUM(socso_employee), 0),
    COALESCE(SUM(eis_employee), 0),
    COALESCE(SUM(pcb_amount), 0),
    COALESCE(SUM(other_deductions), 0),
    COALESCE(SUM(epf_employer), 0),
    COALESCE(SUM(socso_employer), 0),
    COALESCE(SUM(eis_employer), 0)
  INTO
    v_total_gross,
    v_total_net,
    v_total_epf,
    v_total_socso,
    v_total_eis,
    v_total_pcb,
    v_total_other_ded,
    v_total_employer_epf,
    v_total_employer_socso,
    v_total_employer_eis
  FROM public.hr_payroll_run_items
  WHERE payroll_run_id = p_run_id;

  IF v_total_gross <= 0 THEN
    RAISE EXCEPTION 'Invalid payroll totals (gross = %)', v_total_gross;
  END IF;

  -- Load account mappings
  SELECT expense_account_id INTO v_salary_expense_id
  FROM public.hr_gl_mappings
  WHERE organization_id = v_run.organization_id
    AND document_type = 'PAYROLL_RUN' AND mapping_key = 'salary_expense'
    AND is_active = true LIMIT 1;

  SELECT offset_account_id INTO v_payroll_payable_id
  FROM public.hr_gl_mappings
  WHERE organization_id = v_run.organization_id
    AND document_type = 'PAYROLL_RUN' AND mapping_key = 'payroll_payable'
    AND is_active = true LIMIT 1;

  SELECT offset_account_id INTO v_epf_payable_id
  FROM public.hr_gl_mappings
  WHERE organization_id = v_run.organization_id
    AND document_type = 'PAYROLL_RUN' AND mapping_key = 'epf_payable'
    AND is_active = true LIMIT 1;

  SELECT offset_account_id INTO v_socso_payable_id
  FROM public.hr_gl_mappings
  WHERE organization_id = v_run.organization_id
    AND document_type = 'PAYROLL_RUN' AND mapping_key = 'socso_payable'
    AND is_active = true LIMIT 1;

  SELECT offset_account_id INTO v_eis_payable_id
  FROM public.hr_gl_mappings
  WHERE organization_id = v_run.organization_id
    AND document_type = 'PAYROLL_RUN' AND mapping_key = 'eis_payable'
    AND is_active = true LIMIT 1;

  SELECT offset_account_id INTO v_pcb_payable_id
  FROM public.hr_gl_mappings
  WHERE organization_id = v_run.organization_id
    AND document_type = 'PAYROLL_RUN' AND mapping_key = 'pcb_payable'
    AND is_active = true LIMIT 1;

  SELECT offset_account_id INTO v_other_ded_payable_id
  FROM public.hr_gl_mappings
  WHERE organization_id = v_run.organization_id
    AND document_type = 'PAYROLL_RUN' AND mapping_key = 'other_deductions_payable'
    AND is_active = true LIMIT 1;

  SELECT expense_account_id INTO v_employer_expense_id
  FROM public.hr_gl_mappings
  WHERE organization_id = v_run.organization_id
    AND document_type = 'PAYROLL_RUN' AND mapping_key = 'employer_contributions'
    AND is_active = true LIMIT 1;

  -- Validate required accounts
  IF v_salary_expense_id IS NULL THEN
    RAISE EXCEPTION 'Salary expense account not mapped';
  END IF;
  IF v_payroll_payable_id IS NULL THEN
    RAISE EXCEPTION 'Payroll payable account not mapped';
  END IF;

  -- Calculate total debit (salary expense + employer contributions)
  v_total_debit := v_total_gross;
  -- If employer contributions account is configured, add employer portion as separate debit
  IF v_employer_expense_id IS NOT NULL THEN
    v_total_debit := v_total_debit + (v_total_employer_epf + v_total_employer_socso + v_total_employer_eis);
  END IF;

  -- Calculate total credit
  v_total_credit := v_total_net
    + v_total_epf + v_total_employer_epf
    + v_total_socso + v_total_employer_socso
    + v_total_eis + v_total_employer_eis
    + v_total_pcb
    + v_total_other_ded;

  -- If no split employer account, add employer portion into the salary expense debit
  IF v_employer_expense_id IS NULL THEN
    v_total_debit := v_total_credit;  -- force balance
  END IF;

  -- Create journal
  v_journal_no := public.generate_journal_number(v_company_id);

  INSERT INTO public.gl_journals (
    company_id, journal_number, journal_date, posting_date,
    description, journal_type, status,
    total_debit, total_credit,
    created_at, updated_at
  ) VALUES (
    v_company_id, v_journal_no,
    COALESCE(v_run.payroll_date, v_run.period_end),
    COALESCE(v_run.payroll_date, v_run.period_end),
    format('Payroll accrual %s – %s', v_run.period_start, v_run.period_end),
    'PAYROLL_RUN', 'POSTED',
    v_total_debit, v_total_credit,
    now(), now()
  ) RETURNING id INTO v_journal_id;

  -- ── DEBIT LINES ──

  -- Dr Salaries & Wages Expense = total gross
  v_line_num := v_line_num + 1;
  INSERT INTO public.gl_journal_lines (
    journal_id, account_id, line_number, description,
    debit_amount, credit_amount, entity_type, entity_id
  ) VALUES (
    v_journal_id, v_salary_expense_id, v_line_num,
    'Salaries & Wages Expense',
    v_total_gross, 0, NULL, NULL
  );

  -- Dr Employer Statutory Contributions (if split account configured)
  IF v_employer_expense_id IS NOT NULL AND (v_total_employer_epf + v_total_employer_socso + v_total_employer_eis) > 0 THEN
    v_line_num := v_line_num + 1;
    INSERT INTO public.gl_journal_lines (
      journal_id, account_id, line_number, description,
      debit_amount, credit_amount, entity_type, entity_id
    ) VALUES (
      v_journal_id, v_employer_expense_id, v_line_num,
      'Employer Statutory Contributions (EPF/SOCSO/EIS)',
      v_total_employer_epf + v_total_employer_socso + v_total_employer_eis, 0, NULL, NULL
    );
  END IF;

  -- ── CREDIT LINES ──

  -- Cr Payroll Payable (net amount)
  IF v_total_net > 0 THEN
    v_line_num := v_line_num + 1;
    INSERT INTO public.gl_journal_lines (
      journal_id, account_id, line_number, description,
      debit_amount, credit_amount, entity_type, entity_id
    ) VALUES (
      v_journal_id, v_payroll_payable_id, v_line_num,
      'Net Payroll Payable',
      0, v_total_net, NULL, NULL
    );
  END IF;

  -- Cr EPF Payable (employee + employer)
  IF v_epf_payable_id IS NOT NULL AND (v_total_epf + v_total_employer_epf) > 0 THEN
    v_line_num := v_line_num + 1;
    INSERT INTO public.gl_journal_lines (
      journal_id, account_id, line_number, description,
      debit_amount, credit_amount, entity_type, entity_id
    ) VALUES (
      v_journal_id, v_epf_payable_id, v_line_num,
      'EPF Payable (Employee + Employer)',
      0, v_total_epf + v_total_employer_epf, NULL, NULL
    );
  END IF;

  -- Cr SOCSO Payable
  IF v_socso_payable_id IS NOT NULL AND (v_total_socso + v_total_employer_socso) > 0 THEN
    v_line_num := v_line_num + 1;
    INSERT INTO public.gl_journal_lines (
      journal_id, account_id, line_number, description,
      debit_amount, credit_amount, entity_type, entity_id
    ) VALUES (
      v_journal_id, v_socso_payable_id, v_line_num,
      'SOCSO Payable (Employee + Employer)',
      0, v_total_socso + v_total_employer_socso, NULL, NULL
    );
  END IF;

  -- Cr EIS Payable
  IF v_eis_payable_id IS NOT NULL AND (v_total_eis + v_total_employer_eis) > 0 THEN
    v_line_num := v_line_num + 1;
    INSERT INTO public.gl_journal_lines (
      journal_id, account_id, line_number, description,
      debit_amount, credit_amount, entity_type, entity_id
    ) VALUES (
      v_journal_id, v_eis_payable_id, v_line_num,
      'EIS Payable (Employee + Employer)',
      0, v_total_eis + v_total_employer_eis, NULL, NULL
    );
  END IF;

  -- Cr PCB/MTD Payable
  IF v_pcb_payable_id IS NOT NULL AND v_total_pcb > 0 THEN
    v_line_num := v_line_num + 1;
    INSERT INTO public.gl_journal_lines (
      journal_id, account_id, line_number, description,
      debit_amount, credit_amount, entity_type, entity_id
    ) VALUES (
      v_journal_id, v_pcb_payable_id, v_line_num,
      'PCB/MTD Payable',
      0, v_total_pcb, NULL, NULL
    );
  END IF;

  -- Cr Other Deductions Payable
  IF v_other_ded_payable_id IS NOT NULL AND v_total_other_ded > 0 THEN
    v_line_num := v_line_num + 1;
    INSERT INTO public.gl_journal_lines (
      journal_id, account_id, line_number, description,
      debit_amount, credit_amount, entity_type, entity_id
    ) VALUES (
      v_journal_id, v_other_ded_payable_id, v_line_num,
      'Other Deductions Payable',
      0, v_total_other_ded, NULL, NULL
    );
  END IF;

  -- Record posting (idempotency)
  INSERT INTO public.hr_gl_postings (
    organization_id, document_type, document_id,
    journal_id, posted_amount
  ) VALUES (
    v_run.organization_id, 'PAYROLL_RUN', v_run.id,
    v_journal_id, v_total_debit
  );

  -- Also record in gl_document_postings for finance module visibility
  INSERT INTO public.gl_document_postings (
    company_id, document_type, document_id,
    document_number, journal_id, posted_amount, posting_status
  ) VALUES (
    v_company_id, 'PAYROLL_RUN', v_run.id,
    format('PR-%s-%s', v_run.period_start, v_run.period_end),
    v_journal_id, v_total_debit, 'POSTED'
  ) ON CONFLICT (company_id, document_type, document_id) DO NOTHING;

  RETURN v_journal_id;
END;
$$;


ALTER FUNCTION public.hr_post_payroll_run_to_gl(p_run_id uuid, p_amount numeric) OWNER TO supabase_admin;

--
-- Name: hr_post_statutory_payment_to_gl(uuid, text, numeric, text, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.hr_post_statutory_payment_to_gl(p_organization_id uuid, p_statutory_type text, p_amount numeric, p_reference text DEFAULT NULL::text, p_bank_account_id uuid DEFAULT NULL::uuid) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_company_id uuid;
  v_journal_id uuid;
  v_journal_no text;
  v_payable_id uuid;
  v_bank_id uuid;
  v_mapping_key text;
  v_desc text;
BEGIN
  -- Resolve company
  SELECT public.get_company_id(p_organization_id) INTO v_company_id;
  IF v_company_id IS NULL THEN
    RAISE EXCEPTION 'Company not found';
  END IF;

  -- Map statutory type to mapping key
  CASE p_statutory_type
    WHEN 'EPF'   THEN v_mapping_key := 'epf_payable';   v_desc := 'EPF Remittance';
    WHEN 'SOCSO' THEN v_mapping_key := 'socso_payable'; v_desc := 'SOCSO Remittance';
    WHEN 'EIS'   THEN v_mapping_key := 'eis_payable';   v_desc := 'EIS Remittance';
    WHEN 'PCB'   THEN v_mapping_key := 'pcb_payable';   v_desc := 'PCB/MTD Remittance';
    ELSE RAISE EXCEPTION 'Unknown statutory type: %', p_statutory_type;
  END CASE;

  IF p_amount <= 0 THEN
    RAISE EXCEPTION 'Invalid payment amount';
  END IF;

  -- Get payable account
  SELECT offset_account_id INTO v_payable_id
  FROM public.hr_gl_mappings
  WHERE organization_id = p_organization_id
    AND document_type = 'PAYROLL_RUN' AND mapping_key = v_mapping_key
    AND is_active = true LIMIT 1;

  IF v_payable_id IS NULL THEN
    RAISE EXCEPTION '% payable account not mapped', p_statutory_type;
  END IF;

  -- Get bank/cash account
  v_bank_id := p_bank_account_id;
  IF v_bank_id IS NULL THEN
    SELECT cash_account_id INTO v_bank_id
    FROM public.gl_settings
    WHERE company_id = v_company_id;
  END IF;
  IF v_bank_id IS NULL THEN
    RAISE EXCEPTION 'Bank/cash account not configured';
  END IF;

  -- Dr Statutory Payable, Cr Cash/Bank
  v_journal_no := public.generate_journal_number(v_company_id);

  INSERT INTO public.gl_journals (
    company_id, journal_number, journal_date, posting_date,
    description, journal_type, status,
    total_debit, total_credit,
    created_at, updated_at
  ) VALUES (
    v_company_id, v_journal_no,
    CURRENT_DATE, CURRENT_DATE,
    v_desc || COALESCE(' – ' || p_reference, ''),
    'PAYROLL_PAYMENT', 'POSTED',
    p_amount, p_amount,
    now(), now()
  ) RETURNING id INTO v_journal_id;

  INSERT INTO public.gl_journal_lines (
    journal_id, account_id, line_number, description,
    debit_amount, credit_amount, entity_type, entity_id
  ) VALUES
    (v_journal_id, v_payable_id, 1, v_desc, p_amount, 0, NULL, NULL),
    (v_journal_id, v_bank_id, 2, 'Cash/Bank Payment', 0, p_amount, NULL, NULL);

  RETURN v_journal_id;
END;
$$;


ALTER FUNCTION public.hr_post_statutory_payment_to_gl(p_organization_id uuid, p_statutory_type text, p_amount numeric, p_reference text, p_bank_account_id uuid) OWNER TO supabase_admin;

--
-- Name: insert_whatsapp_message(uuid, text, text, uuid, uuid, text, text, text, text, jsonb); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.insert_whatsapp_message(p_conversation_id uuid, p_direction text, p_sender_type text, p_sender_user_id uuid, p_sender_admin_id uuid, p_sender_phone text, p_body_text text, p_external_message_id text, p_external_chat_id text, p_metadata jsonb DEFAULT '{}'::jsonb) RETURNS TABLE(message_id uuid, is_duplicate boolean)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_message_id UUID;
    v_phone_e164 TEXT;
BEGIN
    -- Check for duplicate
    IF p_external_message_id IS NOT NULL AND public.check_whatsapp_message_exists(p_external_message_id) THEN
        -- Return existing message ID
        SELECT id INTO v_message_id
        FROM public.support_conversation_messages
        WHERE external_message_id = p_external_message_id
          AND channel = 'whatsapp'
        LIMIT 1;
        
        RETURN QUERY SELECT v_message_id, true;
        RETURN;
    END IF;
    
    -- Normalize phone
    v_phone_e164 := CASE WHEN p_sender_phone IS NOT NULL 
                        THEN public.normalize_phone_e164(p_sender_phone) 
                        ELSE NULL END;
    
    -- Insert new message
    INSERT INTO public.support_conversation_messages (
        conversation_id,
        direction,
        channel,
        sender_type,
        sender_user_id,
        sender_admin_id,
        sender_phone,
        body_text,
        external_message_id,
        external_chat_id,
        origin,
        metadata
    ) VALUES (
        p_conversation_id,
        p_direction,
        'whatsapp',
        p_sender_type,
        p_sender_user_id,
        p_sender_admin_id,
        v_phone_e164,
        p_body_text,
        p_external_message_id,
        p_external_chat_id,
        'whatsapp',
        p_metadata
    )
    RETURNING id INTO v_message_id;
    
    -- Update conversation
    UPDATE public.support_conversations
    SET 
        last_message_at = NOW(),
        last_message_preview = LEFT(p_body_text, 100),
        last_message_sender_type = p_sender_type,
        admin_unread_count = CASE WHEN p_direction = 'inbound' 
                                  THEN admin_unread_count + 1 
                                  ELSE admin_unread_count END,
        user_unread_count = CASE WHEN p_direction = 'outbound' 
                                 THEN user_unread_count + 1 
                                 ELSE user_unread_count END,
        status = CASE 
            WHEN p_direction = 'inbound' AND status IN ('resolved', 'pending_user') 
            THEN 'open'::public.support_conversation_status
            WHEN p_direction = 'outbound' AND status = 'open'
            THEN 'pending_user'::public.support_conversation_status
            ELSE status
        END,
        updated_at = NOW()
    WHERE id = p_conversation_id;
    
    RETURN QUERY SELECT v_message_id, false;
END;
$$;


ALTER FUNCTION public.insert_whatsapp_message(p_conversation_id uuid, p_direction text, p_sender_type text, p_sender_user_id uuid, p_sender_admin_id uuid, p_sender_phone text, p_body_text text, p_external_message_id text, p_external_chat_id text, p_metadata jsonb) OWNER TO supabase_admin;

--
-- Name: invoice_acknowledge(uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.invoice_acknowledge(p_document_id uuid, p_payment_proof_url text DEFAULT NULL::text) RETURNS public.documents
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE 
  d public.documents; 
  o public.orders; 
  v_pay_id uuid; 
  v_required boolean;
  v_payment_doc_no text;
BEGIN
  SELECT * INTO d FROM public.documents
   WHERE id = p_document_id AND doc_type = 'INVOICE'
   FOR UPDATE;

  IF NOT FOUND THEN 
    RAISE EXCEPTION 'Invoice document not found'; 
  END IF;

  IF d.status <> 'pending' THEN 
    RAISE EXCEPTION 'Invoice must be pending'; 
  END IF;

  SELECT * INTO o FROM public.orders WHERE id = d.order_id;

  v_required := public.is_payment_proof_required(o.company_id);
  IF v_required AND p_payment_proof_url IS NULL THEN
    RAISE EXCEPTION 'Payment proof is required for this organization';
  END IF;

  PERFORM public.add_document_signature(
    p_document_id,
    auth.uid(),
    (SELECT role_code FROM public.users WHERE id = auth.uid())
  );

  UPDATE public.documents
     SET status = 'acknowledged', 
         acknowledged_by = auth.uid(),
         acknowledged_at = NOW(), 
         updated_at = NOW()
   WHERE id = p_document_id
   RETURNING * INTO d;

  v_payment_doc_no := public.format_doc_no_from_order('PAY', o.order_no);

  INSERT INTO public.documents (
    order_id, doc_type, doc_no, status,
    issued_by_org_id, issued_to_org_id,
    company_id, created_by, payload
  )
  VALUES (
    o.id, 'PAYMENT',
    v_payment_doc_no,
    'pending',
    o.buyer_org_id,
    o.seller_org_id,
    o.company_id, auth.uid(),
    jsonb_build_object('invoice_id', p_document_id)
  )
  RETURNING id INTO v_pay_id;

  IF p_payment_proof_url IS NOT NULL THEN
    INSERT INTO public.document_files (document_id, file_url, company_id, uploaded_by)
    VALUES (v_pay_id, p_payment_proof_url, o.company_id, auth.uid());
  END IF;

  RETURN d;
END;
$$;


ALTER FUNCTION public.invoice_acknowledge(p_document_id uuid, p_payment_proof_url text) OWNER TO supabase_admin;

--
-- Name: FUNCTION invoice_acknowledge(p_document_id uuid, p_payment_proof_url text); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.invoice_acknowledge(p_document_id uuid, p_payment_proof_url text) IS 'Acknowledges Invoice and records digital signature. Auto-generates Payment document.';


--
-- Name: is_admin(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.is_admin() RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  -- Check if user has admin role in public.users table
  -- Updated to check actual role codes used in the system
  RETURN EXISTS (
    SELECT 1 FROM public.users
    WHERE id = auth.uid()
    AND role_code IN ('SA', 'HQ', 'POWER_USER', 'HQ_ADMIN', 'admin', 'super_admin', 'hq_admin')
  );
END;
$$;


ALTER FUNCTION public.is_admin() OWNER TO supabase_admin;

--
-- Name: is_document_posted(text, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.is_document_posted(p_document_type text, p_document_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN EXISTS (
        SELECT 1 FROM public.gl_document_postings
        WHERE document_type = p_document_type
        AND document_id = p_document_id
        AND posting_status = 'POSTED'
        AND company_id = public.get_user_company_id()
    );
END;
$$;


