--
-- Name: is_org_admin_or_super(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.is_org_admin_or_super(check_org_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN EXISTS (
        SELECT 1 FROM users 
        WHERE id = auth.uid() 
        AND (
            is_super_admin = true 
            OR (company_id = check_org_id AND role_code IN ('ADMIN', 'HQ', 'SUPER'))
        )
    );
END;
$$;


