--
-- Name: is_platform_super_admin(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.is_platform_super_admin() RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  -- Prefer a direct top-level claim if you mirror it into the JWT at sign-in:
  select coalesce( (auth.jwt() ->> 'is_platform_super_admin')::boolean, false );
$$;


