--
-- Name: is_posting_date_allowed(date, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.is_posting_date_allowed(p_posting_date date, p_company_id uuid DEFAULT NULL::uuid) RETURNS boolean
    LANGUAGE sql STABLE
    AS $$
    SELECT EXISTS (
        SELECT 1 
        FROM public.fiscal_periods fp
        JOIN public.fiscal_years fy ON fp.fiscal_year_id = fy.id
        WHERE fp.company_id = COALESCE(p_company_id, public.get_user_company_id())
          AND fp.status = 'open'
          AND fy.status IN ('open', 'closed') -- Not locked
          AND p_posting_date BETWEEN fp.start_date AND fp.end_date
    );
$$;


ALTER FUNCTION public.is_posting_date_allowed(p_posting_date date, p_company_id uuid) OWNER TO supabase_admin;

--
-- Name: FUNCTION is_posting_date_allowed(p_posting_date date, p_company_id uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.is_posting_date_allowed(p_posting_date date, p_company_id uuid) IS 'Validates if posting is allowed for a given date based on fiscal period status';


--
-- Name: is_power_user(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.is_power_user() RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_role_level integer;
  v_user_role_code text;
BEGIN
  -- Get user's role code first
  SELECT role_code INTO v_user_role_code
  FROM public.users
  WHERE id = auth.uid();
  
  IF v_user_role_code IS NULL THEN
      -- User not found or has no role
      RETURN false;
  END IF;

  -- Try to get role level
  SELECT role_level INTO v_role_level
  FROM public.roles
  WHERE role_name = v_user_role_code OR role_code = v_user_role_code;
  
  IF v_role_level IS NULL THEN
      -- Role not found in roles table
      -- Fallback: If role code contains 'admin', assume power user for safety/continuity?
      -- No, that's dangerous. But we can check if it's 'super_admin' or 'admin_hq'.
      
      IF v_user_role_code IN ('super_admin', 'admin_hq', 'admin') THEN
          RETURN true;
      END IF;
      
      RETURN false;
  END IF;

  RETURN v_role_level <= 20;
END;
$$;


