--
-- Name: kpi_classify_status(numeric, numeric, numeric); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.kpi_classify_status(p_achievement numeric, p_green numeric DEFAULT 90, p_yellow numeric DEFAULT 70) RETURNS text
    LANGUAGE sql IMMUTABLE
    AS $$
    SELECT CASE
        WHEN p_achievement IS NULL THEN 'no_data'
        WHEN p_achievement >= p_green  THEN 'on_track'
        WHEN p_achievement >= p_yellow THEN 'at_risk'
        ELSE 'below_target'
    END;
$$;


ALTER FUNCTION public.kpi_classify_status(p_achievement numeric, p_green numeric, p_yellow numeric) OWNER TO supabase_admin;

--
-- Name: kpi_compute_achievement(numeric, numeric, text, jsonb); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.kpi_compute_achievement(p_target numeric, p_actual numeric, p_direction text, p_config jsonb DEFAULT '{}'::jsonb) RETURNS numeric
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
    v_pct numeric;
    v_min numeric;
    v_max numeric;
BEGIN
    IF p_actual IS NULL OR p_target IS NULL THEN
        RETURN NULL;
    END IF;

    IF p_direction = 'higher_is_better' THEN
        IF p_target = 0 THEN
            RETURN CASE WHEN p_actual = 0 THEN 100 ELSE NULL END;
        END IF;
        v_pct := (p_actual / p_target) * 100;
    ELSIF p_direction = 'lower_is_better' THEN
        IF p_actual = 0 THEN
            RETURN CASE WHEN p_target = 0 THEN 100 ELSE 200 END;
        END IF;
        v_pct := (p_target / p_actual) * 100;
    ELSIF p_direction = 'target_band' THEN
        v_min := COALESCE((p_config->>'band_min')::numeric, p_target * 0.9);
        v_max := COALESCE((p_config->>'band_max')::numeric, p_target * 1.1);
        IF p_actual BETWEEN v_min AND v_max THEN
            v_pct := 100;
        ELSIF p_actual < v_min THEN
            v_pct := GREATEST(0, (p_actual / NULLIF(v_min,0)) * 100);
        ELSE
            v_pct := GREATEST(0, (v_max / NULLIF(p_actual,0)) * 100);
        END IF;
    ELSE
        RETURN NULL;
    END IF;

    RETURN ROUND(v_pct, 2);
END $$;


ALTER FUNCTION public.kpi_compute_achievement(p_target numeric, p_actual numeric, p_direction text, p_config jsonb) OWNER TO supabase_admin;

--
-- Name: kpi_compute_grade(numeric, jsonb); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.kpi_compute_grade(p_score numeric, p_grade_table jsonb DEFAULT '[{"min": 95, "grade": "A+"}, {"min": 85, "grade": "A"}, {"min": 75, "grade": "B+"}, {"min": 65, "grade": "B"}, {"min": 50, "grade": "C"}, {"min": 0, "grade": "D"}]'::jsonb) RETURNS text
    LANGUAGE sql IMMUTABLE
    AS $$
    SELECT (
        SELECT g->>'grade'
        FROM jsonb_array_elements(p_grade_table) g
        WHERE p_score >= (g->>'min')::numeric
        ORDER BY (g->>'min')::numeric DESC
        LIMIT 1
    );
$$;


ALTER FUNCTION public.kpi_compute_grade(p_score numeric, p_grade_table jsonb) OWNER TO supabase_admin;

--
-- Name: kpi_compute_weighted_score(numeric, numeric, numeric); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.kpi_compute_weighted_score(p_achievement numeric, p_weight numeric, p_cap numeric DEFAULT 150) RETURNS numeric
    LANGUAGE sql IMMUTABLE
    AS $$
    SELECT CASE
        WHEN p_achievement IS NULL OR p_weight IS NULL THEN NULL
        ELSE ROUND(LEAST(p_achievement, p_cap) * p_weight / 100.0, 2)
    END;
$$;


ALTER FUNCTION public.kpi_compute_weighted_score(p_achievement numeric, p_weight numeric, p_cap numeric) OWNER TO supabase_admin;

