--
-- Name: log_qr_receive_movement(uuid, uuid, integer, numeric, uuid, text, uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.log_qr_receive_movement(p_variant_id uuid, p_warehouse_org_id uuid, p_units integer, p_unit_cost numeric, p_reference_id uuid, p_reference_no text, p_company_id uuid, p_created_by uuid, p_reason text DEFAULT 'QR items received at warehouse'::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_before int;
  v_after  int;
  v_movement_id uuid;
BEGIN
  SELECT quantity_on_hand
    INTO v_before
  FROM public.product_inventory
  WHERE variant_id = p_variant_id
    AND organization_id = p_warehouse_org_id
    AND is_active = true;

  v_after := COALESCE(v_before,0) + GREATEST(0, p_units);

  INSERT INTO public.stock_movements (
    movement_type, reference_type, reference_id, reference_no,
    variant_id, to_organization_id,
    quantity_change, quantity_before, quantity_after,
    unit_cost, manufacturer_id, warehouse_location,
    reason, notes, company_id, created_by, created_at
  )
  VALUES (
    'warehouse_receive', 'receipt', p_reference_id, p_reference_no,
    p_variant_id, p_warehouse_org_id,
    GREATEST(0, p_units),
    v_before, v_after,
    COALESCE(p_unit_cost,0),
    NULL, NULL,
    p_reason, NULL, p_company_id, p_created_by, NOW()
  )
  RETURNING id INTO v_movement_id;

  RETURN v_movement_id;
END
$$;


ALTER FUNCTION public.log_qr_receive_movement(p_variant_id uuid, p_warehouse_org_id uuid, p_units integer, p_unit_cost numeric, p_reference_id uuid, p_reference_no text, p_company_id uuid, p_created_by uuid, p_reason text) OWNER TO supabase_admin;

--
-- Name: log_qr_shipment_movement(uuid, uuid, integer, numeric, uuid, text, uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.log_qr_shipment_movement(p_variant_id uuid, p_warehouse_org_id uuid, p_units integer, p_unit_cost numeric, p_reference_id uuid, p_reference_no text, p_company_id uuid, p_created_by uuid, p_reason text DEFAULT 'QR items shipped'::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_before int;
  v_after  int;
  v_movement_id uuid;
BEGIN
  SELECT quantity_on_hand
    INTO v_before
  FROM public.product_inventory
  WHERE variant_id = p_variant_id
    AND organization_id = p_warehouse_org_id
    AND is_active = true;

  v_after := GREATEST(0, COALESCE(v_before,0) - GREATEST(0, p_units));

  INSERT INTO public.stock_movements (
    movement_type, reference_type, reference_id, reference_no,
    variant_id, to_organization_id,
    quantity_change, quantity_before, quantity_after,
    unit_cost, manufacturer_id, warehouse_location,
    reason, notes, company_id, created_by, created_at
  )
  VALUES (
    'order_fulfillment', 'order', p_reference_id, p_reference_no,
    p_variant_id, p_warehouse_org_id,
    -GREATEST(0, p_units),
    v_before, v_after,
    COALESCE(p_unit_cost,0),
    NULL, NULL,
    p_reason, NULL, p_company_id, p_created_by, NOW()
  )
  RETURNING id INTO v_movement_id;

  RETURN v_movement_id;
END
$$;


