);


ALTER TABLE public.stock_adjustments OWNER TO supabase_admin;

--
-- Name: manufacturer_acknowledge_adjustment(uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.manufacturer_acknowledge_adjustment(p_adjustment_id uuid, p_notes text DEFAULT NULL::text) RETURNS public.stock_adjustments
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_now timestamp := now();
  v_adj public.stock_adjustments%ROWTYPE;
  v_user_id uuid := auth.uid();
  v_user_org_id uuid;
BEGIN
  -- Get user's org
  SELECT organization_id INTO v_user_org_id FROM public.users WHERE id = v_user_id;

  SELECT * INTO v_adj FROM public.stock_adjustments WHERE id = p_adjustment_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Adjustment not found: %', p_adjustment_id;
  END IF;

  -- Check permission: must be assigned manufacturer OR super admin
  IF v_adj.target_manufacturer_org_id IS DISTINCT FROM v_user_org_id AND NOT public.is_super_admin() THEN
    RAISE EXCEPTION 'Not authorized to acknowledge this adjustment';
  END IF;

  -- Update status
  UPDATE public.stock_adjustments SET
    manufacturer_status = 'acknowledged',
    manufacturer_acknowledged_by = v_user_id,
    manufacturer_acknowledged_at = v_now,
    manufacturer_notes = COALESCE(p_notes, manufacturer_notes)
  WHERE id = p_adjustment_id
  RETURNING * INTO v_adj;

  -- Insert action audit
  INSERT INTO public.stock_adjustment_manufacturer_actions (adjustment_id, manufacturer_org_id, action_type, notes, created_by, created_at)
  VALUES (p_adjustment_id, COALESCE(v_user_org_id, v_adj.target_manufacturer_org_id), 'acknowledged', p_notes, v_user_id, v_now);

  RETURN v_adj;
END;
$$;


ALTER FUNCTION public.manufacturer_acknowledge_adjustment(p_adjustment_id uuid, p_notes text) OWNER TO supabase_admin;

--
-- Name: mark_batch_as_printed(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.mark_batch_as_printed(p_batch_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET statement_timeout TO '120s'
    AS $$
DECLARE
  v_batch_updated integer := 0;
  v_master_updated integer := 0;
  v_unique_updated integer := 0;
  v_chunk_size integer := 1000; -- Process 1000 codes at a time
  v_total_chunks integer := 0;
  v_processed_chunks integer := 0;
BEGIN
  -- Update batch status first (fast operation)
  UPDATE public.qr_batches
  SET 
    status = 'printing',
    updated_at = now()
  WHERE id = p_batch_id AND status = 'generated';
  
  GET DIAGNOSTICS v_batch_updated = ROW_COUNT;

  -- CRITICAL: If batch was not updated (e.g. it's processing or already printed), ABORT
  IF v_batch_updated = 0 THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Batch is not in generated status. It might be processing or already printed.',
      'batch_updated', 0,
      'master_codes_updated', 0,
      'unique_codes_updated', 0
    );
  END IF;

  -- Update master codes (typically small number)
  UPDATE public.qr_master_codes
  SET 
    status = 'printed',
    updated_at = now()
  WHERE batch_id = p_batch_id AND status = 'generated';
  
  GET DIAGNOSTICS v_master_updated = ROW_COUNT;

  -- Update unique codes in chunks to avoid timeout
  -- Use a cursor-based approach for better memory management
  LOOP
    -- Update one chunk at a time
    WITH codes_to_update AS (
      SELECT id
      FROM public.qr_codes
      WHERE batch_id = p_batch_id 
        AND status = 'generated'
      LIMIT v_chunk_size
    )
    UPDATE public.qr_codes
    SET 
      status = 'printed',
      updated_at = now()
    FROM codes_to_update
    WHERE qr_codes.id = codes_to_update.id;
    
    -- Check how many rows were updated
    GET DIAGNOSTICS v_processed_chunks = ROW_COUNT;
    v_unique_updated := v_unique_updated + v_processed_chunks;
    
    -- Exit loop if no more rows to update
    EXIT WHEN v_processed_chunks = 0;
    
    -- Optional: Add a small delay to reduce database load
    -- PERFORM pg_sleep(0.1);
  END LOOP;

  -- Return summary of updates
  RETURN jsonb_build_object(
    'success', true,
    'batch_updated', v_batch_updated,
    'master_codes_updated', v_master_updated,
    'unique_codes_updated', v_unique_updated,
    'message', format('Successfully updated batch and %s codes', v_unique_updated)
  );
  
EXCEPTION
  WHEN OTHERS THEN
    -- Return error information
    RETURN jsonb_build_object(
      'success', false,
      'error', SQLERRM,
      'error_code', SQLSTATE,
      'batch_updated', v_batch_updated,
      'master_codes_updated', v_master_updated,
      'unique_codes_updated', v_unique_updated
    );
END;
$$;


ALTER FUNCTION public.mark_batch_as_printed(p_batch_id uuid) OWNER TO supabase_admin;

--
-- Name: FUNCTION mark_batch_as_printed(p_batch_id uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.mark_batch_as_printed(p_batch_id uuid) IS 'Updates batch status to printing and marks all associated QR codes as printed. Aborts if batch is not in generated status.';


--
-- Name: mark_conversation_read(uuid, text, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.mark_conversation_read(p_conversation_id uuid, p_reader_type text, p_reader_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    IF p_reader_type = 'user' THEN
        -- Mark all admin messages as read by user
        UPDATE public.support_conversation_messages
        SET read_by_user_at = NOW()
        WHERE conversation_id = p_conversation_id
          AND sender_type != 'user'
          AND read_by_user_at IS NULL;
        
        -- Reset user unread count
        UPDATE public.support_conversations
        SET user_unread_count = 0
        WHERE id = p_conversation_id;
        
    ELSIF p_reader_type = 'admin' THEN
        -- Mark all user messages as read by admin
        UPDATE public.support_conversation_messages
        SET read_by_admin_at = NOW()
        WHERE conversation_id = p_conversation_id
          AND sender_type = 'user'
          AND read_by_admin_at IS NULL;
        
        -- Reset admin unread count
        UPDATE public.support_conversations
        SET admin_unread_count = 0
        WHERE id = p_conversation_id;
    END IF;
END;
$$;


