--
-- Name: normalize_phone_columns_trigger(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.normalize_phone_columns_trigger() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
DECLARE
    idx integer;
    column_name text;
    raw_value text;
BEGIN
    FOR idx IN 0..TG_NARGS - 1 LOOP
        column_name := TG_ARGV[idx];
        EXECUTE format('SELECT ($1).%I::text', column_name) USING NEW INTO raw_value;
        NEW := jsonb_populate_record(
            NEW,
            jsonb_build_object(column_name, public.normalize_phone_e164(raw_value))
        );
    END LOOP;

    RETURN NEW;
END;
$_$;


ALTER FUNCTION public.normalize_phone_columns_trigger() OWNER TO supabase_admin;

--
-- Name: normalize_phone_e164(text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.normalize_phone_e164(phone text) RETURNS text
    LANGUAGE plpgsql IMMUTABLE
    AS $_$
DECLARE
    cleaned text;
BEGIN
    IF phone IS NULL OR btrim(phone) = '' THEN
        RETURN NULL;
    END IF;

    cleaned := regexp_replace(phone, '[^0-9+]', '', 'g');
    IF cleaned IS NULL OR cleaned = '' THEN
        RETURN NULL;
    END IF;

    IF cleaned ~ '^\+' THEN
        cleaned := regexp_replace(cleaned, '^\+', '');
    ELSIF cleaned ~ '^00' THEN
        cleaned := substring(cleaned FROM 3);
    ELSIF cleaned ~ '^0' THEN
        cleaned := '60' || substring(cleaned FROM 2);
    ELSIF cleaned ~ '^1[0-9]{7,9}$' THEN
        cleaned := '60' || cleaned;
    END IF;

    IF cleaned !~ '^[1-9][0-9]{7,14}$' THEN
        RETURN NULL;
    END IF;

    RETURN '+' || cleaned;
END;
$_$;


ALTER FUNCTION public.normalize_phone_e164(phone text) OWNER TO supabase_admin;

--
-- Name: on_support_message_insert(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.on_support_message_insert() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
begin
  -- Update thread last message info
  update public.support_threads
  set
    last_message_at = new.created_at,
    last_message_preview = left(new.body, 120),

    -- Status logic:
    -- user sends -> open
    -- admin sends -> pending
    status = case
      when new.sender_type = 'user' then 'open'::support_thread_status
      when new.sender_type = 'admin' then 'pending'::support_thread_status
      else status
    end
  where id = new.thread_id;

  return new;
end;
$$;


ALTER FUNCTION public.on_support_message_insert() OWNER TO supabase_admin;

--
-- Name: on_support_message_read_init(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.on_support_message_read_init() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
begin
  insert into public.support_thread_reads (thread_id, user_id, last_read_at)
  values (new.thread_id, new.sender_user_id, now())
  on conflict (thread_id, user_id)
  do update set last_read_at = excluded.last_read_at;

  return new;
end;
$$;


ALTER FUNCTION public.on_support_message_read_init() OWNER TO supabase_admin;

