--
-- Name: orders_approve(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.orders_approve(p_order_id uuid) RETURNS public.orders
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v public.orders;
  v_user_org uuid;
  v_user_org_type text;
  v_can boolean := false;
  v_po_doc_no text;
  v_item record;
  v_current_qty integer;
  v_current_allocated integer;
  v_inventory_org_id uuid;
  v_seller_type text;
  v_wh_id uuid;
  v_buyer_current_qty integer;
  v_creator_level integer;
  v_user_level integer;
  v_has_authority boolean;
BEGIN
  -- 1) CHECKS & PERMISSIONS (UNCHANGED)
  SELECT * INTO v FROM public.orders WHERE id = p_order_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Order not found'; END IF;
  IF v.status <> 'submitted' THEN RAISE EXCEPTION 'Order must be in submitted'; END IF;

  SELECT organization_id INTO v_user_org FROM public.users WHERE id = auth.uid();
  v_user_org_type := public.get_org_type(v_user_org);

  SELECT r.role_level INTO v_creator_level
  FROM public.users u
  JOIN public.roles r ON u.role_code = r.role_code
  WHERE u.id = v.created_by;

  SELECT r.role_level INTO v_user_level
  FROM public.users u
  JOIN public.roles r ON u.role_code = r.role_code
  WHERE u.id = auth.uid();

  v_creator_level := COALESCE(v_creator_level, 999);
  v_user_level := COALESCE(v_user_level, 999);

  IF v_creator_level = 10 THEN
      v_has_authority := (v_user_level = 10 OR v_user_level = 20);
  ELSE
      v_has_authority := (v_user_level < v_creator_level);
  END IF;

  CASE v.order_type
    WHEN 'H2M' THEN
      IF v_user_org_type='HQ' AND v_has_authority THEN v_can := true; END IF;
    WHEN 'D2H' THEN
      IF v_user_org_type='HQ' AND (v_has_authority OR
          EXISTS (SELECT 1 FROM pg_proc WHERE proname='is_hq_admin' AND pg_function_is_visible(oid) AND public.is_hq_admin())) THEN
        v_can := true;
      END IF;
    WHEN 'S2D' THEN
      IF v_user_org = v.seller_org_id AND v_has_authority THEN v_can := true; END IF;
  END CASE;

  IF NOT v_can THEN
    RAISE EXCEPTION 'User lacks permission to approve this order type';
  END IF;

  IF v.parent_order_id IS NOT NULL THEN
    IF NOT EXISTS (SELECT 1 FROM public.orders WHERE id=v.parent_order_id AND status='approved') THEN
      RAISE EXCEPTION 'Parent order must be approved first';
    END IF;
    PERFORM public.validate_child_quantities(p_order_id, v.parent_order_id);
  END IF;

  v_inventory_org_id := v.seller_org_id;

  SELECT org_type_code INTO v_seller_type FROM public.organizations WHERE id = v.seller_org_id;
  IF v_seller_type = 'HQ' THEN
      SELECT id INTO v_wh_id FROM public.organizations
      WHERE parent_org_id = v.seller_org_id AND org_type_code = 'WH' AND is_active = true LIMIT 1;

      IF v_wh_id IS NOT NULL THEN
          v_inventory_org_id := v_wh_id;
      END IF;
  END IF;

  -- 2) STOCK MOVEMENTS (UNCHANGED)
  IF v.order_type IN ('D2H', 'S2D') THEN
    FOR v_item IN SELECT * FROM public.order_items WHERE order_id = v.id LOOP
        SELECT quantity_on_hand, quantity_allocated
        INTO v_current_qty, v_current_allocated
        FROM public.product_inventory
        WHERE variant_id = v_item.variant_id AND organization_id = v_inventory_org_id
        FOR UPDATE;

        IF v_current_qty IS NULL THEN
            RAISE EXCEPTION 'Inventory not found for variant %', v_item.variant_id;
        END IF;

        IF v_current_qty < v_item.qty THEN
            RAISE EXCEPTION 'Insufficient stock for variant %. On hand: %, Needed: %',
                v_item.variant_id, v_current_qty, v_item.qty;
        END IF;

        UPDATE public.product_inventory
        SET
            quantity_allocated = GREATEST(0, quantity_allocated - v_item.qty),
            quantity_on_hand = quantity_on_hand - v_item.qty,
            updated_at = now()
        WHERE variant_id = v_item.variant_id AND organization_id = v_inventory_org_id;

        INSERT INTO public.product_inventory (organization_id, variant_id, quantity_on_hand)
        VALUES (v.buyer_org_id, v_item.variant_id, 0)
        ON CONFLICT (organization_id, variant_id) DO NOTHING;

        SELECT quantity_on_hand INTO v_buyer_current_qty
        FROM public.product_inventory
        WHERE variant_id = v_item.variant_id AND organization_id = v.buyer_org_id;

        UPDATE public.product_inventory
        SET quantity_on_hand = quantity_on_hand + v_item.qty,
            updated_at = now()
        WHERE variant_id = v_item.variant_id AND organization_id = v.buyer_org_id;

        INSERT INTO public.stock_movements (
            movement_type, reference_type, reference_id, reference_no,
            variant_id, from_organization_id, to_organization_id,
            quantity_change, quantity_before, quantity_after,
            company_id, created_by, created_at, notes
        ) VALUES (
            'transfer_in', 'order', v.id, v.order_no,
            v_item.variant_id, v_inventory_org_id, v.buyer_org_id,
            v_item.qty, v_buyer_current_qty, v_buyer_current_qty + v_item.qty,
            v.company_id, auth.uid(), now(),
            'Order approved - stock received from seller'
        );
    END LOOP;
  END IF;

  -- 3) DOCUMENT GENERATION (PATCHED + GUARDED)
  IF v.order_type IN ('D2H', 'S2D') THEN

      -- SO (NEW - must exist)
      IF NOT EXISTS (SELECT 1 FROM public.documents WHERE order_id = v.id AND doc_type = 'SO') THEN
          INSERT INTO public.documents (
            company_id, order_id, doc_type, doc_no, status,
            issued_by_org_id, issued_to_org_id, created_by, created_at, updated_at
          ) VALUES (
            v.company_id, v.id, 'SO', v.order_no, 'pending',
            v.seller_org_id, v.buyer_org_id, auth.uid(), now(), now()
          );
      END IF;

      -- DO (guarded)
      IF NOT EXISTS (SELECT 1 FROM public.documents WHERE order_id = v.id AND doc_type = 'DO') THEN
          INSERT INTO public.documents (
            company_id, order_id, doc_type, doc_no, status,
            issued_by_org_id, issued_to_org_id, created_by, created_at, updated_at
          ) VALUES (
            v.company_id, v.id, 'DO', 'DO-' || v.order_no, 'pending',
            v.seller_org_id, v.buyer_org_id, auth.uid(), now(), now()
          );
      END IF;

      -- INVOICE (guarded)
      IF NOT EXISTS (SELECT 1 FROM public.documents WHERE order_id = v.id AND doc_type = 'INVOICE') THEN
          INSERT INTO public.documents (
            company_id, order_id, doc_type, doc_no, status,
            issued_by_org_id, issued_to_org_id, created_by, created_at, updated_at
          ) VALUES (
            v.company_id, v.id, 'INVOICE', 'INV-' || v.order_no, 'pending',
            v.seller_org_id, v.buyer_org_id, auth.uid(), now(), now()
          );
      END IF;

  ELSE
      -- H2M -> PO (guarded)
      IF NOT EXISTS (SELECT 1 FROM public.documents WHERE order_id = v.id AND doc_type = 'PO') THEN
          v_po_doc_no := 'PO-' || v.order_no;
          INSERT INTO public.documents (
            company_id, order_id, doc_type, doc_no, status,
            issued_by_org_id, issued_to_org_id, created_by, created_at, updated_at
          ) VALUES (
            v.company_id, v.id, 'PO', v_po_doc_no, 'pending',
            v.buyer_org_id, v.seller_org_id, auth.uid(), now(), now()
          );
      END IF;
  END IF;

  -- 4) UPDATE ORDER STATUS (UNCHANGED)
  UPDATE public.orders
     SET status='approved',
         approved_by=auth.uid(),
         approved_at=now(),
         updated_by=auth.uid(),
         updated_at=now()
     WHERE id = p_order_id
     RETURNING * INTO v;

  RETURN v;
END;
$$;


ALTER FUNCTION public.orders_approve(p_order_id uuid) OWNER TO supabase_admin;

--
-- Name: FUNCTION orders_approve(p_order_id uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.orders_approve(p_order_id uuid) IS 'Approves order and triggers fulfillment (release allocation + deduct stock) for D2H/S2D orders. Allocation happens on submission, not approval.';


--
-- Name: orders_before_insert(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.orders_before_insert() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_order_type_code text;
BEGIN
  -- Detect order type if not provided
  IF NEW.order_type IS NULL THEN
    NEW.order_type := public.detect_order_type(NEW.buyer_org_id, NEW.seller_org_id);
  END IF;

  -- Ensure company_id (root HQ of buyer)
  IF NEW.company_id IS NULL THEN
    NEW.company_id := public.get_company_id(NEW.buyer_org_id);
  END IF;

  -- Generate LEGACY human order number using 2-digit sequence (unchanged for QR codes)
  v_order_type_code := replace(NEW.order_type::text, '2', ''); -- H2M→HM, D2H→DH, S2D→SD
  NEW.order_no := public.generate_doc_number(NEW.company_id, 'ORD', v_order_type_code);

  -- REMOVED: NEW.display_doc_no := public.generate_display_doc_number(NEW.company_id, 'ORD');
  -- This is now handled by orders_auto_display_doc_no trigger

  -- Set created_by if missing
  IF NEW.created_by IS NULL THEN
    NEW.created_by := auth.uid();
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.orders_before_insert() OWNER TO supabase_admin;

--
-- Name: orders_submit(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.orders_submit(p_order_id uuid) RETURNS public.orders
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE v public.orders; v_items int;
BEGIN
  SELECT * INTO v FROM public.orders WHERE id = p_order_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Order not found'; END IF;
  IF v.status <> 'draft' THEN RAISE EXCEPTION 'Order must be in draft'; END IF;

  SELECT COUNT(*) INTO v_items FROM public.order_items WHERE order_id = p_order_id;
  IF v_items = 0 THEN RAISE EXCEPTION 'Order must have at least one item'; END IF;

  IF v.parent_order_id IS NOT NULL THEN
    PERFORM public.validate_child_items(p_order_id, v.parent_order_id);
  END IF;

  UPDATE public.orders
     SET status='submitted', updated_by=auth.uid(), updated_at=now()
   WHERE id=p_order_id
   RETURNING * INTO v;

  RETURN v;
END;
$$;


ALTER FUNCTION public.orders_submit(p_order_id uuid) OWNER TO supabase_admin;

--
-- Name: payment_acknowledge(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.payment_acknowledge(p_document_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  d public.documents;
  o public.orders;
  v_rcpt_id uuid;
  v_ack_cnt integer := 0;
  v_payment_percentage integer := 100;
  v_order_total numeric := 0;
  v_deposit_pct numeric := 0.5;
  v_balance_pct numeric := 0.5;
  v_deposit_amount numeric := 0;
  v_balance_amount numeric := 0;
  v_receipt_amount numeric := 0;
  v_actual_pct numeric := 100;
  v_is_split boolean := false;
  v_is_deposit boolean := false;
  v_is_final boolean := false;
  v_key text;
  v_value_text text;
  v_candidate numeric;
  v_parsed_amount numeric := NULL;
  v_doc_suffix text := '';
  v_receipt_doc_no text;
BEGIN
  -- Lock & fetch the PAYMENT document (must be pending)
  SELECT * INTO d
  FROM public.documents
  WHERE id = p_document_id
    AND doc_type = 'PAYMENT'
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Payment document not found';
  END IF;

  IF d.status <> 'pending' THEN
    RAISE EXCEPTION 'Payment must be pending';
  END IF;

  -- Load order info
  SELECT * INTO o FROM public.orders WHERE id = d.order_id;

  -- Calculate order total from items (fallback for receipts)
  SELECT COALESCE(SUM(line_total), 0)
    INTO v_order_total
  FROM public.order_items
  WHERE order_id = o.id;

  -- Attempt to parse an explicit amount from the payment payload
  FOR v_key IN SELECT key FROM (VALUES
      ('amount'),
      ('payment_amount'),
      ('balance_amount'),
      ('requested_amount'),
      ('total_amount')
    ) AS keys(key)
  LOOP
    v_value_text := NULLIF(d.payload->>v_key, '');
    IF v_value_text IS NULL THEN
      CONTINUE;
    END IF;

    BEGIN
      v_candidate := v_value_text::numeric;
      v_parsed_amount := v_candidate;
      EXIT;
    EXCEPTION WHEN invalid_text_representation THEN
      CONTINUE;
    END;
  END LOOP;

  -- Extract payment term percentages (default 50/50)
  IF o.payment_terms IS NOT NULL THEN
    v_value_text := NULLIF(o.payment_terms->>'deposit_pct', '');
    IF v_value_text IS NOT NULL THEN
      BEGIN
        v_candidate := v_value_text::numeric;
        v_deposit_pct := v_candidate;
      EXCEPTION WHEN invalid_text_representation THEN
        NULL;
      END;
    END IF;

    v_value_text := NULLIF(o.payment_terms->>'balance_pct', '');
    IF v_value_text IS NOT NULL THEN
      BEGIN
        v_candidate := v_value_text::numeric;
        v_balance_pct := v_candidate;
      EXCEPTION WHEN invalid_text_representation THEN
        NULL;
      END;
    END IF;
  END IF;

  -- Normalise to 0..1 range if provided as percentages
  IF v_deposit_pct > 1 THEN
    v_deposit_pct := v_deposit_pct / 100;
  END IF;
  IF v_balance_pct > 1 THEN
    v_balance_pct := v_balance_pct / 100;
  END IF;

  IF v_deposit_pct < 0 THEN
    v_deposit_pct := 0;
  END IF;
  IF v_balance_pct < 0 THEN
    v_balance_pct := 0;
  END IF;

  IF v_deposit_pct + v_balance_pct <= 0 THEN
    v_deposit_pct := 0;
    v_balance_pct := 1;
  END IF;

  v_is_split := v_deposit_pct > 0.001 AND v_deposit_pct < 0.999;

  -- Pre-compute amounts for split flows
  v_deposit_amount := ROUND(GREATEST(v_order_total * v_deposit_pct, 0), 2);
  v_balance_amount := ROUND(GREATEST(v_order_total - v_deposit_amount, 0), 2);

  -- Record a digital signature
  PERFORM public.add_document_signature(
    p_document_id,
    auth.uid(),
    (SELECT role_code FROM public.users WHERE id = auth.uid())
  );

  -- Acknowledge the payment document
  UPDATE public.documents
     SET status = 'acknowledged',
         acknowledged_by = auth.uid(),
         acknowledged_at = NOW(),
         updated_at = NOW()
   WHERE id = p_document_id
   RETURNING * INTO d;

  -- Determine if another payment was previously acknowledged
  SELECT COUNT(*)
    INTO v_ack_cnt
  FROM public.documents
  WHERE order_id = o.id
    AND doc_type = 'PAYMENT'
    AND status = 'acknowledged'
    AND id <> p_document_id;

  IF v_is_split THEN
    IF v_ack_cnt >= 1 THEN
      -- Final/Balance receipt
      v_is_final := TRUE;
      v_receipt_amount := COALESCE(NULLIF(v_balance_amount, 0), v_parsed_amount, v_order_total);
      v_payment_percentage := 100;
      v_doc_suffix := '-BAL';  -- Balance receipt suffix
    ELSE
      -- Deposit receipt
      v_is_deposit := TRUE;
      v_receipt_amount := COALESCE(NULLIF(v_deposit_amount, 0), v_parsed_amount, v_order_total);
      v_payment_percentage := LEAST(100, GREATEST(ROUND(v_deposit_pct * 100)::int, 1));
      v_doc_suffix := '-DEP';  -- Deposit receipt suffix
    END IF;
  ELSE
    -- Single payment flow (no suffix needed)
    v_is_final := TRUE;
    v_receipt_amount := COALESCE(v_parsed_amount, v_order_total);
    v_payment_percentage := 100;
    v_doc_suffix := '';
  END IF;

  v_receipt_amount := ROUND(GREATEST(COALESCE(v_receipt_amount, 0), 0), 2);
  v_deposit_amount := ROUND(GREATEST(v_deposit_amount, 0), 2);
  v_balance_amount := ROUND(GREATEST(v_balance_amount, 0), 2);

  IF v_order_total > 0 THEN
    v_actual_pct := ROUND((v_receipt_amount / v_order_total) * 100, 2);
  ELSE
    v_actual_pct := 100;
  END IF;

  IF v_is_final THEN
    v_payment_percentage := 100;
  ELSIF v_payment_percentage <= 0 THEN
    v_payment_percentage := LEAST(100, GREATEST(ROUND(v_actual_pct)::int, 1));
  END IF;

  -- Generate base receipt number (matching current schema logic)
  IF o.order_no IS NOT NULL THEN
    v_receipt_doc_no := public.format_doc_no_from_order('RCPT', o.order_no);
  ELSE
    v_receipt_doc_no := public.format_doc_no_from_order('RCPT', d.doc_no);
  END IF;

  IF v_receipt_doc_no IS NULL OR v_receipt_doc_no = 'RCPT-' THEN
    v_receipt_doc_no := public.generate_doc_number(o.company_id, 'RCPT', REPLACE(o.order_type::TEXT, '2',''));
  END IF;
  
  -- Add suffix to differentiate deposit and balance receipts
  v_receipt_doc_no := v_receipt_doc_no || v_doc_suffix;

  -- Insert the corresponding receipt document
  INSERT INTO public.documents (
    order_id,
    doc_type,
    doc_no,
    status,
    issued_by_org_id,
    issued_to_org_id,
    company_id,
    created_by,
    payment_percentage,
    payload
  )
  VALUES (
    o.id,
    'RECEIPT',
    v_receipt_doc_no,
    'completed',
    o.seller_org_id,
    o.buyer_org_id,
    o.company_id,
    auth.uid(),
    v_payment_percentage,
    jsonb_build_object(
      'payment_id', d.id,
      'payment_no', d.doc_no,
      'payment_amount', v_receipt_amount,
      'payment_percentage', v_payment_percentage,
      'actual_payment_percentage', v_actual_pct,
      'order_total', v_order_total,
      'deposit_amount', v_deposit_amount,
      'balance_amount', v_balance_amount,
      'is_deposit_receipt', v_is_deposit,
      'is_final_receipt', v_is_final
    )
  )
  RETURNING id INTO v_rcpt_id;

  -- Close the order when the final payment is acknowledged
  IF v_is_final THEN
    UPDATE public.orders
       SET status = 'closed',
           updated_at = NOW()
     WHERE id = o.id;
  END IF;

  RETURN;
END;
$$;


ALTER FUNCTION public.payment_acknowledge(p_document_id uuid) OWNER TO supabase_admin;

--
-- Name: play_scratch_card_turn(uuid, text, uuid, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.play_scratch_card_turn(p_campaign_id uuid DEFAULT NULL::uuid, p_consumer_phone text DEFAULT NULL::text, p_qr_code_id uuid DEFAULT NULL::uuid, p_journey_config_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_campaign RECORD;
    v_reward RECORD;
    v_total_prob FLOAT := 0;
    v_random_val FLOAT;
    v_cumulative_prob FLOAT := 0;
    v_selected_reward_id UUID;
    v_play_id UUID;
    v_plays_today INT;
    v_plays_total INT;
    v_plays_qr INT;
    v_user_org_id UUID;
    v_transaction_id UUID;
    v_current_balance INT;
BEGIN
    IF p_campaign_id IS NOT NULL THEN
        SELECT * INTO v_campaign FROM scratch_card_campaigns WHERE id = p_campaign_id;
    ELSIF p_journey_config_id IS NOT NULL THEN
        SELECT * INTO v_campaign FROM scratch_card_campaigns 
        WHERE journey_config_id = p_journey_config_id 
        AND status = 'active'
        LIMIT 1;
    ELSE
        RETURN jsonb_build_object('error', 'Campaign ID or Journey Config ID required', 'code', 'MISSING_ID');
    END IF;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('error', 'Campaign not found', 'code', 'CAMPAIGN_NOT_FOUND');
    END IF;

    p_campaign_id := v_campaign.id;

    IF v_campaign.status != 'active' THEN
        RETURN jsonb_build_object('error', 'Campaign is not active', 'code', 'CAMPAIGN_NOT_ACTIVE');
    END IF;

    IF v_campaign.start_at IS NOT NULL AND NOW() < v_campaign.start_at THEN
        RETURN jsonb_build_object('error', 'Campaign has not started', 'code', 'CAMPAIGN_NOT_STARTED');
    END IF;

    IF v_campaign.end_at IS NOT NULL AND NOW() > v_campaign.end_at THEN
        RETURN jsonb_build_object('error', 'Campaign has ended', 'code', 'CAMPAIGN_ENDED');
    END IF;

    SELECT COUNT(*) INTO v_plays_today 
    FROM scratch_card_plays 
    WHERE campaign_id = p_campaign_id 
    AND consumer_phone = p_consumer_phone
    AND played_at >= CURRENT_DATE;

    IF v_campaign.max_plays_per_day IS NOT NULL AND v_plays_today >= v_campaign.max_plays_per_day THEN
        RETURN jsonb_build_object('error', 'Daily play limit reached', 'code', 'DAILY_LIMIT_REACHED');
    END IF;

    IF v_campaign.max_plays_total_per_consumer IS NOT NULL THEN
        SELECT COUNT(*) INTO v_plays_total
        FROM scratch_card_plays 
        WHERE campaign_id = p_campaign_id 
        AND consumer_phone = p_consumer_phone;

        IF v_plays_total >= v_campaign.max_plays_total_per_consumer THEN
            RETURN jsonb_build_object('error', 'Total play limit reached', 'code', 'TOTAL_LIMIT_REACHED');
        END IF;
    END IF;

    IF p_qr_code_id IS NOT NULL AND v_campaign.plays_per_qr IS NOT NULL THEN
        SELECT COUNT(*) INTO v_plays_qr
        FROM scratch_card_plays
        WHERE campaign_id = p_campaign_id
        AND qr_code_id = p_qr_code_id;

        IF v_plays_qr >= v_campaign.plays_per_qr THEN
             RETURN jsonb_build_object('error', 'QR play limit reached', 'code', 'QR_LIMIT_REACHED');
        END IF;
    END IF;

    CREATE TEMP TABLE temp_eligible_rewards ON COMMIT DROP AS
    SELECT * FROM scratch_card_rewards 
    WHERE campaign_id = p_campaign_id 
    AND is_active = true
    AND (
        (type = 'product' AND quantity_remaining > 0)
        OR
        (type != 'product' AND (quantity_allocated = 0 OR quantity_remaining > 0))
    );

    IF NOT EXISTS (SELECT 1 FROM temp_eligible_rewards) THEN
        RETURN jsonb_build_object('error', 'No rewards available', 'code', 'NO_REWARDS');
    END IF;

    SELECT SUM(COALESCE(quantity_remaining, 0)) INTO v_total_prob FROM temp_eligible_rewards;
    
    IF v_total_prob IS NULL OR v_total_prob = 0 THEN
         SELECT id INTO v_selected_reward_id 
         FROM temp_eligible_rewards 
         WHERE quantity_allocated = 0 
         LIMIT 1;
         
         IF v_selected_reward_id IS NULL THEN
            SELECT id INTO v_selected_reward_id FROM temp_eligible_rewards ORDER BY random() LIMIT 1;
         END IF;
    ELSE
        v_random_val := floor(random() * v_total_prob);
        
        SELECT id INTO v_selected_reward_id
        FROM (
            SELECT id, SUM(COALESCE(quantity_remaining, 0)) OVER (ORDER BY id) as cum_prob
            FROM temp_eligible_rewards
        ) t
        WHERE cum_prob > v_random_val
        LIMIT 1;
    END IF;

    SELECT 
        r.*,
        pv.image_url as variant_image_url,
        p.product_name as product_name,
        pv.variant_name as variant_name
    INTO v_reward 
    FROM scratch_card_rewards r
    LEFT JOIN product_variants pv ON r.variant_id = pv.id
    LEFT JOIN products p ON r.product_id = p.id
    WHERE r.id = v_selected_reward_id;

    INSERT INTO scratch_card_plays (
        campaign_id,
        qr_code_id,
        consumer_phone,
        reward_id,
        is_win,
        played_at
    ) VALUES (
        p_campaign_id,
        p_qr_code_id,
        p_consumer_phone,
        v_selected_reward_id,
        v_reward.type != 'no_prize',
        NOW()
    ) RETURNING id INTO v_play_id;

    IF v_reward.quantity_allocated > 0 THEN
        UPDATE scratch_card_rewards
        SET quantity_remaining = quantity_remaining - 1
        WHERE id = v_selected_reward_id;
    END IF;

    -- NEW: Save points to points_transactions table when user wins points
    IF v_reward.type = 'points' AND v_reward.value_points > 0 AND p_consumer_phone IS NOT NULL THEN
        SELECT organization_id INTO v_user_org_id 
        FROM users 
        WHERE phone = p_consumer_phone 
        LIMIT 1;
        
        IF v_user_org_id IS NOT NULL THEN
            SELECT COALESCE(current_balance, 0) INTO v_current_balance
            FROM v_shop_points_balance
            WHERE shop_id = v_user_org_id;
            
            IF v_current_balance IS NULL THEN
                v_current_balance := 0;
            END IF;

            INSERT INTO points_transactions (
                id,
                company_id,
                consumer_phone,
                transaction_type,
                points_amount,
                balance_after,
                qr_code_id,
                description,
                transaction_date,
                created_at
            ) VALUES (
                gen_random_uuid(),
                v_user_org_id,
                p_consumer_phone,
                'game_win',
                v_reward.value_points,
                v_current_balance + v_reward.value_points,
                p_qr_code_id,
                'Won ' || v_reward.value_points || ' points from Scratch Card: ' || COALESCE(v_reward.name, 'Game Reward'),
                NOW(),
                NOW()
            ) RETURNING id INTO v_transaction_id;
            
            UPDATE scratch_card_plays
            SET is_claimed = true,
                claimed_at = NOW(),
                shop_id = v_user_org_id,
                claim_details = jsonb_build_object('auto_claimed', true, 'transaction_id', v_transaction_id)
            WHERE id = v_play_id;
        END IF;
    END IF;

    RETURN jsonb_build_object(
        'success', true,
        'play_id', v_play_id,
        'reward', jsonb_build_object(
            'id', v_reward.id,
            'name', v_reward.name,
            'type', v_reward.type,
            'value_points', v_reward.value_points,
            'image_url', COALESCE(v_reward.image_url, v_reward.variant_image_url),
            'product_name', v_reward.product_name,
            'variant_name', v_reward.variant_name
        ),
        'points_added', CASE 
            WHEN v_reward.type = 'points' AND v_reward.value_points > 0 AND v_user_org_id IS NOT NULL 
            THEN true 
            ELSE false 
        END
    );
END;
$$;


ALTER FUNCTION public.play_scratch_card_turn(p_campaign_id uuid, p_consumer_phone text, p_qr_code_id uuid, p_journey_config_id uuid) OWNER TO supabase_admin;

--
-- Name: po_acknowledge(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.po_acknowledge(p_document_id uuid) RETURNS public.documents
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE 
  d public.documents; 
  o public.orders; 
  v_inv_id uuid;
  v_invoice_no text;
BEGIN
  SELECT * INTO d FROM public.documents
   WHERE id = p_document_id AND doc_type = 'PO'
   FOR UPDATE;
   
  IF NOT FOUND THEN 
    RAISE EXCEPTION 'PO document not found'; 
  END IF;
  
  IF d.status <> 'pending' THEN 
    RAISE EXCEPTION 'PO must be pending'; 
  END IF;

  SELECT * INTO o FROM public.orders WHERE id = d.order_id;

  PERFORM public.add_document_signature(
    p_document_id,
    auth.uid(),
    (SELECT role_code FROM public.users WHERE id = auth.uid())
  );

  UPDATE public.documents
     SET status = 'acknowledged', 
         acknowledged_by = auth.uid(),
         acknowledged_at = NOW(), 
         updated_at = NOW()
   WHERE id = p_document_id
   RETURNING * INTO d;

  v_invoice_no := public.format_doc_no_from_order('INV', o.order_no);

  INSERT INTO public.documents (
    order_id, doc_type, doc_no, status,
    issued_by_org_id, issued_to_org_id,
    company_id, created_by, payload
  )
  VALUES (
    o.id, 'INVOICE',
    v_invoice_no,
    'pending',
    o.seller_org_id,
    o.buyer_org_id,
    o.company_id, auth.uid(),
    jsonb_build_object('po_id', p_document_id)
  )
  RETURNING id INTO v_inv_id;

  RETURN d;
END;
$$;


ALTER FUNCTION public.po_acknowledge(p_document_id uuid) OWNER TO supabase_admin;

--
-- Name: FUNCTION po_acknowledge(p_document_id uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.po_acknowledge(p_document_id uuid) IS 'Acknowledges PO and records digital signature. Auto-generates Invoice document.';


--
-- Name: post_customer_receipt_to_gl(uuid, date); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.post_customer_receipt_to_gl(p_receipt_id uuid, p_posting_date date DEFAULT CURRENT_DATE) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_receipt record;
    v_company_id uuid;
    v_result jsonb;
BEGIN
    v_company_id := public.get_user_company_id();
    
    -- Validate receipt exists
    SELECT * INTO v_receipt
    FROM public.documents d
    WHERE d.id = p_receipt_id 
    AND d.doc_type = 'RECEIPT'
    AND d.company_id = v_company_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Receipt document not found or access denied'
        );
    END IF;
    
    -- Verify receipt is for a D2H order (customer receipt)
    PERFORM 1
    FROM public.orders o
    WHERE o.id = v_receipt.order_id
    AND o.order_type IN ('DH', 'D2H');
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Receipt is not for a D2H (customer) order'
        );
    END IF;
    
    -- Use the main GL posting function
    v_result := public.post_document_to_gl('RECEIPT', p_receipt_id, p_posting_date);
    
    RETURN v_result;
EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object(
        'success', false,
        'error', SQLERRM
    );
END;
$$;


ALTER FUNCTION public.post_customer_receipt_to_gl(p_receipt_id uuid, p_posting_date date) OWNER TO supabase_admin;

--
-- Name: post_document_to_gl(text, uuid, date); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.post_document_to_gl(p_document_type text, p_document_id uuid, p_posting_date date DEFAULT CURRENT_DATE) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_company_id uuid;
    v_journal_id uuid;
    v_journal_number text;
    v_journal_type text;
    v_preview jsonb;
    v_line jsonb;
    v_line_number integer := 0;
    v_total_debit numeric(18,2) := 0;
    v_total_credit numeric(18,2) := 0;
    v_doc_number text;
BEGIN
    -- Check permission
    IF NOT public.is_hq_admin() THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Only HQ Admins can post to GL'
        );
    END IF;
    
    v_company_id := public.get_user_company_id();
    
    -- Check idempotency
    IF public.is_document_posted(p_document_type, p_document_id) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Document is already posted to GL'
        );
    END IF;
    
    -- Get posting preview
    v_preview := public.get_posting_preview(p_document_type, p_document_id);
    
    IF NOT (v_preview->>'success')::boolean THEN
        RETURN v_preview;
    END IF;
    
    -- Determine journal type
    v_journal_type := CASE p_document_type
        WHEN 'SUPPLIER_DEPOSIT_PAYMENT' THEN 'SUPPLIER_DEPOSIT'
        WHEN 'SUPPLIER_INVOICE_RECOGNITION' THEN 'SUPPLIER_PAYMENT'
        WHEN 'SUPPLIER_BALANCE_PAYMENT' THEN 'SUPPLIER_PAYMENT'
        WHEN 'SALES_INVOICE' THEN 'SALES_INVOICE'
        WHEN 'RECEIPT' THEN 'RECEIPT'
        ELSE 'ADJUSTMENT'
    END;
    
    -- Generate journal number
    v_journal_number := public.generate_journal_number(v_company_id, v_journal_type);
    
    -- Calculate totals
    FOR v_line IN SELECT * FROM jsonb_array_elements(v_preview->'lines')
    LOOP
        v_total_debit := v_total_debit + COALESCE((v_line->>'debit')::numeric, 0);
        v_total_credit := v_total_credit + COALESCE((v_line->>'credit')::numeric, 0);
    END LOOP;
    
    -- Validate balance
    IF v_total_debit <> v_total_credit THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Journal is not balanced. Debit: ' || v_total_debit || ', Credit: ' || v_total_credit
        );
    END IF;
    
    -- Get document number for reference - PREFER display_doc_no (new format) over doc_no (legacy)
    SELECT COALESCE(display_doc_no, doc_no) INTO v_doc_number 
    FROM public.documents 
    WHERE id = p_document_id;
    
    -- For SALES_INVOICE from orders, use order's display_doc_no
    IF v_doc_number IS NULL AND p_document_type = 'SALES_INVOICE' THEN
        SELECT COALESCE(display_doc_no, order_no) INTO v_doc_number 
        FROM public.orders 
        WHERE id = p_document_id;
    END IF;
    
    -- Create journal header
    INSERT INTO public.gl_journals (
        company_id,
        journal_number,
        journal_date,
        posting_date,
        description,
        journal_type,
        status,
        total_debit,
        total_credit,
        created_by,
        posted_by,
        posted_at
    ) VALUES (
        v_company_id,
        v_journal_number,
        p_posting_date,
        p_posting_date,
        COALESCE(v_preview->>'description', 'Journal Entry'),
        v_journal_type,
        'POSTED',
        v_total_debit,
        v_total_credit,
        auth.uid(),
        auth.uid(),
        now()
    ) RETURNING id INTO v_journal_id;
    
    -- Create journal lines
    FOR v_line IN SELECT * FROM jsonb_array_elements(v_preview->'lines')
    LOOP
        v_line_number := v_line_number + 1;
        
        INSERT INTO public.gl_journal_lines (
            journal_id,
            account_id,
            line_number,
            description,
            debit_amount,
            credit_amount,
            entity_type,
            entity_id,
            created_by
        ) VALUES (
            v_journal_id,
            (v_line->>'account_id')::uuid,
            v_line_number,
            v_line->>'description',
            COALESCE((v_line->>'debit')::numeric, 0),
            COALESCE((v_line->>'credit')::numeric, 0),
            CASE 
                WHEN v_line->>'entity_type' = '' THEN NULL 
                ELSE v_line->>'entity_type' 
            END,
            CASE 
                WHEN v_line->>'entity_id' = '' THEN NULL 
                ELSE (v_line->>'entity_id')::uuid 
            END,
            auth.uid()
        );
    END LOOP;
    
    -- Record the document posting (idempotency tracking) - NOW USING NEW DOCUMENT FORMAT
    INSERT INTO public.gl_document_postings (
        company_id,
        document_type,
        document_id,
        document_number,
        journal_id,
        posted_amount,
        posting_status,
        created_by
    ) VALUES (
        v_company_id,
        p_document_type,
        p_document_id,
        v_doc_number,  -- This now contains display_doc_no (new format)
        v_journal_id,
        v_total_debit,
        'POSTED',
        auth.uid()
    );
    
    RETURN jsonb_build_object(
        'success', true,
        'journal_id', v_journal_id,
        'journal_number', v_journal_number,
        'document_type', p_document_type,
        'document_id', p_document_id,
        'document_number', v_doc_number,
        'posted_amount', v_total_debit,
        'posting_date', p_posting_date,
        'lines_created', v_line_number
    );
END;
$$;


ALTER FUNCTION public.post_document_to_gl(p_document_type text, p_document_id uuid, p_posting_date date) OWNER TO supabase_admin;

--
-- Name: FUNCTION post_document_to_gl(p_document_type text, p_document_id uuid, p_posting_date date); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.post_document_to_gl(p_document_type text, p_document_id uuid, p_posting_date date) IS 'Post a document to GL. Uses display_doc_no (new format) for audit trail. Supported types: SUPPLIER_DEPOSIT_PAYMENT, SUPPLIER_INVOICE_RECOGNITION, SUPPLIER_BALANCE_PAYMENT, SALES_INVOICE, RECEIPT';


--
-- Name: post_payroll_payment_to_gl(uuid, date); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.post_payroll_payment_to_gl(p_payment_batch_id uuid, p_posting_date date DEFAULT CURRENT_DATE) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_batch          record;
    v_company_id     uuid;
    v_journal_id     uuid;
    v_journal_number text;
    v_clearing_id    uuid;
    v_bank_gl_id     uuid;
BEGIN
    SELECT * INTO v_batch
    FROM public.payroll_payment_batches
    WHERE id = p_payment_batch_id;

    IF v_batch IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Payment batch not found');
    END IF;

    v_company_id := v_batch.company_id;

    IF v_batch.status <> 'COMPLETED' THEN
        RETURN jsonb_build_object('success', false, 'error', 'Payment must be completed before posting');
    END IF;

    IF v_batch.gl_journal_id IS NOT NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Payment already posted to GL');
    END IF;

    -- Get clearing account
    SELECT gl_account_id INTO v_clearing_id
    FROM public.payroll_clearing_accounts
    WHERE company_id = v_company_id AND account_type = 'CLEARING' AND is_default = true AND is_active = true
    LIMIT 1;

    -- Get bank GL account from the payment batch's bank account
    SELECT pca.gl_account_id INTO v_bank_gl_id
    FROM public.payroll_clearing_accounts pca
    WHERE pca.id = v_batch.bank_account_id;

    -- Fallback to the default cash account
    IF v_bank_gl_id IS NULL THEN
        SELECT cash_account_id INTO v_bank_gl_id
        FROM public.gl_settings
        WHERE company_id = v_company_id;
    END IF;

    IF v_bank_gl_id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'No bank/cash GL account configured');
    END IF;

    -- For salary payment: Dr Net Salary Payable, Cr Cash/Bank
    v_journal_number := public.generate_journal_number(v_company_id, 'PAYROLL_PAYMENT');

    INSERT INTO public.gl_journals (
        company_id, journal_number, journal_date, posting_date,
        description, journal_type, status,
        total_debit, total_credit,
        created_by, posted_by, posted_at
    ) VALUES (
        v_company_id, v_journal_number, p_posting_date, p_posting_date,
        'Payroll Payment - Batch ' || v_batch.batch_number,
        'PAYROLL_PAYMENT', 'POSTED',
        v_batch.total_amount, v_batch.total_amount,
        auth.uid(), auth.uid(), now()
    ) RETURNING id INTO v_journal_id;

    -- Dr: Net Salary Payable (clear the liability)
    INSERT INTO public.gl_journal_lines (journal_id, account_id, line_number, description, debit_amount, credit_amount, created_by)
    SELECT v_journal_id,
        (SELECT id FROM gl_accounts WHERE company_id = v_company_id AND code = '2200' LIMIT 1),
        1, 'Clear Net Salary Payable', v_batch.total_amount, 0, auth.uid();

    -- Cr: Cash/Bank
    INSERT INTO public.gl_journal_lines (journal_id, account_id, line_number, description, debit_amount, credit_amount, created_by)
    VALUES (v_journal_id, v_bank_gl_id, 2, 'Bank Payment - Salaries', 0, v_batch.total_amount, auth.uid());

    -- Update batch
    UPDATE public.payroll_payment_batches
    SET gl_journal_id = v_journal_id, updated_at = now()
    WHERE id = p_payment_batch_id;

    -- Record in document postings
    INSERT INTO public.gl_document_postings (
        company_id, document_type, document_id, document_number,
        journal_id, posted_amount, posting_status, created_by
    ) VALUES (
        v_company_id, 'PAYROLL_PAYMENT', p_payment_batch_id,
        v_batch.batch_number, v_journal_id, v_batch.total_amount, 'POSTED', auth.uid()
    );

    RETURN jsonb_build_object(
        'success', true,
        'journal_id', v_journal_id,
        'journal_number', v_journal_number,
        'amount', v_batch.total_amount,
        'message', 'Payroll payment posted to GL'
    );
END;
$$;


ALTER FUNCTION public.post_payroll_payment_to_gl(p_payment_batch_id uuid, p_posting_date date) OWNER TO supabase_admin;

--
-- Name: post_payroll_run_to_gl(uuid, date); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.post_payroll_run_to_gl(p_payroll_run_id uuid, p_posting_date date DEFAULT CURRENT_DATE) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_run             record;
    v_company_id      uuid;
    v_journal_id      uuid;
    v_journal_number  text;
    v_total_debit     numeric(18,2) := 0;
    v_total_credit    numeric(18,2) := 0;
    v_line_number     integer := 0;
    v_clearing_id     uuid;
    v_clearing_amount numeric(18,2) := 0;
    v_component       record;
    v_mapping         record;
    v_run_items       record;
    v_missing_maps    text[] := '{}';
BEGIN
    -- ── 1. Load payroll run ──────────────────────────────────────────
    SELECT pr.*
    INTO v_run
    FROM public.hr_payroll_runs pr
    WHERE pr.id = p_payroll_run_id;

    IF v_run IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Payroll run not found');
    END IF;

    -- Resolve company_id (HQ org) from the run's organization
    v_company_id := public.get_company_id(v_run.organization_id);

    IF v_company_id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Could not resolve company for organization');
    END IF;

    -- ── 2. Validate status ───────────────────────────────────────────
    IF v_run.status NOT IN ('approved', 'finalized') THEN
        RETURN jsonb_build_object('success', false, 'error', 
            'Payroll run must be approved/finalized before posting. Current status: ' || v_run.status);
    END IF;

    IF v_run.gl_status = 'POSTED' THEN
        RETURN jsonb_build_object('success', false, 'error', 'Payroll run is already posted to GL');
    END IF;

    -- ── 3. Validate posting date in open fiscal period ───────────────
    IF NOT public.is_posting_date_allowed(p_posting_date, v_company_id) THEN
        RETURN jsonb_build_object('success', false, 'error', 
            'Posting date ' || p_posting_date || ' is not in an open fiscal period');
    END IF;

    -- ── 4. Validate all components have GL mappings ──────────────────
    -- Check: earnings must have debit mapping, deductions must have credit mapping
    FOR v_component IN
        SELECT DISTINCT pc.id, pc.code, pc.name, pc.category
        FROM public.payroll_components pc
        WHERE pc.company_id = v_company_id AND pc.is_active = true
    LOOP
        SELECT * INTO v_mapping
        FROM public.payroll_component_gl_map m
        WHERE m.company_id = v_company_id
        AND m.component_id = v_component.id
        AND m.is_active = true
        AND (m.effective_from IS NULL OR m.effective_from <= p_posting_date)
        AND (m.effective_to IS NULL OR m.effective_to >= p_posting_date)
        ORDER BY m.effective_from DESC NULLS LAST
        LIMIT 1;

        IF v_mapping IS NULL THEN
            -- Only flag as missing if the component has amounts in this run
            -- (components with 0 amounts don't need mapping)
            v_missing_maps := array_append(v_missing_maps, v_component.name || ' (' || v_component.code || ')');
        END IF;
    END LOOP;

    -- NOTE: We don't block on missing maps — we only block if a component with
    -- actual amounts has no mapping. This is checked during journal line generation.

    -- ── 5. Get payroll clearing account ──────────────────────────────
    SELECT gl_account_id INTO v_clearing_id
    FROM public.payroll_clearing_accounts
    WHERE company_id = v_company_id
    AND account_type = 'CLEARING'
    AND is_default = true
    AND is_active = true
    LIMIT 1;

    -- ── 6. Generate journal lines from payroll run items ─────────────
    -- Clear any prior journal entries for this run (in case of retry)
    DELETE FROM public.payroll_journals WHERE payroll_run_id = p_payroll_run_id;

    -- Aggregate payroll items by component and create journal lines
    -- EARNINGS: Dr Expense, Cr Net Salary Payable
    -- DEDUCTIONS: (no separate Dr — they reduce Net from Gross), Cr Statutory Payable
    -- EMPLOYER: Dr Employer Expense, Cr Statutory Payable

    -- a) BASIC salary aggregate
    INSERT INTO public.payroll_journals (payroll_run_id, component_id, gl_account_id, dr_amount, cr_amount, description, employee_count)
    SELECT 
        p_payroll_run_id,
        pc.id,
        m.debit_gl_account_id,
        SUM(pri.basic_salary),
        0,
        'Basic Salary - ' || to_char(v_run.period_start, 'Mon YYYY'),
        COUNT(*)
    FROM public.hr_payroll_run_items pri
    JOIN public.payroll_components pc ON pc.company_id = v_company_id AND pc.code = 'BASIC'
    LEFT JOIN public.payroll_component_gl_map m ON m.component_id = pc.id AND m.company_id = v_company_id AND m.is_active = true
    WHERE pri.payroll_run_id = p_payroll_run_id
    AND pri.basic_salary > 0
    AND m.debit_gl_account_id IS NOT NULL
    GROUP BY pc.id, m.debit_gl_account_id;

    -- b) Overtime aggregate
    INSERT INTO public.payroll_journals (payroll_run_id, component_id, gl_account_id, dr_amount, cr_amount, description, employee_count)
    SELECT 
        p_payroll_run_id,
        pc.id,
        m.debit_gl_account_id,
        SUM(pri.overtime_amount),
        0,
        'Overtime - ' || to_char(v_run.period_start, 'Mon YYYY'),
        COUNT(*)
    FROM public.hr_payroll_run_items pri
    JOIN public.payroll_components pc ON pc.company_id = v_company_id AND pc.code = 'OT'
    LEFT JOIN public.payroll_component_gl_map m ON m.component_id = pc.id AND m.company_id = v_company_id AND m.is_active = true
    WHERE pri.payroll_run_id = p_payroll_run_id
    AND pri.overtime_amount > 0
    AND m.debit_gl_account_id IS NOT NULL
    GROUP BY pc.id, m.debit_gl_account_id;

    -- c) Allowances aggregate
    INSERT INTO public.payroll_journals (payroll_run_id, component_id, gl_account_id, dr_amount, cr_amount, description, employee_count)
    SELECT 
        p_payroll_run_id,
        pc.id,
        m.debit_gl_account_id,
        SUM(pri.allowances_amount),
        0,
        'Allowances - ' || to_char(v_run.period_start, 'Mon YYYY'),
        COUNT(*)
    FROM public.hr_payroll_run_items pri
    JOIN public.payroll_components pc ON pc.company_id = v_company_id AND pc.code = 'ALLOWANCE'
    LEFT JOIN public.payroll_component_gl_map m ON m.component_id = pc.id AND m.company_id = v_company_id AND m.is_active = true
    WHERE pri.payroll_run_id = p_payroll_run_id
    AND pri.allowances_amount > 0
    AND m.debit_gl_account_id IS NOT NULL
    GROUP BY pc.id, m.debit_gl_account_id;

    -- d) Net Salary Payable (credit side — total net pay)
    INSERT INTO public.payroll_journals (payroll_run_id, component_id, gl_account_id, dr_amount, cr_amount, description, employee_count)
    SELECT 
        p_payroll_run_id,
        pc.id,
        m.credit_gl_account_id,
        0,
        SUM(pri.net_amount),
        'Net Salary Payable - ' || to_char(v_run.period_start, 'Mon YYYY'),
        COUNT(*)
    FROM public.hr_payroll_run_items pri
    JOIN public.payroll_components pc ON pc.company_id = v_company_id AND pc.code = 'BASIC'
    LEFT JOIN public.payroll_component_gl_map m ON m.component_id = pc.id AND m.company_id = v_company_id AND m.is_active = true
    WHERE pri.payroll_run_id = p_payroll_run_id
    AND pri.net_amount > 0
    AND m.credit_gl_account_id IS NOT NULL
    GROUP BY pc.id, m.credit_gl_account_id;

    -- e) EPF Employee deduction
    INSERT INTO public.payroll_journals (payroll_run_id, component_id, gl_account_id, dr_amount, cr_amount, description, employee_count)
    SELECT 
        p_payroll_run_id,
        pc.id,
        m.credit_gl_account_id,
        0,
        SUM(pri.epf_employee),
        'EPF Employee Deduction - ' || to_char(v_run.period_start, 'Mon YYYY'),
        COUNT(*)
    FROM public.hr_payroll_run_items pri
    JOIN public.payroll_components pc ON pc.company_id = v_company_id AND pc.code = 'EPF_EE'
    LEFT JOIN public.payroll_component_gl_map m ON m.component_id = pc.id AND m.company_id = v_company_id AND m.is_active = true
    WHERE pri.payroll_run_id = p_payroll_run_id
    AND pri.epf_employee > 0
    AND m.credit_gl_account_id IS NOT NULL
    GROUP BY pc.id, m.credit_gl_account_id;

    -- f) SOCSO Employee deduction
    INSERT INTO public.payroll_journals (payroll_run_id, component_id, gl_account_id, dr_amount, cr_amount, description, employee_count)
    SELECT 
        p_payroll_run_id,
        pc.id,
        m.credit_gl_account_id,
        0,
        SUM(pri.socso_employee),
        'SOCSO Employee Deduction - ' || to_char(v_run.period_start, 'Mon YYYY'),
        COUNT(*)
    FROM public.hr_payroll_run_items pri
    JOIN public.payroll_components pc ON pc.company_id = v_company_id AND pc.code = 'SOCSO_EE'
    LEFT JOIN public.payroll_component_gl_map m ON m.component_id = pc.id AND m.company_id = v_company_id AND m.is_active = true
    WHERE pri.payroll_run_id = p_payroll_run_id
    AND pri.socso_employee > 0
    AND m.credit_gl_account_id IS NOT NULL
    GROUP BY pc.id, m.credit_gl_account_id;

    -- g) EIS Employee deduction
    INSERT INTO public.payroll_journals (payroll_run_id, component_id, gl_account_id, dr_amount, cr_amount, description, employee_count)
    SELECT 
        p_payroll_run_id,
        pc.id,
        m.credit_gl_account_id,
        0,
        SUM(pri.eis_employee),
        'EIS Employee Deduction - ' || to_char(v_run.period_start, 'Mon YYYY'),
        COUNT(*)
    FROM public.hr_payroll_run_items pri
    JOIN public.payroll_components pc ON pc.company_id = v_company_id AND pc.code = 'EIS_EE'
    LEFT JOIN public.payroll_component_gl_map m ON m.component_id = pc.id AND m.company_id = v_company_id AND m.is_active = true
    WHERE pri.payroll_run_id = p_payroll_run_id
    AND pri.eis_employee > 0
    AND m.credit_gl_account_id IS NOT NULL
    GROUP BY pc.id, m.credit_gl_account_id;

    -- h) PCB deduction
    INSERT INTO public.payroll_journals (payroll_run_id, component_id, gl_account_id, dr_amount, cr_amount, description, employee_count)
    SELECT 
        p_payroll_run_id,
        pc.id,
        m.credit_gl_account_id,
        0,
        SUM(pri.pcb_amount),
        'PCB / Income Tax - ' || to_char(v_run.period_start, 'Mon YYYY'),
        COUNT(*)
    FROM public.hr_payroll_run_items pri
    JOIN public.payroll_components pc ON pc.company_id = v_company_id AND pc.code = 'PCB'
    LEFT JOIN public.payroll_component_gl_map m ON m.component_id = pc.id AND m.company_id = v_company_id AND m.is_active = true
    WHERE pri.payroll_run_id = p_payroll_run_id
    AND pri.pcb_amount > 0
    AND m.credit_gl_account_id IS NOT NULL
    GROUP BY pc.id, m.credit_gl_account_id;

    -- i) Employer EPF
    INSERT INTO public.payroll_journals (payroll_run_id, component_id, gl_account_id, dr_amount, cr_amount, description, employee_count)
    SELECT 
        p_payroll_run_id,
        pc.id,
        m.debit_gl_account_id,
        SUM(pri.epf_employer),
        0,
        'Employer EPF Contribution - ' || to_char(v_run.period_start, 'Mon YYYY'),
        COUNT(*)
    FROM public.hr_payroll_run_items pri
    JOIN public.payroll_components pc ON pc.company_id = v_company_id AND pc.code = 'EPF_ER'
    LEFT JOIN public.payroll_component_gl_map m ON m.component_id = pc.id AND m.company_id = v_company_id AND m.is_active = true
    WHERE pri.payroll_run_id = p_payroll_run_id
    AND pri.epf_employer > 0
    AND m.debit_gl_account_id IS NOT NULL
    GROUP BY pc.id, m.debit_gl_account_id;

    -- EPF Employer credit (to EPF Payable)
    INSERT INTO public.payroll_journals (payroll_run_id, component_id, gl_account_id, dr_amount, cr_amount, description, employee_count)
    SELECT 
        p_payroll_run_id,
        pc.id,
        m.credit_gl_account_id,
        0,
        SUM(pri.epf_employer),
        'Employer EPF Payable - ' || to_char(v_run.period_start, 'Mon YYYY'),
        COUNT(*)
    FROM public.hr_payroll_run_items pri
    JOIN public.payroll_components pc ON pc.company_id = v_company_id AND pc.code = 'EPF_ER'
    LEFT JOIN public.payroll_component_gl_map m ON m.component_id = pc.id AND m.company_id = v_company_id AND m.is_active = true
    WHERE pri.payroll_run_id = p_payroll_run_id
    AND pri.epf_employer > 0
    AND m.credit_gl_account_id IS NOT NULL
    GROUP BY pc.id, m.credit_gl_account_id;

    -- j) Employer SOCSO (debit + credit)
    INSERT INTO public.payroll_journals (payroll_run_id, component_id, gl_account_id, dr_amount, cr_amount, description, employee_count)
    SELECT p_payroll_run_id, pc.id, m.debit_gl_account_id, SUM(pri.socso_employer), 0,
        'Employer SOCSO - ' || to_char(v_run.period_start, 'Mon YYYY'), COUNT(*)
    FROM public.hr_payroll_run_items pri
    JOIN public.payroll_components pc ON pc.company_id = v_company_id AND pc.code = 'SOCSO_ER'
    LEFT JOIN public.payroll_component_gl_map m ON m.component_id = pc.id AND m.company_id = v_company_id AND m.is_active = true
    WHERE pri.payroll_run_id = p_payroll_run_id AND pri.socso_employer > 0 AND m.debit_gl_account_id IS NOT NULL
    GROUP BY pc.id, m.debit_gl_account_id;

    INSERT INTO public.payroll_journals (payroll_run_id, component_id, gl_account_id, dr_amount, cr_amount, description, employee_count)
    SELECT p_payroll_run_id, pc.id, m.credit_gl_account_id, 0, SUM(pri.socso_employer),
        'Employer SOCSO Payable - ' || to_char(v_run.period_start, 'Mon YYYY'), COUNT(*)
    FROM public.hr_payroll_run_items pri
    JOIN public.payroll_components pc ON pc.company_id = v_company_id AND pc.code = 'SOCSO_ER'
    LEFT JOIN public.payroll_component_gl_map m ON m.component_id = pc.id AND m.company_id = v_company_id AND m.is_active = true
    WHERE pri.payroll_run_id = p_payroll_run_id AND pri.socso_employer > 0 AND m.credit_gl_account_id IS NOT NULL
    GROUP BY pc.id, m.credit_gl_account_id;

    -- k) Employer EIS (debit + credit)
    INSERT INTO public.payroll_journals (payroll_run_id, component_id, gl_account_id, dr_amount, cr_amount, description, employee_count)
    SELECT p_payroll_run_id, pc.id, m.debit_gl_account_id, SUM(pri.eis_employer), 0,
        'Employer EIS - ' || to_char(v_run.period_start, 'Mon YYYY'), COUNT(*)
    FROM public.hr_payroll_run_items pri
    JOIN public.payroll_components pc ON pc.company_id = v_company_id AND pc.code = 'EIS_ER'
    LEFT JOIN public.payroll_component_gl_map m ON m.component_id = pc.id AND m.company_id = v_company_id AND m.is_active = true
    WHERE pri.payroll_run_id = p_payroll_run_id AND pri.eis_employer > 0 AND m.debit_gl_account_id IS NOT NULL
    GROUP BY pc.id, m.debit_gl_account_id;

    INSERT INTO public.payroll_journals (payroll_run_id, component_id, gl_account_id, dr_amount, cr_amount, description, employee_count)
    SELECT p_payroll_run_id, pc.id, m.credit_gl_account_id, 0, SUM(pri.eis_employer),
        'Employer EIS Payable - ' || to_char(v_run.period_start, 'Mon YYYY'), COUNT(*)
    FROM public.hr_payroll_run_items pri
    JOIN public.payroll_components pc ON pc.company_id = v_company_id AND pc.code = 'EIS_ER'
    LEFT JOIN public.payroll_component_gl_map m ON m.component_id = pc.id AND m.company_id = v_company_id AND m.is_active = true
    WHERE pri.payroll_run_id = p_payroll_run_id AND pri.eis_employer > 0 AND m.credit_gl_account_id IS NOT NULL
    GROUP BY pc.id, m.credit_gl_account_id;

    -- ── 7. Validate balance ──────────────────────────────────────────
    SELECT COALESCE(SUM(dr_amount), 0), COALESCE(SUM(cr_amount), 0)
    INTO v_total_debit, v_total_credit
    FROM public.payroll_journals
    WHERE payroll_run_id = p_payroll_run_id;

    IF v_total_debit <> v_total_credit THEN
        -- Imbalance — use clearing account if configured
        IF v_clearing_id IS NOT NULL THEN
            v_clearing_amount := v_total_debit - v_total_credit;
            IF v_clearing_amount > 0 THEN
                INSERT INTO public.payroll_journals (payroll_run_id, gl_account_id, dr_amount, cr_amount, description)
                VALUES (p_payroll_run_id, v_clearing_id, 0, v_clearing_amount, 'Payroll Clearing (auto-balance)');
                v_total_credit := v_total_credit + v_clearing_amount;
            ELSE
                INSERT INTO public.payroll_journals (payroll_run_id, gl_account_id, dr_amount, cr_amount, description)
                VALUES (p_payroll_run_id, v_clearing_id, ABS(v_clearing_amount), 0, 'Payroll Clearing (auto-balance)');
                v_total_debit := v_total_debit + ABS(v_clearing_amount);
            END IF;
        ELSE
            RETURN jsonb_build_object('success', false, 'error',
                'Payroll journal is not balanced (Dr: ' || v_total_debit || ' Cr: ' || v_total_credit || 
                '). Configure a Payroll Clearing account to auto-balance.');
        END IF;
    END IF;

    -- Final balance check
    IF v_total_debit <> v_total_credit THEN
        RETURN jsonb_build_object('success', false, 'error', 
            'Journal still not balanced after clearing adjustment');
    END IF;

    IF v_total_debit = 0 THEN
        RETURN jsonb_build_object('success', false, 'error', 'No journal lines generated — check GL mappings');
    END IF;

    -- ── 8. Create GL Journal ─────────────────────────────────────────
    v_journal_number := public.generate_journal_number(v_company_id, 'PAYROLL');

    INSERT INTO public.gl_journals (
        company_id, journal_number, journal_date, posting_date,
        description, journal_type, status,
        total_debit, total_credit,
        created_by, posted_by, posted_at
    ) VALUES (
        v_company_id, v_journal_number, p_posting_date, p_posting_date,
        'Payroll - ' || to_char(v_run.period_start, 'Mon YYYY') || 
        ' (' || (SELECT COUNT(*) FROM hr_payroll_run_items WHERE payroll_run_id = p_payroll_run_id) || ' employees)',
        'PAYROLL', 'POSTED',
        v_total_debit, v_total_credit,
        auth.uid(), auth.uid(), now()
    ) RETURNING id INTO v_journal_id;

    -- ── 9. Create GL Journal Lines from payroll_journals ─────────────
    INSERT INTO public.gl_journal_lines (
        journal_id, account_id, line_number, description,
        debit_amount, credit_amount, entity_type, created_by
    )
    SELECT
        v_journal_id,
        pj.gl_account_id,
        ROW_NUMBER() OVER (ORDER BY pj.created_at),
        pj.description,
        pj.dr_amount,
        pj.cr_amount,
        'EMPLOYEE',
        auth.uid()
    FROM public.payroll_journals pj
    WHERE pj.payroll_run_id = p_payroll_run_id
    AND (pj.dr_amount > 0 OR pj.cr_amount > 0);

    -- ── 10. Record in document postings (for idempotency) ────────────
    INSERT INTO public.gl_document_postings (
        company_id, document_type, document_id, document_number,
        journal_id, posted_amount, posting_status, created_by
    ) VALUES (
        v_company_id, 'PAYROLL_RUN', p_payroll_run_id,
        COALESCE(v_run.run_number, 'PR-' || to_char(v_run.period_start, 'YYYYMM')),
        v_journal_id, v_total_debit, 'POSTED', auth.uid()
    );

    -- ── 11. Update payroll run GL status ─────────────────────────────
    UPDATE public.hr_payroll_runs
    SET gl_journal_id = v_journal_id,
        gl_status = 'POSTED',
        gl_posted_at = now(),
        posted_at = now(),
        posted_by = auth.uid()
    WHERE id = p_payroll_run_id;

    -- ── 12. Audit log ────────────────────────────────────────────────
    INSERT INTO public.hr_payroll_audit (organization_id, payroll_run_id, actor_user_id, action, metadata)
    VALUES (v_run.organization_id, p_payroll_run_id, auth.uid(), 'GL_POSTED', jsonb_build_object(
        'journal_id', v_journal_id,
        'journal_number', v_journal_number,
        'total_debit', v_total_debit,
        'total_credit', v_total_credit,
        'posting_date', p_posting_date
    ));

    RETURN jsonb_build_object(
        'success', true,
        'journal_id', v_journal_id,
        'journal_number', v_journal_number,
        'total_debit', v_total_debit,
        'total_credit', v_total_credit,
        'lines_created', (SELECT COUNT(*) FROM payroll_journals WHERE payroll_run_id = p_payroll_run_id),
        'posting_date', p_posting_date
    );
END;
$$;


ALTER FUNCTION public.post_payroll_run_to_gl(p_payroll_run_id uuid, p_posting_date date) OWNER TO supabase_admin;

--
-- Name: FUNCTION post_payroll_run_to_gl(p_payroll_run_id uuid, p_posting_date date); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.post_payroll_run_to_gl(p_payroll_run_id uuid, p_posting_date date) IS 'Posts an approved payroll run to GL. Aggregates payroll items by component, maps to GL accounts, creates balanced journal entry. Returns journal_id and posting details.';


--
-- Name: process_reference_change(uuid, text, uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.process_reference_change(p_shop_user_id uuid, p_new_reference_phone text, p_changed_by uuid DEFAULT NULL::uuid, p_changed_by_type text DEFAULT 'shop'::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_shop_user    record;
  v_settings     record;
  v_old_ref_phone text;
  v_old_ref_user record;
  v_new_ref_user record;
  v_is_first_time boolean;
  v_policy_mode  text;
  v_status       public.referral_change_status;
  v_effective_from timestamptz;
  v_last_change  timestamptz;
  v_cooldown_days integer;
  v_assignment_id uuid;
  v_change_id    uuid;
  v_org_id       uuid;
  v_normalized_phone text;
BEGIN
  -- Get the shop user
  SELECT * INTO v_shop_user FROM public.users WHERE id = p_shop_user_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Shop user not found');
  END IF;

  -- Determine org (use first org we find)
  v_org_id := v_shop_user.organization_id;
  IF v_org_id IS NULL THEN
    SELECT id INTO v_org_id FROM public.organizations WHERE org_type_code = 'HQ' LIMIT 1;
  END IF;

  -- Get referral settings
  SELECT * INTO v_settings
  FROM public.referral_incentive_settings
  WHERE org_id = v_org_id;

  -- If no settings exist, use defaults
  IF NOT FOUND THEN
    v_settings := ROW(
      gen_random_uuid(), v_org_id, false, 1000, 1.00, false, 10.00,
      true, 'auto', 0, NULL, now(), now()
    )::public.referral_incentive_settings;
  END IF;

  -- Get old reference phone
  v_old_ref_phone := v_shop_user.referral_phone;
  v_is_first_time := (v_old_ref_phone IS NULL OR trim(v_old_ref_phone) = '');

  -- Normalize new phone
  v_normalized_phone := regexp_replace(p_new_reference_phone, '[^0-9+]', '', 'g');
  IF v_normalized_phone LIKE '0%' THEN
    v_normalized_phone := '+6' || v_normalized_phone;
  ELSIF v_normalized_phone NOT LIKE '+%' THEN
    v_normalized_phone := '+60' || v_normalized_phone;
  END IF;

  -- Check cooldown
  v_cooldown_days := v_settings.cooldown_days;
  IF NOT v_is_first_time AND v_cooldown_days > 0 THEN
    SELECT max(changed_at) INTO v_last_change
    FROM public.reference_change_log
    WHERE shop_user_id = p_shop_user_id
      AND status IN ('auto_approved', 'approved');

    IF v_last_change IS NOT NULL AND (now() - v_last_change) < (v_cooldown_days || ' days')::interval THEN
      RETURN jsonb_build_object(
        'ok', false,
        'error', 'Cooldown period not elapsed. Next change allowed after ' ||
                 (v_last_change + (v_cooldown_days || ' days')::interval)::text
      );
    END IF;
  END IF;

  -- Resolve old reference user
  IF v_old_ref_phone IS NOT NULL AND trim(v_old_ref_phone) != '' THEN
    SELECT id, full_name INTO v_old_ref_user
    FROM public.users
    WHERE phone = (
      CASE
        WHEN v_old_ref_phone LIKE '+6%' THEN regexp_replace(v_old_ref_phone, '[^0-9+]', '', 'g')
        WHEN regexp_replace(v_old_ref_phone, '[^0-9]', '', 'g') LIKE '0%' THEN '+6' || regexp_replace(v_old_ref_phone, '[^0-9]', '', 'g')
        ELSE '+60' || regexp_replace(v_old_ref_phone, '[^0-9]', '', 'g')
      END
    )
    LIMIT 1;
  END IF;

  -- Resolve new reference user
  SELECT id, full_name INTO v_new_ref_user
  FROM public.users
  WHERE phone = v_normalized_phone
  LIMIT 1;

  -- Determine policy and status
  IF v_is_first_time THEN
    v_policy_mode := 'first_time_auto';
    IF v_settings.first_time_auto_approve THEN
      v_status := 'auto_approved';
      v_effective_from := now();
    ELSE
      v_status := 'pending';
      v_effective_from := NULL;
    END IF;
  ELSE
    v_policy_mode := v_settings.subsequent_change_mode;
    IF v_settings.subsequent_change_mode = 'auto' THEN
      v_status := 'auto_approved';
      v_effective_from := now();
    ELSE
      v_status := 'pending';
      v_effective_from := NULL;
    END IF;
  END IF;

  -- Close old assignment if auto-approved
  IF v_status = 'auto_approved' THEN
    UPDATE public.reference_assignments
    SET effective_to = now()
    WHERE shop_user_id = p_shop_user_id
      AND effective_to IS NULL;

    -- Create new assignment
    INSERT INTO public.reference_assignments (
      org_id, shop_user_id, reference_user_id, reference_phone,
      effective_from, change_source, created_by
    )
    VALUES (
      v_org_id, p_shop_user_id, v_new_ref_user.id, v_normalized_phone,
      v_effective_from, COALESCE(p_changed_by_type, 'mobile'), COALESCE(p_changed_by, p_shop_user_id)
    )
    RETURNING id INTO v_assignment_id;

    -- Update users.referral_phone
    UPDATE public.users
    SET referral_phone = p_new_reference_phone,
        updated_at = now()
    WHERE id = p_shop_user_id;
  END IF;

  -- Insert change log
  INSERT INTO public.reference_change_log (
    org_id, shop_user_id, shop_name, shop_phone,
    old_reference_phone, old_reference_name, old_reference_id,
    new_reference_phone, new_reference_name, new_reference_id,
    changed_by, changed_by_type, policy_mode, status,
    effective_from, assignment_id
  )
  VALUES (
    v_org_id, p_shop_user_id, v_shop_user.shop_name, v_shop_user.phone,
    v_old_ref_phone, v_old_ref_user.full_name, v_old_ref_user.id,
    p_new_reference_phone, v_new_ref_user.full_name, v_new_ref_user.id,
    COALESCE(p_changed_by, p_shop_user_id), p_changed_by_type, v_policy_mode, v_status,
    v_effective_from, v_assignment_id
  )
  RETURNING id INTO v_change_id;

  RETURN jsonb_build_object(
    'ok', true,
    'change_id', v_change_id,
    'status', v_status::text,
    'effective_from', v_effective_from,
    'policy_mode', v_policy_mode,
    'assignment_id', v_assignment_id,
    'is_first_time', v_is_first_time
  );
END;
$$;


ALTER FUNCTION public.process_reference_change(p_shop_user_id uuid, p_new_reference_phone text, p_changed_by uuid, p_changed_by_type text) OWNER TO supabase_admin;

--
-- Name: process_referral_claim(uuid, text, uuid, text, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.process_referral_claim(p_claim_id uuid, p_action text, p_reviewer_id uuid, p_reason text DEFAULT NULL::text, p_payment_reference text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_claim record;
BEGIN
  SELECT * INTO v_claim FROM public.referral_claims WHERE id = p_claim_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Claim not found');
  END IF;

  IF p_action = 'approve' THEN
    IF v_claim.status != 'pending' THEN
      RETURN jsonb_build_object('ok', false, 'error', 'Claim is not pending');
    END IF;

    UPDATE public.referral_claims
    SET status = 'approved',
        reviewed_by = p_reviewer_id,
        reviewed_at = now(),
        approval_notes = p_reason
    WHERE id = p_claim_id;

  ELSIF p_action = 'reject' THEN
    IF v_claim.status != 'pending' THEN
      RETURN jsonb_build_object('ok', false, 'error', 'Claim is not pending');
    END IF;

    UPDATE public.referral_claims
    SET status = 'rejected',
        reviewed_by = p_reviewer_id,
        reviewed_at = now(),
        rejection_reason = p_reason
    WHERE id = p_claim_id;

  ELSIF p_action = 'mark_paid' THEN
    IF v_claim.status != 'approved' THEN
      RETURN jsonb_build_object('ok', false, 'error', 'Claim must be approved before marking paid');
    END IF;

    UPDATE public.referral_claims
    SET status = 'paid',
        paid_by = p_reviewer_id,
        paid_at = now(),
        payment_reference = p_payment_reference
    WHERE id = p_claim_id;

  ELSE
    RETURN jsonb_build_object('ok', false, 'error', 'Invalid action');
  END IF;

  RETURN jsonb_build_object(
    'ok', true,
    'claim_id', p_claim_id,
    'action', p_action,
    'new_status', p_action
  );
END;
$$;


ALTER FUNCTION public.process_referral_claim(p_claim_id uuid, p_action text, p_reviewer_id uuid, p_reason text, p_payment_reference text) OWNER TO supabase_admin;

--
-- Name: propagate_warehouse_to_master_codes(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.propagate_warehouse_to_master_codes(p_batch_id uuid) RETURNS TABLE(cases_updated integer, warehouse_org_id uuid)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_warehouse_org_id UUID;
  v_cases_updated INTEGER;
BEGIN
  -- Get the warehouse_org_id from the order
  SELECT o.warehouse_org_id INTO v_warehouse_org_id
  FROM qr_batches qb
  JOIN orders o ON o.id = qb.order_id
  WHERE qb.id = p_batch_id;
  
  -- Check if warehouse was found
  IF v_warehouse_org_id IS NULL THEN
    RAISE EXCEPTION 'No warehouse assigned to order for batch %', p_batch_id;
  END IF;
  
  -- Update all master codes in this batch with the warehouse assignment
  UPDATE qr_master_codes
  SET 
    warehouse_org_id = v_warehouse_org_id,
    status = 'packed',
    updated_at = NOW()
  WHERE batch_id = p_batch_id;
  
  -- Get count of updated rows
  GET DIAGNOSTICS v_cases_updated = ROW_COUNT;
  
  -- Return results
  RETURN QUERY SELECT v_cases_updated, v_warehouse_org_id;
END;
$$;


ALTER FUNCTION public.propagate_warehouse_to_master_codes(p_batch_id uuid) OWNER TO supabase_admin;

--
-- Name: queue_notification(uuid, text, text, text, text, text, jsonb, text, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.queue_notification(p_org_id uuid, p_event_code text, p_channel text, p_recipient_phone text DEFAULT NULL::text, p_recipient_email text DEFAULT NULL::text, p_template_code text DEFAULT NULL::text, p_payload jsonb DEFAULT '{}'::jsonb, p_priority text DEFAULT 'normal'::text, p_scheduled_for timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_notification_id UUID;
  v_template_body TEXT;
  v_provider_name TEXT;
  v_is_enabled BOOLEAN;
BEGIN
  -- Check if this event type is enabled for the org
  SELECT enabled INTO v_is_enabled
  FROM public.notification_settings
  WHERE org_id = p_org_id 
    AND event_code = p_event_code
    AND p_channel = ANY(channels_enabled);

  IF NOT FOUND OR v_is_enabled = false THEN
    -- RAISE NOTICE 'Notification event % not enabled for org % on channel %', p_event_code, p_org_id, p_channel;
    RETURN NULL;
  END IF;

  -- Get active provider for this channel
  SELECT provider_name INTO v_provider_name
  FROM public.notification_provider_configs
  WHERE org_id = p_org_id
    AND channel = p_channel
    AND is_active = true
  ORDER BY created_at DESC
  LIMIT 1;

  IF v_provider_name IS NULL THEN
    -- CHANGED: Log warning instead of raising exception to prevent blocking transactions
    RAISE WARNING 'No active provider configured for channel % in org %', p_channel, p_org_id;
    RETURN NULL;
  END IF;

  -- Get template if specified, otherwise use default from notification_types
  IF p_template_code IS NULL THEN
    SELECT default_template_code INTO p_template_code
    FROM public.notification_types
    WHERE event_code = p_event_code;
  END IF;

  -- Insert into outbox
  INSERT INTO public.notifications_outbox (
    org_id,
    event_code,
    channel,
    to_phone,
    to_email,
    template_code,
    payload_json,
    priority,
    scheduled_for,
    provider_name
  ) VALUES (
    p_org_id,
    p_event_code,
    p_channel,
    p_recipient_phone,
    p_recipient_email,
    p_template_code,
    p_payload,
    p_priority,
    p_scheduled_for,
    v_provider_name
  ) RETURNING id INTO v_notification_id;

  RETURN v_notification_id;
END;
$$;


ALTER FUNCTION public.queue_notification(p_org_id uuid, p_event_code text, p_channel text, p_recipient_phone text, p_recipient_email text, p_template_code text, p_payload jsonb, p_priority text, p_scheduled_for timestamp with time zone) OWNER TO supabase_admin;

--
-- Name: FUNCTION queue_notification(p_org_id uuid, p_event_code text, p_channel text, p_recipient_phone text, p_recipient_email text, p_template_code text, p_payload jsonb, p_priority text, p_scheduled_for timestamp with time zone); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.queue_notification(p_org_id uuid, p_event_code text, p_channel text, p_recipient_phone text, p_recipient_email text, p_template_code text, p_payload jsonb, p_priority text, p_scheduled_for timestamp with time zone) IS 'Queues a notification for delivery. Checks if event is enabled and provider is configured.';


--
-- Name: record_roadtour_reward(uuid, uuid, uuid, uuid, uuid, uuid, integer, uuid, uuid, text, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.record_roadtour_reward(p_org_id uuid, p_campaign_id uuid, p_qr_code_id uuid, p_account_manager_user_id uuid, p_scanned_by_user_id uuid, p_shop_id uuid, p_points integer, p_scan_event_id uuid DEFAULT NULL::uuid, p_survey_response_id uuid DEFAULT NULL::uuid, p_duplicate_rule text DEFAULT 'one_per_user_per_campaign'::text, p_transaction_type text DEFAULT 'roadtour'::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_existing_count integer;
  v_balance integer := 0;
  v_txn_id uuid;
  v_phone text;
  v_email text;
  v_description text;
BEGIN
  -- Check duplicate based on rule
  IF p_duplicate_rule = 'one_per_user_per_campaign' THEN
    SELECT COUNT(*) INTO v_existing_count
    FROM public.roadtour_scan_events
    WHERE campaign_id = p_campaign_id
      AND scanned_by_user_id = p_scanned_by_user_id
      AND scan_status = 'success'
      AND points_awarded > 0;
  ELSIF p_duplicate_rule = 'one_per_user_per_day' THEN
    SELECT COUNT(*) INTO v_existing_count
    FROM public.roadtour_scan_events
    WHERE campaign_id = p_campaign_id
      AND scanned_by_user_id = p_scanned_by_user_id
      AND scan_status = 'success'
      AND points_awarded > 0
      AND scan_time::date = CURRENT_DATE;
  ELSIF p_duplicate_rule = 'one_per_shop_per_am_per_day' THEN
    SELECT COUNT(*) INTO v_existing_count
    FROM public.roadtour_scan_events
    WHERE campaign_id = p_campaign_id
      AND account_manager_user_id = p_account_manager_user_id
      AND shop_id = p_shop_id
      AND scan_status = 'success'
      AND points_awarded > 0
      AND scan_time::date = CURRENT_DATE;
  ELSE
    v_existing_count := 0;
  END IF;

  IF v_existing_count > 0 THEN
    RETURN jsonb_build_object('success', false, 'error', 'duplicate', 'message', 'Reward already claimed based on the duplicate prevention rule.');
  END IF;

  -- Preferred balance source for independent consumers.
  SELECT COALESCE(v.current_balance, 0) INTO v_balance
  FROM public.v_consumer_points_balance v
  WHERE v.user_id = p_scanned_by_user_id;

  -- SHOP-attached GUEST/CONSUMER users are excluded from the consumer view.
  -- Use the ledger total in that case so RoadTour rewards add onto the
  -- same balance shown in the profile screen.
  IF v_balance IS NULL THEN
    SELECT COALESCE(SUM(points_change), 0)::integer INTO v_balance
    FROM public.shop_points_ledger
    WHERE consumer_id = p_scanned_by_user_id;
  END IF;

  -- Last fallback for older users without ledger rows.
  IF v_balance IS NULL THEN
    SELECT COALESCE(SUM(points_amount), 0)::integer INTO v_balance
    FROM public.consumer_qr_scans
    WHERE consumer_id = p_scanned_by_user_id
      AND collected_points = true;
  END IF;

  IF v_balance IS NULL THEN
    v_balance := 0;
  END IF;

  -- Get phone/email
  SELECT u.phone, u.email INTO v_phone, v_email
  FROM public.users u WHERE u.id = p_scanned_by_user_id;

  v_description := format('RoadTour bonus — campaign scan reward (%s points)', p_points);

  -- Insert points transaction — keep taxonomy columns aligned with phase 1.
  INSERT INTO public.points_transactions (
    company_id, consumer_phone, consumer_email,
    transaction_type, points_amount, balance_after,
    description, transaction_date, user_id, created_by,
    point_category, point_indicator, point_owner_type, point_direction
  ) VALUES (
    p_org_id, COALESCE(v_phone, ''), v_email,
    p_transaction_type, p_points, COALESCE(v_balance, 0) + COALESCE(p_points, 0),
    v_description, now(), p_scanned_by_user_id, p_scanned_by_user_id,
    CASE WHEN p_transaction_type = 'roadtour_survey' THEN 'survey' ELSE 'roadtour' END,
    CASE WHEN p_transaction_type = 'roadtour_survey' THEN 'survey_completion' ELSE 'booth_scan' END,
    'consumer',
    'earn'
  )
  RETURNING id INTO v_txn_id;

  -- Update scan event with reward
  IF p_scan_event_id IS NOT NULL THEN
    UPDATE public.roadtour_scan_events
    SET points_awarded = p_points, scan_status = 'success', reward_transaction_id = v_txn_id
    WHERE id = p_scan_event_id;
  END IF;

  -- Update survey response with reward
  IF p_survey_response_id IS NOT NULL THEN
    UPDATE public.roadtour_survey_responses
    SET points_awarded = p_points, reward_transaction_id = v_txn_id
    WHERE id = p_survey_response_id;
  END IF;

  -- Try to create official visit (ignore if duplicate constraint fires)
  BEGIN
    INSERT INTO public.roadtour_official_visits (
      campaign_id, account_manager_user_id, shop_id,
      official_scan_event_id, official_survey_response_id, visit_date
    ) VALUES (
      p_campaign_id, p_account_manager_user_id, p_shop_id,
      p_scan_event_id, p_survey_response_id, CURRENT_DATE
    );
  EXCEPTION WHEN unique_violation THEN
    NULL;
  END;

  RETURN jsonb_build_object(
    'success', true,
    'transaction_id', v_txn_id,
    'points_awarded', p_points,
    'balance_after', COALESCE(v_balance, 0) + COALESCE(p_points, 0),
    'message', 'RoadTour reward credited successfully.'
  );
END;
$$;


ALTER FUNCTION public.record_roadtour_reward(p_org_id uuid, p_campaign_id uuid, p_qr_code_id uuid, p_account_manager_user_id uuid, p_scanned_by_user_id uuid, p_shop_id uuid, p_points integer, p_scan_event_id uuid, p_survey_response_id uuid, p_duplicate_rule text, p_transaction_type text) OWNER TO supabase_admin;

--
-- Name: record_stock_movement(text, uuid, uuid, integer, numeric, uuid, text, text, text, text, uuid, text, uuid, uuid, text[]); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.record_stock_movement(p_movement_type text, p_variant_id uuid, p_organization_id uuid, p_quantity_change integer, p_unit_cost numeric DEFAULT NULL::numeric, p_manufacturer_id uuid DEFAULT NULL::uuid, p_warehouse_location text DEFAULT NULL::text, p_reason text DEFAULT NULL::text, p_notes text DEFAULT NULL::text, p_reference_type text DEFAULT 'manual'::text, p_reference_id uuid DEFAULT NULL::uuid, p_reference_no text DEFAULT NULL::text, p_company_id uuid DEFAULT NULL::uuid, p_created_by uuid DEFAULT NULL::uuid, p_evidence_urls text[] DEFAULT NULL::text[]) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_movement_id UUID;
    v_current_qty INTEGER;
    v_new_qty INTEGER;
    v_inventory_id UUID;
    v_company_id UUID;
    v_from_org UUID := NULL;
    v_to_org UUID := NULL;
    v_final_unit_cost numeric;
    v_normalized_type text;
BEGIN
    v_normalized_type := LOWER(TRIM(p_movement_type));

    -- Force unit cost to 0 for warranty_bonus
    IF v_normalized_type = 'warranty_bonus' THEN
        v_final_unit_cost := 0;
    ELSE
        v_final_unit_cost := p_unit_cost;
    END IF;

    -- Determine direction of movement for org columns
    -- warranty_bonus is an addition, so it goes to p_organization_id
    IF p_quantity_change < 0 THEN
        v_from_org := p_organization_id;
    ELSE
        v_to_org := p_organization_id;
    END IF;

    -- Get company_id if not provided
    IF p_company_id IS NULL THEN
        SELECT get_company_id(p_organization_id) INTO v_company_id;
    ELSE
        v_company_id := p_company_id;
    END IF;

    -- Get current inventory record
    SELECT id, quantity_on_hand INTO v_inventory_id, v_current_qty
    FROM public.product_inventory
    WHERE variant_id = p_variant_id
      AND organization_id = p_organization_id
      AND is_active = true;

    -- If no inventory record exists, create one
    IF v_inventory_id IS NULL THEN
        INSERT INTO public.product_inventory (
            variant_id,
            organization_id,
            quantity_on_hand,
            quantity_allocated,
            warehouse_location,
            average_cost,
            created_at,
            updated_at
        ) VALUES (
            p_variant_id,
            p_organization_id,
            0,
            0,
            p_warehouse_location,
            v_final_unit_cost,
            NOW(),
            NOW()
        ) RETURNING id, quantity_on_hand INTO v_inventory_id, v_current_qty;
    END IF;

    -- Calculate new quantity
    v_new_qty := v_current_qty + p_quantity_change;

    -- Ensure quantity doesn't go negative
    IF v_new_qty < 0 THEN
        RAISE EXCEPTION 'Insufficient stock. Current: %, Requested change: %', v_current_qty, p_quantity_change;
    END IF;

    -- Create movement record
    INSERT INTO public.stock_movements (
        movement_type,
        reference_type,
        reference_id,
        reference_no,
        variant_id,
        from_organization_id,
        to_organization_id,
        quantity_change,
        quantity_before,
        quantity_after,
        unit_cost,
        manufacturer_id,
        warehouse_location,
        reason,
        notes,
        company_id,
        created_by,
        evidence_urls
    ) VALUES (
        p_movement_type, -- Keep original case for display if needed, or use v_normalized_type
        p_reference_type,
        p_reference_id,
        p_reference_no,
        p_variant_id,
        v_from_org,
        v_to_org,
        p_quantity_change,
        v_current_qty,
        v_new_qty,
        v_final_unit_cost,
        p_manufacturer_id,
        p_warehouse_location,
        p_reason,
        p_notes,
        v_company_id,
        p_created_by,
        p_evidence_urls
    ) RETURNING id INTO v_movement_id;

    -- Update inventory quantity and average cost
    UPDATE public.product_inventory
    SET 
        quantity_on_hand = v_new_qty,
        updated_at = NOW(),
        -- Update average cost if unit cost is provided (or forced to 0) and it's an addition
        average_cost = CASE 
            WHEN p_quantity_change > 0 AND v_final_unit_cost IS NOT NULL THEN
                ((quantity_on_hand * COALESCE(average_cost, 0)) + (p_quantity_change * v_final_unit_cost)) / (quantity_on_hand + p_quantity_change)
            ELSE average_cost
        END
    WHERE id = v_inventory_id;

    RETURN v_movement_id;
END;
$$;


ALTER FUNCTION public.record_stock_movement(p_movement_type text, p_variant_id uuid, p_organization_id uuid, p_quantity_change integer, p_unit_cost numeric, p_manufacturer_id uuid, p_warehouse_location text, p_reason text, p_notes text, p_reference_type text, p_reference_id uuid, p_reference_no text, p_company_id uuid, p_created_by uuid, p_evidence_urls text[]) OWNER TO supabase_admin;

--
-- Name: recycle_doc_number(uuid, text, text, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.recycle_doc_number(p_company_id uuid, p_display_doc_no text, p_source_table text, p_source_id uuid DEFAULT NULL::uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_doc_type text;
    v_year integer;
    v_seq_number integer;
    v_prefix_len integer;
BEGIN
    -- Skip if no display_doc_no
    IF p_display_doc_no IS NULL OR p_display_doc_no = '' THEN
        RETURN false;
    END IF;
    
    -- Parse display_doc_no format: PREFIX + YY + 6-digit seq
    -- Example: ORD26000017 -> doc_type=ORD, year=2026, seq=17
    
    -- Find prefix by looking for where digits start
    v_prefix_len := 0;
    FOR i IN 1..LENGTH(p_display_doc_no) LOOP
        IF SUBSTRING(p_display_doc_no FROM i FOR 1) ~ '[0-9]' THEN
            v_prefix_len := i - 1;
            EXIT;
        END IF;
    END LOOP;
    
    IF v_prefix_len = 0 THEN
        RETURN false; -- Invalid format
    END IF;
    
    v_doc_type := SUBSTRING(p_display_doc_no FROM 1 FOR v_prefix_len);
    v_year := 2000 + SUBSTRING(p_display_doc_no FROM v_prefix_len + 1 FOR 2)::integer;
    v_seq_number := SUBSTRING(p_display_doc_no FROM v_prefix_len + 3)::integer;
    
    -- Insert into recycle pool (ignore if already exists)
    INSERT INTO public.recycled_doc_numbers (
        company_id,
        doc_type,
        year,
        seq_number,
        display_doc_no,
        source_table,
        source_id
    ) VALUES (
        p_company_id,
        v_doc_type,
        v_year,
        v_seq_number,
        p_display_doc_no,
        p_source_table,
        p_source_id
    )
    ON CONFLICT (company_id, display_doc_no) DO NOTHING;
    
    RETURN true;
EXCEPTION WHEN OTHERS THEN
    RAISE WARNING 'Failed to recycle doc number %: %', p_display_doc_no, SQLERRM;
    RETURN false;
END;
$$;


