--
-- Name: regenerate_order_doc_numbers(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.regenerate_order_doc_numbers(p_order_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_order RECORD;
    v_doc RECORD;
    v_new_display_no text;
    v_updated_count integer := 0;
    v_results jsonb := '[]'::jsonb;
BEGIN
    -- Get order details
    SELECT id, company_id, display_doc_no, base_seq
    INTO v_order
    FROM public.orders
    WHERE id = p_order_id;
    
    IF v_order.id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Order not found');
    END IF;
    
    -- Ensure order has base_seq
    IF v_order.base_seq IS NULL AND v_order.display_doc_no IS NOT NULL THEN
        v_order.base_seq := extract_seq_from_display_doc_no(v_order.display_doc_no);
        UPDATE public.orders SET base_seq = v_order.base_seq WHERE id = p_order_id;
    END IF;
    
    IF v_order.base_seq IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Order has no base sequence number');
    END IF;
    
    -- Reset sub-sequences for this order
    DELETE FROM public.order_doc_sequences WHERE order_id = p_order_id;
    
    -- Process each document in creation order
    FOR v_doc IN 
        SELECT id, doc_type, doc_no, display_doc_no, created_at
        FROM public.documents
        WHERE order_id = p_order_id
        ORDER BY created_at ASC
    LOOP
        -- Generate new display_doc_no
        v_new_display_no := generate_order_referenced_doc_number(
            v_order.company_id,
            p_order_id,
            v_doc.doc_type::text,
            EXTRACT(YEAR FROM v_doc.created_at)::integer
        );
        
        -- Update document
        UPDATE public.documents
        SET display_doc_no = v_new_display_no
        WHERE id = v_doc.id;
        
        v_updated_count := v_updated_count + 1;
        
        v_results := v_results || jsonb_build_object(
            'doc_id', v_doc.id,
            'doc_type', v_doc.doc_type,
            'old_display_no', v_doc.display_doc_no,
            'new_display_no', v_new_display_no
        );
    END LOOP;
    
    RETURN jsonb_build_object(
        'success', true,
        'order_id', p_order_id,
        'order_display_no', v_order.display_doc_no,
        'base_seq', v_order.base_seq,
        'documents_updated', v_updated_count,
        'details', v_results
    );
END;
$$;


ALTER FUNCTION public.regenerate_order_doc_numbers(p_order_id uuid) OWNER TO supabase_admin;

