-- Name: FUNCTION regenerate_order_doc_numbers(p_order_id uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.regenerate_order_doc_numbers(p_order_id uuid) IS 'Regenerates all document numbers for an order using the order-referenced numbering system';


--
-- Name: release_allocation_for_order(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.release_allocation_for_order(p_order_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_order record;
    v_item record;
    v_inventory_org_id uuid;
    v_seller_type text;
    v_wh_id uuid;
    v_current_allocated integer;
    v_unit_cost numeric;
BEGIN
    SELECT * INTO v_order FROM public.orders WHERE id = p_order_id;
    
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Order not found: %', p_order_id;
    END IF;
    
    IF v_order.order_type NOT IN ('D2H', 'S2D') THEN
        RETURN;
    END IF;
    
    v_inventory_org_id := v_order.seller_org_id;
    
    SELECT org_type_code INTO v_seller_type 
    FROM public.organizations 
    WHERE id = v_order.seller_org_id;
    
    IF v_seller_type = 'HQ' THEN
        SELECT id INTO v_wh_id 
        FROM public.organizations 
        WHERE parent_org_id = v_order.seller_org_id 
          AND org_type_code = 'WH' 
          AND is_active = true 
        ORDER BY created_at ASC
        LIMIT 1;
        
        IF v_wh_id IS NOT NULL THEN
            v_inventory_org_id := v_wh_id;
        END IF;
    END IF;
    
    FOR v_item IN 
        SELECT * FROM public.order_items WHERE order_id = p_order_id
    LOOP
        -- Check if deallocation already exists for this order item
        IF EXISTS (
            SELECT 1 FROM public.stock_movements
            WHERE reference_id = p_order_id
              AND variant_id = v_item.variant_id
              AND movement_type = 'deallocation'
        ) THEN
            RAISE NOTICE 'Deallocation already exists for order % variant %', v_order.order_no, v_item.variant_id;
            CONTINUE;
        END IF;
        
        SELECT 
            quantity_allocated,
            COALESCE(average_cost, 0)
        INTO v_current_allocated, v_unit_cost
        FROM public.product_inventory
        WHERE variant_id = v_item.variant_id 
          AND organization_id = v_inventory_org_id
        FOR UPDATE;
        
        IF NOT FOUND THEN
            RAISE WARNING 'Inventory not found for variant % at organization %', 
                v_item.variant_id, v_inventory_org_id;
            CONTINUE;
        END IF;
        
        UPDATE public.product_inventory
        SET 
            quantity_allocated = GREATEST(0, quantity_allocated - v_item.qty),
            updated_at = now()
        WHERE variant_id = v_item.variant_id 
          AND organization_id = v_inventory_org_id;
        
        -- Create deallocation movement to reverse the allocation
        -- Swap from/to so it displays at the buyer location (matching the original allocation)
        INSERT INTO public.stock_movements (
            movement_type,
            reference_type,
            reference_id,
            reference_no,
            variant_id,
            from_organization_id,
            to_organization_id,
            quantity_change,
            quantity_before,
            quantity_after,
            unit_cost,
            company_id,
            created_by,
            created_at,
            notes
        ) VALUES (
            'deallocation',
            'order',
            v_order.id,
            v_order.order_no,
            v_item.variant_id,
            v_order.buyer_org_id,    -- FROM: Buyer location (where allocation was shown)
            v_inventory_org_id,       -- TO: Warehouse (stock returns here)
            -v_item.qty,
            v_item.qty, -- Before: The allocated amount for this order
            0,          -- After: 0
            v_unit_cost,
            v_order.company_id,
            COALESCE(auth.uid(), v_order.created_by),
            now(),
            CASE 
                WHEN v_order.status = 'cancelled' THEN 'order_cancelled'
                ELSE 'order_deleted'
            END
        );
    END LOOP;
END;
$$;


ALTER FUNCTION public.release_allocation_for_order(p_order_id uuid) OWNER TO supabase_admin;

--
-- Name: FUNCTION release_allocation_for_order(p_order_id uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.release_allocation_for_order(p_order_id uuid) IS 'Releases allocated inventory for D2H/S2D orders by creating deallocation movements. Preserves audit trail.';


--
-- Name: render_template(text, uuid, jsonb); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.render_template(p_template_code text, p_org_id uuid, p_payload jsonb) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_template_body TEXT;
  v_result TEXT;
  v_key TEXT;
  v_value TEXT;
BEGIN
  -- Get template body
  SELECT body INTO v_template_body
  FROM public.message_templates
  WHERE code = p_template_code
    AND org_id = p_org_id
    AND is_active = true;

  IF v_template_body IS NULL THEN
    RAISE EXCEPTION 'Template not found: % for org %', p_template_code, p_org_id;
  END IF;

  v_result := v_template_body;

  -- Simple variable replacement ({{variable_name}})
  FOR v_key, v_value IN SELECT * FROM jsonb_each_text(p_payload)
  LOOP
    v_result := REPLACE(v_result, '{{' || v_key || '}}', v_value);
  END LOOP;

  RETURN v_result;
END;
$$;


