--

COMMENT ON FUNCTION public.render_template(p_template_code text, p_org_id uuid, p_payload jsonb) IS 'Renders a message template with variable substitution from payload';


--
-- Name: reverse_gl_journal(uuid, text, date); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.reverse_gl_journal(p_journal_id uuid, p_reason text, p_reversal_date date DEFAULT CURRENT_DATE) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_company_id uuid;
    v_original_journal record;
    v_reversal_journal_id uuid;
    v_reversal_number text;
    v_line record;
    v_line_number integer := 0;
BEGIN
    -- Check permission
    IF NOT public.is_hq_admin() THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Only HQ Admins can reverse journals'
        );
    END IF;
    
    v_company_id := public.get_user_company_id();
    
    -- Get original journal
    SELECT * INTO v_original_journal
    FROM public.gl_journals
    WHERE id = p_journal_id
    AND company_id = v_company_id
    AND status = 'POSTED';
    
    IF v_original_journal IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Journal not found or not in POSTED status'
        );
    END IF;
    
    IF v_original_journal.reversal_journal_id IS NOT NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Journal has already been reversed'
        );
    END IF;
    
    -- Generate reversal journal number
    v_reversal_number := public.generate_journal_number(v_company_id, 'REVERSAL');
    
    -- Create reversal journal (swap DR/CR)
    INSERT INTO public.gl_journals (
        company_id,
        journal_number,
        journal_date,
        posting_date,
        description,
        journal_type,
        status,
        is_reversal,
        reversed_journal_id,
        reversal_reason,
        total_debit,
        total_credit,
        created_by,
        posted_by,
        posted_at
    ) VALUES (
        v_company_id,
        v_reversal_number,
        CURRENT_DATE,
        p_reversal_date,
        'REVERSAL: ' || v_original_journal.description || ' - ' || p_reason,
        'REVERSAL',
        'POSTED',
        true,
        p_journal_id,
        p_reason,
        v_original_journal.total_credit,  -- Swap
        v_original_journal.total_debit,   -- Swap
        auth.uid(),
        auth.uid(),
        now()
    )
    RETURNING id INTO v_reversal_journal_id;
    
    -- Create reversed lines (swap DR/CR)
    FOR v_line IN 
        SELECT * FROM public.gl_journal_lines 
        WHERE journal_id = p_journal_id 
        ORDER BY line_number
    LOOP
        v_line_number := v_line_number + 1;
        
        INSERT INTO public.gl_journal_lines (
            journal_id,
            account_id,
            line_number,
            description,
            debit_amount,
            credit_amount,
            entity_type,
            entity_id
        ) VALUES (
            v_reversal_journal_id,
            v_line.account_id,
            v_line_number,
            'REVERSAL: ' || COALESCE(v_line.description, ''),
            v_line.credit_amount,  -- Swap: credit becomes debit
            v_line.debit_amount,   -- Swap: debit becomes credit
            v_line.entity_type,
            v_line.entity_id
        );
    END LOOP;
    
    -- Update original journal
    UPDATE public.gl_journals
    SET status = 'REVERSED',
        reversal_journal_id = v_reversal_journal_id,
        updated_at = now()
    WHERE id = p_journal_id;
    
    -- Update document posting status
    UPDATE public.gl_document_postings
    SET posting_status = 'REVERSED'
    WHERE journal_id = p_journal_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'reversal_journal_id', v_reversal_journal_id,
        'reversal_number', v_reversal_number,
        'original_journal_id', p_journal_id
    );
END;
$$;


ALTER FUNCTION public.reverse_gl_journal(p_journal_id uuid, p_reason text, p_reversal_date date) OWNER TO supabase_admin;

--
-- Name: reverse_payroll_gl_posting(uuid, text, date); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.reverse_payroll_gl_posting(p_payroll_run_id uuid, p_reason text DEFAULT 'Payroll rerun'::text, p_reversal_date date DEFAULT CURRENT_DATE) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_run           record;
    v_journal_id    uuid;
    v_result        jsonb;
BEGIN
    SELECT * INTO v_run
    FROM public.hr_payroll_runs
    WHERE id = p_payroll_run_id;

    IF v_run IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Payroll run not found');
    END IF;

    IF v_run.gl_status <> 'POSTED' OR v_run.gl_journal_id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Payroll run has no GL posting to reverse');
    END IF;

    -- Use the existing reverse_gl_journal function
    v_result := public.reverse_gl_journal(v_run.gl_journal_id, p_reason, p_reversal_date);

    IF NOT (v_result->>'success')::boolean THEN
        RETURN v_result;
    END IF;

    -- Update payroll run
    UPDATE public.hr_payroll_runs
    SET gl_status = 'REVERSED',
        gl_reversal_journal_id = (v_result->>'reversal_journal_id')::uuid
    WHERE id = p_payroll_run_id;

    -- Update document posting
    UPDATE public.gl_document_postings
    SET posting_status = 'REVERSED'
    WHERE document_type = 'PAYROLL_RUN' AND document_id = p_payroll_run_id;

    -- Audit
    INSERT INTO public.hr_payroll_audit (organization_id, payroll_run_id, actor_user_id, action, metadata)
    VALUES (v_run.organization_id, p_payroll_run_id, auth.uid(), 'GL_REVERSED', jsonb_build_object(
        'original_journal_id', v_run.gl_journal_id,
        'reversal_journal_id', v_result->>'reversal_journal_id',
        'reason', p_reason,
        'reversal_date', p_reversal_date
    ));

    RETURN jsonb_build_object(
        'success', true,
        'original_journal_id', v_run.gl_journal_id,
        'reversal_journal_id', v_result->>'reversal_journal_id',
        'message', 'Payroll GL posting reversed successfully'
    );
END;
$$;


ALTER FUNCTION public.reverse_payroll_gl_posting(p_payroll_run_id uuid, p_reason text, p_reversal_date date) OWNER TO supabase_admin;

