-- Name: FUNCTION reverse_payroll_gl_posting(p_payroll_run_id uuid, p_reason text, p_reversal_date date); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.reverse_payroll_gl_posting(p_payroll_run_id uuid, p_reason text, p_reversal_date date) IS 'Reverses the GL journal for a payroll run. Used when payroll needs to be recalculated and reposted.';


--
-- Name: revert_inventory_on_movement_delete(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.revert_inventory_on_movement_delete() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_target_org uuid;
  v_order_status text;
BEGIN
  -- Ignore zero deltas
  IF COALESCE(OLD.quantity_change,0) = 0 THEN
    RETURN OLD;
  END IF;

  -- Skip allocation and deallocation movements
  -- These affect quantity_allocated, not quantity_on_hand
  IF OLD.movement_type IN ('allocation', 'deallocation') THEN
    RETURN OLD;
  END IF;

  -- Check if this movement is from a fulfilled order
  -- If so, don't revert - the stock has actually left the warehouse
  IF OLD.reference_type = 'order' AND OLD.reference_id IS NOT NULL THEN
    SELECT status INTO v_order_status
    FROM public.orders
    WHERE id = OLD.reference_id;
    
    IF v_order_status IN ('approved', 'warehouse_packed', 'shipped_distributor', 'fulfilled', 'completed') THEN
      -- Order was fulfilled, don't revert inventory
      RETURN OLD;
    END IF;
  END IF;

  -- Determine which organization's inventory was updated
  IF OLD.quantity_change < 0 THEN
    v_target_org := COALESCE(OLD.from_organization_id, OLD.to_organization_id);
  ELSE
    v_target_org := COALESCE(OLD.to_organization_id, OLD.from_organization_id);
  END IF;

  IF v_target_org IS NULL THEN
    RETURN OLD;
  END IF;

  -- Revert the change
  -- If we added 100 (change +100), we need to subtract 100.
  -- If we removed 100 (change -100), we need to add 100.
  -- So we subtract OLD.quantity_change.

  UPDATE public.product_inventory
     SET quantity_on_hand = quantity_on_hand - OLD.quantity_change,
         updated_at       = NOW()
   WHERE variant_id = OLD.variant_id
     AND organization_id = v_target_org;

  RETURN OLD;
END
$$;


ALTER FUNCTION public.revert_inventory_on_movement_delete() OWNER TO supabase_admin;

--
-- Name: FUNCTION revert_inventory_on_movement_delete(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.revert_inventory_on_movement_delete() IS 'Reverts inventory changes when stock movements are deleted. Skips allocation/deallocation and fulfilled orders.';


--
-- Name: search_eligible_references(text, integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.search_eligible_references(p_search_term text, p_limit integer DEFAULT 10) RETURNS TABLE(user_id uuid, full_name text, phone text, email text, organization_name text)
    LANGUAGE sql STABLE SECURITY DEFINER
    AS $$
  SELECT
    u.id AS user_id,
    u.full_name,
    u.phone,
    u.email,
    o.org_name AS organization_name
  FROM public.users u
  LEFT JOIN public.organizations o ON o.id = u.organization_id
  WHERE u.can_be_reference = true
    AND u.is_active = true
    AND (
      p_search_term IS NULL
      OR TRIM(p_search_term) = ''
      OR u.full_name ILIKE '%' || TRIM(p_search_term) || '%'
      OR u.phone ILIKE '%' || TRIM(p_search_term) || '%'
      OR u.email ILIKE '%' || TRIM(p_search_term) || '%'
    )
  ORDER BY u.full_name ASC
  LIMIT LEAST(p_limit, 20);
$$;


ALTER FUNCTION public.search_eligible_references(p_search_term text, p_limit integer) OWNER TO supabase_admin;

