-- Name: FUNCTION search_eligible_references(p_search_term text, p_limit integer); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.search_eligible_references(p_search_term text, p_limit integer) IS 'Autocomplete search for eligible reference users. Searches by name, phone, or email.';


--
-- Name: search_products(text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.search_products(search_query text) RETURNS TABLE(product_id uuid, product_code text, product_name text, brand_name text, category_name text, is_active boolean, relevance real)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    p.id,
    p.product_code,
    p.product_name,
    b.brand_name,
    c.category_name,
    p.is_active,
    ts_rank(
      to_tsvector(
        'english',
        COALESCE(p.product_name,'') || ' ' ||
        COALESCE(b.brand_name,'')   || ' ' ||
        COALESCE(p.product_description,'')
      ),
      plainto_tsquery('english', search_query)
    ) AS relevance
  FROM public.products p
  LEFT JOIN public.brands b             ON b.id = p.brand_id
  LEFT JOIN public.product_categories c ON c.id = p.category_id
  WHERE to_tsvector(
          'english',
          COALESCE(p.product_name,'') || ' ' ||
          COALESCE(b.brand_name,'')   || ' ' ||
          COALESCE(p.product_description,'')
        ) @@ plainto_tsquery('english', search_query)
  ORDER BY relevance DESC, p.product_name;
END;
$$;


ALTER FUNCTION public.search_products(search_query text) OWNER TO supabase_admin;

--
-- Name: FUNCTION search_products(search_query text); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.search_products(search_query text) IS 'Full-text search over products with relevance ranking (name + brand + description).';


--
-- Name: search_shops(text, integer); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.search_shops(p_search_term text, p_limit integer DEFAULT 10) RETURNS TABLE(org_id uuid, org_name text, branch text, contact_name text, contact_phone text, state_name text, display_label text)
    LANGUAGE sql STABLE SECURITY DEFINER
    AS $$
  SELECT
    o.id AS org_id,
    o.org_name,
    o.branch,
    o.contact_name,
    o.contact_phone,
    s.state_name AS state_name,
    CASE
      WHEN o.branch IS NOT NULL AND TRIM(o.branch) <> ''
        THEN o.org_name || ' (' || o.branch || ')'
      ELSE o.org_name
    END AS display_label
  FROM public.organizations o
  LEFT JOIN public.states s ON s.id = o.state_id
  WHERE o.org_type_code = 'SHOP'
    AND o.is_active = true
    AND (
      p_search_term IS NULL
      OR TRIM(p_search_term) = ''
      OR o.org_name ILIKE '%' || TRIM(p_search_term) || '%'
      OR o.branch ILIKE '%' || TRIM(p_search_term) || '%'
      OR o.contact_name ILIKE '%' || TRIM(p_search_term) || '%'
      OR o.contact_phone ILIKE '%' || TRIM(p_search_term) || '%'
    )
  ORDER BY o.org_name ASC, o.branch ASC NULLS LAST
  LIMIT LEAST(p_limit, 30);
$$;


