-- Name: FUNCTION seed_hr_gl_accounts(p_company_id uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.seed_hr_gl_accounts(p_company_id uuid) IS 'Seeds HR-related GL accounts (expense + liability + clearing) into the Chart of Accounts for a company.';


--
-- Name: seed_payroll_components(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.seed_payroll_components(p_company_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_count integer;
BEGIN
    INSERT INTO public.payroll_components (company_id, code, name, category, is_statutory, is_taxable, sort_order, description)
    VALUES
        -- Earnings
        (p_company_id, 'BASIC',         'Basic Salary',                  'earning',    false, true,  10, 'Monthly basic salary'),
        (p_company_id, 'OT',            'Overtime',                      'earning',    false, true,  20, 'Overtime payments'),
        (p_company_id, 'ALLOWANCE',     'Fixed Allowance',               'earning',    false, true,  30, 'Recurring allowances'),
        (p_company_id, 'BONUS',         'Bonus / Incentive',             'earning',    false, true,  40, 'Performance bonus'),
        (p_company_id, 'COMMISSION',    'Commission',                    'earning',    false, true,  50, 'Sales commission'),
        -- Deductions (employee portion)
        (p_company_id, 'EPF_EE',        'EPF (Employee)',                'deduction',  true,  false, 100, 'Employee EPF contribution'),
        (p_company_id, 'SOCSO_EE',      'SOCSO (Employee)',              'deduction',  true,  false, 110, 'Employee SOCSO contribution'),
        (p_company_id, 'EIS_EE',        'EIS (Employee)',                'deduction',  true,  false, 120, 'Employee EIS contribution'),
        (p_company_id, 'PCB',           'PCB / Income Tax',              'deduction',  true,  false, 130, 'Monthly tax deduction'),
        (p_company_id, 'OTHER_DED',     'Other Deductions',              'deduction',  false, false, 200, 'Miscellaneous deductions'),
        -- Employer contributions
        (p_company_id, 'EPF_ER',        'EPF (Employer)',                'employer',   true,  false, 300, 'Employer EPF contribution'),
        (p_company_id, 'SOCSO_ER',      'SOCSO (Employer)',              'employer',   true,  false, 310, 'Employer SOCSO contribution'),
        (p_company_id, 'EIS_ER',        'EIS (Employer)',                'employer',   true,  false, 320, 'Employer EIS contribution')
    ON CONFLICT (company_id, code) DO NOTHING;

    SELECT count(*) INTO v_count
    FROM public.payroll_components
    WHERE company_id = p_company_id;

    RETURN jsonb_build_object(
        'success', true,
        'components_count', v_count,
        'message', 'Default payroll components seeded'
    );
END;
$$;


ALTER FUNCTION public.seed_payroll_components(p_company_id uuid) OWNER TO supabase_admin;

--
-- Name: seed_payroll_gl_mappings(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.seed_payroll_gl_mappings(p_company_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_count integer;
    v_component record;
    v_debit_id uuid;
    v_credit_id uuid;
BEGIN
    FOR v_component IN
        SELECT pc.id, pc.code, pc.category
        FROM public.payroll_components pc
        WHERE pc.company_id = p_company_id AND pc.is_active = true
    LOOP
        -- Determine default GL account IDs based on component code
        v_debit_id := NULL;
        v_credit_id := NULL;

        CASE v_component.code
            WHEN 'BASIC' THEN
                SELECT id INTO v_debit_id  FROM gl_accounts WHERE company_id = p_company_id AND code = '6100';
                SELECT id INTO v_credit_id FROM gl_accounts WHERE company_id = p_company_id AND code = '2200';
            WHEN 'OT' THEN
                SELECT id INTO v_debit_id  FROM gl_accounts WHERE company_id = p_company_id AND code = '6110';
                SELECT id INTO v_credit_id FROM gl_accounts WHERE company_id = p_company_id AND code = '2200';
            WHEN 'ALLOWANCE' THEN
                SELECT id INTO v_debit_id  FROM gl_accounts WHERE company_id = p_company_id AND code = '6120';
                SELECT id INTO v_credit_id FROM gl_accounts WHERE company_id = p_company_id AND code = '2200';
            WHEN 'BONUS' THEN
                SELECT id INTO v_debit_id  FROM gl_accounts WHERE company_id = p_company_id AND code = '6130';
                SELECT id INTO v_credit_id FROM gl_accounts WHERE company_id = p_company_id AND code = '2200';
            WHEN 'COMMISSION' THEN
                SELECT id INTO v_debit_id  FROM gl_accounts WHERE company_id = p_company_id AND code = '6140';
                SELECT id INTO v_credit_id FROM gl_accounts WHERE company_id = p_company_id AND code = '2200';
            -- Deductions: no debit (reduces net pay), credit the liability
            WHEN 'EPF_EE' THEN
                SELECT id INTO v_credit_id FROM gl_accounts WHERE company_id = p_company_id AND code = '2210';
            WHEN 'SOCSO_EE' THEN
                SELECT id INTO v_credit_id FROM gl_accounts WHERE company_id = p_company_id AND code = '2220';
            WHEN 'EIS_EE' THEN
                SELECT id INTO v_credit_id FROM gl_accounts WHERE company_id = p_company_id AND code = '2230';
            WHEN 'PCB' THEN
                SELECT id INTO v_credit_id FROM gl_accounts WHERE company_id = p_company_id AND code = '2240';
            WHEN 'OTHER_DED' THEN
                SELECT id INTO v_credit_id FROM gl_accounts WHERE company_id = p_company_id AND code = '2250';
            -- Employer contributions
            WHEN 'EPF_ER' THEN
                SELECT id INTO v_debit_id  FROM gl_accounts WHERE company_id = p_company_id AND code = '6150';
                SELECT id INTO v_credit_id FROM gl_accounts WHERE company_id = p_company_id AND code = '2210';
            WHEN 'SOCSO_ER' THEN
                SELECT id INTO v_debit_id  FROM gl_accounts WHERE company_id = p_company_id AND code = '6160';
                SELECT id INTO v_credit_id FROM gl_accounts WHERE company_id = p_company_id AND code = '2220';
            WHEN 'EIS_ER' THEN
                SELECT id INTO v_debit_id  FROM gl_accounts WHERE company_id = p_company_id AND code = '6170';
                SELECT id INTO v_credit_id FROM gl_accounts WHERE company_id = p_company_id AND code = '2230';
            ELSE
                CONTINUE;
        END CASE;

        -- Only insert if at least one side is mapped
        IF v_debit_id IS NOT NULL OR v_credit_id IS NOT NULL THEN
            INSERT INTO public.payroll_component_gl_map (
                company_id, component_id, debit_gl_account_id, credit_gl_account_id,
                is_active, created_by
            ) VALUES (
                p_company_id, v_component.id, v_debit_id, v_credit_id,
                true, auth.uid()
            )
            ON CONFLICT (company_id, component_id, effective_from) DO NOTHING;
        END IF;
    END LOOP;

    SELECT count(*) INTO v_count
    FROM public.payroll_component_gl_map
    WHERE company_id = p_company_id;

    RETURN jsonb_build_object(
        'success', true,
        'mappings_count', v_count,
        'message', 'Default payroll GL mappings seeded'
    );
END;
$$;


ALTER FUNCTION public.seed_payroll_gl_mappings(p_company_id uuid) OWNER TO supabase_admin;

--
-- Name: send_admin_support_message(uuid, text, jsonb); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.send_admin_support_message(p_conversation_id uuid, p_message text, p_attachments jsonb DEFAULT '[]'::jsonb) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_message_id UUID;
    v_admin_id UUID := auth.uid();
BEGIN
    -- Verify admin
    IF NOT public.is_support_admin() THEN
        RAISE EXCEPTION 'Access denied';
    END IF;
    
    -- Insert message
    INSERT INTO public.support_conversation_messages (
        conversation_id,
        sender_type,
        sender_admin_id,
        message_type,
        body_text,
        attachments
    ) VALUES (
        p_conversation_id,
        'admin',
        v_admin_id,
        'text',
        p_message,
        p_attachments
    )
    RETURNING id INTO v_message_id;
    
    RETURN v_message_id;
END;
$$;


ALTER FUNCTION public.send_admin_support_message(p_conversation_id uuid, p_message text, p_attachments jsonb) OWNER TO supabase_admin;

--
-- Name: send_announcement_blast(text, text, jsonb); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.send_announcement_blast(announcement_subject text, announcement_message text, announcement_attachments jsonb DEFAULT '[]'::jsonb) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    target_user RECORD;
    new_thread_id UUID;
BEGIN
    -- Check if caller is admin
    IF NOT public.is_admin() THEN
        RAISE EXCEPTION 'Access denied';
    END IF;

    -- Loop through all active users
    -- Adjust the WHERE clause to target specific users if needed
    FOR target_user IN 
        SELECT id FROM public.users 
        WHERE role_code = 'user' -- Assuming 'user' role exists for normal users
        -- AND status = 'active' -- Uncomment if status column exists
    LOOP
        -- Create thread
        INSERT INTO public.support_threads (
            created_by_user_id,
            subject,
            status,
            last_message_preview,
            last_message_at
        ) VALUES (
            target_user.id,
            announcement_subject,
            'open',
            substring(announcement_message from 1 for 50),
            NOW()
        ) RETURNING id INTO new_thread_id;

        -- Create message
        INSERT INTO public.support_messages (
            thread_id,
            sender_type,
            sender_user_id,
            body,
            attachments
        ) VALUES (
            new_thread_id,
            'admin',
            auth.uid(),
            announcement_message,
            announcement_attachments
        );
    END LOOP;
END;
$$;


ALTER FUNCTION public.send_announcement_blast(announcement_subject text, announcement_message text, announcement_attachments jsonb) OWNER TO supabase_admin;

--
-- Name: send_support_message(uuid, text, jsonb); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.send_support_message(p_conversation_id uuid, p_message text, p_attachments jsonb DEFAULT '[]'::jsonb) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_message_id UUID;
    v_user_id UUID := auth.uid();
BEGIN
    -- Verify ownership
    IF NOT EXISTS (
        SELECT 1 FROM public.support_conversations
        WHERE id = p_conversation_id
          AND created_by_user_id = v_user_id
    ) THEN
        RAISE EXCEPTION 'Conversation not found or access denied';
    END IF;
    
    -- Insert message
    INSERT INTO public.support_conversation_messages (
        conversation_id,
        sender_type,
        sender_user_id,
        message_type,
        body_text,
        attachments
    ) VALUES (
        p_conversation_id,
        'user',
        v_user_id,
        'text',
        p_message,
        p_attachments
    )
    RETURNING id INTO v_message_id;
    
    RETURN v_message_id;
END;
$$;


