--
-- Name: set_whatsapp_draft(uuid, text, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.set_whatsapp_draft(p_org_id uuid, p_user_phone text, p_draft text) RETURNS public.whatsapp_conversations
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_result whatsapp_conversations;
BEGIN
    UPDATE whatsapp_conversations SET
        pending_draft = p_draft,
        pending_draft_at = now(),
        updated_at = now()
    WHERE org_id = p_org_id AND user_phone_digits = p_user_phone
    RETURNING * INTO v_result;
    
    IF v_result IS NULL THEN
        INSERT INTO whatsapp_conversations (org_id, user_phone_digits, pending_draft, pending_draft_at)
        VALUES (p_org_id, p_user_phone, p_draft, now())
        RETURNING * INTO v_result;
    END IF;
    
    RETURN v_result;
END;
$$;


