--
-- Name: setup_hr_gl_mappings(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.setup_hr_gl_mappings(p_organization_id uuid) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_company_id uuid;
  v_mappings jsonb;
  v_rec jsonb;
  v_account_id uuid;
  v_created integer := 0;
  v_skipped integer := 0;
BEGIN
  SELECT public.get_company_id(p_organization_id) INTO v_company_id;
  IF v_company_id IS NULL THEN
    RAISE EXCEPTION 'Company not found for organization %', p_organization_id;
  END IF;

  -- Define default mappings: document_type -> mapping_key -> account_code
  -- expense_account_id = debit side, offset_account_id = credit side
  v_mappings := '[
    {"doc": "PAYROLL_RUN", "key": "salary_expense",             "expense_code": "6100", "offset_code": null,   "desc": "Salaries & Wages Expense (debit)"},
    {"doc": "PAYROLL_RUN", "key": "payroll_payable",            "expense_code": null,   "offset_code": "2200", "desc": "Net Payroll Payable (credit)"},
    {"doc": "PAYROLL_RUN", "key": "epf_payable",                "expense_code": null,   "offset_code": "2210", "desc": "EPF Payable (credit)"},
    {"doc": "PAYROLL_RUN", "key": "socso_payable",              "expense_code": null,   "offset_code": "2220", "desc": "SOCSO Payable (credit)"},
    {"doc": "PAYROLL_RUN", "key": "eis_payable",                "expense_code": null,   "offset_code": "2230", "desc": "EIS Payable (credit)"},
    {"doc": "PAYROLL_RUN", "key": "pcb_payable",                "expense_code": null,   "offset_code": "2240", "desc": "PCB/MTD Payable (credit)"},
    {"doc": "PAYROLL_RUN", "key": "other_deductions_payable",   "expense_code": null,   "offset_code": "2250", "desc": "Other Deductions Payable (credit)"},
    {"doc": "PAYROLL_RUN", "key": "employer_contributions",     "expense_code": "6110", "offset_code": null,   "desc": "Employer Contributions Expense (debit, optional split)"},
    {"doc": "EXPENSE_CLAIM", "key": "claims_expense",           "expense_code": "6200", "offset_code": null,   "desc": "Staff Claims Expense (debit)"},
    {"doc": "EXPENSE_CLAIM", "key": "claims_payable",           "expense_code": null,   "offset_code": "2300", "desc": "Employee Claims Payable (credit)"}
  ]'::jsonb;

  FOR v_rec IN SELECT * FROM jsonb_array_elements(v_mappings)
  LOOP
    -- Skip if mapping already exists
    IF EXISTS (
      SELECT 1 FROM public.hr_gl_mappings
      WHERE organization_id = p_organization_id
        AND document_type = v_rec->>'doc'
        AND mapping_key = v_rec->>'key'
    ) THEN
      v_skipped := v_skipped + 1;
      CONTINUE;
    END IF;

    -- Resolve account IDs from codes
    DECLARE
      v_expense_id uuid := null;
      v_offset_id uuid := null;
    BEGIN
      IF v_rec->>'expense_code' IS NOT NULL THEN
        SELECT id INTO v_expense_id
        FROM public.gl_accounts
        WHERE company_id = v_company_id
          AND code = v_rec->>'expense_code'
          AND is_active = true
        LIMIT 1;
      END IF;

      IF v_rec->>'offset_code' IS NOT NULL THEN
        SELECT id INTO v_offset_id
        FROM public.gl_accounts
        WHERE company_id = v_company_id
          AND code = v_rec->>'offset_code'
          AND is_active = true
        LIMIT 1;
      END IF;

      INSERT INTO public.hr_gl_mappings (
        organization_id, document_type, mapping_key,
        expense_account_id, offset_account_id,
        description, is_active
      ) VALUES (
        p_organization_id, v_rec->>'doc', v_rec->>'key',
        v_expense_id, v_offset_id,
        v_rec->>'desc', true
      );
      v_created := v_created + 1;
    END;
  END LOOP;

  RETURN jsonb_build_object(
    'organization_id', p_organization_id,
    'created', v_created,
    'skipped', v_skipped
  );
END;
$$;


ALTER FUNCTION public.setup_hr_gl_mappings(p_organization_id uuid) OWNER TO supabase_admin;

--
-- Name: slugify_roadtour_segment(text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.slugify_roadtour_segment(p_value text) RETURNS text
    LANGUAGE sql IMMUTABLE
    AS $$
  SELECT COALESCE(
    NULLIF(
      regexp_replace(
        regexp_replace(
          regexp_replace(lower(trim(COALESCE(p_value, ''))), '[_\s]+', '-', 'g'),
          '[^a-z0-9-]', '', 'g'
        ),
        '-+', '-', 'g'
      ),
      ''
    ),
    'untitled'
  )
$$;


ALTER FUNCTION public.slugify_roadtour_segment(p_value text) OWNER TO supabase_admin;

