-- Name: snapshot_roadtour_run_id(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.snapshot_roadtour_run_id() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_run uuid;
BEGIN
  IF NEW.roadtour_run_id IS NOT NULL THEN
    RETURN NEW;
  END IF;
  IF NEW.campaign_id IS NULL THEN
    RETURN NEW;
  END IF;
  SELECT roadtour_run_id INTO v_run FROM public.roadtour_campaigns WHERE id = NEW.campaign_id;
  NEW.roadtour_run_id := v_run;
  RETURN NEW;
END;
$$;


