--
-- Name: stock_movements_apply_to_inventory(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.stock_movements_apply_to_inventory() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_inventory_id uuid;
  v_before int;
  v_after  int;
  v_target_org uuid;
BEGIN
  -- Ignore zero deltas
  IF COALESCE(NEW.quantity_change,0) = 0 THEN
    RETURN NEW;
  END IF;

  -- Only handle types that are NOT handled by explicit functions or record_stock_movement
  -- Removed: manual_in, manual_out, order_fulfillment, warehouse_adjustment_in, warehouse_adjustment_out
  -- Kept: qr_ship, warehouse_receive (assuming these might rely on trigger)
  IF NEW.movement_type NOT IN ('qr_ship', 'warehouse_receive') THEN
    RETURN NEW;
  END IF;

  -- Determine which organization's inventory should be updated
  IF NEW.quantity_change < 0 THEN
    v_target_org := COALESCE(NEW.from_organization_id, NEW.to_organization_id);
  ELSE
    v_target_org := COALESCE(NEW.to_organization_id, NEW.from_organization_id);
  END IF;

  IF v_target_org IS NULL THEN
    RETURN NEW;
  END IF;

  -- Lock/ensure inventory row
  SELECT id, quantity_on_hand
  INTO v_inventory_id, v_before
  FROM public.product_inventory
  WHERE variant_id = NEW.variant_id
    AND organization_id = v_target_org
    AND is_active = true
  FOR UPDATE;

  IF v_inventory_id IS NULL THEN
    -- Create a fresh row if missing
    INSERT INTO public.product_inventory(
      variant_id, organization_id, quantity_on_hand,
      quantity_allocated, warehouse_location, average_cost,
      created_at, updated_at, is_active
    )
    VALUES(
      NEW.variant_id, v_target_org, 0,
      0, NEW.warehouse_location, NEW.unit_cost,
      NOW(), NOW(), true
    )
    RETURNING id, quantity_on_hand INTO v_inventory_id, v_before;
  END IF;

  v_after := GREATEST(0, v_before + NEW.quantity_change);

  UPDATE public.product_inventory
     SET quantity_on_hand = v_after,
         updated_at       = NOW()
   WHERE id = v_inventory_id;

  -- If the inserter didn't fill before/after, backfill for consistency
  IF NEW.quantity_before IS NULL OR NEW.quantity_after IS NULL THEN
    NEW.quantity_before := v_before;
    NEW.quantity_after  := v_after;
  END IF;

  RETURN NEW;
END
$$;


ALTER FUNCTION public.stock_movements_apply_to_inventory() OWNER TO supabase_admin;

--
-- Name: submit_referral_claim(uuid, integer, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.submit_referral_claim(p_reference_user_id uuid, p_claim_points integer, p_org_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_settings  record;
  v_org_id    uuid;
  v_claimable_points bigint;
  v_claim_rm  numeric(12,2);
  v_claim_id  uuid;
  v_ref_user  record;
BEGIN
  -- Get reference user
  SELECT * INTO v_ref_user FROM public.users WHERE id = p_reference_user_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Reference user not found');
  END IF;

  -- Check employment status
  IF v_ref_user.employment_status = 'resigned' OR v_ref_user.employment_status = 'terminated' THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Inactive references cannot submit claims');
  END IF;

  -- Determine org
  v_org_id := COALESCE(p_org_id, v_ref_user.organization_id);
  IF v_org_id IS NULL THEN
    SELECT id INTO v_org_id FROM public.organizations WHERE org_type_code = 'HQ' LIMIT 1;
  END IF;

  -- Get settings
  SELECT * INTO v_settings
  FROM public.referral_incentive_settings
  WHERE org_id = v_org_id;

  IF NOT FOUND OR NOT v_settings.enabled THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Referral incentives are not enabled');
  END IF;

  -- Calculate claimable balance
  SELECT
    (COALESCE(sum(rac.points_amount), 0)
     + COALESCE((SELECT sum(CASE WHEN adj.adjustment_type IN ('credit','transfer_in') THEN adj.points_amount ELSE 0 END)
                 FROM public.referral_adjustments adj WHERE adj.reference_user_id = p_reference_user_id), 0)
     - COALESCE((SELECT sum(CASE WHEN adj.adjustment_type IN ('debit','transfer_out') THEN adj.points_amount ELSE 0 END)
                 FROM public.referral_adjustments adj WHERE adj.reference_user_id = p_reference_user_id), 0)
     - COALESCE((SELECT sum(rc.claim_points) FROM public.referral_claims rc
                 WHERE rc.reference_user_id = p_reference_user_id AND rc.status IN ('approved','paid','pending')), 0)
    )
  INTO v_claimable_points
  FROM public.referral_accruals rac
  WHERE rac.reference_user_id = p_reference_user_id;

  IF p_claim_points > v_claimable_points THEN
    RETURN jsonb_build_object(
      'ok', false,
      'error', 'Claim exceeds claimable balance',
      'claimable_points', v_claimable_points,
      'requested_points', p_claim_points
    );
  END IF;

  -- Convert points to RM
  v_claim_rm := (p_claim_points::numeric / v_settings.conversion_points) * v_settings.conversion_rm;

  -- Check minimum threshold
  IF v_claim_rm < v_settings.min_claim_threshold_rm THEN
    RETURN jsonb_build_object(
      'ok', false,
      'error', 'Claim amount below minimum threshold of RM ' || v_settings.min_claim_threshold_rm::text,
      'claim_rm', v_claim_rm,
      'min_threshold', v_settings.min_claim_threshold_rm
    );
  END IF;

  -- Insert claim
  INSERT INTO public.referral_claims (
    org_id, reference_user_id, claim_points, claim_rm,
    conversion_points, conversion_rm, status,
    submitted_by
  )
  VALUES (
    v_org_id, p_reference_user_id, p_claim_points, v_claim_rm,
    v_settings.conversion_points, v_settings.conversion_rm, 'pending',
    p_reference_user_id
  )
  RETURNING id INTO v_claim_id;

  RETURN jsonb_build_object(
    'ok', true,
    'claim_id', v_claim_id,
    'claim_points', p_claim_points,
    'claim_rm', v_claim_rm,
    'claimable_after', v_claimable_points - p_claim_points
  );
END;
$$;


ALTER FUNCTION public.submit_referral_claim(p_reference_user_id uuid, p_claim_points integer, p_org_id uuid) OWNER TO supabase_admin;

--
-- Name: sync_roadtour_qr_route_fields(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.sync_roadtour_qr_route_fields() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_campaign_name text;
  v_start_date date;
  v_reference_name text;
  v_year integer;
  v_campaign_slug text;
  v_reference_slug text;
  v_short_code text;
BEGIN
  SELECT c.name, c.start_date
    INTO v_campaign_name, v_start_date
  FROM public.roadtour_campaigns c
  WHERE c.id = NEW.campaign_id;

  SELECT COALESCE(u.full_name, u.phone, NEW.token)
    INTO v_reference_name
  FROM public.users u
  WHERE u.id = NEW.account_manager_user_id;

  v_year := COALESCE(EXTRACT(YEAR FROM v_start_date)::integer, EXTRACT(YEAR FROM NEW.created_at)::integer, EXTRACT(YEAR FROM now())::integer);
  v_campaign_slug := public.slugify_roadtour_segment(v_campaign_name);
  v_reference_slug := public.slugify_roadtour_segment(v_reference_name);
  v_short_code := lower(substr(regexp_replace(COALESCE(NEW.token, ''), '[^a-zA-Z0-9]', '', 'g'), 1, 8));
  IF v_short_code = '' THEN
    v_short_code := substr(md5(COALESCE(NEW.id::text, clock_timestamp()::text)), 1, 8);
  END IF;

  NEW.route_year := v_year;
  NEW.campaign_slug := v_campaign_slug;
  NEW.reference_slug := v_reference_slug;
  NEW.short_code := v_short_code;
  NEW.canonical_path := '/roadtour/' || v_year::text || '/' || v_campaign_slug || '/' || v_reference_slug || '-' || v_short_code;
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.sync_roadtour_qr_route_fields() OWNER TO supabase_admin;

--
-- Name: sync_shop_distributor_link(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.sync_shop_distributor_link() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Only for SHOP rows that are active and have a DIST parent
  IF NEW.org_type_code = 'SHOP'
     AND NEW.is_active = TRUE
     AND NEW.parent_org_id IS NOT NULL
     AND (SELECT org_type_code FROM public.organizations WHERE id = NEW.parent_org_id) = 'DIST'
  THEN
    INSERT INTO public.shop_distributors (
      shop_id, distributor_id, payment_terms, is_active, is_preferred, created_at, updated_at
    )
    VALUES (NEW.id, NEW.parent_org_id, 'NET_30', TRUE, TRUE, NOW(), NOW())
    ON CONFLICT (shop_id, distributor_id) DO NOTHING;
  END IF;

  RETURN NEW;
END; $$;


ALTER FUNCTION public.sync_shop_distributor_link() OWNER TO supabase_admin;

--
-- Name: sync_user_profile(uuid, text, text, uuid, text, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.sync_user_profile(p_user_id uuid, p_email text, p_role_code text DEFAULT 'GUEST'::text, p_organization_id uuid DEFAULT NULL::uuid, p_full_name text DEFAULT NULL::text, p_phone text DEFAULT NULL::text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_result   JSON;
  v_scope    TEXT;
BEGIN
  -- Infer account_scope: users with an organization are portal users
  IF p_organization_id IS NOT NULL AND p_role_code NOT IN ('GUEST', 'CONSUMER') THEN
    v_scope := 'portal';
  ELSE
    v_scope := 'store';
  END IF;

  INSERT INTO public.users (
    id, email, role_code, organization_id, full_name, phone,
    account_scope, is_active, is_verified, email_verified_at,
    created_at, updated_at
  ) VALUES (
    p_user_id, p_email, p_role_code, p_organization_id, p_full_name, p_phone,
    v_scope, TRUE, TRUE, NOW(),
    NOW(), NOW()
  )
  ON CONFLICT (id) DO UPDATE SET
    email              = EXCLUDED.email,
    role_code          = EXCLUDED.role_code,
    organization_id    = EXCLUDED.organization_id,
    full_name          = EXCLUDED.full_name,
    phone              = EXCLUDED.phone,
    account_scope      = EXCLUDED.account_scope,
    is_active          = EXCLUDED.is_active,
    is_verified        = EXCLUDED.is_verified,
    email_verified_at  = EXCLUDED.email_verified_at,
    updated_at         = NOW();

  SELECT json_build_object(
    'success', TRUE,
    'user_id', p_user_id,
    'email',   p_email
  ) INTO v_result;

  RETURN v_result;
END;
$$;


ALTER FUNCTION public.sync_user_profile(p_user_id uuid, p_email text, p_role_code text, p_organization_id uuid, p_full_name text, p_phone text) OWNER TO supabase_admin;

--
-- Name: FUNCTION sync_user_profile(p_user_id uuid, p_email text, p_role_code text, p_organization_id uuid, p_full_name text, p_phone text); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.sync_user_profile(p_user_id uuid, p_email text, p_role_code text, p_organization_id uuid, p_full_name text, p_phone text) IS 'Syncs or creates public.users record after auth.users is created. Automatically sets account_scope=portal when organization_id is provided.';


--
-- Name: sync_variant_default_media(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.sync_variant_default_media() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- When a media item is set as default, update the variant's image_url
    IF NEW.is_default = true THEN
        -- Unset other defaults for this variant
        UPDATE public.variant_media
        SET is_default = false, updated_at = now()
        WHERE variant_id = NEW.variant_id
          AND id <> NEW.id
          AND is_default = true;

        -- Sync to product_variants.image_url for backward compat
        IF NEW.type = 'image' THEN
            UPDATE public.product_variants
            SET image_url = NEW.url, updated_at = now()
            WHERE id = NEW.variant_id;
        ELSIF NEW.type = 'video' AND NEW.thumbnail_url IS NOT NULL THEN
            UPDATE public.product_variants
            SET image_url = NEW.thumbnail_url, updated_at = now()
            WHERE id = NEW.variant_id;
        END IF;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.sync_variant_default_media() OWNER TO supabase_admin;

