--
-- Name: trg_block_duplicate_outbound(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.trg_block_duplicate_outbound() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.movement_type IN ('manual_out','shipment','transfer_out') THEN
        PERFORM 1
            FROM public.stock_movements m
         WHERE m.movement_type IN ('manual_out','shipment','transfer_out')
             AND m.variant_id = NEW.variant_id
             AND m.from_organization_id = NEW.from_organization_id
             AND m.to_organization_id   = NEW.to_organization_id
             AND COALESCE(m.reference_no,'') = COALESCE(NEW.reference_no,'')
             AND COALESCE(m.company_id, '00000000-0000-0000-0000-000000000000') =
                     COALESCE(NEW.company_id, '00000000-0000-0000-0000-000000000000')
             AND (m.created_at, m.id) < (COALESCE(NEW.created_at, now()), COALESCE(NEW.id, gen_random_uuid()));

        IF FOUND THEN
            RAISE EXCEPTION
                'Duplicate outbound detected for (company/wh/dist/variant/ref): (%/%/%/%/%). Insert aborted.',
                NEW.company_id, NEW.from_organization_id, NEW.to_organization_id, NEW.variant_id, NEW.reference_no;
        END IF;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.trg_block_duplicate_outbound() OWNER TO supabase_admin;

--
-- Name: trg_on_purchase_receive_create_balance_request(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.trg_on_purchase_receive_create_balance_request() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
  v_order_id uuid;
  v_terms jsonb;
  v_trigger_mode text := 'on_first_receive';
  v_exists boolean := false;
  v_should_run boolean := false;
BEGIN
  -- 1) Decide if this movement should attempt to create a balance request
  BEGIN
    IF NEW.movement_type IS NOT DISTINCT FROM 'purchase_in' THEN
      v_should_run := true;
    ELSIF NEW.movement_type IS NOT DISTINCT FROM 'warehouse_receive' THEN
      v_should_run := true;
    ELSIF NEW.movement_type IS NOT DISTINCT FROM 'addition' THEN
      BEGIN
        IF COALESCE(NEW.reason, '') = 'warehouse_receive'
           AND NEW.reference_type IS NOT DISTINCT FROM 'order'
           AND NEW.reference_id IS NOT NULL THEN
          v_should_run := true;
        END IF;
      EXCEPTION WHEN undefined_column THEN
        -- If reason/reference columns are unavailable, ignore and fall back to legacy behaviour
        NULL;
      END;
    END IF;
  EXCEPTION WHEN undefined_column THEN
    -- movement_type column missing; nothing to do
    RETURN NEW;
  END;

  IF NOT v_should_run THEN
    RETURN NEW;
  END IF;

  -- 2) Resolve order_id from multiple sources
  v_order_id := NULL;

  -- Direct column (legacy schemas may include order_id)
  BEGIN
    v_order_id := NEW.order_id;
  EXCEPTION WHEN undefined_column THEN
    v_order_id := NULL;
  END;

  -- Reference-based fallback (current API stores order in reference fields)
  IF v_order_id IS NULL THEN
    BEGIN
      IF NEW.reference_type IS NOT DISTINCT FROM 'order' AND NEW.reference_id IS NOT NULL THEN
        v_order_id := NEW.reference_id;
      END IF;
    EXCEPTION WHEN undefined_column THEN
      NULL;
    END;
  END IF;

  -- Batch fallback for QR batch workflows
  IF v_order_id IS NULL THEN
    BEGIN
      PERFORM 1 FROM information_schema.columns
       WHERE table_schema = 'public' AND table_name = 'stock_movements' AND column_name = 'batch_id';
      IF FOUND AND NEW.batch_id IS NOT NULL THEN
        SELECT qb.order_id INTO v_order_id
        FROM public.qr_batches qb
        WHERE qb.id = NEW.batch_id;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      v_order_id := NULL;
    END;
  END IF;

  IF v_order_id IS NULL THEN
    -- No order context; nothing to do
    RETURN NEW;
  END IF;

  -- 3) Read order.payment_terms to decide trigger mode (defaults to on_first_receive)
  BEGIN
    SELECT o.payment_terms INTO v_terms
    FROM public.orders o
    WHERE o.id = v_order_id;
    IF v_terms IS NOT NULL THEN
      v_trigger_mode := COALESCE(v_terms->>'balance_trigger', 'on_first_receive');
    END IF;
  EXCEPTION WHEN OTHERS THEN
    v_trigger_mode := 'on_first_receive';
  END;

  -- 4) Enforce one-per-order (quick check to avoid needless work)
  BEGIN
    SELECT TRUE INTO v_exists
    FROM public.documents d
    WHERE d.doc_type = 'PAYMENT_REQUEST'
      AND (d.payload ? 'order_id')
      AND (d.payload->>'order_id') = v_order_id::text
      AND (d.payload->>'reason') = 'BALANCE_50_AFTER_RECEIVE'
    LIMIT 1;
  EXCEPTION WHEN undefined_table OR undefined_column THEN
    v_exists := FALSE;
  END;

  IF v_exists THEN
    RETURN NEW;
  END IF;

  -- 5) Decide when to fire:
  --    - on_first_receive : create immediately
  --    - on_full_receive  : only create if we can verify "fully received" (best-effort)
  IF v_trigger_mode = 'on_first_receive' THEN
    PERFORM public.fn_create_balance_payment_request(v_order_id);
    RETURN NEW;
  ELSIF v_trigger_mode = 'on_full_receive' THEN
    -- Best-effort: if you later add a function public.order_receive_completion_pct(order_id) returning [0..1],
    -- we will use it; otherwise, we NO-OP (scan again when function exists or switch to on_first_receive).
    BEGIN
      IF EXISTS (
        SELECT 1
        FROM pg_proc
        WHERE proname = 'order_receive_completion_pct'
          AND pg_function_is_visible(oid)
      ) THEN
        -- Dynamic call to avoid signature drift; assumes (uuid) -> numeric
        -- If >= 0.999, treat as fully received.
        DECLARE v_pct numeric;
        BEGIN
          EXECUTE 'SELECT public.order_receive_completion_pct($1)'
          INTO v_pct
          USING v_order_id;

          IF COALESCE(v_pct, 0) >= 0.999 THEN
            PERFORM public.fn_create_balance_payment_request(v_order_id);
          END IF;
        EXCEPTION WHEN OTHERS THEN
          -- Silent fallthrough; we will try again on next receive or admin can run manually.
          NULL;
        END;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      -- No verifier available; do nothing
      NULL;
    END;
    RETURN NEW;
  ELSE
    -- Unknown mode; fail safe (do nothing)
    RETURN NEW;
  END IF;
END;
$_$;


ALTER FUNCTION public.trg_on_purchase_receive_create_balance_request() OWNER TO supabase_admin;

--
-- Name: trg_qr_unique_shipdeduct(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.trg_qr_unique_shipdeduct() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_from uuid;
  v_to   uuid;
  v_ord  uuid;
  v_when timestamptz := now();
  v_batch_update boolean := false;
BEGIN
  -- Only process status transition to shipped_distributor
  IF TG_OP = 'UPDATE'
     AND NEW.status = 'shipped_distributor'
     AND (OLD.status IS DISTINCT FROM NEW.status)
  THEN
    -- ✅ FIX: Check if this is a batch update from the API
    -- If updating many codes at once, the API has already created consolidated movement
    -- We skip trigger processing to avoid duplicates
    --
    -- Detection: If within a transaction that's updating multiple rows,
    -- check if there's a session variable indicating batch processing
    BEGIN
      v_batch_update := current_setting('app.skip_ship_trigger', true)::boolean;
    EXCEPTION
      WHEN OTHERS THEN
        v_batch_update := false;
    END;

    -- Skip trigger if batch update flag is set
    IF v_batch_update THEN
      RETURN NEW;
    END IF;

    -- Resolve orgs/order from the master record
    WITH source AS (
      SELECT
        qmc.warehouse_org_id AS from_org,
        qmc.shipped_to_distributor_id,
        qmc.shipment_order_id,
        qb.order_id           AS batch_order_id
      FROM public.qr_master_codes qmc
      LEFT JOIN public.qr_batches qb ON qb.id = qmc.batch_id
      WHERE qmc.id = NEW.master_code_id
    )
    SELECT
      src.from_org,
      public.wms_resolve_ship_to(
        src.shipped_to_distributor_id,
        ord.buyer_org_id,
        buyer.org_type_code,
        ord.order_type,
        ord.warehouse_org_id,
        src.from_org
      ),
      COALESCE(src.shipment_order_id, src.batch_order_id)
    INTO v_from, v_to, v_ord
    FROM source src
    LEFT JOIN public.orders ord ON ord.id = COALESCE(src.shipment_order_id, src.batch_order_id)
    LEFT JOIN public.organizations buyer ON buyer.id = ord.buyer_org_id;

    IF v_to IS NULL THEN
      RETURN NEW;
    END IF;

    -- Deduct 1 unit (array with the single QR) and write movement row
    PERFORM public.wms_ship_unique_auto(ARRAY[NEW.id], v_from, v_to, v_ord, v_when);
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.trg_qr_unique_shipdeduct() OWNER TO supabase_admin;

--
-- Name: FUNCTION trg_qr_unique_shipdeduct(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.trg_qr_unique_shipdeduct() IS 'Trigger to create inventory movement when QR code status changes to shipped_distributor. 
Modified to skip processing when app.skip_ship_trigger session variable is set to true, 
preventing duplicate movements when API handles batch updates.';


--
-- Name: trg_qr_unique_shipdeduct_stmt(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.trg_qr_unique_shipdeduct_stmt() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  r record;
  v_skip boolean := false;
BEGIN
  -- Optional guard: let API suppress trigger when it already writes consolidated movement
  BEGIN
    v_skip := current_setting('app.skip_ship_trigger', true)::boolean;
  EXCEPTION WHEN OTHERS THEN
    v_skip := false;
  END;

  IF v_skip THEN
    RETURN NULL;  -- API will write the movement; skip trigger
  END IF;

  -- Batch rows that changed to shipped_distributor in this statement
  FOR r IN
    SELECT
      n.variant_id                         AS variant_id,
      qmc.warehouse_org_id                 AS from_org,
      dest.resolved_to                     AS to_org,
      COALESCE(qmc.shipment_order_id, qb.order_id) AS order_id,
      COUNT(*)                             AS units,
      MIN(now())                           AS shipped_at
    FROM newrows n
    JOIN oldrows old_data USING (id)
    JOIN public.qr_master_codes qmc ON qmc.id = n.master_code_id
    LEFT JOIN public.qr_batches qb ON qb.id = qmc.batch_id
    LEFT JOIN public.orders ord ON ord.id = COALESCE(qmc.shipment_order_id, qb.order_id)
    LEFT JOIN public.organizations buyer ON buyer.id = ord.buyer_org_id
    LEFT JOIN LATERAL (
      SELECT public.wms_resolve_ship_to(
        qmc.shipped_to_distributor_id,
        ord.buyer_org_id,
        buyer.org_type_code,
        ord.order_type,
        ord.warehouse_org_id,
        qmc.warehouse_org_id
      ) AS resolved_to
    ) dest ON TRUE
    WHERE n.status = 'shipped_distributor'
      AND old_data.status IS DISTINCT FROM n.status
      AND dest.resolved_to IS NOT NULL
    GROUP BY 1,2,3,4
  LOOP
    PERFORM public.wms_record_movements_from_items(
      jsonb_build_array(
        jsonb_build_object(
          'variant_id', r.variant_id,
          'from_org',   r.from_org,
          'to_org',     r.to_org,
          'order_id',   r.order_id,
          'units',      r.units,
          'shipped_at', r.shipped_at
        )
      )
    );
  END LOOP;

  RETURN NULL; -- statement-level triggers return NULL
END;
$$;


ALTER FUNCTION public.trg_qr_unique_shipdeduct_stmt() OWNER TO supabase_admin;

--
-- Name: FUNCTION trg_qr_unique_shipdeduct_stmt(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.trg_qr_unique_shipdeduct_stmt() IS 'Statement-level trigger for qr_codes updates to shipped_distributor status. 
Aggregates changes and creates consolidated stock movements via WMS.
Fixed: Changed table alias from "old" to "old_data" to avoid ambiguous column reference errors during DELETE operations.';


--
-- Name: trg_qrmaster_shipdeduct(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.trg_qrmaster_shipdeduct() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_skip_trigger text;
BEGIN
  -- only on status transition to shipped_distributor
  IF TG_OP = 'UPDATE'
     AND NEW.status = 'shipped_distributor'
     AND (OLD.status IS DISTINCT FROM NEW.status)
  THEN
    -- Check if we should skip trigger execution (session variable set by API)
    v_skip_trigger := current_setting('app.skip_ship_trigger', true);
    
    IF v_skip_trigger IS NULL OR v_skip_trigger != 'true' THEN
      -- Only call WMS function if not explicitly skipped
      PERFORM public.wms_ship_master_auto(NEW.id);
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.trg_qrmaster_shipdeduct() OWNER TO supabase_admin;

--
-- Name: FUNCTION trg_qrmaster_shipdeduct(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.trg_qrmaster_shipdeduct() IS 'Trigger function for master QR code shipment deduction. 
Respects app.skip_ship_trigger session variable to prevent duplicate WMS calls when API handles inventory manually.';


--
-- Name: trg_stock_movements_fill_cost_and_balance(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.trg_stock_movements_fill_cost_and_balance() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_wh_id uuid;
  v_prev_after integer;
  v_cost numeric;
BEGIN
  -- Determine warehouse context for running balance
  v_wh_id := public._movement_warehouse_id(NEW.movement_type, NEW.from_organization_id, NEW.to_organization_id);
  
  -- 2.3.a) Fill outbound cost if missing: use latest known unit_cost at this warehouse & variant
  IF NEW.unit_cost IS NULL
     AND NEW.movement_type IN ('manual_out','shipment','transfer_out') THEN
    SELECT sm.unit_cost
      INTO v_cost
      FROM public.stock_movements sm
     WHERE sm.from_organization_id = NEW.from_organization_id
       AND sm.variant_id = NEW.variant_id
       AND sm.unit_cost IS NOT NULL
       AND (sm.created_at, sm.id) < (COALESCE(NEW.created_at, now()), COALESCE(NEW.id, gen_random_uuid()))
     ORDER BY sm.created_at DESC, sm.id DESC
     LIMIT 1;

    NEW.unit_cost := COALESCE(v_cost, 0);
  END IF;

  -- 2.3.b) Compute running balance deterministically (prev_after + quantity_change)
  -- BUT: Skip for allocation/deallocation movements, as they show per-order values
  IF NEW.movement_type NOT IN ('allocation', 'deallocation') THEN
    -- Find the previous WAREHOUSE-LEVEL movement (skip allocation/deallocation)
    SELECT sm.quantity_after
      INTO v_prev_after
      FROM public.stock_movements sm
     WHERE public._movement_warehouse_id(sm.movement_type, sm.from_organization_id, sm.to_organization_id) = v_wh_id
       AND sm.variant_id = NEW.variant_id
       AND sm.movement_type NOT IN ('allocation', 'deallocation')
       AND (sm.created_at, sm.id) < (COALESCE(NEW.created_at, now()), COALESCE(NEW.id, gen_random_uuid()))
     ORDER BY sm.created_at DESC, sm.id DESC
     LIMIT 1;

    NEW.quantity_after := COALESCE(v_prev_after, 0) + COALESCE(NEW.quantity_change, 0);
  END IF;
  -- For allocation/deallocation, keep the quantity_after value set by the calling function

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.trg_stock_movements_fill_cost_and_balance() OWNER TO supabase_admin;

--
-- Name: FUNCTION trg_stock_movements_fill_cost_and_balance(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.trg_stock_movements_fill_cost_and_balance() IS 'Fills cost and computes running balance for movements. Skips balance calculation for allocation/deallocation to preserve per-order display values.';


--
-- Name: trigger_document_notification(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.trigger_document_notification() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_event_code TEXT;
  v_order RECORD;
BEGIN
  IF TG_OP = 'INSERT' THEN
    -- Map document type and status to event code
    v_event_code := CASE
      WHEN NEW.doc_type = 'PO' AND NEW.status = 'pending' THEN 'po_created'
      WHEN NEW.doc_type = 'PO' AND NEW.status = 'acknowledged' THEN 'po_acknowledged'
      WHEN NEW.doc_type = 'INVOICE' AND NEW.status = 'pending' THEN 'invoice_created'
      WHEN NEW.doc_type = 'INVOICE' AND NEW.status = 'acknowledged' THEN 'invoice_acknowledged'
      WHEN NEW.doc_type = 'PAYMENT' AND NEW.status = 'acknowledged' THEN 'payment_received'
      WHEN NEW.doc_type = 'RECEIPT' THEN 'receipt_issued'
      ELSE NULL
    END;

    IF v_event_code IS NOT NULL THEN
      -- Get order details
      SELECT * INTO v_order FROM public.orders WHERE id = NEW.order_id;

      -- Queue notification
      PERFORM public.queue_notification(
        NEW.company_id,
        v_event_code,
        channel,
        NULL,
        NULL,
        NULL,
        jsonb_build_object(
          'doc_type', NEW.doc_type,
          'doc_no', NEW.doc_no,
          'order_no', v_order.order_no,
          'issued_by', (SELECT org_name FROM organizations WHERE id = NEW.issued_by_org_id),
          'issued_to', (SELECT org_name FROM organizations WHERE id = NEW.issued_to_org_id)
        ),
        'normal',
        NULL
      )
      FROM unnest(ARRAY['whatsapp', 'email']) AS channel;
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.trigger_document_notification() OWNER TO supabase_admin;

--
-- Name: FUNCTION trigger_document_notification(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.trigger_document_notification() IS 'Automatically queues notifications for document workflow events';


--
-- Name: trigger_order_notification(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.trigger_order_notification() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
  v_event_code TEXT;
  v_company_id UUID;
  v_buyer_org_id UUID;
  v_seller_org_id UUID;
  v_payload JSONB;
  v_total_amount NUMERIC;
  v_total_cases INT;
  v_total_items INT;
  v_item_list TEXT;
  v_customer_name TEXT;
  v_customer_phone TEXT;
  v_delivery_address TEXT;
  v_notes TEXT;
  v_approver_name TEXT;
BEGIN
  IF TG_OP != 'UPDATE' THEN
    RETURN NEW;
  END IF;

  IF NEW.status = 'submitted' AND OLD.status = 'draft' THEN
    v_event_code := 'order_submitted';
  ELSIF NEW.status = 'approved' AND OLD.status = 'submitted' THEN
    v_event_code := 'order_approved';
  ELSIF NEW.status = 'closed' THEN
    v_event_code := 'order_closed';
  ELSIF NEW.status = 'rejected' THEN
    v_event_code := 'order_rejected';
  ELSIF NEW.status = 'cancelled' THEN
    v_event_code := 'order_rejected';
  ELSE
    RETURN NEW;
  END IF;

  v_company_id := NEW.company_id;
  v_buyer_org_id := NEW.buyer_org_id;
  v_seller_org_id := NEW.seller_org_id;

  SELECT 
    COALESCE(SUM(oi.line_total), 0),
    COALESCE(COUNT(*), 0),
    COALESCE(SUM(CEIL(oi.qty::numeric / GREATEST(COALESCE(oi.units_per_case, NEW.units_per_case, 100), 1))), 0)
  INTO v_total_amount, v_total_items, v_total_cases
  FROM order_items oi
  WHERE oi.order_id = NEW.id;

  SELECT string_agg(
    '• ' || COALESCE(p.product_name, 'Product') || 
    CASE WHEN pv.variant_name IS NOT NULL AND pv.variant_name != '' 
         THEN ' – ' || pv.variant_name ELSE '' END ||
    ' × ' || oi.qty || ' units' ||
    ' (' || CEIL(oi.qty::numeric / GREATEST(COALESCE(oi.units_per_case, NEW.units_per_case, 100), 1)) || ' case' ||
    CASE WHEN CEIL(oi.qty::numeric / GREATEST(COALESCE(oi.units_per_case, NEW.units_per_case, 100), 1)) > 1 THEN 's' ELSE '' END ||
    ') — RM ' || TO_CHAR(oi.line_total, 'FM999,999,990.00'),
    E'\n'
  )
  INTO v_item_list
  FROM order_items oi
  LEFT JOIN products p ON p.id = oi.product_id
  LEFT JOIN product_variants pv ON pv.id = oi.variant_id
  WHERE oi.order_id = NEW.id;

  v_notes := COALESCE(NEW.notes, '');
  v_customer_name := COALESCE(
    (SELECT m[1] FROM regexp_matches(v_notes, 'Customer:\s*([^,]+)') AS m),
    (SELECT org_name FROM organizations WHERE id = v_buyer_org_id),
    'Customer'
  );
  v_customer_phone := COALESCE(
    (SELECT m[1] FROM regexp_matches(v_notes, 'Phone:\s*([^,]+)') AS m),
    ''
  );
  v_delivery_address := COALESCE(
    (SELECT m[1] FROM regexp_matches(v_notes, 'Address:\s*(.+)$') AS m),
    ''
  );

  v_payload := jsonb_build_object(
    'order_no', COALESCE(NEW.display_doc_no, NEW.order_no, ''),
    'order_date', TO_CHAR(NEW.created_at, 'DD Mon YYYY'),
    'order_type', NEW.order_type,
    'status', NEW.status,
    'buyer_org', (SELECT org_name FROM organizations WHERE id = v_buyer_org_id),
    'seller_org', (SELECT org_name FROM organizations WHERE id = v_seller_org_id),
    'customer_name', v_customer_name,
    'customer_phone', v_customer_phone,
    'delivery_address', v_delivery_address,
    'amount', TO_CHAR(v_total_amount, 'FM999,999,990.00'),
    'total_cases', v_total_cases::text,
    'total_items', v_total_items::text,
    'item_list', COALESCE(v_item_list, 'No items'),
    'order_url', 'https://app.serapod2u.com/supply-chain'
  );

  IF v_event_code = 'order_approved' THEN
    SELECT COALESCE(u.full_name, u.email, 'System')
    INTO v_approver_name
    FROM users u WHERE u.id = NEW.approved_by;
    v_payload := v_payload || jsonb_build_object(
      'approved_by', COALESCE(v_approver_name, 'System'),
      'approved_at', COALESCE(TO_CHAR(NEW.approved_at, 'DD Mon YYYY HH24:MI'), '')
    );
  END IF;

  IF v_event_code = 'order_rejected' THEN
    v_payload := v_payload || jsonb_build_object(
      'reason', CASE 
        WHEN NEW.status = 'cancelled' THEN 'Order was cancelled'
        ELSE 'Order was rejected'
      END,
      'action', NEW.status
    );
  END IF;

  IF v_event_code = 'order_closed' THEN
    v_payload := v_payload || jsonb_build_object(
      'closed_at', TO_CHAR(NEW.updated_at, 'DD Mon YYYY HH24:MI')
    );
  END IF;

  PERFORM public.queue_notification(
    v_company_id, v_event_code, channel,
    NULL, NULL, NULL, v_payload, 'normal', NULL
  )
  FROM unnest(ARRAY['whatsapp', 'sms', 'email']) AS channel;

  RETURN NEW;
END;
$_$;


ALTER FUNCTION public.trigger_order_notification() OWNER TO supabase_admin;

--
-- Name: FUNCTION trigger_order_notification(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.trigger_order_notification() IS 'Queues enriched notifications on order status change (submitted, approved, closed, rejected, cancelled). Uses display_doc_no for the order number format.';


