--
-- Name: update_conversation_on_message(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.update_conversation_on_message() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE public.support_conversations
    SET 
        last_message_at = NEW.created_at,
        last_message_preview = LEFT(NEW.body_text, 100),
        last_message_sender_type = NEW.sender_type,
        -- Update unread counts
        user_unread_count = CASE 
            WHEN NEW.sender_type = 'admin' THEN user_unread_count + 1
            ELSE user_unread_count
        END,
        admin_unread_count = CASE 
            WHEN NEW.sender_type = 'user' THEN admin_unread_count + 1
            ELSE admin_unread_count
        END,
        -- Auto-update status based on who sent message
        status = CASE
            WHEN NEW.sender_type = 'admin' THEN 'pending_user'::public.support_conversation_status
            WHEN NEW.sender_type = 'user' AND status = 'pending_user' THEN 'pending_admin'::public.support_conversation_status
            WHEN NEW.sender_type = 'user' AND status = 'resolved' THEN 'open'::public.support_conversation_status  -- Reopen if user replies to resolved
            ELSE status
        END,
        updated_at = NOW()
    WHERE id = NEW.conversation_id;
    
    RETURN NEW;
END;
$$;


