--
-- Name: update_conversation_priority(uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.update_conversation_priority(p_conversation_id uuid, p_new_priority text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_admin_id UUID := auth.uid();
    v_old_priority TEXT;
BEGIN
    IF NOT public.is_support_admin() THEN
        RAISE EXCEPTION 'Access denied';
    END IF;
    
    SELECT priority::text INTO v_old_priority
    FROM public.support_conversations
    WHERE id = p_conversation_id;
    
    UPDATE public.support_conversations
    SET priority = p_new_priority::public.support_priority,
        updated_at = NOW()
    WHERE id = p_conversation_id;
    
    -- Log event
    PERFORM public.log_conversation_event(
        p_conversation_id,
        'admin',
        v_admin_id,
        'priority_changed',
        jsonb_build_object('priority', v_old_priority),
        jsonb_build_object('priority', p_new_priority),
        NULL
    );
END;
$$;


ALTER FUNCTION public.update_conversation_priority(p_conversation_id uuid, p_new_priority text) OWNER TO supabase_admin;

