--
-- Name: update_master_status_skip_trigger(uuid[], uuid, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.update_master_status_skip_trigger(p_master_ids uuid[], p_user_id uuid, p_shipped_at timestamp with time zone DEFAULT now()) RETURNS TABLE(id uuid, master_code text, status text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  -- Set skip flag in this transaction
  PERFORM set_config('app.skip_ship_trigger', 'true', true);
  
  -- Update and return masters
  RETURN QUERY
  UPDATE qr_master_codes
  SET
    status = 'shipped_distributor',
    shipped_at = p_shipped_at,
    shipped_by = p_user_id,
    updated_at = p_shipped_at
  WHERE id = ANY(p_master_ids)
    AND status = 'warehouse_packed'
  RETURNING 
    qr_master_codes.id,
    qr_master_codes.master_code,
    qr_master_codes.status;
END;
$$;


