--
-- Name: update_qr_code_consumer_scan(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.update_qr_code_consumer_scan() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Update the qr_codes table
  UPDATE qr_codes
  SET 
    total_consumer_scans = total_consumer_scans + 1,
    first_consumer_scan_at = COALESCE(first_consumer_scan_at, NEW.scanned_at),
    updated_at = NOW()
  WHERE id = NEW.qr_code_id;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.update_qr_code_consumer_scan() OWNER TO supabase_admin;

--
-- Name: update_redeem_gift_claimed_quantity(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.update_redeem_gift_claimed_quantity() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF TG_OP = 'INSERT' THEN
        UPDATE public.redeem_gifts
        SET claimed_quantity = claimed_quantity + 1
        WHERE id = NEW.redeem_gift_id;
    ELSIF TG_OP = 'DELETE' THEN
        UPDATE public.redeem_gifts
        SET claimed_quantity = GREATEST(0, claimed_quantity - 1)
        WHERE id = OLD.redeem_gift_id;
    END IF;
    
    RETURN NULL;
END;
$$;


ALTER FUNCTION public.update_redeem_gift_claimed_quantity() OWNER TO supabase_admin;

