--
-- Name: update_whatsapp_conversation_mode(uuid, text, public.whatsapp_conversation_mode, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.update_whatsapp_conversation_mode(p_org_id uuid, p_user_phone text, p_mode public.whatsapp_conversation_mode, p_admin_phone text DEFAULT NULL::text) RETURNS public.whatsapp_conversations
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_result whatsapp_conversations;
BEGIN
    UPDATE whatsapp_conversations SET
        mode = p_mode,
        takeover_by_admin_phone = CASE WHEN p_mode = 'takeover' THEN COALESCE(p_admin_phone, takeover_by_admin_phone) ELSE NULL END,
        takeover_at = CASE WHEN p_mode = 'takeover' AND mode = 'auto' THEN now() ELSE takeover_at END,
        last_admin_activity_at = CASE WHEN p_admin_phone IS NOT NULL THEN now() ELSE last_admin_activity_at END,
        updated_at = now()
    WHERE org_id = p_org_id AND user_phone_digits = p_user_phone
    RETURNING * INTO v_result;
    
    IF v_result IS NULL THEN
        -- Create new conversation
        INSERT INTO whatsapp_conversations (org_id, user_phone_digits, mode, takeover_by_admin_phone, takeover_at)
        VALUES (p_org_id, p_user_phone, p_mode, p_admin_phone, CASE WHEN p_mode = 'takeover' THEN now() ELSE NULL END)
        RETURNING * INTO v_result;
    END IF;
    
    RETURN v_result;
END;
$$;


ALTER FUNCTION public.update_whatsapp_conversation_mode(p_org_id uuid, p_user_phone text, p_mode public.whatsapp_conversation_mode, p_admin_phone text) OWNER TO supabase_admin;

--
-- Name: upsert_whatsapp_conversation(uuid, text, public.whatsapp_conversation_mode, text, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.upsert_whatsapp_conversation(p_org_id uuid, p_user_phone text, p_mode public.whatsapp_conversation_mode DEFAULT NULL::public.whatsapp_conversation_mode, p_takeover_admin text DEFAULT NULL::text, p_pending_draft text DEFAULT NULL::text) RETURNS public.whatsapp_conversations
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_result whatsapp_conversations;
BEGIN
    INSERT INTO whatsapp_conversations (org_id, user_phone_digits, mode, takeover_by_admin_phone, takeover_at, pending_draft, pending_draft_at, last_message_at, updated_at)
    VALUES (
        p_org_id, 
        p_user_phone, 
        COALESCE(p_mode, 'auto'),
        p_takeover_admin,
        CASE WHEN p_mode = 'takeover' THEN now() ELSE NULL END,
        p_pending_draft,
        CASE WHEN p_pending_draft IS NOT NULL THEN now() ELSE NULL END,
        now(),
        now()
    )
    ON CONFLICT (org_id, user_phone_digits) DO UPDATE SET
        mode = COALESCE(EXCLUDED.mode, whatsapp_conversations.mode),
        takeover_by_admin_phone = CASE 
            WHEN EXCLUDED.mode = 'takeover' THEN COALESCE(EXCLUDED.takeover_by_admin_phone, whatsapp_conversations.takeover_by_admin_phone)
            WHEN EXCLUDED.mode = 'auto' THEN NULL
            ELSE whatsapp_conversations.takeover_by_admin_phone
        END,
        takeover_at = CASE 
            WHEN EXCLUDED.mode = 'takeover' AND whatsapp_conversations.mode = 'auto' THEN now()
            WHEN EXCLUDED.mode = 'auto' THEN NULL
            ELSE whatsapp_conversations.takeover_at
        END,
        pending_draft = COALESCE(EXCLUDED.pending_draft, whatsapp_conversations.pending_draft),
        pending_draft_at = CASE 
            WHEN EXCLUDED.pending_draft IS NOT NULL THEN now()
            ELSE whatsapp_conversations.pending_draft_at
        END,
        last_message_at = now(),
        message_count = whatsapp_conversations.message_count + 1,
        updated_at = now()
    RETURNING * INTO v_result;
    
    RETURN v_result;
END;
$$;


ALTER FUNCTION public.upsert_whatsapp_conversation(p_org_id uuid, p_user_phone text, p_mode public.whatsapp_conversation_mode, p_takeover_admin text, p_pending_draft text) OWNER TO supabase_admin;

--
-- Name: validate_child_items(uuid, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.validate_child_items(p_order_id uuid, p_parent_order_id uuid) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE v_cnt int;
BEGIN
  SELECT COUNT(*) INTO v_cnt
  FROM public.order_items c
  WHERE c.order_id = p_order_id
    AND NOT EXISTS (
      SELECT 1 FROM public.order_items p
      WHERE p.order_id = p_parent_order_id
        AND p.variant_id = c.variant_id
    );

  IF v_cnt > 0 THEN
    RAISE EXCEPTION 'Child order has % variants not present in parent', v_cnt;
  END IF;
  RETURN true;
END;
$$;


ALTER FUNCTION public.validate_child_items(p_order_id uuid, p_parent_order_id uuid) OWNER TO supabase_admin;

