--
-- Name: validate_msia_bank_account(uuid, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.validate_msia_bank_account(p_bank_id uuid, p_account_number text) RETURNS boolean
    LANGUAGE plpgsql STABLE
    AS $_$
DECLARE
    v_min int;
    v_max int;
    v_is_numeric_only boolean;
BEGIN
    -- No bank or no account -> treat as invalid for this function.
    IF p_bank_id IS NULL OR p_account_number IS NULL THEN
        RETURN false;
    END IF;

    SELECT min_account_length, max_account_length, is_numeric_only
      INTO v_min, v_max, v_is_numeric_only
    FROM public.msia_banks
    WHERE id = p_bank_id
      AND is_active = true;

    IF NOT FOUND THEN
        RETURN false;
    END IF;

    -- Length check
    IF length(p_account_number) < v_min
       OR length(p_account_number) > v_max THEN
        RETURN false;
    END IF;

    -- Numeric-only check
    IF v_is_numeric_only AND p_account_number !~ '^[0-9]+$' THEN
        RETURN false;
    END IF;

    RETURN true;
END;
$_$;


ALTER FUNCTION public.validate_msia_bank_account(p_bank_id uuid, p_account_number text) OWNER TO supabase_admin;

--
-- Name: validate_org_hierarchy(); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.validate_org_hierarchy() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_parent_type text;
    v_parent_hierarchy int;
    v_new_hierarchy int;
BEGIN
    -- Get hierarchy level for new organization type
    SELECT hierarchy_level INTO v_new_hierarchy
    FROM public.organization_types
    WHERE type_code = NEW.org_type_code;

    IF v_new_hierarchy IS NULL THEN
        RAISE EXCEPTION 'Unknown organization type: %', NEW.org_type_code;
    END IF;

    -- If no parent: HQ and MFG may be root-level
    IF NEW.parent_org_id IS NULL THEN
        IF NEW.org_type_code NOT IN ('HQ', 'MFG') THEN
            RAISE EXCEPTION 'Only HQ and Manufacturer organizations can have no parent';
        END IF;
        RETURN NEW;
    END IF;

    -- Get parent organization type and hierarchy
    SELECT o.org_type_code, ot.hierarchy_level
    INTO v_parent_type, v_parent_hierarchy
    FROM public.organizations o
    JOIN public.organization_types ot ON ot.type_code = o.org_type_code
    WHERE o.id = NEW.parent_org_id;

    IF v_parent_type IS NULL THEN
        RAISE EXCEPTION 'Parent organization not found';
    END IF;

    -- INDEP can be child of HQ (special case for independent portal users)
    IF NEW.org_type_code = 'INDEP' AND v_parent_type = 'HQ' THEN
        RETURN NEW;
    END IF;

    -- END_USER can be child of HQ (special case for store customers)
    IF NEW.org_type_code = 'END_USER' AND v_parent_type = 'HQ' THEN
        RETURN NEW;
    END IF;

    -- Child hierarchy must be greater than parent (lower in hierarchy)
    IF v_new_hierarchy <= v_parent_hierarchy THEN
        RAISE EXCEPTION 'Invalid organization hierarchy: % cannot be child of %',
            NEW.org_type_code, v_parent_type;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.validate_org_hierarchy() OWNER TO supabase_admin;

--
-- Name: FUNCTION validate_org_hierarchy(); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.validate_org_hierarchy() IS 'Enforces organization hierarchy rules:
- HQ: Root level (no parent)
- MFG: Root level (no parent) or child of HQ
- INDEP: Special — child of HQ only
- END_USER: Special — child of HQ only (store customers)
- Others: Must have parent with lower hierarchy_level';


--
-- Name: validate_reference_eligibility(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.validate_reference_eligibility(p_reference_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_user RECORD;
BEGIN
  IF p_reference_user_id IS NULL THEN
    RETURN jsonb_build_object('valid', true, 'message', 'No reference assigned');
  END IF;

  SELECT id, full_name, phone, email, can_be_reference, is_active
  INTO v_user
  FROM public.users
  WHERE id = p_reference_user_id;

  IF v_user IS NULL THEN
    RETURN jsonb_build_object('valid', false, 'message', 'Reference user not found');
  END IF;

  IF NOT v_user.is_active THEN
    RETURN jsonb_build_object('valid', false, 'message', 'Reference user is inactive');
  END IF;

  IF NOT v_user.can_be_reference THEN
    RETURN jsonb_build_object('valid', false, 'message', 'User is not eligible to be a reference');
  END IF;

  RETURN jsonb_build_object(
    'valid', true,
    'message', 'Eligible',
    'reference_name', v_user.full_name,
    'reference_phone', v_user.phone,
    'reference_email', v_user.email
  );
END;
$$;


ALTER FUNCTION public.validate_reference_eligibility(p_reference_user_id uuid) OWNER TO supabase_admin;

--
-- Name: FUNCTION validate_reference_eligibility(p_reference_user_id uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.validate_reference_eligibility(p_reference_user_id uuid) IS 'Server-side validation that a user is eligible to be assigned as a reference';


--
-- Name: validate_roadtour_qr_token(text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.validate_roadtour_qr_token(p_token text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_qr public.roadtour_qr_codes%ROWTYPE;
  v_campaign public.roadtour_campaigns%ROWTYPE;
  v_am_name text;
  v_settings public.roadtour_settings%ROWTYPE;
  v_today date;
BEGIN
  v_today := (now() AT TIME ZONE 'Asia/Kuala_Lumpur')::date;

  SELECT * INTO v_qr
  FROM public.roadtour_qr_codes
  WHERE token = p_token
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('valid', false, 'error', 'invalid_qr', 'message', 'QR code is not recognized.');
  END IF;

  IF v_qr.status = 'revoked' THEN
    RETURN jsonb_build_object('valid', false, 'error', 'revoked', 'message', 'This QR code has been revoked.');
  END IF;

  IF v_qr.status = 'expired' OR (v_qr.expires_at IS NOT NULL AND v_qr.expires_at < now()) THEN
    RETURN jsonb_build_object('valid', false, 'error', 'expired', 'message', 'This QR code has expired.');
  END IF;

  SELECT * INTO v_campaign
  FROM public.roadtour_campaigns
  WHERE id = v_qr.campaign_id;

  IF NOT FOUND OR v_campaign.status != 'active' THEN
    RETURN jsonb_build_object('valid', false, 'error', 'inactive_campaign', 'message', 'The campaign is not currently active.');
  END IF;

  IF v_today < v_campaign.start_date OR v_today > v_campaign.end_date THEN
    RETURN jsonb_build_object('valid', false, 'error', 'campaign_date_range', 'message', 'The campaign is not within its scheduled date range.');
  END IF;

  SELECT full_name INTO v_am_name
  FROM public.users WHERE id = v_qr.account_manager_user_id;

  SELECT * INTO v_settings
  FROM public.roadtour_settings
  WHERE org_id = v_campaign.org_id
  LIMIT 1;

  UPDATE public.roadtour_qr_codes
  SET usage_count = usage_count + 1, last_used_at = now()
  WHERE id = v_qr.id;

  RETURN jsonb_build_object(
    'valid', true,
    'qr_code_id', v_qr.id,
    'campaign_id', v_qr.campaign_id,
    'campaign_name', v_campaign.name,
    'account_manager_user_id', v_qr.account_manager_user_id,
    'account_manager_name', COALESCE(v_am_name, ''),
    'shop_id', v_qr.shop_id,
    'qr_mode', v_qr.qr_mode,
    'reward_mode', v_campaign.reward_mode,
    'default_points', v_campaign.default_points,
    'survey_template_id', v_campaign.survey_template_id,
    'org_id', v_campaign.org_id,
    'require_login', COALESCE(v_settings.require_login, true),
    'require_shop_context', COALESCE(v_settings.require_shop_context, false),
    'require_geolocation', COALESCE(v_settings.require_geolocation, false),
    'duplicate_rule_reward', COALESCE(v_settings.duplicate_rule_reward, 'one_per_user_per_campaign')
  );
END;
$$;


ALTER FUNCTION public.validate_roadtour_qr_token(p_token text) OWNER TO supabase_admin;

