--
-- Name: wms_deduct_and_summarize(uuid, uuid, uuid, integer, uuid, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.wms_deduct_and_summarize(p_variant_id uuid, p_from_org_id uuid, p_to_org_id uuid, p_units integer, p_order_id uuid, p_shipped_at timestamp with time zone DEFAULT now()) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_before int;
  v_after  int;
BEGIN
  IF p_units IS NULL OR p_units <= 0 THEN
    RAISE EXCEPTION 'p_units must be > 0 (got %)', p_units;
  END IF;

  -- Read BEFORE qty (warehouse side)
  SELECT pi.quantity_on_hand
  INTO v_before
  FROM public.product_inventory pi
  WHERE pi.variant_id = p_variant_id
    AND pi.organization_id = p_from_org_id
  FOR UPDATE;

  v_before := COALESCE(v_before, 0);

  -- Deduct inventory using existing adjustment function
  PERFORM public.apply_inventory_ship_adjustment(
    p_variant_id,
    p_from_org_id,
    p_units,
    0,                -- cases optional; units drive the truth
    p_shipped_at
  );

  -- Read AFTER qty
  SELECT pi.quantity_on_hand
  INTO v_after
  FROM public.product_inventory pi
  WHERE pi.variant_id = p_variant_id
    AND pi.organization_id = p_from_org_id;

  v_after := COALESCE(v_after, 0);

  RETURN jsonb_build_object(
    'variant_id',  p_variant_id,
    'from_org',    p_from_org_id,
    'to_org',      p_to_org_id,
    'order_id',    p_order_id,
    'units',       p_units,
    'before',      v_before,
    'after',       v_after,
    'shipped_at',  p_shipped_at
  );
END;
$$;


ALTER FUNCTION public.wms_deduct_and_summarize(p_variant_id uuid, p_from_org_id uuid, p_to_org_id uuid, p_units integer, p_order_id uuid, p_shipped_at timestamp with time zone) OWNER TO supabase_admin;

--
-- Name: wms_from_master(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.wms_from_master(p_master_code_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_qmc         record;     -- qr_master_codes row
  v_variant_id  uuid;       -- variant inferred from any child qr_code
  v_units       int;        -- shipped units (actual > expected)
  v_from_org    uuid;
  v_to_org      uuid;
  v_order_id    uuid;
  v_buyer_org_id uuid;
  v_buyer_org_type text;
  v_order_type public.order_type;
  v_order_warehouse uuid;
  v_shipped_at  timestamptz;
  v_result      jsonb;
BEGIN
  -- Load the master record
  SELECT * INTO v_qmc
  FROM public.qr_master_codes
  WHERE id = p_master_code_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'qr_master_codes % not found', p_master_code_id;
  END IF;

  -- Prefer actual over expected units
  v_units := COALESCE(NULLIF(v_qmc.actual_unit_count, 0), v_qmc.expected_unit_count, 0);
  IF v_units <= 0 THEN
    RAISE EXCEPTION 'Cannot determine shipped units for master %', p_master_code_id;
  END IF;

  -- Resolve variant_id from any child QR (cases are homogeneous)
  SELECT qc.variant_id
  INTO v_variant_id
  FROM public.qr_codes qc
  WHERE qc.master_code_id = p_master_code_id
  LIMIT 1;

  IF v_variant_id IS NULL THEN
    RAISE EXCEPTION 'No child QR codes mapped to master %', p_master_code_id;
  END IF;

  v_order_id := v_qmc.shipment_order_id;

  SELECT
    COALESCE(v_qmc.shipment_order_id, qb.order_id),
    ord.buyer_org_id,
    buyer.org_type_code,
    ord.order_type,
    ord.warehouse_org_id
  INTO
    v_order_id,
    v_buyer_org_id,
    v_buyer_org_type,
    v_order_type,
    v_order_warehouse
  FROM public.qr_batches qb
  LEFT JOIN public.orders ord ON ord.id = COALESCE(v_qmc.shipment_order_id, qb.order_id)
  LEFT JOIN public.organizations buyer ON buyer.id = ord.buyer_org_id
  WHERE qb.id = v_qmc.batch_id;

  v_from_org   := v_qmc.warehouse_org_id;
  v_to_org     := public.wms_resolve_ship_to(
    v_qmc.shipped_to_distributor_id,
    v_buyer_org_id,
    v_buyer_org_type,
    v_order_type,
    v_order_warehouse,
    v_qmc.warehouse_org_id
  );

  IF v_to_org IS NULL THEN
    RAISE EXCEPTION 'Unable to resolve shipment destination for master %', p_master_code_id;
  END IF;

  v_shipped_at := COALESCE(v_qmc.shipped_at, now());

  -- Deduct & summarize
  v_result := public.wms_deduct_and_summarize(
    v_variant_id,
    v_from_org,
    v_to_org,
    v_units,
    v_order_id,
    v_shipped_at
  );

  RETURN v_result;
END;
$$;


ALTER FUNCTION public.wms_from_master(p_master_code_id uuid) OWNER TO supabase_admin;

--
-- Name: wms_from_mixed(uuid, uuid[], uuid, uuid, uuid, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.wms_from_mixed(p_master_code_id uuid, p_qr_code_ids uuid[], p_from_org_id uuid, p_to_org_id uuid, p_order_id uuid, p_shipped_at timestamp with time zone DEFAULT now()) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_master jsonb;
  v_unique jsonb;
  v_all    jsonb := '[]'::jsonb;
BEGIN
  IF p_master_code_id IS NOT NULL THEN
    v_master := public.wms_from_master(p_master_code_id);
    v_all := v_all || jsonb_build_array(v_master);
  END IF;

  IF p_qr_code_ids IS NOT NULL AND array_length(p_qr_code_ids,1) IS NOT NULL THEN
    v_unique := public.wms_from_unique_codes(p_qr_code_ids, p_from_org_id, p_to_org_id, p_order_id, p_shipped_at);
    v_all := v_all || COALESCE(v_unique->'items', '[]'::jsonb);
  END IF;

  RETURN jsonb_build_object('items', v_all);
END;
$$;


ALTER FUNCTION public.wms_from_mixed(p_master_code_id uuid, p_qr_code_ids uuid[], p_from_org_id uuid, p_to_org_id uuid, p_order_id uuid, p_shipped_at timestamp with time zone) OWNER TO supabase_admin;

--
-- Name: wms_from_unique_codes(uuid[], uuid, uuid, uuid, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.wms_from_unique_codes(p_qr_code_ids uuid[], p_from_org_id uuid, p_to_org_id uuid, p_order_id uuid, p_shipped_at timestamp with time zone DEFAULT now()) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  r           record;
  v_items     jsonb := '[]'::jsonb;
  v_result    jsonb;
BEGIN
  IF p_qr_code_ids IS NULL OR array_length(p_qr_code_ids, 1) IS NULL THEN
    RAISE EXCEPTION 'p_qr_code_ids must not be empty';
  END IF;

  -- For unique scans, each code = 1 unit.
  -- Group by variant so we deduct once per variant.
  FOR r IN
    SELECT qc.variant_id, COUNT(*)::int AS units
    FROM public.qr_codes qc
    WHERE qc.id = ANY(p_qr_code_ids)
    GROUP BY qc.variant_id
  LOOP
    IF r.variant_id IS NULL OR r.units <= 0 THEN
      CONTINUE;
    END IF;

    v_result := public.wms_deduct_and_summarize(
      r.variant_id,
      p_from_org_id,
      p_to_org_id,
      r.units,
      p_order_id,
      p_shipped_at
    );

    v_items := v_items || jsonb_build_array(v_result);
  END LOOP;

  RETURN jsonb_build_object('items', v_items);
END;
$$;


ALTER FUNCTION public.wms_from_unique_codes(p_qr_code_ids uuid[], p_from_org_id uuid, p_to_org_id uuid, p_order_id uuid, p_shipped_at timestamp with time zone) OWNER TO supabase_admin;

--
-- Name: wms_record_movement_from_summary(jsonb); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.wms_record_movement_from_summary(p_summary jsonb) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  v_variant_id   uuid := (p_summary->>'variant_id')::uuid;
  v_from_org     uuid := (p_summary->>'from_org')::uuid;
  v_to_org       uuid := (p_summary->>'to_org')::uuid;
  v_order_id     uuid := (p_summary->>'order_id')::uuid;
  v_units        int  := (p_summary->>'units')::int;
  v_before       int  := COALESCE((p_summary->>'before')::int, 0);
  v_after        int  := COALESCE((p_summary->>'after')::int, 0);
  v_when         timestamptz := COALESCE((p_summary->>'shipped_at')::timestamptz, now());
  v_company_id   uuid;
  v_created_by   uuid := auth.uid();  -- may be NULL in SQL editor context
  v_movement_id  uuid;
  v_dedup_key    text;
BEGIN
  IF v_variant_id IS NULL OR v_from_org IS NULL OR v_units IS NULL OR v_units <= 0 THEN
    RAISE EXCEPTION 'Invalid input summary: variant/from_org/units required (%).', p_summary;
  END IF;

  -- fallback creator if running without JWT (SQL editor, cron, etc.)
  IF v_created_by IS NULL THEN
    SELECT u.id
    INTO v_created_by
    FROM public.users u
    WHERE u.organization_id = v_from_org
      AND COALESCE(u.is_active, true) = true
    ORDER BY (u.role_code = 'HQ_ADMIN') DESC, u.created_at ASC
    LIMIT 1;

    IF v_created_by IS NULL THEN
      RAISE EXCEPTION 'No active user found in org % to use as created_by', v_from_org;
    END IF;
  END IF;

  -- tenant/guard
  v_company_id := public.get_company_id(v_from_org);

  -- stable dedup key
  v_dedup_key := encode(digest(
      COALESCE(v_variant_id::text,'') || '|' ||
      COALESCE(v_from_org::text,'')   || '|' ||
      COALESCE(v_to_org::text,'')     || '|' ||
      COALESCE(v_order_id::text,'')   || '|' ||
      v_units::text                   || '|' ||
      to_char(v_when::date, 'YYYY-MM-DD'),
      'sha256'), 'hex');

  -- idempotency check
  PERFORM 1 FROM public.wms_movement_dedup d WHERE d.dedup_key = v_dedup_key;
  IF FOUND THEN
    SELECT d.movement_id INTO v_movement_id FROM public.wms_movement_dedup d WHERE d.dedup_key = v_dedup_key;
    RETURN v_movement_id;
  END IF;

  -- insert movement
  INSERT INTO public.stock_movements (
    id,
    variant_id,
    from_organization_id,
    to_organization_id,
    movement_type,
    quantity_change,
    quantity_before,
    quantity_after,
    reference_type,
    reference_id,
    reference_no,
    company_id,
    created_by,
    created_at
  )
  VALUES (
    gen_random_uuid(),
    v_variant_id,
    v_from_org,
    NULLIF(v_to_org, v_from_org),
    'order_fulfillment',
    -v_units,
    v_before,
    v_after,
    'order',
    v_order_id,
    NULL,               -- no doc number column in your orders
    v_company_id,
    v_created_by,
    v_when
  )
  RETURNING id INTO v_movement_id;

  INSERT INTO public.wms_movement_dedup (dedup_key, movement_id)
  VALUES (v_dedup_key, v_movement_id)
  ON CONFLICT (dedup_key) DO NOTHING;

  RETURN v_movement_id;
END;
$$;


ALTER FUNCTION public.wms_record_movement_from_summary(p_summary jsonb) OWNER TO supabase_admin;

--
-- Name: wms_record_movements_from_items(jsonb); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.wms_record_movements_from_items(p_items jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  elem   jsonb;
  v_id   uuid;
  v_ids  jsonb := '[]'::jsonb;
BEGIN
  -- Case 1: { "items": [ {...}, {...} ] }
  IF jsonb_typeof(p_items->'items') = 'array' THEN
    FOR elem IN
      SELECT value FROM jsonb_array_elements(p_items->'items')
    LOOP
      v_id := public.wms_record_movement_from_summary(elem);
      v_ids := v_ids || jsonb_build_array(v_id);
    END LOOP;

  -- Case 2: plain array: [ {...}, {...} ]
  ELSIF jsonb_typeof(p_items) = 'array' THEN
    FOR elem IN
      SELECT value FROM jsonb_array_elements(p_items)
    LOOP
      v_id := public.wms_record_movement_from_summary(elem);
      v_ids := v_ids || jsonb_build_array(v_id);
    END LOOP;

  -- Case 3: single object
  ELSE
    v_id := public.wms_record_movement_from_summary(p_items);
    v_ids := v_ids || jsonb_build_array(v_id);
  END IF;

  RETURN jsonb_build_object('movement_ids', v_ids);
END;
$$;


ALTER FUNCTION public.wms_record_movements_from_items(p_items jsonb) OWNER TO supabase_admin;

--
-- Name: wms_resolve_ship_to(uuid, uuid, text, public.order_type, uuid, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.wms_resolve_ship_to(p_shipped_to_distributor_id uuid, p_buyer_org_id uuid, p_buyer_org_type text, p_order_type public.order_type, p_order_warehouse_org_id uuid, p_case_warehouse_org_id uuid) RETURNS uuid
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  v_buyer_type text := p_buyer_org_type;
  v_from_type  text;
BEGIN
  IF p_shipped_to_distributor_id IS NOT NULL THEN
    RETURN p_shipped_to_distributor_id;
  END IF;

  IF p_buyer_org_id IS NULL THEN
    RETURN NULL;
  END IF;

  IF v_buyer_type IS NULL THEN
    SELECT org_type_code INTO v_buyer_type
    FROM public.organizations
    WHERE id = p_buyer_org_id;
  END IF;

  IF p_case_warehouse_org_id IS NOT NULL THEN
    SELECT org_type_code INTO v_from_type
    FROM public.organizations
    WHERE id = p_case_warehouse_org_id;
  END IF;

  -- Non-HQ buyers always receive the stock
  IF v_buyer_type IS NULL OR v_buyer_type <> 'HQ' THEN
    RETURN p_buyer_org_id;
  END IF;

  -- HQ can receive stock when it is explicitly the warehouse of record
  IF p_case_warehouse_org_id IS NOT NULL AND p_case_warehouse_org_id = p_buyer_org_id THEN
    RETURN p_buyer_org_id;
  END IF;

  IF p_order_warehouse_org_id IS NOT NULL AND p_order_warehouse_org_id = p_buyer_org_id THEN
    RETURN p_buyer_org_id;
  END IF;

  -- HQ may receive goods directly from manufacturer on H2M orders
  IF v_from_type = 'MFG' AND p_order_type = 'H2M' THEN
    RETURN p_buyer_org_id;
  END IF;

  RETURN NULL;
END;
$$;


ALTER FUNCTION public.wms_resolve_ship_to(p_shipped_to_distributor_id uuid, p_buyer_org_id uuid, p_buyer_org_type text, p_order_type public.order_type, p_order_warehouse_org_id uuid, p_case_warehouse_org_id uuid) OWNER TO supabase_admin;

--
-- Name: wms_reverse_manual_movement(uuid, text, uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.wms_reverse_manual_movement(p_movement_id uuid, p_reversal_reason text DEFAULT 'Rollback of manual shipment due to downstream failure'::text, p_override_user uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_original public.stock_movements%ROWTYPE;
    v_reversal_id uuid;
    v_created_by uuid;
    v_qty integer;
BEGIN
    SELECT *
    INTO v_original
    FROM public.stock_movements
    WHERE id = p_movement_id
      AND movement_type = 'manual_out';

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Manual_out movement % not found', p_movement_id;
    END IF;

    v_created_by := COALESCE(p_override_user, v_original.created_by);
    v_qty := ABS(v_original.quantity_change);

    IF v_qty <= 0 THEN
        RAISE EXCEPTION 'Cannot reverse manual movement % with zero quantity', p_movement_id;
    END IF;

    v_reversal_id := public.record_stock_movement(
        p_movement_type      := 'manual_in',
        p_variant_id         := v_original.variant_id,
        p_organization_id    := COALESCE(v_original.from_organization_id, v_original.to_organization_id),
        p_quantity_change    := v_qty,
        p_unit_cost          := v_original.unit_cost,
        p_manufacturer_id    := v_original.manufacturer_id,
        p_warehouse_location := v_original.warehouse_location,
        p_reason             := p_reversal_reason,
        p_notes              := CONCAT('Rollback of manual movement ', p_movement_id),
        p_reference_type     := v_original.reference_type,
        p_reference_id       := v_original.reference_id,
        p_reference_no       := v_original.reference_no,
        p_company_id         := v_original.company_id,
        p_created_by         := v_created_by
    );

    UPDATE public.stock_movements
    SET notes = CONCAT(
        COALESCE(notes, ''),
        CASE WHEN notes IS NULL OR notes = '' THEN '' ELSE ' ' END,
        '[Rolled back via ', v_reversal_id, ']'::text
    )
    WHERE id = v_original.id;

    RETURN jsonb_build_object(
        'reversal_movement_id', v_reversal_id,
        'reversed_movement_id', v_original.id
    );
END;
$$;


ALTER FUNCTION public.wms_reverse_manual_movement(p_movement_id uuid, p_reversal_reason text, p_override_user uuid) OWNER TO supabase_admin;

--
-- Name: FUNCTION wms_reverse_manual_movement(p_movement_id uuid, p_reversal_reason text, p_override_user uuid); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.wms_reverse_manual_movement(p_movement_id uuid, p_reversal_reason text, p_override_user uuid) IS 'Creates a compensating manual_in movement to undo a previous manual_out movement when mixed shipments fail mid-process.';


--
-- Name: wms_ship_manual(uuid, uuid, uuid, uuid, integer, uuid, text, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.wms_ship_manual(p_company_id uuid, p_warehouse_id uuid, p_distributor_id uuid, p_variant_id uuid, p_qty integer, p_user_id uuid, p_reference_no text DEFAULT NULL::text, p_notes text DEFAULT NULL::text) RETURNS TABLE(movement_id uuid, quantity_before integer, quantity_after integer)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_req_qty            integer;
  v_manual_balance     integer;
  v_onhand_before      integer;
  v_onhand_after       integer;
  v_new_id             uuid;
  v_dummy              int;
BEGIN
  -- ✅ Validate required orgs exist and are active
  SELECT 1 INTO v_dummy
  FROM public.organizations o
  WHERE o.id = p_warehouse_id
    AND o.org_type_code = 'WH'
    AND COALESCE(o.is_active, true) = true;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Invalid warehouse organization: %', p_warehouse_id;
  END IF;

  SELECT 1 INTO v_dummy
  FROM public.organizations o
  WHERE o.id = p_distributor_id
    AND o.org_type_code = 'DIST'
    AND COALESCE(o.is_active, true) = true;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Invalid distributor organization: %', p_distributor_id;
  END IF;

  -- ✅ Validate input qty
  IF p_qty IS NULL OR p_qty <= 0 THEN
    RAISE EXCEPTION 'Invalid quantity: % (must be > 0)', p_qty;
  END IF;

  v_req_qty := p_qty;

  -- ✅ Validate manual balance (manual_in - manual_out)
  SELECT COALESCE(SUM(
      CASE 
        WHEN sm.movement_type = 'manual_in'
             AND sm.to_organization_id = p_warehouse_id
          THEN sm.quantity_change
        WHEN sm.movement_type = 'manual_out'
             AND sm.from_organization_id = p_warehouse_id
          THEN sm.quantity_change
        ELSE 0
      END
  ), 0)
  INTO v_manual_balance
  FROM public.stock_movements sm
  WHERE sm.variant_id = p_variant_id
    AND sm.movement_type IN ('manual_in','manual_out');

  IF v_manual_balance < v_req_qty THEN
    RAISE EXCEPTION 'INSUFFICIENT_MANUAL_STOCK: have %, need %, warehouse %, variant %',
      v_manual_balance, v_req_qty, p_warehouse_id, p_variant_id;
  END IF;

  -- ✅ Get overall on-hand before shipment (all movement types)
  SELECT COALESCE(SUM(
    CASE 
      WHEN sm.movement_type IN ('addition','transfer_in','deallocation','order_cancelled','manual_in')
           AND sm.to_organization_id = p_warehouse_id
        THEN sm.quantity_change
      WHEN sm.movement_type IN ('transfer_out','allocation','order_fulfillment','manual_out')
           AND sm.from_organization_id = p_warehouse_id
        THEN sm.quantity_change
      WHEN sm.movement_type = 'adjustment'
           AND (sm.to_organization_id = p_warehouse_id OR sm.from_organization_id = p_warehouse_id)
        THEN sm.quantity_change
      ELSE 0
    END
  ), 0)
  INTO v_onhand_before
  FROM public.stock_movements sm
  WHERE sm.variant_id = p_variant_id;

  v_onhand_after := v_onhand_before - v_req_qty;

  -- ✅ Insert movement row: manual_out
  INSERT INTO public.stock_movements (
    movement_type,
    reference_type,
    reference_id,
    reference_no,
    variant_id,
    from_organization_id,
    to_organization_id,
    quantity_change,
    quantity_before,
    quantity_after,
    unit_cost,
    manufacturer_id,
    warehouse_location,
    reason,
    notes,
    company_id,
    created_by
  )
  VALUES (
    'manual_out',
    'manual',
    NULL,
    p_reference_no,
    p_variant_id,
    p_warehouse_id,
    p_distributor_id,
    -v_req_qty,
    v_onhand_before,
    v_onhand_after,
    NULL,
    NULL,
    NULL,
    'Manual Out to Distributor',
    p_notes,
    p_company_id,
    p_user_id
  )
  RETURNING id INTO v_new_id;

  movement_id     := v_new_id;
  quantity_before := v_onhand_before;
  quantity_after  := v_onhand_after;
  RETURN;
END;
$$;


ALTER FUNCTION public.wms_ship_manual(p_company_id uuid, p_warehouse_id uuid, p_distributor_id uuid, p_variant_id uuid, p_qty integer, p_user_id uuid, p_reference_no text, p_notes text) OWNER TO supabase_admin;

--
-- Name: wms_ship_master_auto(uuid); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.wms_ship_master_auto(p_master_code_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_summary jsonb;
  v_mid     uuid;
BEGIN
  v_summary := public.wms_from_master(p_master_code_id);
  v_mid     := public.wms_record_movement_from_summary(v_summary);
  RETURN jsonb_build_object('summary', v_summary, 'movement_id', v_mid);
END;
$$;


ALTER FUNCTION public.wms_ship_master_auto(p_master_code_id uuid) OWNER TO supabase_admin;

--
-- Name: wms_ship_mixed(uuid, uuid, uuid, uuid, integer, jsonb, uuid, text, text); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.wms_ship_mixed(p_company_id uuid, p_warehouse_id uuid, p_distributor_id uuid, p_variant_id uuid, p_manual_qty integer DEFAULT 0, p_qr_codes jsonb DEFAULT NULL::jsonb, p_user_id uuid DEFAULT NULL::uuid, p_reference_no text DEFAULT NULL::text, p_notes text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_manual_balance integer := 0;
    v_manual_balance_after integer := 0;
    v_movement_id uuid := NULL;
    v_inventory_after integer := NULL;
BEGIN
    IF COALESCE(p_manual_qty, 0) < 0 THEN
        RAISE EXCEPTION 'Manual quantity cannot be negative';
    END IF;

    IF COALESCE(p_manual_qty, 0) > 0 AND p_variant_id IS NULL THEN
        RAISE EXCEPTION 'Variant id is required when manual quantity > 0';
    END IF;

    IF COALESCE(p_manual_qty, 0) > 0 THEN
        BEGIN
            SELECT COALESCE(manual_balance_qty, 0)
            INTO v_manual_balance
            FROM vw_manual_stock_balance
            WHERE warehouse_id = p_warehouse_id
              AND variant_id = p_variant_id;

            IF NOT FOUND THEN
                v_manual_balance := 0;
            END IF;
        EXCEPTION
            WHEN undefined_table THEN
                SELECT COALESCE(SUM(
                    CASE
                        WHEN movement_type = 'manual_in'  AND to_organization_id = p_warehouse_id THEN quantity_change
                        WHEN movement_type = 'manual_out' AND from_organization_id = p_warehouse_id THEN quantity_change
                        ELSE 0
                    END
                ), 0)
                INTO v_manual_balance
                FROM public.stock_movements
                WHERE variant_id = p_variant_id
                  AND movement_type IN ('manual_in', 'manual_out');
        END;

        IF v_manual_balance < p_manual_qty THEN
            RAISE EXCEPTION 'Insufficient manual stock balance. Available: %, requested: %', v_manual_balance, p_manual_qty;
        END IF;

        v_movement_id := public.record_stock_movement(
            p_movement_type      := 'manual_out',
            p_variant_id         := p_variant_id,
            p_organization_id    := p_warehouse_id,
            p_quantity_change    := -p_manual_qty,
            p_unit_cost          := NULL,
            p_manufacturer_id    := NULL,
            p_warehouse_location := NULL,
            p_reason             := 'Manual Out to Distributor',
            p_notes              := p_notes,
            p_reference_type     := 'manual',
            p_reference_id       := p_distributor_id,
            p_reference_no       := p_reference_no,
            p_company_id         := p_company_id,
            p_created_by         := p_user_id
        );

        UPDATE public.stock_movements
        SET to_organization_id = p_distributor_id
        WHERE id = v_movement_id;

        SELECT quantity_after
        INTO v_inventory_after
        FROM public.stock_movements
        WHERE id = v_movement_id;

        v_manual_balance_after := v_manual_balance - p_manual_qty;
    END IF;

    RETURN jsonb_build_object(
        'success', true,
        'manual_quantity',        COALESCE(p_manual_qty, 0),
        'manual_movement_id',     v_movement_id,
        'manual_balance_before',  v_manual_balance,
        'manual_balance_after',   v_manual_balance_after,
        'quantity_after',         v_inventory_after
    );
END;
$$;


ALTER FUNCTION public.wms_ship_mixed(p_company_id uuid, p_warehouse_id uuid, p_distributor_id uuid, p_variant_id uuid, p_manual_qty integer, p_qr_codes jsonb, p_user_id uuid, p_reference_no text, p_notes text) OWNER TO supabase_admin;

--
-- Name: FUNCTION wms_ship_mixed(p_company_id uuid, p_warehouse_id uuid, p_distributor_id uuid, p_variant_id uuid, p_manual_qty integer, p_qr_codes jsonb, p_user_id uuid, p_reference_no text, p_notes text); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.wms_ship_mixed(p_company_id uuid, p_warehouse_id uuid, p_distributor_id uuid, p_variant_id uuid, p_manual_qty integer, p_qr_codes jsonb, p_user_id uuid, p_reference_no text, p_notes text) IS 'Processes manual portion of mixed shipments using record_stock_movement once and returns resulting movement metadata.';


--
-- Name: wms_ship_unique_auto(uuid[], uuid, uuid, uuid, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: supabase_admin
--

CREATE FUNCTION public.wms_ship_unique_auto(p_qr_code_ids uuid[], p_from_org_id uuid, p_to_org_id uuid, p_order_id uuid, p_shipped_at timestamp with time zone DEFAULT now()) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_payload jsonb;
  v_ids     jsonb;
BEGIN
  -- Step 1: Aggregate variant data from QR codes
  v_payload := public.wms_from_unique_codes(
    p_qr_code_ids, 
    p_from_org_id, 
    p_to_org_id, 
    p_order_id, 
    p_shipped_at
  );
  
  -- Step 2: Record consolidated stock movements and update inventory
  v_ids := public.wms_record_movements_from_items(v_payload);
  
  -- Step 3: Update QR codes status SAFELY (bypassing trigger)
  -- We set the session variable within this transaction block
  PERFORM set_config('app.skip_ship_trigger', 'true', true);
  
  UPDATE public.qr_codes
  SET 
    status = 'shipped_distributor',
    current_location_org_id = p_to_org_id,
    updated_at = p_shipped_at
  WHERE id = ANY(p_qr_code_ids)
    -- Only update if not already shipped (idempotency)
    AND status != 'shipped_distributor';
    
  -- Step 4: Return combined result
  RETURN (v_payload || v_ids);
END;
$$;


ALTER FUNCTION public.wms_ship_unique_auto(p_qr_code_ids uuid[], p_from_org_id uuid, p_to_org_id uuid, p_order_id uuid, p_shipped_at timestamp with time zone) OWNER TO supabase_admin;

--
-- Name: FUNCTION wms_ship_unique_auto(p_qr_code_ids uuid[], p_from_org_id uuid, p_to_org_id uuid, p_order_id uuid, p_shipped_at timestamp with time zone); Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON FUNCTION public.wms_ship_unique_auto(p_qr_code_ids uuid[], p_from_org_id uuid, p_to_org_id uuid, p_order_id uuid, p_shipped_at timestamp with time zone) IS 'Handles warehouse shipment of unique QR codes by:
1. Aggregating variant quantities from QR code IDs
2. Deducting from warehouse inventory
3. Creating consolidated stock movements
4. Returns summary with movement IDs';


