    user_id uuid NOT NULL,
    provider text DEFAULT 'openclaw'::text NOT NULL,
    module text DEFAULT 'hr'::text NOT NULL,
    model text,
    tokens_used integer DEFAULT 0,
    response_ms integer DEFAULT 0,
    status text DEFAULT 'success'::text NOT NULL,
    error_message text,
    message_preview text,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE public.ai_usage_logs OWNER TO supabase_admin;

--
-- Name: ai_usage_summary; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.ai_usage_summary AS
 SELECT organization_id,
    user_id,
    provider,
    module,
    date(created_at) AS usage_date,
    (count(*))::integer AS request_count,
    (sum(
        CASE
            WHEN (status = 'success'::text) THEN 1
            ELSE 0
        END))::integer AS success_count,
    (sum(
        CASE
            WHEN (status = 'error'::text) THEN 1
            ELSE 0
        END))::integer AS error_count,
    (COALESCE(sum(tokens_used), (0)::bigint))::integer AS total_tokens,
    (COALESCE(avg(response_ms), (0)::numeric))::integer AS avg_response_ms
   FROM public.ai_usage_logs
  GROUP BY organization_id, user_id, provider, module, (date(created_at));


ALTER VIEW public.ai_usage_summary OWNER TO supabase_admin;

