    CONSTRAINT users_address_max_length CHECK ((length(address) <= 255)),
    CONSTRAINT users_employment_status_check CHECK ((employment_status = ANY (ARRAY['active'::text, 'resigned'::text, 'terminated'::text]))),
    CONSTRAINT users_employment_type_check CHECK (((employment_type IS NULL) OR (employment_type = ANY (ARRAY['Full-time'::text, 'Part-time'::text, 'Contract'::text, 'Intern'::text])))),
    CONSTRAINT users_no_self_manager CHECK ((id IS DISTINCT FROM manager_user_id)),
    CONSTRAINT users_phone_e164_chk CHECK (((phone IS NULL) OR (phone ~ '^\+[1-9][0-9]{7,14}$'::text))),
    CONSTRAINT valid_email CHECK ((email ~* '^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$'::text))
);


