--
-- Name: hr_employee_dashboard; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.hr_employee_dashboard AS
 SELECT u.id AS user_id,
    u.full_name,
    u.organization_id,
    u.role_code,
    he.employee_no,
    ( SELECT json_build_object('clocked_in', ((ae.clock_in_at IS NOT NULL) AND (ae.clock_out_at IS NULL)), 'clock_in_at', ae.clock_in_at, 'clock_out_at', ae.clock_out_at) AS json_build_object
           FROM public.hr_attendance_entries ae
          WHERE ((ae.user_id = u.id) AND (ae.clock_in_at >= CURRENT_DATE))
          ORDER BY ae.clock_in_at DESC
         LIMIT 1) AS today_attendance,
    ( SELECT count(*) AS count
           FROM public.hr_leave_requests lr
          WHERE ((lr.organization_id = u.organization_id) AND (lr.status = 'pending'::text) AND (lr.employee_id <> u.id))) AS pending_approvals
   FROM (public.users u
     LEFT JOIN public.hr_employees he ON ((he.user_id = u.id)));


ALTER VIEW public.hr_employee_dashboard OWNER TO supabase_admin;

