--
-- Name: journey_configurations; Type: TABLE; Schema: public; Owner: supabase_admin
--

CREATE TABLE public.journey_configurations (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    org_id uuid NOT NULL,
    name text NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    is_default boolean DEFAULT false NOT NULL,
    points_enabled boolean,
    lucky_draw_enabled boolean,
    redemption_enabled boolean,
    require_staff_otp_for_points boolean,
    require_customer_otp_for_lucky_draw boolean,
    require_customer_otp_for_redemption boolean,
    start_at timestamp with time zone,
    end_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by uuid,
    welcome_title text DEFAULT 'Welcome!'::text,
    welcome_message text DEFAULT '...'::text,
    thank_you_message text DEFAULT 'Thank you for your participation!'::text,
    primary_color text DEFAULT '#2563eb'::text,
    button_color text DEFAULT '#3b82f6'::text,
    show_product_image boolean DEFAULT true,
    product_image_source text DEFAULT 'genuine_badge'::text,
    custom_image_url text,
    genuine_badge_style text DEFAULT 'gold'::text,
    activation_mode text DEFAULT 'manual'::text,
    activation_status text DEFAULT 'ready'::text,
    enable_scratch_card_game boolean DEFAULT false,
    scratch_card_require_otp boolean DEFAULT false,
    points_title text DEFAULT 'Collect Points'::text,
    points_description text DEFAULT 'Earn rewards with every scan'::text,
    points_icon text DEFAULT 'Coins'::text,
    lucky_draw_title text DEFAULT 'Lucky Draw'::text,
    lucky_draw_description text DEFAULT 'Try your luck and win prizes!'::text,
    lucky_draw_icon text DEFAULT 'Star'::text,
    redemption_title text DEFAULT 'Claim Free Gift'::text,
    redemption_description text DEFAULT 'Get your free gift at the shop'::text,
    redemption_icon text DEFAULT 'Gift'::text,
    scratch_card_title text DEFAULT 'Scratch Card Game'::text,
    scratch_card_description text DEFAULT 'Scratch & win surprise rewards'::text,
    scratch_card_icon text DEFAULT 'Gift'::text,
    template_type text DEFAULT 'classic'::text,
    skip_security_code_for_points boolean DEFAULT false,
    skip_security_code_for_lucky_draw boolean DEFAULT false,
    skip_security_code_for_redemption boolean DEFAULT false,
    skip_security_code_for_scratch_card boolean DEFAULT false,
    banner_config jsonb DEFAULT '{"items": [], "enabled": false, "template": "grid"}'::jsonb,
    require_security_code boolean DEFAULT false NOT NULL,
    require_security_code_for_features boolean DEFAULT false,
    CONSTRAINT journey_configurations_activation_mode_check CHECK ((activation_mode = ANY (ARRAY['manual'::text, 'auto_on_ship'::text, 'pending_ship'::text]))),
    CONSTRAINT journey_configurations_activation_status_check CHECK ((activation_status = ANY (ARRAY['ready'::text, 'pending_ship'::text, 'auto_activated'::text, 'manually_deactivated'::text]))),
    CONSTRAINT journey_configurations_template_type_check CHECK (((template_type IS NULL) OR (template_type = ANY (ARRAY['classic'::text, 'premium'::text]))))
);


ALTER TABLE public.journey_configurations OWNER TO supabase_admin;

--
-- Name: TABLE journey_configurations; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON TABLE public.journey_configurations IS 'Journey configurations with theme and appearance settings';


--
-- Name: COLUMN journey_configurations.activation_mode; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON COLUMN public.journey_configurations.activation_mode IS 'How journey activates: manual (normal toggle), auto_on_ship (auto-activate when products ship), pending_ship (waiting for products to ship)';


--
-- Name: COLUMN journey_configurations.activation_status; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON COLUMN public.journey_configurations.activation_status IS 'Current activation state: ready (can toggle), pending_ship (waiting), auto_activated (activated by system), manually_deactivated (user turned off)';


--
-- Name: COLUMN journey_configurations.template_type; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON COLUMN public.journey_configurations.template_type IS 'Template style for the journey: classic (simple welcome page) or premium (modern app-like interface with bottom navigation)';


