--
-- Name: order_document_flow; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.order_document_flow AS
 SELECT o.id AS order_id,
    o.order_no,
    o.display_doc_no AS order_display_no,
    o.base_seq,
    o.company_id,
    o.status AS order_status,
    o.created_at AS order_created_at,
    d.id AS document_id,
    d.doc_type,
    d.doc_no AS document_legacy_no,
    d.display_doc_no AS document_display_no,
    d.status AS document_status,
    d.created_at AS document_created_at,
        CASE
            WHEN (d.display_doc_no ~~ '%-%'::text) THEN (split_part(d.display_doc_no, '-'::text, 2))::integer
            ELSE NULL::integer
        END AS sub_sequence
   FROM (public.orders o
     LEFT JOIN public.documents d ON ((d.order_id = o.id)))
  ORDER BY o.created_at DESC, d.created_at;


ALTER VIEW public.order_document_flow OWNER TO supabase_admin;

