--
-- Name: phone_normalization_collision_report; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.phone_normalization_collision_report AS
 SELECT 'users.phone'::text AS source_field,
    public.normalize_phone_e164(phone) AS canonical_phone,
    count(*) AS row_count,
    array_agg((id)::text ORDER BY created_at DESC) AS record_ids
   FROM public.users
  WHERE ((phone IS NOT NULL) AND (btrim(phone) <> ''::text))
  GROUP BY 'users.phone'::text, (public.normalize_phone_e164(phone))
 HAVING (count(*) > 1);


