--
-- Name: stock_movements; Type: TABLE; Schema: public; Owner: supabase_admin
--

CREATE TABLE public.stock_movements (
    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,
    movement_type text NOT NULL,
    reference_type text,
    reference_id uuid,
    reference_no text,
    variant_id uuid NOT NULL,
    from_organization_id uuid,
    to_organization_id uuid,
    quantity_change integer NOT NULL,
    quantity_before integer NOT NULL,
    quantity_after integer NOT NULL,
    unit_cost numeric(12,2),
    total_cost numeric(15,2) GENERATED ALWAYS AS (((abs(quantity_change))::numeric * COALESCE(unit_cost, (0)::numeric))) STORED,
    manufacturer_id uuid,
    warehouse_location text,
    reason text,
    notes text,
    company_id uuid NOT NULL,
    created_by uuid NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    evidence_urls text[],
    CONSTRAINT stock_movements_reference_type_check CHECK ((reference_type = ANY (ARRAY['manual'::text, 'order'::text, 'transfer'::text, 'adjustment'::text, 'purchase_order'::text, 'return'::text, 'campaign'::text]))),
    CONSTRAINT valid_movement_direction CHECK ((((movement_type = 'transfer_out'::text) AND (from_organization_id IS NOT NULL)) OR ((movement_type = 'transfer_in'::text) AND (to_organization_id IS NOT NULL)) OR (movement_type <> ALL (ARRAY['transfer_out'::text, 'transfer_in'::text])))),
    CONSTRAINT valid_quantity_change CHECK ((((movement_type = ANY (ARRAY['addition'::text, 'transfer_in'::text, 'order_cancelled'::text, 'manual_in'::text, 'scratch_game_in'::text, 'allocation'::text, 'warranty_bonus'::text])) AND (quantity_change > 0)) OR ((movement_type = 'adjustment'::text) AND (quantity_change <> 0)) OR ((movement_type = ANY (ARRAY['transfer_out'::text, 'order_fulfillment'::text, 'manual_out'::text, 'scratch_game_out'::text, 'deallocation'::text])) AND (quantity_change < 0))))
);


ALTER TABLE public.stock_movements OWNER TO supabase_admin;

