--
-- Name: v_admin_redemptions; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_admin_redemptions AS
 SELECT pt.id,
    pt.transaction_date AS redeemed_at,
    pt.created_at,
    pt.points_amount,
    pt.balance_after,
    pt.description,
    pt.redemption_code,
    pt.fulfillment_status,
    pt.fulfilled_by,
    pt.fulfilled_at,
    pt.fulfillment_notes,
    pt.company_id AS shop_id,
    ri.id AS reward_id,
    ri.item_name AS reward_name,
    ri.item_code AS reward_code,
    ri.item_image_url AS reward_image_url,
    ri.points_required,
    ri.company_id,
    shop_org.org_name AS shop_name,
    shop_org.contact_phone AS shop_phone,
    shop_org.contact_email AS shop_email,
    shop_org.address AS shop_address,
    shop_org.address_line2 AS shop_address_line2,
    shop_org.city AS shop_city,
    shop_org.state_id AS shop_state_id,
    shop_org.postal_code AS shop_postal_code,
    COALESCE(shop_org.bank_name, mb.short_name, mb.name) AS shop_bank_name,
    COALESCE(shop_org.bank_account_number, u.bank_account_number) AS shop_bank_account_number,
    COALESCE(shop_org.bank_account_holder_name, u.bank_account_holder_name) AS shop_bank_account_holder_name,
    u.id AS staff_user_id,
    COALESCE(u.full_name, 'Unknown User'::text) AS staff_name,
    u.email AS staff_email,
    u.phone AS staff_phone,
    u.location AS staff_location,
    u.address AS staff_address,
    fb.full_name AS fulfilled_by_name,
    fb.email AS fulfilled_by_email
   FROM (((((public.points_transactions pt
     LEFT JOIN public.redeem_items ri ON ((ri.id = pt.redeem_item_id)))
     LEFT JOIN public.organizations shop_org ON ((shop_org.id = pt.company_id)))
     LEFT JOIN public.users u ON ((u.id = pt.user_id)))
     LEFT JOIN public.msia_banks mb ON ((mb.id = u.bank_id)))
     LEFT JOIN public.users fb ON ((fb.id = pt.fulfilled_by)))
  WHERE (pt.transaction_type = 'redeem'::text)
  ORDER BY pt.transaction_date DESC;


ALTER VIEW public.v_admin_redemptions OWNER TO supabase_admin;

--
-- Name: v_admin_support_conversations; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_admin_support_conversations AS
 SELECT c.id,
    c.case_number,
    c.created_by_user_id,
    c.subject,
    c.status,
    c.priority,
    c.assigned_admin_id,
    c.last_message_at,
    c.last_message_preview,
    c.last_message_sender_type,
    c.user_unread_count,
    c.admin_unread_count,
    c.user_deleted_at,
    c.admin_deleted_at,
    c.created_at,
    c.updated_at,
    u.full_name AS user_full_name,
    u.email AS user_email,
    u.phone AS user_phone,
    a.full_name AS assigned_admin_name,
    a.email AS assigned_admin_email,
    ( SELECT count(*) AS count
           FROM public.support_conversation_messages m
          WHERE (m.conversation_id = c.id)) AS total_messages,
    ( SELECT json_agg(json_build_object('id', t.id, 'name', t.name, 'color', t.color)) AS json_agg
           FROM (public.support_conversation_tags ct
             JOIN public.support_tags t ON ((t.id = ct.tag_id)))
          WHERE (ct.conversation_id = c.id)) AS tags
   FROM ((public.support_conversations c
     LEFT JOIN public.users u ON ((u.id = c.created_by_user_id)))
     LEFT JOIN public.users a ON ((a.id = c.assigned_admin_id)))
  WHERE (c.admin_deleted_at IS NULL);


ALTER VIEW public.v_admin_support_conversations OWNER TO supabase_admin;

--
-- Name: v_consumer_points_balance; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_consumer_points_balance AS
 WITH scan_points AS (
         SELECT cqs.consumer_id,
            sum(
                CASE
                    WHEN COALESCE(cqs.is_manual_adjustment, false) THEN 0
                    ELSE cqs.points_amount
                END) AS total_earned_scans,
            sum(
                CASE
                    WHEN COALESCE(cqs.is_manual_adjustment, false) THEN cqs.points_amount
                    ELSE 0
                END) AS total_manual_scans,
            count(*) AS scan_count,
            max(cqs.scanned_at) AS last_scan_at
           FROM public.consumer_qr_scans cqs
          WHERE ((cqs.collected_points = true) AND (cqs.consumer_id IS NOT NULL))
          GROUP BY cqs.consumer_id
        ), transaction_points AS (
         SELECT pt.user_id,
            sum(
                CASE
                    WHEN (pt.transaction_type = 'adjust'::text) THEN 0
                    ELSE pt.points_amount
                END) AS total_transaction_points,
            count(*) AS transaction_count,
            max(pt.transaction_date) AS last_transaction_at,
            sum(
                CASE
                    WHEN (pt.transaction_type = 'redeem'::text) THEN abs(pt.points_amount)
                    ELSE 0
                END) AS total_redeemed,
            sum(
                CASE
                    WHEN (pt.transaction_type = 'adjust'::text) THEN pt.points_amount
                    ELSE 0
                END) AS total_adjusted,
            sum(
                CASE
                    WHEN (pt.transaction_type = 'MIGRATION'::text) THEN pt.points_amount
                    ELSE 0
                END) AS total_migration,
            sum(
                CASE
                    WHEN (pt.transaction_type <> ALL (ARRAY['redeem'::text, 'adjust'::text, 'MIGRATION'::text])) THEN pt.points_amount
                    ELSE 0
                END) AS total_other,
            string_agg(DISTINCT
                CASE
                    WHEN (pt.transaction_type <> ALL (ARRAY['redeem'::text, 'adjust'::text, 'MIGRATION'::text])) THEN pt.transaction_type
                    ELSE NULL::text
                END, ', '::text) AS other_types,
            ( SELECT pt2.created_by
                   FROM public.points_transactions pt2
                  WHERE ((pt2.user_id = pt.user_id) AND (pt2.transaction_type = 'MIGRATION'::text))
                  ORDER BY pt2.transaction_date DESC
                 LIMIT 1) AS last_migration_by_id
           FROM public.points_transactions pt
          WHERE (pt.user_id IS NOT NULL)
          GROUP BY pt.user_id
        )
 SELECT u.id AS user_id,
    COALESCE(u.full_name, 'Unknown Consumer'::text) AS consumer_name,
    u.phone AS consumer_phone,
    u.email AS consumer_email,
    u.location AS consumer_location,
    u.referral_phone AS consumer_reference,
    ref_user.full_name AS referral_name,
    ref_user.email AS referral_email,
    ref_user.phone AS referral_phone_full,
    u.shop_name AS consumer_shop_name,
    u.organization_id AS consumer_org_id,
    org.org_name AS consumer_org_name,
    u.role_code,
    ((COALESCE(sp.total_earned_scans, (0)::bigint) +
        CASE
            WHEN (COALESCE(sp.total_manual_scans, (0)::bigint) > 0) THEN COALESCE(sp.total_manual_scans, (0)::bigint)
            ELSE COALESCE(tp.total_adjusted, (0)::bigint)
        END) + COALESCE(tp.total_transaction_points, (0)::bigint)) AS current_balance,
    COALESCE(sp.total_earned_scans, (0)::bigint) AS total_collected_system,
        CASE
            WHEN (COALESCE(sp.total_manual_scans, (0)::bigint) > 0) THEN COALESCE(sp.total_manual_scans, (0)::bigint)
            ELSE COALESCE(tp.total_adjusted, (0)::bigint)
        END AS total_collected_manual,
    COALESCE(tp.total_migration, (0)::bigint) AS total_migration,
    COALESCE(tp.total_redeemed, (0)::bigint) AS total_redeemed,
    COALESCE(tp.total_other, (0)::bigint) AS total_other,
    tp.other_types,
    (COALESCE(sp.scan_count, (0)::bigint) + COALESCE(tp.transaction_count, (0)::bigint)) AS transaction_count,
    GREATEST(sp.last_scan_at, tp.last_transaction_at) AS last_transaction_date,
    mu.full_name AS last_migration_by_name
   FROM (((((public.users u
     LEFT JOIN scan_points sp ON ((u.id = sp.consumer_id)))
     LEFT JOIN transaction_points tp ON ((u.id = tp.user_id)))
     LEFT JOIN public.users mu ON ((tp.last_migration_by_id = mu.id)))
     LEFT JOIN public.users ref_user ON ((public._normalize_phone_my(ref_user.phone) = public._normalize_phone_my(u.referral_phone))))
     LEFT JOIN public.organizations org ON ((u.organization_id = org.id)))
  WHERE (((u.role_code = ANY (ARRAY['CONSUMER'::text, 'GUEST'::text])) OR (sp.consumer_id IS NOT NULL) OR (tp.user_id IS NOT NULL)) AND (COALESCE(org.org_type_code, 'NO_ORG'::text) <> 'SHOP'::text));


ALTER VIEW public.v_consumer_points_balance OWNER TO supabase_admin;

--
-- Name: v_current_pricing; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_current_pricing AS
 SELECT pp.id,
    pp.variant_id,
    pv.variant_code,
    pv.variant_name,
    p.id AS product_id,
    p.product_code,
    p.product_name,
    pp.organization_id,
    o.org_name,
    o.org_type_code,
    pp.price_tier,
    pp.unit_price,
    pp.case_price,
    pp.min_quantity,
    pp.max_quantity,
    pp.volume_discount_percent,
    pp.promotional_discount_percent,
    round(((pp.unit_price * ((1)::numeric - (COALESCE(pp.volume_discount_percent, (0)::numeric) / (100)::numeric))) * ((1)::numeric - (COALESCE(pp.promotional_discount_percent, (0)::numeric) / (100)::numeric))), 2) AS effective_unit_price,
    pp.currency_code,
    pp.effective_from,
    pp.effective_to
   FROM (((public.product_pricing pp
     JOIN public.product_variants pv ON ((pv.id = pp.variant_id)))
     JOIN public.products p ON ((p.id = pv.product_id)))
     LEFT JOIN public.organizations o ON ((o.id = pp.organization_id)))
  WHERE ((pp.is_active = true) AND (pp.effective_from <= CURRENT_DATE) AND ((pp.effective_to IS NULL) OR (pp.effective_to >= CURRENT_DATE)));


ALTER VIEW public.v_current_pricing OWNER TO supabase_admin;

--
-- Name: VIEW v_current_pricing; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON VIEW public.v_current_pricing IS 'Current active pricing with discounts applied and no need for date filtering.';


--
-- Name: v_document_workflow; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_document_workflow AS
 SELECT o.id AS order_id,
    o.order_no,
    o.order_type,
    o.status AS order_status,
    max(
        CASE
            WHEN (d.doc_type = 'PO'::public.document_type) THEN d.status
            ELSE NULL::public.document_status
        END) AS po_status,
    max(
        CASE
            WHEN (d.doc_type = 'INVOICE'::public.document_type) THEN d.status
            ELSE NULL::public.document_status
        END) AS invoice_status,
    max(
        CASE
            WHEN (d.doc_type = 'PAYMENT'::public.document_type) THEN d.status
            ELSE NULL::public.document_status
        END) AS payment_status,
    max(
        CASE
            WHEN (d.doc_type = 'RECEIPT'::public.document_type) THEN d.status
            ELSE NULL::public.document_status
        END) AS receipt_status,
    max(
        CASE
            WHEN (d.doc_type = 'PO'::public.document_type) THEN d.doc_no
            ELSE NULL::text
        END) AS po_no,
    max(
        CASE
            WHEN (d.doc_type = 'INVOICE'::public.document_type) THEN d.doc_no
            ELSE NULL::text
        END) AS invoice_no,
    max(
        CASE
            WHEN (d.doc_type = 'PAYMENT'::public.document_type) THEN d.doc_no
            ELSE NULL::text
        END) AS payment_no,
    max(
        CASE
            WHEN (d.doc_type = 'RECEIPT'::public.document_type) THEN d.doc_no
            ELSE NULL::text
        END) AS receipt_no,
    o.warehouse_org_id,
    wh.org_name AS warehouse_name
   FROM ((public.orders o
     LEFT JOIN public.documents d ON ((d.order_id = o.id)))
     LEFT JOIN public.organizations wh ON ((wh.id = o.warehouse_org_id)))
  GROUP BY o.id, o.order_no, o.order_type, o.status, o.warehouse_org_id, wh.org_name;


ALTER VIEW public.v_document_workflow OWNER TO supabase_admin;

--
-- Name: VIEW v_document_workflow; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON VIEW public.v_document_workflow IS 'PO/Invoice/Payment/Receipt numbers + statuses per order';


--
-- Name: v_documents_gl_status; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_documents_gl_status AS
 SELECT d.id AS document_id,
    d.doc_type,
    d.doc_no,
    d.order_id,
    o.order_no,
    d.status AS document_status,
    d.created_at AS document_date,
    d.company_id,
        CASE
            WHEN ((dp.id IS NOT NULL) AND (dp.posting_status = 'POSTED'::text)) THEN true
            ELSE false
        END AS is_gl_posted,
    dp.posting_status AS gl_posting_status,
    dp.document_type AS gl_document_type,
    j.journal_number AS gl_journal_number,
    j.posting_date AS gl_posting_date,
    dp.posted_amount AS gl_posted_amount,
    seller_org.org_name AS supplier_name,
    buyer_org.org_name AS buyer_name
   FROM (((((public.documents d
     LEFT JOIN public.orders o ON ((o.id = d.order_id)))
     LEFT JOIN public.gl_document_postings dp ON (((dp.document_id = d.id) AND (dp.company_id = d.company_id))))
     LEFT JOIN public.gl_journals j ON ((j.id = dp.journal_id)))
     LEFT JOIN public.organizations seller_org ON ((seller_org.id = o.seller_org_id)))
     LEFT JOIN public.organizations buyer_org ON ((buyer_org.id = o.buyer_org_id)))
  WHERE (d.doc_type = ANY (ARRAY['PAYMENT'::public.document_type, 'PAYMENT_REQUEST'::public.document_type]));


ALTER VIEW public.v_documents_gl_status OWNER TO supabase_admin;

--
-- Name: VIEW v_documents_gl_status; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON VIEW public.v_documents_gl_status IS 'View of PAYMENT and PAYMENT_REQUEST documents with their GL posting status';


--
-- Name: v_gl_account_ledger; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_gl_account_ledger AS
 SELECT jl.account_id,
    a.code AS account_code,
    a.name AS account_name,
    a.account_type,
    a.normal_balance,
    j.company_id,
    j.id AS journal_id,
    j.journal_number,
    j.journal_date,
    j.posting_date,
    j.description,
    jl.debit_amount,
    jl.credit_amount,
        CASE a.normal_balance
            WHEN 'DEBIT'::text THEN (jl.debit_amount - jl.credit_amount)
            WHEN 'CREDIT'::text THEN (jl.credit_amount - jl.debit_amount)
            ELSE (jl.debit_amount - jl.credit_amount)
        END AS movement,
    jl.entity_type,
    jl.entity_id
   FROM ((public.gl_journal_lines jl
     JOIN public.gl_journals j ON (((j.id = jl.journal_id) AND (j.status = 'POSTED'::text))))
     JOIN public.gl_accounts a ON ((a.id = jl.account_id)))
  ORDER BY a.code, j.posting_date, j.journal_number;


ALTER VIEW public.v_gl_account_ledger OWNER TO supabase_admin;

--
-- Name: v_gl_journal_lines; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_gl_journal_lines AS
 SELECT jl.id,
    jl.journal_id,
    j.journal_number,
    j.company_id,
    jl.line_number,
    jl.account_id,
    a.code AS account_code,
    a.name AS account_name,
    a.account_type,
    jl.description,
    jl.debit_amount,
    jl.credit_amount,
    jl.entity_type,
    jl.entity_id,
        CASE jl.entity_type
            WHEN 'CUSTOMER'::text THEN ( SELECT organizations.org_name
               FROM public.organizations
              WHERE (organizations.id = jl.entity_id))
            WHEN 'SUPPLIER'::text THEN ( SELECT organizations.org_name
               FROM public.organizations
              WHERE (organizations.id = jl.entity_id))
            ELSE NULL::text
        END AS entity_name,
    j.journal_date,
    j.posting_date,
    j.status AS journal_status
   FROM ((public.gl_journal_lines jl
     JOIN public.gl_journals j ON ((j.id = jl.journal_id)))
     JOIN public.gl_accounts a ON ((a.id = jl.account_id)));


ALTER VIEW public.v_gl_journal_lines OWNER TO supabase_admin;

--
-- Name: v_gl_journals; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_gl_journals AS
 SELECT j.id,
    j.company_id,
    j.journal_number,
    j.journal_date,
    j.posting_date,
    j.description,
    j.journal_type,
    j.status,
    j.is_reversal,
    j.reversed_journal_id,
    j.reversal_journal_id,
    j.reversal_reason,
    j.total_debit,
    j.total_credit,
    j.created_at,
    j.posted_at,
    u.email AS created_by_email,
    pu.email AS posted_by_email,
    dp.document_type,
    dp.document_id,
    dp.document_number
   FROM (((public.gl_journals j
     LEFT JOIN auth.users u ON ((u.id = j.created_by)))
     LEFT JOIN auth.users pu ON ((pu.id = j.posted_by)))
     LEFT JOIN public.gl_document_postings dp ON ((dp.journal_id = j.id)));


ALTER VIEW public.v_gl_journals OWNER TO supabase_admin;

--
-- Name: v_gl_subledger; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_gl_subledger AS
 SELECT jl.entity_type,
    jl.entity_id,
    org.org_name AS entity_name,
    j.company_id,
    a.account_type,
    sum(jl.debit_amount) AS total_debit,
    sum(jl.credit_amount) AS total_credit,
    sum((jl.debit_amount - jl.credit_amount)) AS balance
   FROM (((public.gl_journal_lines jl
     JOIN public.gl_journals j ON (((j.id = jl.journal_id) AND (j.status = 'POSTED'::text))))
     JOIN public.gl_accounts a ON ((a.id = jl.account_id)))
     LEFT JOIN public.organizations org ON ((org.id = jl.entity_id)))
  WHERE (jl.entity_id IS NOT NULL)
  GROUP BY jl.entity_type, jl.entity_id, org.org_name, j.company_id, a.account_type;


