-- Name: v_hq_inventory; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_hq_inventory AS
 SELECT p.id AS product_id,
    p.product_code,
    p.product_name,
    pv.id AS variant_id,
    pv.variant_code,
    pv.variant_name,
    hq.id AS hq_org_id,
    hq.org_name AS hq_org_name,
    pi.quantity_on_hand,
    pi.quantity_allocated,
    pi.quantity_available,
    pi.average_cost,
    pi.total_value
   FROM (((public.products p
     JOIN public.product_variants pv ON (((pv.product_id = p.id) AND (pv.is_active = true))))
     JOIN public.organizations hq ON ((hq.org_type_code = 'HQ'::text)))
     LEFT JOIN public.product_inventory pi ON (((pi.variant_id = pv.id) AND (pi.organization_id = hq.id) AND (pi.is_active = true))));


ALTER VIEW public.v_hq_inventory OWNER TO supabase_admin;

--
-- Name: v_low_stock_alerts; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_low_stock_alerts AS
 SELECT pi.id,
    pi.organization_id,
    o.org_name,
    o.org_type_code,
    pi.variant_id,
    pv.variant_code,
    pv.variant_name,
    p.id AS product_id,
    p.product_code,
    p.product_name,
    p.brand_id,
    b.brand_name,
    pi.quantity_on_hand,
    pi.quantity_allocated,
    pi.quantity_available,
    pi.reorder_point,
    pi.reorder_quantity,
    pi.max_stock_level,
    (pi.reorder_point - pi.quantity_available) AS units_below_reorder,
        CASE
            WHEN (pi.reorder_point > 0) THEN round((((pi.quantity_available)::numeric / (pi.reorder_point)::numeric) * (100)::numeric), 1)
            ELSE (0)::numeric
        END AS stock_level_percent,
        CASE
            WHEN (pi.quantity_available <= 0) THEN 'CRITICAL'::text
            WHEN ((pi.quantity_available)::numeric <= ((pi.reorder_point)::numeric * 0.5)) THEN 'HIGH'::text
            WHEN (pi.quantity_available <= pi.reorder_point) THEN 'MEDIUM'::text
            ELSE 'LOW'::text
        END AS priority,
    pi.warehouse_location,
    pi.last_counted_at,
    pi.updated_at
   FROM ((((public.product_inventory pi
     JOIN public.product_variants pv ON ((pv.id = pi.variant_id)))
     JOIN public.products p ON ((p.id = pv.product_id)))
     LEFT JOIN public.brands b ON ((b.id = p.brand_id)))
     JOIN public.organizations o ON ((o.id = pi.organization_id)))
  WHERE ((pi.is_active = true) AND (pi.quantity_available <= pi.reorder_point))
  ORDER BY
        CASE
            WHEN (pi.quantity_available <= 0) THEN 1
            WHEN ((pi.quantity_available)::numeric <= ((pi.reorder_point)::numeric * 0.5)) THEN 2
            WHEN (pi.quantity_available <= pi.reorder_point) THEN 3
            ELSE 4
        END, pi.quantity_available;


ALTER VIEW public.v_low_stock_alerts OWNER TO supabase_admin;

--
-- Name: VIEW v_low_stock_alerts; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON VIEW public.v_low_stock_alerts IS 'Low stock alerts with priority levels (CRITICAL/HIGH/MEDIUM/LOW).';


--
-- Name: v_order_engagement_summary; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_order_engagement_summary AS
 SELECT o.id AS order_id,
    o.order_no,
    o.company_id,
    o.order_type,
    o.status,
    o.has_redeem,
    o.has_lucky_draw,
    jol.journey_config_id,
    jc.name AS journey_name,
    jc.is_active AS journey_is_active,
    count(DISTINCT rg.id) AS redeem_gifts_count,
    COALESCE(sum(rg.total_quantity), (0)::bigint) AS total_redeem_quantity,
    COALESCE(sum(rg.claimed_quantity), (0)::bigint) AS claimed_redeem_quantity,
    count(DISTINCT ldol.campaign_id) AS lucky_draw_campaigns_count,
    count(DISTINCT qr.id) AS total_qr_codes,
    count(DISTINCT
        CASE
            WHEN (qr.status = 'activated'::text) THEN qr.id
            ELSE NULL::uuid
        END) AS activated_qr_codes
   FROM (((((public.orders o
     LEFT JOIN public.journey_order_links jol ON ((jol.order_id = o.id)))
     LEFT JOIN public.journey_configurations jc ON ((jc.id = jol.journey_config_id)))
     LEFT JOIN public.redeem_gifts rg ON ((rg.order_id = o.id)))
     LEFT JOIN public.lucky_draw_order_links ldol ON ((ldol.order_id = o.id)))
     LEFT JOIN public.qr_codes qr ON ((qr.order_id = o.id)))
  WHERE ((o.has_redeem = true) OR (o.has_lucky_draw = true))
  GROUP BY o.id, o.order_no, o.company_id, o.order_type, o.status, o.has_redeem, o.has_lucky_draw, jol.journey_config_id, jc.name, jc.is_active;


ALTER VIEW public.v_order_engagement_summary OWNER TO supabase_admin;

