CREATE VIEW public.v_qr_recovery_candidates AS
 SELECT vl.id,
    vl.created_at,
    vl.raw_code,
    vl.parsed_order_no,
    vl.parsed_product_sku,
    vl.parsed_variant_code,
    vl.parsed_sequence,
    vl.parsed_hash_suffix,
    vl.trust_level,
    vl.hash_status,
    vl.lookup_result,
    vl.order_exists,
    vl.qr_exists,
    vl.user_facing_outcome,
    vl.points_outcome,
    vl.recovery_status,
    vl.consumer_phone,
    vl.consumer_name,
    vl.ip_address,
    vl.user_agent,
    vl.notes,
    o.order_no AS matched_order_no,
    o.id AS matched_order_id,
    vl.is_test_data
   FROM (public.qr_verification_log vl
     LEFT JOIN public.orders o ON ((o.order_no = vl.parsed_order_no)))
  WHERE (vl.is_recovery_candidate = true)
  ORDER BY vl.created_at DESC;


