-- Name: v_qr_recovery_summary; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_qr_recovery_summary AS
 SELECT trust_level,
    user_facing_outcome,
    recovery_status,
    count(*) AS total_scans,
    count(*) FILTER (WHERE (created_at >= (now() - '24:00:00'::interval))) AS last_24h,
    count(*) FILTER (WHERE (created_at >= (now() - '7 days'::interval))) AS last_7d,
    min(created_at) AS first_seen,
    max(created_at) AS last_seen
   FROM public.qr_verification_log
  GROUP BY trust_level, user_facing_outcome, recovery_status;


