   FROM public.qr_verification_log
  WHERE (created_at >= (now() - '30 days'::interval))
  GROUP BY (date_trunc('hour'::text, created_at)), trust_level, user_facing_outcome
  ORDER BY (date_trunc('hour'::text, created_at)) DESC;


