    min(seq_number) FILTER (WHERE (reused_at IS NULL)) AS next_available_seq,
    array_agg(display_doc_no ORDER BY seq_number) FILTER (WHERE (reused_at IS NULL)) AS available_numbers
   FROM public.recycled_doc_numbers
  GROUP BY company_id, doc_type, year
  ORDER BY company_id, doc_type, year;


