--
-- Name: v_referral_monitor; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_referral_monitor AS
 WITH active_assignments AS (
         SELECT ra.reference_user_id,
            ra.org_id,
            count(*) AS assigned_shops_count
           FROM public.reference_assignments ra
          WHERE ((ra.effective_to IS NULL) AND (ra.reference_user_id IS NOT NULL))
          GROUP BY ra.reference_user_id, ra.org_id
        ), accrual_totals AS (
         SELECT rac.reference_user_id,
            rac.org_id,
            COALESCE(sum(rac.points_amount), (0)::bigint) AS total_accrued_points,
            COALESCE(sum(rac.rm_amount), (0)::numeric) AS total_accrued_rm
           FROM public.referral_accruals rac
          GROUP BY rac.reference_user_id, rac.org_id
        ), claim_totals AS (
         SELECT rc.reference_user_id,
            rc.org_id,
            COALESCE(sum(
                CASE
                    WHEN (rc.status = ANY (ARRAY['approved'::public.referral_claim_status, 'paid'::public.referral_claim_status])) THEN rc.claim_points
                    ELSE 0
                END), (0)::bigint) AS total_claimed_points,
            COALESCE(sum(
                CASE
                    WHEN (rc.status = ANY (ARRAY['approved'::public.referral_claim_status, 'paid'::public.referral_claim_status])) THEN rc.claim_rm
                    ELSE (0)::numeric
                END), (0)::numeric) AS total_claimed_rm,
            count(
                CASE
                    WHEN (rc.status = 'pending'::public.referral_claim_status) THEN 1
                    ELSE NULL::integer
                END) AS pending_claims_count
           FROM public.referral_claims rc
          GROUP BY rc.reference_user_id, rc.org_id
        ), adjustment_totals AS (
         SELECT radj.reference_user_id,
            radj.org_id,
            COALESCE(sum(
                CASE
                    WHEN (radj.adjustment_type = ANY (ARRAY['credit'::public.referral_adjustment_type, 'transfer_in'::public.referral_adjustment_type])) THEN radj.points_amount
                    ELSE 0
                END), (0)::bigint) AS total_adj_credit_points,
            COALESCE(sum(
                CASE
                    WHEN (radj.adjustment_type = ANY (ARRAY['debit'::public.referral_adjustment_type, 'transfer_out'::public.referral_adjustment_type])) THEN radj.points_amount
                    ELSE 0
                END), (0)::bigint) AS total_adj_debit_points,
            COALESCE(sum(
                CASE
                    WHEN (radj.adjustment_type = ANY (ARRAY['credit'::public.referral_adjustment_type, 'transfer_in'::public.referral_adjustment_type])) THEN radj.rm_amount
                    ELSE (0)::numeric
                END), (0)::numeric) AS total_adj_credit_rm,
            COALESCE(sum(
                CASE
                    WHEN (radj.adjustment_type = ANY (ARRAY['debit'::public.referral_adjustment_type, 'transfer_out'::public.referral_adjustment_type])) THEN radj.rm_amount
                    ELSE (0)::numeric
                END), (0)::numeric) AS total_adj_debit_rm
           FROM public.referral_adjustments radj
          GROUP BY radj.reference_user_id, radj.org_id
        )
 SELECT u.id AS reference_user_id,
    u.full_name AS reference_name,
    u.phone AS reference_phone,
    u.email AS reference_email,
    COALESCE(u.employment_status, u.role_code) AS employment_status,
    u.organization_id AS reference_org_id,
    COALESCE(aa.org_id, at2.org_id, ct.org_id, adj.org_id, u.organization_id) AS org_id,
    COALESCE(aa.assigned_shops_count, (0)::bigint) AS assigned_shops_count,
    COALESCE(at2.total_accrued_points, (0)::bigint) AS total_accrued_points,
    (COALESCE(at2.total_accrued_rm, (0)::numeric))::numeric(12,2) AS total_accrued_rm,
    COALESCE(ct.total_claimed_points, (0)::bigint) AS total_claimed_points,
    (COALESCE(ct.total_claimed_rm, (0)::numeric))::numeric(12,2) AS total_claimed_rm,
    COALESCE(ct.pending_claims_count, (0)::bigint) AS pending_claims_count,
    (((COALESCE(at2.total_accrued_points, (0)::bigint) + COALESCE(adj.total_adj_credit_points, (0)::bigint)) - COALESCE(adj.total_adj_debit_points, (0)::bigint)) - COALESCE(ct.total_claimed_points, (0)::bigint)) AS claimable_points,
    ((((COALESCE(at2.total_accrued_rm, (0)::numeric) + COALESCE(adj.total_adj_credit_rm, (0)::numeric)) - COALESCE(adj.total_adj_debit_rm, (0)::numeric)) - COALESCE(ct.total_claimed_rm, (0)::numeric)))::numeric(12,2) AS claimable_rm
   FROM ((((public.users u
     LEFT JOIN active_assignments aa ON ((aa.reference_user_id = u.id)))
     LEFT JOIN accrual_totals at2 ON ((at2.reference_user_id = u.id)))
     LEFT JOIN claim_totals ct ON ((ct.reference_user_id = u.id)))
     LEFT JOIN adjustment_totals adj ON ((adj.reference_user_id = u.id)))
  WHERE ((u.can_be_reference = true) AND (u.is_active = true));


ALTER VIEW public.v_referral_monitor OWNER TO supabase_admin;

--
-- Name: v_reverse_job_status; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_reverse_job_status AS
 SELECT j.id,
    j.order_id,
    j.batch_id,
    j.product_variant_key,
    j.case_number,
    j.status,
    j.total_spoiled,
    j.total_replacements,
    j.master_code,
    j.final_unit_count,
    j.created_at,
    j.completed_at,
    j.error_message,
    j.expected_units_per_case,
    o.order_no,
    u.email AS created_by_email,
    count(
        CASE
            WHEN (ji.status = 'pending'::text) THEN 1
            ELSE NULL::integer
        END) AS pending_items,
    count(
        CASE
            WHEN (ji.status = 'replaced'::text) THEN 1
            ELSE NULL::integer
        END) AS replaced_items,
    count(
        CASE
            WHEN (ji.status = 'failed'::text) THEN 1
            ELSE NULL::integer
        END) AS failed_items
   FROM (((public.qr_reverse_jobs j
     LEFT JOIN public.orders o ON ((j.order_id = o.id)))
     LEFT JOIN public.users u ON ((j.created_by = u.id)))
     LEFT JOIN public.qr_reverse_job_items ji ON ((j.id = ji.job_id)))
  GROUP BY j.id, j.order_id, j.batch_id, j.product_variant_key, j.case_number, j.status, j.total_spoiled, j.total_replacements, j.master_code, j.final_unit_count, j.created_at, j.completed_at, j.error_message, j.expected_units_per_case, o.order_no, u.email;


ALTER VIEW public.v_reverse_job_status OWNER TO supabase_admin;

--
-- Name: VIEW v_reverse_job_status; Type: COMMENT; Schema: public; Owner: supabase_admin
--

COMMENT ON VIEW public.v_reverse_job_status IS 'Convenient view for monitoring reverse job progress with item counts.';


--
-- Name: v_shop_available_products; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_shop_available_products AS
 SELECT DISTINCT sd.shop_id,
    s.org_name AS shop_name,
    sd.distributor_id,
    d.org_name AS distributor_name,
    p.id AS product_id,
    p.product_code,
    p.product_name,
    p.is_vape,
    b.brand_name,
    c.category_name,
    dp.distributor_cost AS distributor_wholesale_cost,
    dp.territory_coverage,
    dp.lead_time_days,
    sd.payment_terms,
    sd.credit_limit,
    pi.quantity_available AS distributor_stock,
    dp.is_active AS distributor_carries_product,
    sd.is_active AS shop_distributor_active,
    p.is_active AS product_active
   FROM ((((((((public.shop_distributors sd
     JOIN public.organizations s ON (((s.id = sd.shop_id) AND (s.org_type_code = 'SHOP'::text))))
     JOIN public.organizations d ON (((d.id = sd.distributor_id) AND (d.org_type_code = 'DIST'::text))))
     JOIN public.distributor_products dp ON ((dp.distributor_id = sd.distributor_id)))
     JOIN public.products p ON ((p.id = dp.product_id)))
     LEFT JOIN public.brands b ON ((b.id = p.brand_id)))
     LEFT JOIN public.product_categories c ON ((c.id = p.category_id)))
     LEFT JOIN public.product_variants pv ON (((pv.product_id = p.id) AND (pv.is_default = true))))
     LEFT JOIN public.product_inventory pi ON (((pi.variant_id = pv.id) AND (pi.organization_id = sd.distributor_id))));


ALTER VIEW public.v_shop_available_products OWNER TO supabase_admin;

--
-- Name: v_shop_points_balance; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_shop_points_balance AS
 SELECT shop_id,
    sum(points_change) AS current_balance,
    count(*) AS transaction_count,
    min(occurred_at) AS first_transaction_at,
    max(occurred_at) AS last_transaction_at,
    sum(
        CASE
            WHEN (transaction_type = 'scan'::text) THEN points_change
            ELSE 0
        END) AS total_earned_scans,
    sum(
        CASE
            WHEN (transaction_type = ANY (ARRAY['manual'::text, 'adjust'::text])) THEN points_change
            ELSE 0
        END) AS total_manual_adjustments,
    sum(
        CASE
            WHEN (transaction_type = 'redeem'::text) THEN abs(points_change)
            ELSE 0
        END) AS total_redeemed,
    count(
        CASE
            WHEN (transaction_type = 'scan'::text) THEN 1
            ELSE NULL::integer
        END) AS scan_count,
    count(
        CASE
            WHEN (transaction_type = 'redeem'::text) THEN 1
            ELSE NULL::integer
        END) AS redemption_count
   FROM public.shop_points_ledger
  WHERE (shop_id IS NOT NULL)
  GROUP BY shop_id;


ALTER VIEW public.v_shop_points_balance OWNER TO supabase_admin;

