--
-- Name: v_shop_points_summary; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_shop_points_summary AS
 WITH user_counts AS (
         SELECT o_1.id AS shop_id,
            count(u.id) AS total_consumers
           FROM (public.organizations o_1
             LEFT JOIN public.users u ON (((u.organization_id = o_1.id) AND (u.role_code = ANY (ARRAY['CONSUMER'::text, 'GUEST'::text])) AND (u.is_active = true))))
          WHERE (o_1.org_type_code = 'SHOP'::text)
          GROUP BY o_1.id
        )
 SELECT o.id AS shop_id,
    o.org_name AS shop_name,
    o.branch AS branch_name,
    o.contact_name,
    o.contact_phone,
    COALESCE(s.state_name, ''::text) AS state,
    COALESCE(uc.total_consumers, (0)::bigint) AS total_consumers,
    COALESCE((vsp.current_balance)::numeric, (0)::numeric) AS total_points_balance,
    COALESCE((vsp.total_earned_scans)::numeric, (0)::numeric) AS total_collected_system,
    COALESCE((vsp.total_manual_adjustments)::numeric, (0)::numeric) AS total_collected_manual,
    (0)::numeric AS total_migration_points,
    COALESCE((vsp.total_redeemed)::numeric, (0)::numeric) AS total_redeemed,
    COALESCE((vsp.transaction_count)::numeric, (0)::numeric) AS total_transactions,
    vsp.last_transaction_at AS last_activity
   FROM (((public.organizations o
     LEFT JOIN public.states s ON ((o.state_id = s.id)))
     LEFT JOIN user_counts uc ON ((uc.shop_id = o.id)))
     LEFT JOIN public.v_shop_points_balance vsp ON ((vsp.shop_id = o.id)))
  WHERE (o.org_type_code = 'SHOP'::text)
  ORDER BY COALESCE((vsp.current_balance)::numeric, (0)::numeric) DESC;


ALTER VIEW public.v_shop_points_summary OWNER TO supabase_admin;

