    reason,
    created_by
   FROM public.stock_movements sm
  WHERE ((NOT ((movement_type = 'order_fulfillment'::text) AND (quantity_before = 0) AND (quantity_after = 0))) AND (NOT ((from_organization_id IS NULL) AND (to_organization_id IS NULL))));


