   FROM public.roles
  WHERE ((is_active = true) AND (role_code = ANY (ARRAY['SA'::text, 'HQ'::text, 'POWER_USER'::text, 'MANAGER'::text, 'USER'::text, 'GUEST'::text])))
  ORDER BY role_level, role_code;


