--
-- Name: v_user_shop_migration; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.v_user_shop_migration AS
 SELECT u.id AS user_id,
    u.full_name,
    u.phone,
    u.email,
    u.shop_name AS current_shop_name,
    u.organization_id AS current_org_id,
    o_current.org_name AS current_org_name,
    o_match.id AS matched_org_id,
    o_match.org_name AS matched_org_name,
    o_match.branch AS matched_org_branch,
        CASE
            WHEN (u.organization_id IS NOT NULL) THEN 'linked'::text
            WHEN ((u.shop_name IS NOT NULL) AND ((u.shop_name)::text <> ''::text) AND (o_match.id IS NOT NULL)) THEN 'auto_matchable'::text
            WHEN ((u.shop_name IS NOT NULL) AND ((u.shop_name)::text <> ''::text) AND (o_match.id IS NULL)) THEN 'unmatched'::text
            ELSE 'no_shop'::text
        END AS match_status,
    u.created_at,
    u.is_active
   FROM ((public.users u
     LEFT JOIN public.organizations o_current ON ((u.organization_id = o_current.id)))
     LEFT JOIN public.organizations o_match ON (((lower(TRIM(BOTH FROM u.shop_name)) = lower(TRIM(BOTH FROM o_match.org_name))) AND (o_match.org_type_code = 'SHOP'::text))))
  WHERE (u.role_code = ANY (ARRAY['CONSUMER'::text, 'GUEST'::text]));


ALTER VIEW public.v_user_shop_migration OWNER TO supabase_admin;

