--
-- Name: vw_inventory_on_hand; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.vw_inventory_on_hand AS
 SELECT pi.id,
    pi.variant_id,
    pi.organization_id,
    pi.quantity_on_hand,
    pi.quantity_allocated,
    pi.quantity_available,
    pi.reorder_point,
    pi.reorder_quantity,
    pi.max_stock_level,
    pi.safety_stock,
    pi.lead_time_days,
    pi.average_cost,
    pi.total_value,
    pi.warehouse_location,
    pv.variant_code,
    pv.variant_name,
    pv.image_url AS variant_image_url,
    p.id AS product_id,
    p.product_name,
    p.product_code,
    o.org_name AS organization_name,
    o.org_code AS organization_code,
    pi.updated_at
   FROM (((public.product_inventory pi
     JOIN public.product_variants pv ON ((pi.variant_id = pv.id)))
     JOIN public.products p ON ((pv.product_id = p.id)))
     JOIN public.organizations o ON ((pi.organization_id = o.id)))
  WHERE (pi.is_active = true);


ALTER VIEW public.vw_inventory_on_hand OWNER TO supabase_admin;

--
-- Name: vw_manual_stock_balance; Type: VIEW; Schema: public; Owner: supabase_admin
--

CREATE VIEW public.vw_manual_stock_balance AS
 SELECT
        CASE
            WHEN (movement_type = 'manual_in'::text) THEN to_organization_id
            WHEN (movement_type = 'manual_out'::text) THEN from_organization_id
            ELSE NULL::uuid
        END AS warehouse_id,
    variant_id,
    sum(
        CASE
            WHEN (movement_type = 'manual_in'::text) THEN quantity_change
            WHEN (movement_type = 'manual_out'::text) THEN quantity_change
            ELSE 0
        END) AS manual_balance_qty
   FROM public.stock_movements
  WHERE (movement_type = ANY (ARRAY['manual_in'::text, 'manual_out'::text]))
  GROUP BY
        CASE
            WHEN (movement_type = 'manual_in'::text) THEN to_organization_id
            WHEN (movement_type = 'manual_out'::text) THEN from_organization_id
            ELSE NULL::uuid
        END, variant_id;


ALTER VIEW public.vw_manual_stock_balance OWNER TO supabase_admin;

