--

CREATE TRIGGER trg_auto_post_document_status_change AFTER UPDATE OF status ON public.documents FOR EACH ROW WHEN (((new.status = 'completed'::public.document_status) AND (old.status IS DISTINCT FROM new.status) AND (new.doc_type = ANY (ARRAY['PAYMENT'::public.document_type, 'PAYMENT_REQUEST'::public.document_type])))) EXECUTE FUNCTION public.auto_post_payment_to_gl();


