--
-- Name: system_preferences Allow all access for admins; Type: POLICY; Schema: core; Owner: supabase_admin
--

CREATE POLICY "Allow all access for admins" ON core.system_preferences USING ((EXISTS ( SELECT 1
   FROM (public.users up
     JOIN public.roles r ON ((up.role_code = r.role_code)))
  WHERE ((up.id = auth.uid()) AND (up.organization_id = system_preferences.company_id) AND (r.role_level <= 20)))));


--
-- Name: system_preferences Allow read access for users in same company; Type: POLICY; Schema: core; Owner: supabase_admin
--

CREATE POLICY "Allow read access for users in same company" ON core.system_preferences FOR SELECT USING ((company_id IN ( SELECT users.organization_id
   FROM public.users
  WHERE (users.id = auth.uid()))));


--
-- Name: system_preferences; Type: ROW SECURITY; Schema: core; Owner: supabase_admin
--

