-- Name: users Users can view hierarchy including independents; Type: POLICY; Schema: public; Owner: supabase_admin
--

CREATE POLICY "Users can view hierarchy including independents" ON public.users FOR SELECT TO authenticated USING (((CURRENT_USER = 'postgres'::name) OR (auth.uid() = id) OR public.is_super_admin() OR (EXISTS ( SELECT 1
   FROM public.get_auth_user_info() my(organization_id, role_level)
  WHERE ((((my.organization_id IS NOT NULL) AND (my.organization_id = users.organization_id)) OR ((users.organization_id IS NULL) AND (my.role_level <= 40))) AND ((my.role_level <= 20) OR (my.role_level <= ( SELECT COALESCE(r2.role_level, 999) AS "coalesce"
           FROM public.roles r2
          WHERE (r2.role_code = users.role_code)))))))));


