--
-- Name: document_signatures power_user_view_company_signatures; Type: POLICY; Schema: public; Owner: supabase_admin
--

CREATE POLICY power_user_view_company_signatures ON public.document_signatures FOR SELECT TO authenticated USING ((public.has_role_level(30) AND (EXISTS ( SELECT 1
   FROM public.documents d
  WHERE ((d.id = document_signatures.document_id) AND (d.company_id = ( SELECT u.organization_id
           FROM public.users u
          WHERE (u.id = auth.uid()))))))));


--
-- Name: product_pricing pricing_hq_manage; Type: POLICY; Schema: public; Owner: supabase_admin
--

CREATE POLICY pricing_hq_manage ON public.product_pricing TO authenticated USING (public.is_hq_admin()) WITH CHECK (public.is_hq_admin());


--
-- Name: product_pricing pricing_read_org_hierarchy; Type: POLICY; Schema: public; Owner: supabase_admin
--

CREATE POLICY pricing_read_org_hierarchy ON public.product_pricing FOR SELECT TO authenticated USING (((is_active = true) AND (effective_from <= CURRENT_DATE) AND ((effective_to IS NULL) OR (effective_to >= CURRENT_DATE)) AND ((organization_id IS NULL) OR public.can_access_org(organization_id) OR public.is_hq_admin())));


